def normalize_timestamp(value):
    if value is None:
        return ""
    return str(value).strip()


def to_number(value):
    if value is None:
        return None
    try:
        if isinstance(value, str):
            value = value.replace(",", "").strip()
            if value in {"", "-", "xx", "None", "nan"}:
                return None
        number = float(value)
        if math.isnan(number) or math.isinf(number):
            return None
        return number
    except Exception:
        return None


def json_safe(value):
    """Convert pandas/numeric objects into JSON-safe Python values."""
    if value is None:
        return None
    if isinstance(value, dict):
        return {str(k): json_safe(v) for k, v in value.items()}
    if isinstance(value, (list, tuple, set)):
        return [json_safe(v) for v in value]
    if isinstance(value, pd.Timestamp):
        return value.isoformat()
    if hasattr(value, "to_pydatetime"):
        try:
            return value.to_pydatetime().isoformat()
        except Exception:
            pass
    if hasattr(value, "item") and not isinstance(value, (str, bytes)):
        try:
            value = value.item()
        except Exception:
            pass
    if isinstance(value, float):
        if math.isnan(value) or math.isinf(value):
            return None
        return value
    return value


def row_json(row):
    """Return a JSON-safe dict for pandas Series / SQL result mapping rows."""
    try:
        data = row.to_dict()
    except Exception:
        data = dict(row)
    return json_safe(data)


def parse_timestamp(value):
    text = normalize_timestamp(value)
    for fmt in ("%d-%b-%Y %H:%M:%S", "%d-%b-%Y %H:%M", "%Y-%m-%d %H:%M:%S"):
        try:
            return datetime.strptime(text, fmt)
        except Exception:
            pass
    return datetime.min


def timestamp_date(value):
    parsed = parse_timestamp(value)
    if parsed == datetime.min:
        return ""
    return parsed.strftime("%Y-%m-%d")



def trade_date_to_nse_prefix(trade_date):
    """Convert YYYY-MM-DD into NSE text timestamp prefix like 18-May-2026."""
    if not trade_date:
        return None
    try:
        return datetime.strptime(str(trade_date), "%Y-%m-%d").strftime("%d-%b-%Y")
    except Exception:
        return None


def expiry_variants(expiry):
    """
    Return possible DB text formats for the same expiry date.

    Older/newer scripts may store expiryDate as 26-May-2026, 26-05-2026,
    or 2026-05-26. Use all variants so exact SQL filtering does not miss rows.
    """
    if not expiry:
        return []

    raw = str(expiry).strip()
    values = [raw]

    parsed = None
    for fmt in ("%d-%b-%Y", "%d-%m-%Y", "%Y-%m-%d"):
        try:
            parsed = datetime.strptime(raw, fmt)
            break
        except Exception:
            pass

    if parsed is None:
        try:
            parsed_pd = pd.to_datetime(raw, errors="coerce", dayfirst=True)
            if pd.notna(parsed_pd):
                parsed = parsed_pd.to_pydatetime()
        except Exception:
            parsed = None

    if parsed is not None:
        values.extend([
            parsed.strftime("%d-%b-%Y"),
            parsed.strftime("%d-%m-%Y"),
            parsed.strftime("%Y-%m-%d"),
        ])

    out = []
    for value in values:
        value = str(value).strip()
        if value and value not in out:
            out.append(value)
    return out


def expiry_key(value):
    """Normalize expiry text/date into YYYY-MM-DD for reliable comparison."""
    if value is None:
        return ""
    raw = str(value).strip()
    if not raw or raw.lower() in {"none", "nan", "nat"}:
        return ""

    # Remove time part if a DB driver converts date/datetime to text.
    raw_short = raw.split()[0]

    for candidate in (raw, raw_short):
        for fmt in ("%d-%b-%Y", "%d-%m-%Y", "%Y-%m-%d"):
            try:
                return datetime.strptime(candidate, fmt).strftime("%Y-%m-%d")
            except Exception:
                pass
        try:
            parsed = pd.to_datetime(candidate, errors="coerce", dayfirst=True)
            if pd.notna(parsed):
                return parsed.strftime("%Y-%m-%d")
        except Exception:
            pass
    return raw_short.lower()


def filter_frame_by_expiry(df, expiry, expiry_col=None):
    """
    Filter a DataFrame by expiry while tolerating different stored text formats.
    """
    if df.empty or not expiry:
        return df

    expiry_col = expiry_col or find_column(df, ("expiryDate", "expiry"))
    if not expiry_col:
        return df

    target_keys = {expiry_key(value) for value in expiry_variants(expiry)}
    target_keys = {value for value in target_keys if value}
    raw_variants = {str(value).strip() for value in expiry_variants(expiry)}

    if not target_keys and not raw_variants:
        return df

    mask = df[expiry_col].map(
        lambda value: expiry_key(value) in target_keys or str(value).strip() in raw_variants
    )
    return df[mask].copy()


def read_sql_with_date_filter(engine, symbol, trade_date, limit_latest_timestamps=None):
    """
    Fast date reader for timestamp stored as TEXT.

    The previous version first loaded every distinct timestamp from the whole table,
    then filtered in pandas. That becomes slow as the database grows. This version
    filters in PostgreSQL using the NSE text date prefix first, with CAST fallback.
    """
    if symbol not in SYMBOLS:
        raise ValueError("Invalid symbol")
    if not trade_date:
        return pd.DataFrame()

    prefix = trade_date_to_nse_prefix(trade_date)
    queries = []
    if prefix:
        queries.append((
            f'SELECT * FROM "{symbol}" WHERE "timestamp" LIKE :ts_prefix',
            {"ts_prefix": prefix + "%"},
        ))
    queries.append((
        f'SELECT * FROM "{symbol}" WHERE CAST("timestamp" AS DATE) = CAST(:trade_date AS DATE)',
        {"trade_date": trade_date},
    ))

    last_error = None
    for sql, params in queries:
        try:
            df = pd.read_sql(sqlalchemy.text(sql), engine, params=params)
            if df.empty or "timestamp" not in df.columns:
                continue
            df["timestamp"] = df["timestamp"].map(normalize_timestamp)
            if limit_latest_timestamps is not None:
                timestamps = sorted(df["timestamp"].dropna().unique(), key=parse_timestamp, reverse=True)
                keep = set(timestamps[:limit_latest_timestamps])
                df = df[df["timestamp"].isin(keep)].copy()
            return df
        except Exception as exc:
            last_error = exc
            continue
    if last_error:
        return pd.DataFrame()
    return pd.DataFrame()


def get_available_dates_fast(symbol, row_limit=60000):
    """
    Return all available option table dates.

    The previous ctid/recent-row shortcut can miss older dates when the latest
    date has many option rows. Use PostgreSQL DISTINCT date extraction first so
    the frontend date dropdown shows every date present in the table.
    """
    if symbol not in SYMBOLS:
        raise ValueError("Invalid symbol")

    try:
        query = sqlalchemy.text(
            f'SELECT DISTINCT CAST("timestamp" AS DATE) AS trade_date '
            f'FROM "{symbol}" '
            f'ORDER BY trade_date DESC'
        )
        df = pd.read_sql(query, ENGINE)
        if not df.empty and "trade_date" in df.columns:
            dates = []
            for value in df["trade_date"].dropna().tolist():
                try:
                    dates.append(pd.to_datetime(value).strftime("%Y-%m-%d"))
                except Exception:
                    dates.append(str(value))
            return dates
    except Exception:
        pass

    # Fallback: read a larger recent sample and parse in pandas.
    try:
        query = sqlalchemy.text(f'SELECT "timestamp" FROM "{symbol}" ORDER BY ctid DESC LIMIT :limit')
        df = pd.read_sql(query, ENGINE, params={"limit": int(row_limit)})
        if not df.empty and "timestamp" in df.columns:
            return sorted(
                {timestamp_date(value) for value in df["timestamp"].tolist() if timestamp_date(value)},
                reverse=True,
            )
    except Exception:
        pass

    return []

def expiry_sort_key(value):
    """
    Sort expiry text reliably.

    Fix V11.8.39:
    Older function only parsed 30-Jun-2026. If DB returned 30-06-2026
    and 07-07-2026, both sorted as datetime.max and dropdown could show
    next expiry first. This now normalizes all common formats first.
    """
    if value is None:
        return datetime.max

    # Use expiry_key if already available at runtime; functions can reference globals
    # defined later in the file.
    try:
        key = expiry_key(value)
        if key:
            return datetime.strptime(key, "%Y-%m-%d")
    except Exception:
        pass

    raw = str(value).strip().split()[0]
    for fmt in ("%d-%b-%Y", "%d-%m-%Y", "%Y-%m-%d", "%d/%m/%Y", "%Y/%m/%d"):
        try:
            return datetime.strptime(raw, fmt)
        except Exception:
            pass
    try:
        parsed = pd.to_datetime(raw, errors="coerce", dayfirst=True)
        if pd.notna(parsed):
            return parsed.to_pydatetime()
    except Exception:
        pass
    return datetime.max


def get_expiries_from_frame(df, expiry_col):
    if df.empty or not expiry_col:
        return []
    values = []
    for value in df[expiry_col].dropna().astype(str).tolist():
        value = value.strip()
        if value and value not in values:
            values.append(value)
    return sorted(values, key=expiry_sort_key)


def timestamp_time_label(value):
    parsed = parse_timestamp(value)
    if parsed == datetime.min:
        return normalize_timestamp(value)
    return parsed.strftime("%H:%M")


def find_column(df, aliases):
    lowered = {str(col).lower(): col for col in df.columns}
    for alias in aliases:
        col = lowered.get(alias.lower())
        if col is not None:
            return col
    return None


def read_symbol_table(symbol, max_timestamps=8):
    if symbol not in SYMBOLS:
        raise ValueError("Invalid symbol")

    query = f'SELECT * FROM "{symbol}"'
    df = pd.read_sql(query, ENGINE)
    if df.empty or "timestamp" not in df.columns:
        return df

    df["timestamp"] = df["timestamp"].map(normalize_timestamp)
    timestamps = sorted(df["timestamp"].dropna().unique(), key=parse_timestamp, reverse=True)
    keep = set(timestamps[:max_timestamps])
    return df[df["timestamp"].isin(keep)].copy()


def get_available_dates(symbol):
    return get_available_dates_fast(symbol)


def read_rows_for_timestamps(symbol, timestamps):
    if not timestamps:
        return pd.DataFrame()

    stmt = sqlalchemy.text(f'SELECT * FROM "{symbol}" WHERE "timestamp" IN :timestamps')
    stmt = stmt.bindparams(sqlalchemy.bindparam("timestamps", expanding=True))
    return pd.read_sql(stmt, ENGINE, params={"timestamps": list(timestamps)})


def read_symbol_table_for_date(symbol, trade_date, max_timestamps=None):
    """
    Read rows for the selected date.

    max_timestamps=None means full day, from first timestamp to latest timestamp.
    Uses SQL-side date filtering for fast startup.
    """
    if not trade_date:
        return read_symbol_table(symbol, max_timestamps=max_timestamps or 8)

    return read_sql_with_date_filter(
        ENGINE,
        symbol,
        trade_date,
        limit_latest_timestamps=max_timestamps,
    )


def read_futures_table_for_date(symbol, trade_date):
    """Read full-day futures rows from idxfuturesdata_current for the selected symbol/date."""
    if symbol not in SYMBOLS:
        raise ValueError("Invalid symbol")
    if not trade_date:
        return pd.DataFrame()
    try:
        return read_sql_with_date_filter(FUTURES_ENGINE, symbol, trade_date, limit_latest_timestamps=None)
    except Exception:
        return pd.DataFrame()


def aggregate_sum_values(values):
    numbers = [to_number(value) for value in values]
    numbers = [value for value in numbers if value is not None]
    if not numbers:
        return None
    return sum(numbers)


def build_futures_series(symbol, trade_date):
    """
    Build full-day futures time series for the selected date.

    Output fields are merged into option chart points and table rows:
      futurePrice, futurePriceRoc, futureOpenInterest, futureOiRoc,
      futureVolume, futureVolumeRoc, futureCoi, futureCoiRoc,
      futureCoiVolPct, futureCoiVolRoc, basis, basisPct.
    """
    df = read_futures_table_for_date(symbol, trade_date)
    if df.empty or "timestamp" not in df.columns:
        return []

    price_col = find_column(df, ("lastPrice", "ltp", "closePrice", "vwap"))
    oi_col = find_column(df, ("openInterest", "openinterest", "oi"))
    volume_col = find_column(df, ("tradedContracts", "volume", "totalTradedVolume", "numberOfContractsTraded"))
    change_oi_col = find_column(df, (
        "changeinOI",
        "changeinOpenInterest",
        "changeInOpenInterest",
        "coi",
        "changeOI",
    ))
    spot_col = find_column(df, ("spotPrice", "underlyingValue"))
    expiry_col = find_column(df, ("expiryDate", "expiry"))

    lot_size = _v11819_lot_size(symbol)
    timestamps = sorted(df["timestamp"].dropna().unique(), key=parse_timestamp)
    previous_price = None
    previous_oi = None
    previous_volume = None
    previous_coi = None
    previous_coi_vol_pct = None
    rows = []

    for ts in timestamps:
        frame = df[df["timestamp"] == ts].copy()
        if frame.empty:
            continue

        price = first_valid_number(frame[price_col].tolist()) if price_col else None
        spot = first_valid_number(frame[spot_col].tolist()) if spot_col else None
        oi = aggregate_sum_values(frame[oi_col].tolist()) if oi_col else None
        volume = aggregate_sum_values(frame[volume_col].tolist()) if volume_col else None
        coi = aggregate_sum_values(frame[change_oi_col].tolist()) if change_oi_col else None
        coi_vol_pct = safe_ratio_pct(coi, volume)
        expiry = str(frame.iloc[0].get(expiry_col, "")) if expiry_col else ""

        basis = price - spot if price is not None and spot not in (None, 0) else None
        basis_pct = (basis / spot) * 100.0 if basis is not None and spot not in (None, 0) else None

        item = {
            "timestamp": ts,
            "time": timestamp_time_label(ts),
            "futureTimestamp": ts,
            "futureExpiry": expiry,
            "futurePrice": price,
            "futurePriceRoc": pct_change(price, previous_price),
            "futureOpenInterest": oi,
            "futureOiRoc": pct_change(oi, previous_oi),
            "futureVolume": volume,
            "futureVolumeRoc": pct_change(volume, previous_volume),
            "futureCoi": coi,
            "futureCoiRoc": pct_change(coi, previous_coi),
            "futureCoiVolPct": coi_vol_pct,
            "futureCoiVolRoc": pct_change(coi_vol_pct, previous_coi_vol_pct),
            "futureSpot": spot,
            "basis": basis,
            "basisPct": basis_pct,
        }
        rows.append(item)

        if price is not None:
            previous_price = price
        if oi is not None:
            previous_oi = oi
        if volume is not None:
            previous_volume = volume
        if coi is not None:
            previous_coi = coi
        if coi_vol_pct is not None:
            previous_coi_vol_pct = coi_vol_pct

    return rows

def nearest_future_point(timestamp, futures_series, max_seconds=150):
    if not futures_series:
        return None

    exact = {item.get("timestamp"): item for item in futures_series}
    if timestamp in exact:
        return exact[timestamp]

    target_dt = parse_timestamp(timestamp)
    if target_dt == datetime.min:
        return None

    best = None
    best_diff = None
    for item in futures_series:
        item_dt = parse_timestamp(item.get("timestamp"))
        if item_dt == datetime.min:
            continue
        diff = abs((item_dt - target_dt).total_seconds())
        if best_diff is None or diff < best_diff:
            best = item
            best_diff = diff

    if best is not None and best_diff is not None and best_diff <= max_seconds:
        return best
    return None


def enrich_charts_with_futures(charts, futures_series):
    """Attach nearest futures values to each option chart point."""
    if not charts:
        return charts

    futures_fields = (
        "futureTimestamp",
        "futureExpiry",
        "futurePrice",
        "futurePriceRoc",
        "futureOpenInterest",
        "futureOiRoc",
        "futureVolume",
        "futureVolumeRoc",
        "futureCoi",
        "futureCoiRoc",
        "futureCoiVolPct",
        "futureCoiVolRoc",
        "futureSpot",
        "basis",
        "basisPct",
    )

    for metric_key, points in charts.items():
        for point in points:
            future = nearest_future_point(point.get("timestamp"), futures_series)
            for field in futures_fields:
                point[field] = future.get(field) if future else None
    return charts


def infer_strike_step(strikes):
    values = sorted({int(x) for x in strikes if x is not None})
    diffs = [b - a for a, b in zip(values, values[1:]) if b > a]
    if not diffs:
        return 50
    return min(diffs)


def nearest_atm(strikes, spot):
    clean = [x for x in strikes if x is not None]
    if not clean:
        return None
    if spot is None:
        return clean[len(clean) // 2]
    return min(clean, key=lambda strike: abs(strike - spot))


def pct_change(current, previous):
    if current is None or previous is None:
        return None
    if previous == 0:
        return None
    return ((current - previous) / abs(previous)) * 100.0


def safe_ratio_pct(numerator, denominator):
    """Return numerator / denominator as percentage, or None when not meaningful."""
    numerator = to_number(numerator)
    denominator = to_number(denominator)
    if numerator is None or denominator in (None, 0):
        return None
    return (numerator / abs(denominator)) * 100.0


def latest_previous_frames(df):
    timestamps = sorted(df["timestamp"].dropna().unique(), key=parse_timestamp, reverse=True)
    latest = timestamps[0] if timestamps else None
    previous = timestamps[1] if len(timestamps) > 1 else None
    latest_df = df[df["timestamp"] == latest].copy() if latest else pd.DataFrame()
    previous_df = df[df["timestamp"] == previous].copy() if previous else pd.DataFrame()
    return latest, previous, latest_df, previous_df


def first_valid_number(values):
    for value in values:
        number = to_number(value)
        if number is not None and number > 0:
            return number
    return None


def aggregate_metric(frame, column, metric_key):
    if frame.empty or not column:
        return None

    values = [to_number(value) for value in frame[column].tolist()]
    values = [value for value in values if value is not None]
    if not values:
        return None

    aggregate = METRICS.get(metric_key, {}).get("aggregate", "sum")
    if aggregate == "avg":
        return sum(values) / len(values)
    return sum(values)


def build_intraday_line_charts(df, band, strike_col, opt_col, spot_col, metric_cols, chart_strike=None):
    """
    Build time-series data for the Graphical tab.

    For every timestamp in the selected date:
      - calculate ATM based on that timestamp's spot
      - keep ATM +/- selected band
      - aggregate CE and PE values separately
      - calculate ROC from immediately previous timestamp
      - keep spot as raw price for the right-side chart axis
    """
    if df.empty or "timestamp" not in df.columns:
        return {key: [] for key in METRICS}

    working = df.copy()
    working["_strike"] = working[strike_col].map(to_number)
    working["_optionType"] = working[opt_col].map(lambda value: str(value).upper().strip())

    timestamps = sorted(working["timestamp"].dropna().unique(), key=parse_timestamp)
    charts = {key: [] for key in METRICS}
    previous_totals = {key: {"CE": None, "PE": None} for key in METRICS}

    for ts in timestamps:
        frame = working[working["timestamp"] == ts].copy()
        if frame.empty:
            continue

        spot = first_valid_number(frame[spot_col].tolist()) if spot_col else None
        strikes = [to_number(value) for value in frame[strike_col].tolist()]
        atm = nearest_atm(strikes, spot)
        step = infer_strike_step(strikes)

        specific_strike = to_number(chart_strike)
        if specific_strike is not None:
            band_frame = frame[frame["_strike"].map(lambda value: value is not None and abs(value - specific_strike) < 0.0001)].copy()
        elif atm is None:
            band_frame = frame.iloc[0:0].copy()
        else:
            wanted = {atm + (i * step) for i in range(-band, band + 1)}
            band_frame = frame[frame["_strike"].isin(wanted)].copy()

        for metric_key in METRICS:
            col = metric_cols.get(metric_key)
            point = {
                "timestamp": ts,
                "time": timestamp_time_label(ts),
                "spot": spot,
                "atm": atm,
            }

            for side in ("CE", "PE"):
                side_frame = band_frame[band_frame["_optionType"] == side]
                total = aggregate_metric(side_frame, col, metric_key)
                roc = pct_change(total, previous_totals[metric_key][side])
                previous_totals[metric_key][side] = total

                side_key = side.lower()
                point[f"{side_key}Total"] = total
                point[f"{side_key}Roc"] = roc

            charts[metric_key].append(point)

    return charts


def build_dashboard_payload(symbol, band, trade_date=None, expiry=None, chart_strike=None):
    available_dates = get_available_dates(symbol)
    if not trade_date and available_dates:
        trade_date = available_dates[0]

    # Full selected day is loaded so the chart starts from the beginning of that day.
    df = read_symbol_table_for_date(symbol, trade_date, max_timestamps=None)
    if df.empty:
        return {
            "symbol": symbol,
            "date": trade_date,
            "availableDates": available_dates,
            "availableExpiries": [],
            "error": f"No option rows found for {trade_date or 'selected date'}",
            "rows": [],
            "charts": {},
        }

    strike_col = find_column(df, ("strikePrice", "strike"))
    opt_col = find_column(df, ("optionType", "type"))
    spot_col = find_column(df, ("spotPrice", "underlyingValue"))
    expiry_col = find_column(df, ("expiryDate", "expiry"))

    available_expiries = get_expiries_from_frame(df, expiry_col)
    if not expiry and available_expiries:
        expiry = available_expiries[0]
    if expiry and expiry_col:
        # V11.7: expiry-safe filtering. Auto-refresh may send 2026-06-02 while
        # the live option table may store 02-06-2026 or 02-Jun-2026.
        # Exact string matching caused intermittent blank Spot/ATM/header cards.
        filtered_df = filter_frame_by_expiry(df, expiry, expiry_col=expiry_col)
        df = filtered_df.copy()
    if df.empty:
        return {
            "symbol": symbol,
            "date": trade_date,
            "expiry": expiry,
            "availableDates": available_dates,
            "availableExpiries": available_expiries,
            "error": f"No option rows found for expiry {expiry or 'selected expiry'} on {trade_date or 'selected date'}",
            "rows": [],
            "charts": {},
        }

    if not strike_col or not opt_col:
        return {
            "symbol": symbol,
            "date": trade_date,
            "expiry": expiry,
            "availableDates": available_dates,
            "availableExpiries": available_expiries,
            "error": "Required columns strikePrice/optionType not found",
            "rows": [],
            "charts": {},
        }

    latest_ts, previous_ts, latest_df, previous_df = latest_previous_frames(df)
    latest_df["_strike"] = latest_df[strike_col].map(to_number)
    previous_df["_strike"] = previous_df[strike_col].map(to_number) if not previous_df.empty else None

    spot = None
    if spot_col:
        spot_candidates = [to_number(v) for v in latest_df[spot_col].tolist()]
        spot_candidates = [v for v in spot_candidates if v is not None and v > 0]
        spot = spot_candidates[0] if spot_candidates else None

    strikes = [to_number(v) for v in latest_df[strike_col].tolist()]
    atm = nearest_atm(strikes, spot)
    step = infer_strike_step(strikes)
    wanted = {atm + (i * step) for i in range(-band, band + 1)} if atm is not None else set()

    metric_cols = {
        key: find_column(df, config["aliases"])
        for key, config in METRICS.items()
    }
    change_oi_col = find_column(df, (
        "changeinOI",
        "changeinOpenInterest",
        "coi",
    ))
    change_oi_col = find_column(df, (
        "changeinOI",
        "changeinOpenInterest",
        "changeInOpenInterest",
        "coi",
        "changeOI",
    ))

    previous_lookup = {}
    if previous_ts and not previous_df.empty:
        for _, row in previous_df.iterrows():
            strike = to_number(row.get(strike_col))
            option_type = str(row.get(opt_col, "")).upper()
            previous_lookup[(strike, option_type)] = row

    rows = []
    for _, row in latest_df.iterrows():
        strike = to_number(row.get(strike_col))
        if strike not in wanted:
            continue

        option_type = str(row.get(opt_col, "")).upper()
        if option_type not in {"CE", "PE"}:
            continue

        previous_row = previous_lookup.get((strike, option_type))
        item = {
            "symbol": symbol,
            "timestamp": latest_ts,
            "previousTimestamp": previous_ts,
            "expiryDate": str(row.get(expiry_col, "")) if expiry_col else "",
            "strike": strike,
            "optionType": option_type,
            "distance": int(round((strike - atm) / step)) if atm and step else 0,
            "atm": strike == atm,
        }

        for key, col in metric_cols.items():
            current = to_number(row.get(col)) if col else None
            previous = to_number(previous_row.get(col)) if previous_row is not None and col else None
            item[key] = current
            item[f"{key}Roc"] = pct_change(current, previous)

        # COI/Volume shows how much of the traded volume is creating fresh OI.
        # COI means Change in Open Interest from NSE's changeinOI/changeinOpenInterest field.
        current_coi = to_number(row.get(change_oi_col)) if change_oi_col else None
        previous_coi = to_number(previous_row.get(change_oi_col)) if previous_row is not None and change_oi_col else None
        current_volume = item.get("volume")
        previous_volume = to_number(previous_row.get(metric_cols.get("volume"))) if previous_row is not None and metric_cols.get("volume") else None
        item["coi"] = current_coi
        item["coiVolPct"] = safe_ratio_pct(current_coi, current_volume)
        item["coiVolRoc"] = pct_change(item["coiVolPct"], safe_ratio_pct(previous_coi, previous_volume))

        rows.append(item)

    rows.sort(key=lambda item: (item["strike"], item["optionType"]))

    charts = build_intraday_line_charts(
        df=df,
        band=band,
        strike_col=strike_col,
        opt_col=opt_col,
        spot_col=spot_col,
        metric_cols=metric_cols,
        chart_strike=chart_strike,
    )

    futures_series = build_futures_series(symbol, trade_date)
    charts = enrich_charts_with_futures(charts, futures_series)
    futures_latest = futures_series[-1] if futures_series else {}
    latest_future = nearest_future_point(latest_ts, futures_series) or futures_latest or {}
    futures_row_fields = (
        "futureTimestamp", "futureExpiry", "futurePrice", "futurePriceRoc",
        "futureOpenInterest", "futureOiRoc", "futureVolume", "futureVolumeRoc",
        "futureCoi", "futureCoiRoc", "futureCoiVolPct", "futureCoiVolRoc",
        "basis", "basisPct"
    )
    for item in rows:
        for field in futures_row_fields:
            item[field] = latest_future.get(field)

    timestamps_asc = sorted(df["timestamp"].dropna().unique(), key=parse_timestamp)
    first_ts = timestamps_asc[0] if timestamps_asc else ""
    last_ts = timestamps_asc[-1] if timestamps_asc else ""

    return {
        "symbol": symbol,
        "date": trade_date,
        "expiry": expiry,
        "availableDates": available_dates,
        "availableExpiries": available_expiries,
        "generatedAt": datetime.now(IST).strftime("%d-%b-%Y %H:%M:%S"),
        "timestamp": latest_ts,
        "previousTimestamp": previous_ts,
        "firstTimestamp": first_ts,
        "lastTimestamp": last_ts,
        "chartPoints": len(timestamps_asc),
        "futuresPoints": len(futures_series),
        "futuresLatest": futures_latest,
        "spot": spot,
        "atm": atm,
        "strikeStep": step,
        "band": band,
        "chartStrike": to_number(chart_strike),
        "chartScope": "specific" if to_number(chart_strike) is not None else "atm_band",
        "rows": rows,
        "charts": charts,
    }


def build_strike_full_day_payload(symbol, trade_date=None, strike_value=None, expiry=None):
    """
    Build full-day CE/PE table for one strike on the selected date.

    Output is one row per timestamp, from first timestamp to latest timestamp,
    with CE and PE values side-by-side for the entered strike price.
    """
    available_dates = get_available_dates(symbol)
    if not trade_date and available_dates:
        trade_date = available_dates[0]

    strike = to_number(strike_value)
    if strike is None:
        return {
            "symbol": symbol,
            "date": trade_date,
            "strike": strike_value,
            "error": "Please enter a valid strike price.",
            "rows": [],
        }

    df = read_symbol_table_for_date(symbol, trade_date, max_timestamps=None)
    if df.empty:
        return {
            "symbol": symbol,
            "date": trade_date,
            "strike": strike,
            "error": f"No option rows found for {trade_date or 'selected date'}.",
            "rows": [],
        }

    strike_col = find_column(df, ("strikePrice", "strike"))
    opt_col = find_column(df, ("optionType", "type"))
    spot_col = find_column(df, ("spotPrice", "underlyingValue"))
    expiry_col = find_column(df, ("expiryDate", "expiry"))

    available_expiries = get_expiries_from_frame(df, expiry_col)
    if not expiry and available_expiries:
        expiry = available_expiries[0]
    if expiry and expiry_col:
        # V11.7: expiry-safe filtering. Auto-refresh may send 2026-06-02 while
        # the live option table may store 02-06-2026 or 02-Jun-2026.
        # Exact string matching caused intermittent blank Spot/ATM/header cards.
        filtered_df = filter_frame_by_expiry(df, expiry, expiry_col=expiry_col)
        df = filtered_df.copy()
    if df.empty:
        return {
            "symbol": symbol,
            "date": trade_date,
            "expiry": expiry,
            "strike": strike,
            "error": f"No option rows found for expiry {expiry or 'selected expiry'} on {trade_date or 'selected date'}.",
            "rows": [],
        }

    if not strike_col or not opt_col:
        return {
            "symbol": symbol,
            "date": trade_date,
            "strike": strike,
            "error": "Required columns strikePrice/optionType not found.",
            "rows": [],
        }

    metric_cols = {
        key: find_column(df, config["aliases"])
        for key, config in METRICS.items()
    }
    change_oi_col = find_column(df, (
        "changeinOI",
        "changeinOpenInterest",
        "coi",
    ))
    lot_size = _lot_size_for_symbol(symbol)

    working = df.copy()
    working["_strike"] = working[strike_col].map(to_number)
    working["_optionType"] = working[opt_col].map(lambda value: str(value).upper().strip())
    working = working[working["_strike"].map(lambda value: value is not None and abs(value - strike) < 0.0001)].copy()
    working = working[working["_optionType"].isin(["CE", "PE"])].copy()

    if working.empty:
        return {
            "symbol": symbol,
            "date": trade_date,
            "strike": strike,
            "error": f"No CE/PE rows found for strike {int(strike) if float(strike).is_integer() else strike} on {trade_date}.",
            "rows": [],
        }

    metric_name = {
        "premium": "Premium",
        "volume": "Volume",
        "openInterest": "OpenInterest",
        "iv": "IV",
    }

    timestamps = sorted(working["timestamp"].dropna().unique(), key=parse_timestamp)
    previous_values = {
        "CE": {key: None for key in METRICS},
        "PE": {key: None for key in METRICS},
    }
    previous_coi_vol_pct = {
        "CE": None,
        "PE": None,
    }
    futures_series = build_futures_series(symbol, trade_date)
    futures_row_fields = (
        "futureTimestamp", "futureExpiry", "futurePrice", "futurePriceRoc",
        "futureOpenInterest", "futureOiRoc", "futureVolume", "futureVolumeRoc",
        "futureCoi", "futureCoiRoc", "futureCoiVolPct", "futureCoiVolRoc",
        "basis", "basisPct"
    )

    rows = []
    for ts in timestamps:
        frame = working[working["timestamp"] == ts].copy()
        if frame.empty:
            continue

        spot = first_valid_number(frame[spot_col].tolist()) if spot_col else None
        item = {
            "timestamp": ts,
            "time": timestamp_time_label(ts),
            "symbol": symbol,
            "date": trade_date,
            "strike": strike,
            "spot": spot,
        }

        future = nearest_future_point(ts, futures_series)
        for field in futures_row_fields:
            item[field] = future.get(field) if future else None

        for side in ("CE", "PE"):
            prefix = side.lower()
            side_frame = frame[frame["_optionType"] == side]
            side_row = side_frame.iloc[0] if not side_frame.empty else None
            item[f"{prefix}Available"] = side_row is not None
            item[f"{prefix}Expiry"] = str(side_row.get(expiry_col, "")) if side_row is not None and expiry_col else ""

            current_volume = None
            current_coi = to_number(side_row.get(change_oi_col)) if side_row is not None and change_oi_col else None

            for metric_key in METRICS:
                col = metric_cols.get(metric_key)
                current = to_number(side_row.get(col)) if side_row is not None and col else None
                previous = previous_values[side][metric_key]
                key_name = metric_name[metric_key]
                item[f"{prefix}{key_name}"] = current
                item[f"{prefix}{key_name}Roc"] = pct_change(current, previous)
                if metric_key == "volume":
                    current_volume = current
                if current is not None:
                    previous_values[side][metric_key] = current

            current_coi_vol_pct = safe_ratio_pct(current_coi, current_volume)
            current_coi_vol = _signed_coi_volume_lot_ratio(current_coi, current_volume, lot_size)
            item[f"{prefix}CoiVol"] = current_coi_vol
            item[f"{prefix}CoiVolPct"] = current_coi_vol_pct
            item[f"{prefix}CoiVolRoc"] = pct_change(current_coi_vol_pct, previous_coi_vol_pct[side])
            if current_coi_vol_pct is not None:
                previous_coi_vol_pct[side] = current_coi_vol_pct

        rows.append(item)

    first_ts = rows[0]["timestamp"] if rows else ""
    last_ts = rows[-1]["timestamp"] if rows else ""

    return {
        "symbol": symbol,
        "date": trade_date,
        "expiry": expiry,
        "availableExpiries": available_expiries,
        "strike": strike,
        "firstTimestamp": first_ts,
        "lastTimestamp": last_ts,
        "points": len(rows),
        "futuresPoints": len(futures_series),
        "generatedAt": datetime.now(IST).strftime("%d-%b-%Y %H:%M:%S"),
        "rows": rows,
    }


def parse_manual_strikes(value):
    strikes = []
    for part in re.split(r"[,\s]+", str(value or "")):
        part = part.strip()
        if not part:
            continue
        number = to_number(part)
        if number is None:
            continue
        if number not in strikes:
            strikes.append(number)
    return strikes


def strike_display_value(value):
    number = to_number(value)
    if number is None:
        return str(value or "")
    if float(number).is_integer():
        return str(int(number))
    return str(number)


def build_expiry_roc_matrix_payload(symbol, trade_date=None, expiry=None, mode="atm", strikes_text="", span=1):
    """
    Build Excel-style premium/IV ROC matrix across current and next expiry.

    Output format:
    - rows are timestamps
    - columns are Current Expiry and Next Expiry
    - each expiry has selected strikes
    - each strike has PE Premium ROC, CE Premium ROC, PE COI/VOL, CE COI/VOL, PE IV ROC, CE IV ROC
    """
    available_dates = get_available_dates(symbol)
    if not trade_date and available_dates:
        trade_date = available_dates[0]

    try:
        span = max(0, min(5, int(float(span))))
    except Exception:
        span = 1

    df = read_symbol_table_for_date(symbol, trade_date, max_timestamps=None)
    if df.empty:
        return {
            "symbol": symbol,
            "date": trade_date,
            "error": f"No option rows found for {trade_date or 'selected date'}.",
            "rows": [],
        }

    strike_col = find_column(df, ("strikePrice", "strike"))
    opt_col = find_column(df, ("optionType", "type"))
    spot_col = find_column(df, ("spotPrice", "underlyingValue"))
    expiry_col = find_column(df, ("expiryDate", "expiry"))
    premium_col = find_column(df, METRICS["premium"]["aliases"])
    iv_col = find_column(df, METRICS["iv"]["aliases"])
    volume_col = find_column(df, METRICS["volume"]["aliases"])
    open_interest_col = find_column(df, METRICS["openInterest"]["aliases"])
    lot_size = _lot_size_for_symbol(symbol)

    if not strike_col or not opt_col or not expiry_col:
        return {
            "symbol": symbol,
            "date": trade_date,
            "error": "Required columns strikePrice/optionType/expiryDate not found.",
            "rows": [],
        }

    available_expiries = get_expiries_from_frame(df, expiry_col)
    if not available_expiries:
        return {
            "symbol": symbol,
            "date": trade_date,
            "error": "No expiries found in option data.",
            "rows": [],
        }

    current_expiry = expiry or available_expiries[0]
    current_key = expiry_key(current_expiry)
    sorted_expiries = sorted(available_expiries, key=expiry_sort_key)
    next_expiry = None
    for exp in sorted_expiries:
        exp_key = expiry_key(exp)
        if current_key and exp_key and exp_key > current_key:
            next_expiry = exp
            break
    if next_expiry is None:
        for exp in sorted_expiries:
            if expiry_key(exp) != current_key:
                next_expiry = exp
                break

    selected_expiries = []
    for role, exp in (("Current Expiry", current_expiry), ("Next Expiry", next_expiry)):
        if exp and expiry_key(exp) not in [item["key"] for item in selected_expiries]:
            selected_expiries.append({"role": role, "label": str(exp), "key": expiry_key(exp) or str(exp)})

    working = df.copy()
    working["timestamp"] = working["timestamp"].map(normalize_timestamp)
    working["_strike"] = working[strike_col].map(to_number)
    working["_optionType"] = working[opt_col].map(lambda value: str(value).upper().strip())
    working["_expiryKey"] = working[expiry_col].map(expiry_key)
    selected_expiry_keys = {item["key"] for item in selected_expiries}
    working = working[working["_expiryKey"].isin(selected_expiry_keys)].copy()
    working = working[working["_optionType"].isin(["CE", "PE"])].copy()

    if working.empty:
        return {
            "symbol": symbol,
            "date": trade_date,
            "expiry": current_expiry,
            "nextExpiry": next_expiry,
            "error": "No CE/PE rows found for selected current/next expiry.",
            "rows": [],
        }

    timestamps_sorted = sorted(working["timestamp"].dropna().unique(), key=parse_timestamp)
    latest_ts = timestamps_sorted[-1] if timestamps_sorted else None
    latest_frame = working[working["timestamp"] == latest_ts] if latest_ts else working
    latest_spot = first_valid_number(latest_frame[spot_col].tolist()) if spot_col and not latest_frame.empty else None

    mode = str(mode or "atm").lower().strip()
    if mode == "manual":
        selected_strikes = parse_manual_strikes(strikes_text)
    else:
        current_expiry_df = working[working["_expiryKey"] == (selected_expiries[0]["key"] if selected_expiries else current_key)].copy()
        strike_source = current_expiry_df if not current_expiry_df.empty else working
        available_strikes = sorted({value for value in strike_source["_strike"].tolist() if value is not None})
        atm_strike = nearest_atm(available_strikes, latest_spot)
        if atm_strike is None:
            selected_strikes = []
        else:
            try:
                atm_index = available_strikes.index(atm_strike)
            except ValueError:
                atm_index = min(range(len(available_strikes)), key=lambda idx: abs(available_strikes[idx] - atm_strike))
            lo = max(0, atm_index - span)
            hi = min(len(available_strikes), atm_index + span + 1)
            selected_strikes = available_strikes[lo:hi]
            # If ATM is at edge and count is short, extend opposite side.
            desired = (span * 2) + 1
            if len(selected_strikes) < desired:
                if lo == 0:
                    selected_strikes = available_strikes[:min(len(available_strikes), desired)]
                elif hi == len(available_strikes):
                    selected_strikes = available_strikes[max(0, len(available_strikes) - desired):]

    selected_strikes = [to_number(value) for value in selected_strikes]
    selected_strikes = [value for value in selected_strikes if value is not None]
    if not selected_strikes:
        return {
            "symbol": symbol,
            "date": trade_date,
            "expiry": current_expiry,
            "nextExpiry": next_expiry,
            "mode": mode,
            "error": "No valid strike selection. Use ATM +- 1 or enter manual strike(s) like 24100,24150,24200.",
            "rows": [],
        }

    selected_strikes = sorted(dict.fromkeys(selected_strikes))
    strike_keys = [strike_display_value(value) for value in selected_strikes]
    working = working[working["_strike"].map(lambda value: value in selected_strikes)].copy()

    previous = {}
    for exp_item in selected_expiries:
        previous[exp_item["key"]] = {}
        for strike in selected_strikes:
            s_key = strike_display_value(strike)
            previous[exp_item["key"]][s_key] = {
                "CE": {"premium": None, "iv": None, "volume": None, "openInterest": None},
                "PE": {"premium": None, "iv": None, "volume": None, "openInterest": None},
            }

    rows = []
    for ts in timestamps_sorted:
        frame = working[working["timestamp"] == ts].copy()
        if frame.empty:
            continue
        spot = first_valid_number(frame[spot_col].tolist()) if spot_col else None
        row = {
            "timestamp": ts,
            "time": timestamp_time_label(ts),
            "spot": spot,
            "values": {},
        }
        for exp_item in selected_expiries:
            exp_key = exp_item["key"]
            row["values"][exp_key] = {}
            exp_frame = frame[frame["_expiryKey"] == exp_key]
            for strike in selected_strikes:
                s_key = strike_display_value(strike)
                row["values"][exp_key][s_key] = {}
                strike_frame = exp_frame[exp_frame["_strike"] == strike]
                for side in ("PE", "CE"):
                    side_frame = strike_frame[strike_frame["_optionType"] == side]
                    side_row = side_frame.iloc[0] if not side_frame.empty else None
                    premium = to_number(side_row.get(premium_col)) if side_row is not None and premium_col else None
                    iv = to_number(side_row.get(iv_col)) if side_row is not None and iv_col else None
                    volume_cum = to_number(side_row.get(volume_col)) if side_row is not None and volume_col else None
                    open_interest = to_number(side_row.get(open_interest_col)) if side_row is not None and open_interest_col else None
                    prev_premium = previous[exp_key][s_key][side]["premium"]
                    prev_iv = previous[exp_key][s_key][side]["iv"]
                    prev_volume = previous[exp_key][s_key][side]["volume"]
                    prev_open_interest = previous[exp_key][s_key][side]["openInterest"]
                    premium_roc = pct_change(premium, prev_premium)
                    iv_roc = pct_change(iv, prev_iv)
                    minute_volume = _v11814_delta_nonnegative(volume_cum, prev_volume)
                    minute_coi = _v11814_delta_signed(open_interest, prev_open_interest)
                    coi_vol = _signed_coi_volume_lot_ratio(minute_coi, minute_volume, lot_size)
                    if premium is not None:
                        previous[exp_key][s_key][side]["premium"] = premium
                    if iv is not None:
                        previous[exp_key][s_key][side]["iv"] = iv
                    if volume_cum is not None:
                        previous[exp_key][s_key][side]["volume"] = volume_cum
                    if open_interest is not None:
                        previous[exp_key][s_key][side]["openInterest"] = open_interest
                    row["values"][exp_key][s_key][side] = {
                        "premium": premium,
                        "premiumRoc": premium_roc,
                        "iv": iv,
                        "ivRoc": iv_roc,
                        "coiVol": coi_vol,
                    }
        rows.append(row)

    return {
        "symbol": symbol,
        "date": trade_date,
        "mode": mode,
        "span": span,
        "expiry": current_expiry,
        "nextExpiry": next_expiry,
        "expiries": selected_expiries,
        "availableExpiries": available_expiries,
        "spot": latest_spot,
        "strikes": [{"value": strike, "label": strike_display_value(strike)} for strike in selected_strikes],
        "firstTimestamp": rows[0]["timestamp"] if rows else "",
        "lastTimestamp": rows[-1]["timestamp"] if rows else "",
        "points": len(rows),
        "generatedAt": datetime.now(IST).strftime("%d-%b-%Y %H:%M:%S"),
        "rows": rows,
    }



def get_available_expiries_for_date(symbol, trade_date):
    """Return expiries available for selected symbol/date without loading full-day rows."""
    if symbol not in SYMBOLS or not trade_date:
        return []
    prefix = trade_date_to_nse_prefix(trade_date)
    queries = []
    if prefix:
        queries.append((
            f'SELECT DISTINCT "expiryDate" FROM "{symbol}" WHERE "timestamp" LIKE :ts_prefix',
            {"ts_prefix": prefix + "%"},
        ))
    queries.append((
        f'SELECT DISTINCT "expiryDate" FROM "{symbol}" WHERE CAST("timestamp" AS DATE) = CAST(:trade_date AS DATE)',
        {"trade_date": trade_date},
    ))

    for sql, params in queries:
        try:
            df = pd.read_sql(sqlalchemy.text(sql), ENGINE, params=params)
            if not df.empty and "expiryDate" in df.columns:
                values = []
                for value in df["expiryDate"].dropna().astype(str).tolist():
                    value = value.strip()
                    if value and value not in values:
                        values.append(value)
                return sorted(values, key=expiry_sort_key)
        except Exception:
            continue
    return []


def read_latest_option_snapshot_for_date_expiry(symbol, trade_date, expiry=None):
    """
    Read the latest snapshot for selected date + expiry.

    Important:
    - Select timestamp by date first.
    - Then load rows at that timestamp.
    - Then filter expiry in pandas using normalized expiry keys.

    This avoids failures caused by mixed expiryDate formats such as
    26-May-2026, 26-05-2026, 2026-05-26, or date/datetime objects.
    """
    if symbol not in SYMBOLS or not trade_date:
        return pd.DataFrame(), None

    prefix = trade_date_to_nse_prefix(trade_date)
    date_attempts = []
    if prefix:
        date_attempts.append(('"timestamp" LIKE :ts_prefix', {"ts_prefix": prefix + "%"}))
    date_attempts.append(('CAST("timestamp" AS DATE) = CAST(:trade_date AS DATE)', {"trade_date": trade_date}))

    for date_sql, date_params in date_attempts:
        try:
            ts_query = sqlalchemy.text(
                f'SELECT DISTINCT "timestamp" FROM "{symbol}" WHERE {date_sql}'
            )
            ts_df = pd.read_sql(ts_query, ENGINE, params=date_params)
            if ts_df.empty or "timestamp" not in ts_df.columns:
                continue

            timestamps = [
                normalize_timestamp(value)
                for value in ts_df["timestamp"].dropna().astype(str).tolist()
            ]
            timestamps = sorted(set(timestamps), key=parse_timestamp, reverse=True)

            for latest_ts in timestamps:
                row_query = sqlalchemy.text(
                    f'SELECT * FROM "{symbol}" WHERE "timestamp" = :latest_ts'
                )
                row_df = pd.read_sql(row_query, ENGINE, params={"latest_ts": latest_ts})
                if row_df.empty:
                    continue

                if "timestamp" in row_df.columns:
                    row_df["timestamp"] = row_df["timestamp"].map(normalize_timestamp)

                filtered_df = filter_frame_by_expiry(row_df, expiry)
                if not filtered_df.empty:
                    return filtered_df, latest_ts

            # If expiry was not provided, first non-empty timestamp would have returned.
            # If expiry was provided but no timestamp matched, try next date strategy.
        except Exception:
            continue

    return pd.DataFrame(), None


def read_option_strike_side_for_date_expiry(symbol, trade_date, expiry, strike, side):
    """
    Read full-day rows for one strike and one side only.

    The SQL filter uses only date + strike + side for speed. Expiry filtering is
    done in pandas with normalized keys so mixed expiry formats do not break it.
    """
    if symbol not in SYMBOLS or not trade_date:
        return pd.DataFrame()

    prefix = trade_date_to_nse_prefix(trade_date)
    side = str(side or "CE").upper()

    date_attempts = []
    if prefix:
        date_attempts.append(('"timestamp" LIKE :ts_prefix', {"ts_prefix": prefix + "%"}))
    date_attempts.append(('CAST("timestamp" AS DATE) = CAST(:trade_date AS DATE)', {"trade_date": trade_date}))

    for date_sql, date_params in date_attempts:
        where_parts = [date_sql, 'CAST("strikePrice" AS NUMERIC) = :strike', 'UPPER("optionType") = :side']
        params = dict(date_params)
        params.update({
            "strike": float(strike),
            "side": side,
        })
        where_sql = " AND ".join(where_parts)

        try:
            query = sqlalchemy.text(
                f'SELECT * FROM "{symbol}" '
                f'WHERE {where_sql} '
                f'ORDER BY CAST("timestamp" AS TIMESTAMP)'
            )
            df = pd.read_sql(query, ENGINE, params=params)
            if df.empty:
                continue

            if "timestamp" in df.columns:
                df["timestamp"] = df["timestamp"].map(normalize_timestamp)

            df = filter_frame_by_expiry(df, expiry)
            if not df.empty:
                return df
        except Exception:
            continue

    return pd.DataFrame()


def build_nse_oc_payload(symbol, trade_date=None, expiry=None, band=5):
    """
    Build latest NSE-style option-chain snapshot for ATM +/- band.

    Uses a latest-snapshot SQL reader instead of loading the whole selected day.
    """
    available_dates = get_available_dates(symbol)
    if not trade_date and available_dates:
        trade_date = available_dates[0]

    available_expiries = get_available_expiries_for_date(symbol, trade_date)
    if not expiry and available_expiries:
        expiry = available_expiries[0]

    df, latest_ts = read_latest_option_snapshot_for_date_expiry(symbol, trade_date, expiry)
    if df.empty:
        return {
            "symbol": symbol,
            "date": trade_date,
            "expiry": expiry,
            "availableDates": available_dates,
            "availableExpiries": available_expiries,
            "error": f"No latest option rows found for {trade_date or 'selected date'} / expiry {expiry or 'selected expiry'}. Check expiryDate stored format in table.",
            "rows": [],
        }

    strike_col = find_column(df, ("strikePrice", "strike"))
    opt_col = find_column(df, ("optionType", "type"))
    spot_col = find_column(df, ("spotPrice", "underlyingValue"))
    expiry_col = find_column(df, ("expiryDate", "expiry"))

    if not strike_col or not opt_col:
        return {
            "symbol": symbol,
            "date": trade_date,
            "expiry": expiry,
            "availableDates": available_dates,
            "availableExpiries": available_expiries,
            "error": "Required columns strikePrice/optionType not found.",
            "rows": [],
        }

    metric_cols = {
        key: find_column(df, config["aliases"])
        for key, config in METRICS.items()
    }
    change_oi_col = find_column(df, (
        "changeinOI",
        "changeinOpenInterest",
        "changeInOpenInterest",
        "coi",
        "changeOI",
    ))

    df = df.copy()
    df["_strike"] = df[strike_col].map(to_number)
    df["_optionType"] = df[opt_col].map(lambda value: str(value).upper().strip())

    spot = None
    if spot_col:
        spot_candidates = [to_number(v) for v in df[spot_col].tolist()]
        spot_candidates = [v for v in spot_candidates if v is not None and v > 0]
        spot = spot_candidates[0] if spot_candidates else None

    strikes = [to_number(v) for v in df[strike_col].tolist()]
    atm = nearest_atm(strikes, spot)
    step = infer_strike_step(strikes)
    wanted = {atm + (i * step) for i in range(-band, band + 1)} if atm is not None else set()

    rows = []
    for strike in sorted(wanted):
        frame = df[df["_strike"].map(lambda value: value is not None and abs(value - strike) < 0.0001)].copy()
        if frame.empty:
            continue

        item = {
            "symbol": symbol,
            "date": trade_date,
            "expiry": expiry,
            "timestamp": latest_ts,
            "time": timestamp_time_label(latest_ts),
            "spot": spot,
            "strike": strike,
            "atm": atm is not None and abs(strike - atm) < 0.0001,
            "distance": int(round((strike - atm) / step)) if atm and step else 0,
        }

        for side in ("CE", "PE"):
            prefix = side.lower()
            side_frame = frame[frame["_optionType"] == side]
            row = side_frame.iloc[0] if not side_frame.empty else None

            oi = to_number(row.get(metric_cols.get("openInterest"))) if row is not None and metric_cols.get("openInterest") else None
            volume = to_number(row.get(metric_cols.get("volume"))) if row is not None and metric_cols.get("volume") else None
            iv = to_number(row.get(metric_cols.get("iv"))) if row is not None and metric_cols.get("iv") else None
            ltp = to_number(row.get(metric_cols.get("premium"))) if row is not None and metric_cols.get("premium") else None
            coi = to_number(row.get(change_oi_col)) if row is not None and change_oi_col else None
            range_pct = safe_ratio_pct(coi, oi)

            item[f"{prefix}Oi"] = oi
            item[f"{prefix}Volume"] = volume
            item[f"{prefix}Iv"] = iv
            item[f"{prefix}Ltp"] = ltp
            item[f"{prefix}Coi"] = coi
            item[f"{prefix}RangePct"] = range_pct
            item[f"{prefix}Available"] = row is not None

        rows.append(item)

    return {
        "symbol": symbol,
        "date": trade_date,
        "expiry": expiry,
        "availableDates": available_dates,
        "availableExpiries": available_expiries,
        "timestamp": latest_ts,
        "previousTimestamp": "",
        "generatedAt": datetime.now(IST).strftime("%d-%b-%Y %H:%M:%S"),
        "spot": spot,
        "atm": atm,
        "strikeStep": step,
        "band": band,
        "rows": rows,
    }


def build_big_player_presence_payload(symbol, trade_date=None, expiry=None, threshold=0.25, lot_size=65):
    """
    Live Big Player Presence scanner.

    User requested NIFTY-only logic:
      Big Player Presence = ABS(COI / Volume)
      show rows where value >= threshold.

    Lot size is retained only for money/exposure calculations, not for this ratio.
    """
    symbol = normalize_index_symbol(symbol or "NIFTY")
    threshold = float(threshold or 0.25)
    lot_size = int(float(lot_size or 65))
    if symbol != "NIFTY":
        return {
            "symbol": symbol,
            "date": trade_date,
            "expiry": expiry,
            "threshold": threshold,
            "lotSize": lot_size,
            "error": "Big Player Presence is enabled only for NIFTY as requested.",
            "rows": [],
        }

    available_dates = get_available_dates(symbol)
    if not trade_date and available_dates:
        trade_date = available_dates[0]

    available_expiries = get_available_expiries_for_date(symbol, trade_date)
    if not expiry and available_expiries:
        expiry = available_expiries[0]

    df, latest_ts = read_latest_option_snapshot_for_date_expiry(symbol, trade_date, expiry)
    if df.empty:
        return {
            "symbol": symbol,
            "date": trade_date,
            "expiry": expiry,
            "availableDates": available_dates,
            "availableExpiries": available_expiries,
            "threshold": threshold,
            "lotSize": lot_size,
            "timestamp": latest_ts,
            "error": f"No latest option rows found for {trade_date or 'selected date'} / expiry {expiry or 'selected expiry'}.",
            "rows": [],
        }

    strike_col = find_column(df, ("strikePrice", "strike"))
    opt_col = find_column(df, ("optionType", "type"))
    spot_col = find_column(df, ("spotPrice", "underlyingValue"))
    expiry_col = find_column(df, ("expiryDate", "expiry"))
    volume_col = find_column(df, METRICS["volume"]["aliases"])
    trades_col = find_column(df, ("noOfTrades", "numberOfTrades", "no_of_trades", "number_of_trades", "trades", "noTrades", "no_trades", "no_of_trade", "TtlNbOfTxsExctd"))
    oi_col = find_column(df, ("openInterest", "openinterest", "oi"))
    premium_col = find_column(df, ("lastPrice", "ltp", "closePrice"))
    iv_col = find_column(df, ("impliedVolatility", "iv"))
    change_oi_col = find_column(df, (
        "changeinOI",
        "changeinOpenInterest",
        "changeInOpenInterest",
        "coi",
        "changeOI",
    ))

    if not strike_col or not opt_col or not volume_col or not change_oi_col:
        return {
            "symbol": symbol,
            "date": trade_date,
            "expiry": expiry,
            "availableDates": available_dates,
            "availableExpiries": available_expiries,
            "threshold": threshold,
            "lotSize": lot_size,
            "timestamp": latest_ts,
            "error": "Required columns strikePrice/optionType/NSE volume(noOfTrades)/changeinOI not found.",
            "rows": [],
        }

    spot = None
    if spot_col:
        spot_candidates = [to_number(v) for v in df[spot_col].tolist()]
        spot_candidates = [v for v in spot_candidates if v is not None and v > 0]
        spot = spot_candidates[0] if spot_candidates else None

    rows = []
    for _, row in df.iterrows():
        side = str(row.get(opt_col, "")).upper().strip()
        if side not in {"CE", "PE"}:
            continue
        strike = to_number(row.get(strike_col))
        volume = to_number(row.get(volume_col))
        coi = to_number(row.get(change_oi_col))
        oi = to_number(row.get(oi_col)) if oi_col else None
        if volume in (None, 0) or coi is None:
            continue

        signed_presence = coi / abs(volume)
        presence = abs(signed_presence)
        if presence < threshold:
            continue

        if side == "CE" and coi > 0:
            meaning = "CE fresh activity"
        elif side == "PE" and coi > 0:
            meaning = "PE fresh activity"
        elif side == "CE" and coi < 0:
            meaning = "CE unwinding/covering"
        elif side == "PE" and coi < 0:
            meaning = "PE unwinding/covering"
        else:
            meaning = "Neutral"

        rows.append({
            "symbol": symbol,
            "date": trade_date,
            "expiry": expiry,
            "timestamp": latest_ts,
            "time": timestamp_time_label(latest_ts),
            "spot": spot,
            "strike": strike,
            "side": side,
            "coi": coi,
            "volume": volume,
            "coiVolPct": safe_ratio_pct(coi, volume),
            "lotSize": lot_size,
            "presence": presence,
            "signedPresence": signed_presence,
            "openInterest": oi,
            "coiOiPct": safe_ratio_pct(coi, oi),
            "premium": to_number(row.get(premium_col)) if premium_col else None,
            "iv": to_number(row.get(iv_col)) if iv_col else None,
            "meaning": meaning,
            "expiryRaw": str(row.get(expiry_col, "")) if expiry_col else "",
        })

    rows.sort(key=lambda item: (item.get("presence") or 0), reverse=True)

    return {
        "symbol": symbol,
        "date": trade_date,
        "expiry": expiry,
        "availableDates": available_dates,
        "availableExpiries": available_expiries,
        "threshold": threshold,
        "lotSize": lot_size,
        "timestamp": latest_ts,
        "generatedAt": datetime.now(IST).strftime("%d-%b-%Y %H:%M:%S"),
        "spot": spot,
        "rows": rows,
        "count": len(rows),
        "formula": "ABS(1m COI / 1m Volume) >= 0.25",
        "error": "",
    }

def build_nse_oc_strike_chart_payload(symbol, trade_date=None, expiry=None, strike_value=None, side="CE"):
    """
    Build intraday raw-value chart payload for one side/strike:
    OI line, Volume bars, IV bars, LTP line.

    Uses direct SQL filters for date + expiry + strike + side.
    """
    available_dates = get_available_dates(symbol)
    if not trade_date and available_dates:
        trade_date = available_dates[0]

    available_expiries = get_available_expiries_for_date(symbol, trade_date)
    if not expiry and available_expiries:
        expiry = available_expiries[0]

    strike = to_number(strike_value)
    side = str(side or "CE").upper().strip()
    if strike is None:
        return {
            "symbol": symbol,
            "date": trade_date,
            "expiry": expiry,
            "side": side,
            "strike": strike_value,
            "availableDates": available_dates,
            "availableExpiries": available_expiries,
            "error": "Please select a valid strike price.",
            "points": [],
        }
    if side not in {"CE", "PE"}:
        return {
            "symbol": symbol,
            "date": trade_date,
            "expiry": expiry,
            "side": side,
            "strike": strike,
            "availableDates": available_dates,
            "availableExpiries": available_expiries,
            "error": "Side must be CE or PE.",
            "points": [],
        }

    df = read_option_strike_side_for_date_expiry(symbol, trade_date, expiry, strike, side)
    if df.empty:
        return {
            "symbol": symbol,
            "date": trade_date,
            "expiry": expiry,
            "side": side,
            "strike": strike,
            "availableDates": available_dates,
            "availableExpiries": available_expiries,
            "error": f"No {side} rows found for strike {int(strike) if float(strike).is_integer() else strike} on {trade_date} / expiry {expiry or 'selected expiry'}.",
            "points": [],
        }

    strike_col = find_column(df, ("strikePrice", "strike"))
    opt_col = find_column(df, ("optionType", "type"))
    spot_col = find_column(df, ("spotPrice", "underlyingValue"))
    expiry_col = find_column(df, ("expiryDate", "expiry"))

    metric_cols = {
        key: find_column(df, config["aliases"])
        for key, config in METRICS.items()
    }

    points = []
    timestamps = sorted(df["timestamp"].dropna().unique(), key=parse_timestamp)
    for ts in timestamps:
        frame = df[df["timestamp"] == ts]
        if frame.empty:
            continue
        row = frame.iloc[0]
        spot = first_valid_number(frame[spot_col].tolist()) if spot_col else None
        points.append({
            "timestamp": ts,
            "time": timestamp_time_label(ts),
            "spot": spot,
            "openInterest": to_number(row.get(metric_cols.get("openInterest"))) if metric_cols.get("openInterest") else None,
            "volume": to_number(row.get(metric_cols.get("volume"))) if metric_cols.get("volume") else None,
            "iv": to_number(row.get(metric_cols.get("iv"))) if metric_cols.get("iv") else None,
            "ltp": to_number(row.get(metric_cols.get("premium"))) if metric_cols.get("premium") else None,
        })

    return {
        "symbol": symbol,
        "date": trade_date,
        "expiry": expiry,
        "availableDates": available_dates,
        "availableExpiries": available_expiries,
        "side": side,
        "strike": strike,
        "firstTimestamp": points[0]["timestamp"] if points else "",
        "lastTimestamp": points[-1]["timestamp"] if points else "",
        "pointsCount": len(points),
        "generatedAt": datetime.now(IST).strftime("%d-%b-%Y %H:%M:%S"),
        "points": points,
    }



# ============================== EOD PARTICIPATION + STRIKE INFERENCE ==============================

def eod_search_dirs():
    """Return folders where NSE EOD reports may be present."""
    candidates = [Path(EOD_REPORTS_DIR), Path(BASE_DIR), Path('/mnt/data')]
    out = []
    seen = set()
    for folder in candidates:
        try:
            key = str(folder.resolve())
        except Exception:
            key = str(folder)
        if key in seen:
            continue
        seen.add(key)
        if folder.exists():
            out.append(folder)
    return out


def eod_date_tokens(trade_date):
    day = pd.to_datetime(trade_date).to_pydatetime()
    return {
        'date': day.strftime('%Y-%m-%d'),
        'yyyymmdd': day.strftime('%Y%m%d'),
        'ddmmyyyy': day.strftime('%d%m%Y'),
        'dd-Mon-yyyy': day.strftime('%d-%b-%Y'),
    }


def eod_file_mtime(path):
    try:
        return path.stat().st_mtime
    except Exception:
        return 0


def find_eod_file(kind, trade_date):
    tok = eod_date_tokens(trade_date)
    patterns = {
        'participant_oi': [f"fao_participant_oi_{tok['ddmmyyyy']}*.csv"],
        'participant_vol': [f"fao_participant_vol_{tok['ddmmyyyy']}*.csv"],
        'fo_bhavcopy': [
            f"BhavCopy_NSE_FO_0_0_0_{tok['yyyymmdd']}_F_0000*.csv.zip",
            f"BhavCopy_NSE_FO_0_0_0_{tok['yyyymmdd']}_F_0000*.csv",
        ],
        'cm_bhavcopy': [
            f"BhavCopy_NSE_CM_0_0_0_{tok['yyyymmdd']}_F_0000*.csv.zip",
            f"BhavCopy_NSE_CM_0_0_0_{tok['yyyymmdd']}_F_0000*.csv",
        ],
        'sec_bhav': [f"sec_bhavdata_full_{tok['ddmmyyyy']}*.csv"],
        'fii_stats': [f"fii_stats_{tok['dd-Mon-yyyy']}*.xls"],
    }.get(kind, [])

    matches = []
    for folder in eod_search_dirs():
        for pattern in patterns:
            matches.extend(folder.glob(pattern))
    matches = [path for path in matches if path.exists()]
    if not matches:
        return None
    return sorted(matches, key=eod_file_mtime, reverse=True)[0]


def discover_eod_dates():
    dates = set()
    for folder in eod_search_dirs():
        for path in folder.glob('fao_participant_oi_*.csv'):
            match = re.search(r'(\d{8})', path.name)
            if match:
                try:
                    dates.add(datetime.strptime(match.group(1), '%d%m%Y').strftime('%Y-%m-%d'))
                except Exception:
                    pass
        for path in folder.glob('fao_participant_vol_*.csv'):
            match = re.search(r'(\d{8})', path.name)
            if match:
                try:
                    dates.add(datetime.strptime(match.group(1), '%d%m%Y').strftime('%Y-%m-%d'))
                except Exception:
                    pass
        for path in folder.glob('BhavCopy_NSE_FO_0_0_0_*_F_0000*'):
            match = re.search(r'_(\d{8})_F_0000', path.name)
            if match:
                try:
                    dates.add(datetime.strptime(match.group(1), '%Y%m%d').strftime('%Y-%m-%d'))
                except Exception:
                    pass
        for path in folder.glob('BhavCopy_NSE_CM_0_0_0_*_F_0000*'):
            match = re.search(r'_(\d{8})_F_0000', path.name)
            if match:
                try:
                    dates.add(datetime.strptime(match.group(1), '%Y%m%d').strftime('%Y-%m-%d'))
                except Exception:
                    pass
        for path in folder.glob('sec_bhavdata_full_*.csv'):
            match = re.search(r'(\d{8})', path.name)
            if match:
                try:
                    dates.add(datetime.strptime(match.group(1), '%d%m%Y').strftime('%Y-%m-%d'))
                except Exception:
                    pass
    return sorted(dates, reverse=True)


def read_eod_csv_or_zip(path, usecols=None):
    if path is None:
        return pd.DataFrame()
    path = Path(path)
    if str(path).lower().endswith('.zip'):
        with zipfile.ZipFile(path) as zf:
            names = [name for name in zf.namelist() if name.lower().endswith('.csv')]
            if not names:
                return pd.DataFrame()
            with zf.open(names[0]) as handle:
                return pd.read_csv(handle, usecols=usecols)
    return pd.read_csv(path, usecols=usecols)


def read_participant_report(kind, trade_date):
    path = find_eod_file(kind, trade_date)
    if path is None:
        return pd.DataFrame(), None
    try:
        df = pd.read_csv(path, skiprows=1)
    except Exception:
        return pd.DataFrame(), str(path)
    df.columns = [str(col).strip() for col in df.columns]
    if 'Client Type' not in df.columns:
        return pd.DataFrame(), str(path)
    df['Client Type'] = df['Client Type'].astype(str).str.strip()
    for col in df.columns:
        if col == 'Client Type':
            continue
        df[col] = pd.to_numeric(df[col], errors='coerce').fillna(0)
    return df, str(path)


def eod_number(row, column):
    try:
        return float(row.get(column, 0) or 0)
    except Exception:
        return 0.0


def balance_pct(long_value, short_value):
    long_value = float(long_value or 0)
    short_value = float(short_value or 0)
    total = long_value + short_value
    if not total:
        return 0.0
    return ((long_value - short_value) / total) * 100.0


def eod_direction(score, threshold=5):
    if score >= threshold:
        return 'Bullish'
    if score <= -threshold:
        return 'Bearish'
    return 'Neutral'


def participant_score_from_row(row):
    if row is None:
        return None
    future_score = balance_pct(
        eod_number(row, 'Future Index Long'),
        eod_number(row, 'Future Index Short'),
    )
    # For options, CE long + PE short is treated as bullish, while PE long + CE short is treated as bearish.
    call_long = eod_number(row, 'Option Index Call Long')
    put_long = eod_number(row, 'Option Index Put Long')
    call_short = eod_number(row, 'Option Index Call Short')
    put_short = eod_number(row, 'Option Index Put Short')
    buyer_score = balance_pct(call_long, put_long)
    writer_score = balance_pct(put_short, call_short)
    option_score = (0.35 * buyer_score) + (0.65 * writer_score)
    composite = (0.40 * future_score) + (0.60 * option_score)
    return {
        'futureScore': future_score,
        'buyerScore': buyer_score,
        'writerScore': writer_score,
        'optionScore': option_score,
        'score': composite,
        'direction': eod_direction(composite),
        'futureNet': eod_number(row, 'Future Index Long') - eod_number(row, 'Future Index Short'),
        'callLong': call_long,
        'putLong': put_long,
        'callShort': call_short,
        'putShort': put_short,
        'callShortMinusPutShort': call_short - put_short,
        'putShortMinusCallShort': put_short - call_short,
    }


def participant_table(oi_df, vol_df=None, previous_oi_df=None):
    rows = []
    participants = ['FII', 'Pro', 'DII', 'Client']
    for participant in participants:
        current_match = oi_df[oi_df['Client Type'].str.upper() == participant.upper()] if not oi_df.empty else pd.DataFrame()
        if current_match.empty:
            continue
        row = current_match.iloc[0]
        score = participant_score_from_row(row)

        prev_score = None
        if previous_oi_df is not None and not previous_oi_df.empty:
            prev_match = previous_oi_df[previous_oi_df['Client Type'].str.upper() == participant.upper()]
            if not prev_match.empty:
                prev_score = participant_score_from_row(prev_match.iloc[0])

        vol_row = None
        if vol_df is not None and not vol_df.empty:
            vol_match = vol_df[vol_df['Client Type'].str.upper() == participant.upper()]
            if not vol_match.empty:
                vol_row = vol_match.iloc[0]

        index_option_volume = 0
        index_option_vol_score = 0
        if vol_row is not None:
            cl = eod_number(vol_row, 'Option Index Call Long')
            pl = eod_number(vol_row, 'Option Index Put Long')
            cs = eod_number(vol_row, 'Option Index Call Short')
            ps = eod_number(vol_row, 'Option Index Put Short')
            index_option_volume = cl + pl + cs + ps
            index_option_vol_score = balance_pct(cl + ps, pl + cs)

        rows.append({
            'participant': 'Prop' if participant == 'Pro' else participant,
            'rawParticipant': participant,
            'direction': score['direction'],
            'score': score['score'],
            'futureScore': score['futureScore'],
            'optionScore': score['optionScore'],
            'buyerScore': score['buyerScore'],
            'writerScore': score['writerScore'],
            'futureNet': score['futureNet'],
            'callLong': score['callLong'],
            'putLong': score['putLong'],
            'callShort': score['callShort'],
            'putShort': score['putShort'],
            'callShortMinusPutShort': score['callShortMinusPutShort'],
            'putShortMinusCallShort': score['putShortMinusCallShort'],
            'indexOptionVolume': index_option_volume,
            'indexOptionVolumeScore': index_option_vol_score,
            'scoreChange': None if prev_score is None else score['score'] - prev_score['score'],
            'futureNetChange': None if prev_score is None else score['futureNet'] - prev_score['futureNet'],
        })
    return rows


def big_money_from_participants(rows):
    by_raw = {row.get('rawParticipant'): row for row in rows}
    fii = by_raw.get('FII')
    pro = by_raw.get('Pro')
    if not fii and not pro:
        return {'score': 0, 'direction': 'Neutral', 'confidence': 'Low', 'note': 'FII/Prop rows not available'}
    if fii and pro:
        score = (0.60 * fii['score']) + (0.40 * pro['score'])
        alignment = fii['direction'] == pro['direction'] and fii['direction'] != 'Neutral'
    elif fii:
        score = fii['score']
        alignment = False
    else:
        score = pro['score']
        alignment = False
    direction = eod_direction(score)
    strength = abs(score)
    if alignment and strength >= 15:
        confidence = 'High'
    elif strength >= 8:
        confidence = 'Medium'
    else:
        confidence = 'Low'
    return {
        'score': score,
        'direction': direction,
        'confidence': confidence,
        'fiiScore': fii['score'] if fii else None,
        'propScore': pro['score'] if pro else None,
        'fiiDirection': fii['direction'] if fii else '',
        'propDirection': pro['direction'] if pro else '',
        'aligned': alignment,
    }


def read_fo_bhavcopy_for_date(trade_date):
    path = find_eod_file('fo_bhavcopy', trade_date)
    if path is None:
        return pd.DataFrame(), None
    usecols = None
    try:
        usecols = [
            'TradDt', 'FinInstrmTp', 'TckrSymb', 'XpryDt', 'StrkPric', 'OptnTp',
            'ClsPric', 'LastPric', 'PrvsClsgPric', 'UndrlygPric', 'OpnIntrst',
            'ChngInOpnIntrst', 'TtlTradgVol', 'TtlTrfVal'
        ]
        df = read_eod_csv_or_zip(path, usecols=usecols)
    except Exception:
        df = read_eod_csv_or_zip(path)
    if df.empty:
        return df, str(path)
    for col in ('StrkPric', 'ClsPric', 'LastPric', 'PrvsClsgPric', 'UndrlygPric', 'OpnIntrst', 'ChngInOpnIntrst', 'TtlTradgVol', 'TtlTrfVal'):
        if col in df.columns:
            df[col] = pd.to_numeric(df[col], errors='coerce').fillna(0)
    return df, str(path)




def read_cm_bhavcopy_for_date(trade_date):
    """Read cash-market Bhavcopy (CM) for cash movement fallback when delivery file is absent."""
    path = find_eod_file('cm_bhavcopy', trade_date)
    if path is None:
        return pd.DataFrame(), None
    try:
        usecols = [
            'TradDt', 'FinInstrmTp', 'TckrSymb', 'SctySrs', 'OpnPric', 'HghPric',
            'LwPric', 'ClsPric', 'LastPric', 'PrvsClsgPric', 'TtlTradgVol',
            'TtlTrfVal', 'TtlNbOfTxsExctd'
        ]
        df = read_eod_csv_or_zip(path, usecols=usecols)
    except Exception:
        df = read_eod_csv_or_zip(path)
    if df.empty:
        return df, str(path)
    df.columns = [str(col).strip() for col in df.columns]
    for col in ('OpnPric', 'HghPric', 'LwPric', 'ClsPric', 'LastPric', 'PrvsClsgPric', 'TtlTradgVol', 'TtlTrfVal', 'TtlNbOfTxsExctd'):
        if col in df.columns:
            df[col] = pd.to_numeric(df[col], errors='coerce').fillna(0)
    return df, str(path)


def read_cash_bhavcopy_for_date(trade_date):
    """
    Read cash delivery footprint. Prefer sec_bhavdata_full because it has DELIV_QTY/DELIV_PER.
    Fall back to CM bhavcopy when delivery file is unavailable.
    """
    path = find_eod_file('sec_bhav', trade_date)
    if path is not None:
        try:
            df = pd.read_csv(path)
            df.columns = [str(col).strip() for col in df.columns]
            for col in ('PREV_CLOSE', 'OPEN_PRICE', 'HIGH_PRICE', 'LOW_PRICE', 'LAST_PRICE',
                        'CLOSE_PRICE', 'AVG_PRICE', 'TTL_TRD_QNTY', 'TURNOVER_LACS',
                        'NO_OF_TRADES', 'DELIV_QTY', 'DELIV_PER'):
                if col in df.columns:
                    df[col] = pd.to_numeric(df[col], errors='coerce').fillna(0)
            return df, str(path), 'sec_bhavdata_full'
        except Exception:
            pass

    cm_df, cm_path = read_cm_bhavcopy_for_date(trade_date)
    if cm_df.empty:
        return pd.DataFrame(), cm_path, 'missing'
    out = pd.DataFrame({
        'SYMBOL': cm_df.get('TckrSymb', pd.Series(dtype=str)),
        'SERIES': cm_df.get('SctySrs', pd.Series(dtype=str)),
        'PREV_CLOSE': cm_df.get('PrvsClsgPric', 0),
        'OPEN_PRICE': cm_df.get('OpnPric', 0),
        'HIGH_PRICE': cm_df.get('HghPric', 0),
        'LOW_PRICE': cm_df.get('LwPric', 0),
        'LAST_PRICE': cm_df.get('LastPric', 0),
        'CLOSE_PRICE': cm_df.get('ClsPric', 0),
        'AVG_PRICE': 0,
        'TTL_TRD_QNTY': cm_df.get('TtlTradgVol', 0),
        'TURNOVER_LACS': pd.to_numeric(cm_df.get('TtlTrfVal', 0), errors='coerce').fillna(0) / 100000,
        'NO_OF_TRADES': cm_df.get('TtlNbOfTxsExctd', 0),
        'DELIV_QTY': 0,
        'DELIV_PER': 0,
    })
    return out, cm_path, 'cm_bhavcopy_no_delivery'


def classify_cash_delivery(price_pct, delivery_pct, delivery_value_lacs, high_value_cutoff):
    price_pct = float(price_pct or 0)
    delivery_pct = float(delivery_pct or 0)
    delivery_value_lacs = float(delivery_value_lacs or 0)
    is_large = delivery_value_lacs >= float(high_value_cutoff or 0)

    if is_large and delivery_pct >= 50 and price_pct >= 1.0:
        return 'Cash accumulation'
    if is_large and delivery_pct >= 50 and price_pct <= -1.0:
        return 'Cash distribution'
    if is_large and delivery_pct >= 35 and abs(price_pct) <= 0.75:
        return 'Large delivery, no price acceptance'
    if delivery_pct >= 40 and price_pct >= 2.0:
        return 'Delivery momentum buying'
    if delivery_pct >= 40 and price_pct <= -2.0:
        return 'Delivery pressure / selling'
    if is_large:
        return 'Large delivery watch'
    return 'Normal / ignore'


def build_eod_cash_footprint(trade_date, top_n=30):
    current, current_path, source_kind = read_cash_bhavcopy_for_date(trade_date)
    if current.empty:
        return {
            'error': f'Cash bhavcopy / sec bhavdata not found for {trade_date}.',
            'sourceFile': current_path,
            'sourceKind': source_kind,
            'summary': {},
            'rows': [],
            'topRows': [],
            'accumulation': [],
            'distribution': [],
            'noAcceptance': [],
        }

    df = current.copy()
    df.columns = [str(col).strip() for col in df.columns]
    if 'SERIES' in df.columns:
        df = df[df['SERIES'].astype(str).str.strip().str.upper().eq('EQ')].copy()
    if df.empty:
        return {
            'error': f'No EQ cash rows found for {trade_date}.',
            'sourceFile': current_path,
            'sourceKind': source_kind,
            'summary': {},
            'rows': [],
            'topRows': [],
            'accumulation': [],
            'distribution': [],
            'noAcceptance': [],
        }

    numeric_cols = ['PREV_CLOSE', 'OPEN_PRICE', 'HIGH_PRICE', 'LOW_PRICE', 'LAST_PRICE',
                    'CLOSE_PRICE', 'AVG_PRICE', 'TTL_TRD_QNTY', 'TURNOVER_LACS',
                    'NO_OF_TRADES', 'DELIV_QTY', 'DELIV_PER']
    for col in numeric_cols:
        if col in df.columns:
            df[col] = pd.to_numeric(df[col], errors='coerce').fillna(0)
        else:
            df[col] = 0

    df['pricePct'] = df.apply(
        lambda row: ((row['CLOSE_PRICE'] - row['PREV_CLOSE']) / row['PREV_CLOSE'] * 100) if row['PREV_CLOSE'] else 0,
        axis=1,
    )
    df['deliveryValueLacs'] = (df['CLOSE_PRICE'] * df['DELIV_QTY']) / 100000
    df['tradedValueLacs'] = df['TURNOVER_LACS']

    prev_dates = [d for d in discover_eod_dates() if d < trade_date]
    previous_day = sorted(prev_dates)[-1] if prev_dates else None
    if previous_day:
        prev_df, _, _ = read_cash_bhavcopy_for_date(previous_day)
        if not prev_df.empty:
            prev_df.columns = [str(col).strip() for col in prev_df.columns]
            if 'SERIES' in prev_df.columns:
                prev_df = prev_df[prev_df['SERIES'].astype(str).str.strip().str.upper().eq('EQ')].copy()
            for col in ('TTL_TRD_QNTY', 'TURNOVER_LACS', 'DELIV_QTY', 'DELIV_PER'):
                if col in prev_df.columns:
                    prev_df[col] = pd.to_numeric(prev_df[col], errors='coerce').fillna(0)
                else:
                    prev_df[col] = 0
            prev_keep = prev_df[['SYMBOL', 'TTL_TRD_QNTY', 'TURNOVER_LACS', 'DELIV_QTY', 'DELIV_PER']].rename(columns={
                'TTL_TRD_QNTY': 'prevTradedQty',
                'TURNOVER_LACS': 'prevTurnoverLacs',
                'DELIV_QTY': 'prevDeliveryQty',
                'DELIV_PER': 'prevDeliveryPct',
            })
            df = df.merge(prev_keep, on='SYMBOL', how='left')
    for col in ('prevTradedQty', 'prevTurnoverLacs', 'prevDeliveryQty', 'prevDeliveryPct'):
        if col not in df.columns:
            df[col] = None

    df['deliveryQtyChangePct'] = df.apply(lambda row: pct_change(row['DELIV_QTY'], row.get('prevDeliveryQty')), axis=1)
    df['turnoverChangePct'] = df.apply(lambda row: pct_change(row['TURNOVER_LACS'], row.get('prevTurnoverLacs')), axis=1)
    df['volumeChangePct'] = df.apply(lambda row: pct_change(row['TTL_TRD_QNTY'], row.get('prevTradedQty')), axis=1)

    value_series = pd.to_numeric(df['deliveryValueLacs'], errors='coerce').fillna(0)
    high_value_cutoff = float(value_series.quantile(0.75)) if not value_series.empty else 0
    if high_value_cutoff <= 0:
        high_value_cutoff = float(pd.to_numeric(df['tradedValueLacs'], errors='coerce').fillna(0).quantile(0.75)) if not df.empty else 0

    df['cashSignal'] = df.apply(
        lambda row: classify_cash_delivery(row['pricePct'], row['DELIV_PER'], row['deliveryValueLacs'], high_value_cutoff),
        axis=1,
    )
    df['activityScore'] = 100 * (
        0.42 * percentile_rank(df['deliveryValueLacs']) +
        0.25 * percentile_rank(df['tradedValueLacs']) +
        0.20 * percentile_rank(df['DELIV_PER']) +
        0.13 * percentile_rank(df['pricePct'].abs())
    )

    up_value = float(df.loc[df['pricePct'] > 0, 'deliveryValueLacs'].sum())
    down_value = float(df.loc[df['pricePct'] < 0, 'deliveryValueLacs'].sum())
    total_delivery_value = float(df['deliveryValueLacs'].sum())
    total_turnover = float(df['TURNOVER_LACS'].sum())
    advancers = int((df['pricePct'] > 0).sum())
    decliners = int((df['pricePct'] < 0).sum())
    unchanged = int((df['pricePct'] == 0).sum())
    cash_bias_score = ((up_value - down_value) / (up_value + down_value) * 100) if (up_value + down_value) else 0
    top10_value = float(df.sort_values('deliveryValueLacs', ascending=False).head(10)['deliveryValueLacs'].sum())

    rows = []
    for _, row in df.sort_values('activityScore', ascending=False).head(max(top_n, 30)).iterrows():
        rows.append({
            'symbol': str(row.get('SYMBOL', '')).strip(),
            'signal': str(row.get('cashSignal', '')),
            'pricePct': float(row.get('pricePct') or 0),
            'close': float(row.get('CLOSE_PRICE') or 0),
            'deliveryPct': float(row.get('DELIV_PER') or 0),
            'deliveryQty': float(row.get('DELIV_QTY') or 0),
            'deliveryValueLacs': float(row.get('deliveryValueLacs') or 0),
            'tradedQty': float(row.get('TTL_TRD_QNTY') or 0),
            'turnoverLacs': float(row.get('TURNOVER_LACS') or 0),
            'deliveryQtyChangePct': None if pd.isna(row.get('deliveryQtyChangePct')) else row.get('deliveryQtyChangePct'),
            'turnoverChangePct': None if pd.isna(row.get('turnoverChangePct')) else row.get('turnoverChangePct'),
            'volumeChangePct': None if pd.isna(row.get('volumeChangePct')) else row.get('volumeChangePct'),
            'activityScore': float(row.get('activityScore') or 0),
        })

    accumulation = [row for row in rows if 'accumulation' in row['signal'].lower() or 'buying' in row['signal'].lower()]
    distribution = [row for row in rows if 'distribution' in row['signal'].lower() or 'selling' in row['signal'].lower() or 'pressure' in row['signal'].lower()]
    no_acceptance = [row for row in rows if 'no price acceptance' in row['signal'].lower()]

    return {
        'error': '',
        'sourceFile': current_path,
        'sourceKind': source_kind,
        'previousDate': previous_day,
        'date': trade_date,
        'updatedAt': (rows[0].get('updatedAt') if rows else ''),
        'summary': {
            'date': trade_date,
            'updatedAt': (rows[0].get('updatedAt') if rows else ''),
            'cashDirection': eod_direction(cash_bias_score),
            'cashBiasScore': cash_bias_score,
            'advancers': advancers,
            'decliners': decliners,
            'unchanged': unchanged,
            'upDeliveryValueLacs': up_value,
            'downDeliveryValueLacs': down_value,
            'totalDeliveryValueLacs': total_delivery_value,
            'totalTurnoverLacs': total_turnover,
            'top10DeliveryConcentrationPct': (top10_value / total_delivery_value * 100) if total_delivery_value else None,
            'highValueCutoffLacs': high_value_cutoff,
            'sourceKind': source_kind,
        },
        'rows': rows,
        'topRows': rows[:top_n],
        'accumulation': accumulation[:12],
        'distribution': distribution[:12],
        'noAcceptance': no_acceptance[:12],
    }


def cm_market_metrics_from_df(df):
    """Aggregate NSE CM bhavcopy into the same market-wide fields shown on NSE Business Growth CM page."""
    if df is None or df.empty:
        return {}
    work = df.copy()
    work.columns = [str(col).strip() for col in work.columns]
    for col in ('TtlTradgVol', 'TtlTrfVal', 'TtlNbOfTxsExctd'):
        if col in work.columns:
            work[col] = pd.to_numeric(work[col], errors='coerce').fillna(0)
        else:
            work[col] = 0
    if 'FinInstrmId' in work.columns:
        securities_traded = int(work['FinInstrmId'].nunique())
    elif 'TckrSymb' in work.columns and 'SctySrs' in work.columns:
        securities_traded = int(work[['TckrSymb', 'SctySrs']].drop_duplicates().shape[0])
    elif 'TckrSymb' in work.columns:
        securities_traded = int(work['TckrSymb'].nunique())
    else:
        securities_traded = int(len(work))

    traded_qty = float(work['TtlTradgVol'].sum())
    traded_value = float(work['TtlTrfVal'].sum())
    trades = float(work['TtlNbOfTxsExctd'].sum())
    traded_value_crores = traded_value / 10000000.0
    traded_qty_lakhs = traded_qty / 100000.0
    avg_trade_size = traded_value / trades if trades else None
    avg_value_per_security_crores = traded_value_crores / securities_traded if securities_traded else None
    return {
        'securitiesTraded': securities_traded,
        'tradedQtyLakhs': traded_qty_lakhs,
        'tradedValueCrores': traded_value_crores,
        'noOfTrades': trades,
        'avgTradeSize': avg_trade_size,
        'avgValuePerSecurityCrores': avg_value_per_security_crores,
    }


def classify_cm_participation(value_change, qty_change, trades_change, avg_trade_change):
    value_change = float(value_change or 0)
    qty_change = float(qty_change or 0)
    trades_change = float(trades_change or 0)
    avg_trade_change = float(avg_trade_change or 0)
    score = (0.38 * value_change) + (0.27 * qty_change) + (0.25 * trades_change) + (0.10 * avg_trade_change)
    if score >= 12:
        regime = 'Strong participation expansion'
    elif score >= 5:
        regime = 'Participation expanding'
    elif score <= -12:
        regime = 'Strong participation contraction'
    elif score <= -5:
        regime = 'Participation contracting'
    elif value_change >= 5 and trades_change <= 0:
        regime = 'Value-led block / large-ticket activity'
    elif qty_change >= 10 and value_change < 3:
        regime = 'Quantity-heavy churn'
    else:
        regime = 'Normal participation'
    return regime, score


def build_cm_market_regime(trade_date, history_limit=12):
    """
    Build market-wide CM participation regime from NSE CM bhavcopy.

    This mirrors the NSE Business Growth in CM Segment daily table using local
    BhavCopy_NSE_CM files: securities traded, trades, traded quantity and value.
    It is a confirmation/participation layer, not a directional buy/sell signal.
    """
    current_df, current_path = read_cm_bhavcopy_for_date(trade_date)
    if current_df.empty:
        return {
            'error': f'CM Bhavcopy not found for {trade_date}. Keep BhavCopy_NSE_CM_... file in {EOD_REPORTS_DIR}.',
            'sourceFile': current_path,
            'summary': {},
            'history': [],
        }

    current = cm_market_metrics_from_df(current_df)
    dates = sorted([d for d in discover_eod_dates() if d <= trade_date], reverse=True)
    history = []
    metrics_by_date = {}
    source_by_date = {}
    for day in dates[:max(history_limit, 3)]:
        df, path = read_cm_bhavcopy_for_date(day)
        if df.empty:
            continue
        metrics = cm_market_metrics_from_df(df)
        metrics['date'] = day
        metrics_by_date[day] = metrics
        source_by_date[day] = path
        history.append(metrics)

    prev_candidates = [d for d in sorted(metrics_by_date) if d < trade_date]
    previous_day = prev_candidates[-1] if prev_candidates else None
    previous = metrics_by_date.get(previous_day, {}) if previous_day else {}

    value_change = pct_change(current.get('tradedValueCrores'), previous.get('tradedValueCrores'))
    qty_change = pct_change(current.get('tradedQtyLakhs'), previous.get('tradedQtyLakhs'))
    trades_change = pct_change(current.get('noOfTrades'), previous.get('noOfTrades'))
    securities_change = pct_change(current.get('securitiesTraded'), previous.get('securitiesTraded'))
    avg_trade_change = pct_change(current.get('avgTradeSize'), previous.get('avgTradeSize'))
    regime, participation_score = classify_cm_participation(value_change, qty_change, trades_change, avg_trade_change)

    # Confidence is direction-neutral. Expanding participation increases conviction
    # only when the directional layers are already aligned.
    if participation_score >= 8:
        conviction = 'High participation confirmation'
    elif participation_score >= 3:
        conviction = 'Moderate participation confirmation'
    elif participation_score <= -8:
        conviction = 'Low participation / signal reliability reduced'
    else:
        conviction = 'Normal participation / neutral confirmation'

    for idx, row in enumerate(history):
        prev = history[idx + 1] if idx + 1 < len(history) else {}
        row['tradedValueChangePct'] = pct_change(row.get('tradedValueCrores'), prev.get('tradedValueCrores'))
        row['tradedQtyChangePct'] = pct_change(row.get('tradedQtyLakhs'), prev.get('tradedQtyLakhs'))
        row['tradesChangePct'] = pct_change(row.get('noOfTrades'), prev.get('noOfTrades'))
        row['avgTradeSizeChangePct'] = pct_change(row.get('avgTradeSize'), prev.get('avgTradeSize'))

    return {
        'error': '',
        'sourceFile': current_path,
        'previousDate': previous_day,
        'summary': {
            'regime': regime,
            'conviction': conviction,
            'participationScore': participation_score,
            'tradedValueCrores': current.get('tradedValueCrores'),
            'tradedQtyLakhs': current.get('tradedQtyLakhs'),
            'noOfTrades': current.get('noOfTrades'),
            'securitiesTraded': current.get('securitiesTraded'),
            'avgTradeSize': current.get('avgTradeSize'),
            'avgValuePerSecurityCrores': current.get('avgValuePerSecurityCrores'),
            'tradedValueChangePct': value_change,
            'tradedQtyChangePct': qty_change,
            'tradesChangePct': trades_change,
            'securitiesChangePct': securities_change,
            'avgTradeSizeChangePct': avg_trade_change,
            'sourceKind': 'cm_bhavcopy_aggregate',
        },
        'history': history,
    }


def build_eod_future_activity(symbol, trade_date):
    df, source_path = read_fo_bhavcopy_for_date(trade_date)
    if df.empty:
        return {'error': 'FO Bhavcopy not found for futures analysis.', 'sourceFile': source_path, 'rows': [], 'current': {}, 'summary': {}}
    work = df[(df.get('FinInstrmTp').astype(str).str.upper() == 'IDF') & (df.get('TckrSymb').astype(str).str.upper() == symbol.upper())].copy()
    if work.empty:
        return {'error': f'No index future rows found for {symbol}.', 'sourceFile': source_path, 'rows': [], 'current': {}, 'summary': {}}
    for col in ('ClsPric', 'PrvsClsgPric', 'UndrlygPric', 'OpnIntrst', 'ChngInOpnIntrst', 'TtlTradgVol', 'TtlTrfVal'):
        if col in work.columns:
            work[col] = pd.to_numeric(work[col], errors='coerce').fillna(0)
        else:
            work[col] = 0
    work['expiryKey'] = work['XpryDt'].map(expiry_key) if 'XpryDt' in work.columns else ''
    trade_key = pd.to_datetime(trade_date).strftime('%Y-%m-%d')
    future_expiries = sorted([x for x in work['expiryKey'].dropna().unique().tolist() if x and x >= trade_key])
    selected_expiry = future_expiries[0] if future_expiries else (sorted(work['expiryKey'].dropna().unique().tolist())[0] if len(work) else '')

    rows = []
    for _, row in work.sort_values('expiryKey').iterrows():
        close = float(row.get('ClsPric') or 0)
        prev_close = float(row.get('PrvsClsgPric') or 0)
        price_change = close - prev_close
        price_pct = (price_change / prev_close * 100) if prev_close else 0
        coi = float(row.get('ChngInOpnIntrst') or 0)
        build, actor = classify_strike_build('FUT', coi, price_change)
        if build in ('Long build-up', 'Short covering'):
            direction = 'Bullish'
        elif build in ('Short build-up', 'Long unwinding'):
            direction = 'Bearish'
        else:
            direction = 'Neutral'
        rows.append({
            'expiry': row.get('expiryKey') or str(row.get('XpryDt', '')),
            'close': close,
            'prevClose': prev_close,
            'priceChange': price_change,
            'pricePct': price_pct,
            'spot': float(row.get('UndrlygPric') or 0),
            'basis': close - float(row.get('UndrlygPric') or 0) if row.get('UndrlygPric') else None,
            'oi': float(row.get('OpnIntrst') or 0),
            'coi': coi,
            'volume': float(row.get('TtlTradgVol') or 0),
            'turnover': float(row.get('TtlTrfVal') or 0),
            'build': build,
            'actor': actor,
            'direction': direction,
        })
    current = next((row for row in rows if row.get('expiry') == selected_expiry), rows[0] if rows else {})
    summary = {
        'direction': current.get('direction', 'Neutral'),
        'build': current.get('build', ''),
        'expiry': current.get('expiry', ''),
        'pricePct': current.get('pricePct'),
        'coi': current.get('coi'),
        'volume': current.get('volume'),
        'basis': current.get('basis'),
    }
    return {'error': '', 'sourceFile': source_path, 'rows': rows, 'current': current, 'summary': summary}


def build_eod_360_summary(big_money, strikes, futures, cash, cm_market=None):
    def dir_score(value):
        value = str(value or '').lower()
        if 'bull' in value:
            return 1
        if 'bear' in value:
            return -1
        return 0

    walls = (strikes or {}).get('walls') or {}
    resistance = walls.get('resistance') or {}
    support = walls.get('support') or {}
    resistance_score = float(resistance.get('activityScore') or 0)
    support_score = float(support.get('activityScore') or 0)
    if resistance_score > support_score * 1.12:
        option_direction = 'Bearish / Capped'
        option_score = -1
    elif support_score > resistance_score * 1.12:
        option_direction = 'Bullish / Supported'
        option_score = 1
    else:
        option_direction = 'Range / Mixed'
        option_score = 0

    participant_direction = (big_money or {}).get('direction', 'Neutral')
    future_direction = ((futures or {}).get('summary') or {}).get('direction', 'Neutral')
    cash_direction = (((cash or {}).get('summary') or {}).get('cashDirection') or 'Neutral')
    cm_summary = ((cm_market or {}).get('summary') or {})
    cm_score = float(cm_summary.get('participationScore') or 0)
    # CM business growth is not directional by itself. It is used as conviction.
    # When cash delivery has direction and CM participation expands, it lightly confirms that cash signal.
    cm_direction_component = dir_score(cash_direction) * max(-1.0, min(1.0, cm_score / 100.0))

    composite = (
        0.38 * dir_score(participant_direction) +
        0.23 * dir_score(future_direction) +
        0.19 * option_score +
        0.15 * dir_score(cash_direction) +
        0.05 * cm_direction_component
    )
    if composite >= 0.45:
        verdict = '360 Bullish'
    elif composite <= -0.45:
        verdict = '360 Bearish'
    elif abs(composite) >= 0.20:
        verdict = '360 Mild / Watch'
    else:
        verdict = '360 Mixed / Range'

    notes = [
        f"Participant Big Money: {participant_direction}.",
        f"Index futures: {future_direction} ({((futures or {}).get('summary') or {}).get('build', 'NA')}).",
        f"Options structure: {option_direction}; CE wall {resistance.get('strike') or 'NA'}, PE wall {support.get('strike') or 'NA'}.",
        f"Cash delivery footprint: {cash_direction}; cash bias score {(((cash or {}).get('summary') or {}).get('cashBiasScore') or 0):.1f}.",
        f"CM business regime: {cm_summary.get('regime', 'NA')}; participation score {cm_score:.1f}.",
    ]
    return {
        'verdict': verdict,
        'score': composite * 100,
        'participantDirection': participant_direction,
        'futureDirection': future_direction,
        'optionDirection': option_direction,
        'cashDirection': cash_direction,
        'cmRegime': cm_summary.get('regime', ''),
        'cmParticipationScore': cm_score,
        'cmConviction': cm_summary.get('conviction', ''),
        'notes': notes,
    }

def eod_available_expiries(symbol, trade_date):
    df, _ = read_fo_bhavcopy_for_date(trade_date)
    if df.empty:
        return []
    work = df[(df.get('FinInstrmTp').astype(str).str.upper() == 'IDO') & (df.get('TckrSymb').astype(str).str.upper() == symbol.upper())].copy()
    if work.empty or 'XpryDt' not in work.columns:
        return []
    expiries = []
    for value in work['XpryDt'].dropna().astype(str).unique().tolist():
        key = expiry_key(value)
        if key and key not in expiries:
            expiries.append(key)
    return sorted(expiries)


def eod_select_expiry(df, symbol, trade_date, expiry=None):
    if df.empty:
        return None
    work = df[(df.get('FinInstrmTp').astype(str).str.upper() == 'IDO') & (df.get('TckrSymb').astype(str).str.upper() == symbol.upper())].copy()
    if work.empty or 'XpryDt' not in work.columns:
        return None
    if expiry:
        target = expiry_key(expiry)
        available = [expiry_key(x) for x in work['XpryDt'].dropna().astype(str).unique().tolist()]
        if target in available:
            return target
    trade_key = pd.to_datetime(trade_date).strftime('%Y-%m-%d')
    expiries = sorted({expiry_key(x) for x in work['XpryDt'].dropna().astype(str).tolist() if expiry_key(x)})
    # For EOD decision-making, same-day expiry is already over after the close.
    # Default to the next live expiry; user can still choose same-day expiry manually.
    future = [x for x in expiries if x > trade_key]
    return future[0] if future else (expiries[0] if expiries else None)


def classify_strike_build(side, coi, price_change):
    coi = float(coi or 0)
    price_change = float(price_change or 0)
    if coi > 0 and price_change > 0:
        return 'Long build-up', 'Buyer active'
    if coi > 0 and price_change < 0:
        return 'Short build-up', 'Writer active'
    if coi < 0 and price_change > 0:
        return 'Short covering', 'Shorts exiting'
    if coi < 0 and price_change < 0:
        return 'Long unwinding', 'Longs exiting'
    return 'Neutral', 'No clear build-up'


def strike_side_meaning(side, build):
    if side == 'CE' and build == 'Short build-up':
        return 'Resistance / call writing zone'
    if side == 'PE' and build == 'Short build-up':
        return 'Support / put writing zone'
    if side == 'CE' and build == 'Long build-up':
        return 'Upside chase / call buying zone'
    if side == 'PE' and build == 'Long build-up':
        return 'Downside hedge / put buying zone'
    return build


def percentile_rank(series):
    if series is None or len(series) == 0:
        return series
    clean = pd.to_numeric(series, errors='coerce').fillna(0)
    if clean.abs().sum() == 0:
        return clean * 0
    return clean.rank(pct=True)


def build_eod_strike_activity(symbol, trade_date, expiry=None):
    current, current_path = read_fo_bhavcopy_for_date(trade_date)
    if current.empty:
        return {
            'error': f'FO Bhavcopy not found for {trade_date}. Put BhavCopy_NSE_FO_... file in {EOD_REPORTS_DIR}.',
            'sourceFile': current_path,
            'expiry': expiry,
            'availableExpiries': [],
            'spot': None,
            'rows': [],
            'topCe': [],
            'topPe': [],
            'walls': {},
        }

    selected_expiry = eod_select_expiry(current, symbol, trade_date, expiry)
    available_expiries = eod_available_expiries(symbol, trade_date)
    work = current[(current['FinInstrmTp'].astype(str).str.upper() == 'IDO') & (current['TckrSymb'].astype(str).str.upper() == symbol.upper())].copy()
    if selected_expiry:
        work = work[work['XpryDt'].map(expiry_key) == selected_expiry].copy()
    work = work[work['OptnTp'].astype(str).str.upper().isin(['CE', 'PE'])].copy()
    if work.empty:
        return {
            'error': f'No index option rows found for {symbol} / {selected_expiry or expiry or "selected expiry"}.',
            'sourceFile': current_path,
            'expiry': selected_expiry or expiry,
            'availableExpiries': available_expiries,
            'spot': None,
            'rows': [],
            'topCe': [],
            'topPe': [],
            'walls': {},
        }

    spot = float(pd.to_numeric(work['UndrlygPric'], errors='coerce').replace(0, pd.NA).dropna().median()) if 'UndrlygPric' in work.columns else None
    agg = work.groupby(['StrkPric', 'OptnTp'], as_index=False).agg(
        oi=('OpnIntrst', 'sum'),
        coi=('ChngInOpnIntrst', 'sum'),
        volume=('TtlTradgVol', 'sum'),
        close=('ClsPric', 'mean'),
        prevClose=('PrvsClsgPric', 'mean'),
    )

    prev_dates = [d for d in discover_eod_dates() if d < trade_date]
    previous_day = sorted(prev_dates)[-1] if prev_dates else None
    prev_agg = pd.DataFrame()
    if previous_day:
        previous, _ = read_fo_bhavcopy_for_date(previous_day)
        if not previous.empty:
            prev_work = previous[(previous['FinInstrmTp'].astype(str).str.upper() == 'IDO') & (previous['TckrSymb'].astype(str).str.upper() == symbol.upper())].copy()
            if selected_expiry:
                prev_work = prev_work[prev_work['XpryDt'].map(expiry_key) == selected_expiry].copy()
            prev_work = prev_work[prev_work['OptnTp'].astype(str).str.upper().isin(['CE', 'PE'])].copy()
            if not prev_work.empty:
                prev_agg = prev_work.groupby(['StrkPric', 'OptnTp'], as_index=False).agg(
                    prevDayOi=('OpnIntrst', 'sum'),
                    prevDayVolume=('TtlTradgVol', 'sum'),
                    prevDayClose=('ClsPric', 'mean'),
                )
    if not prev_agg.empty:
        agg = agg.merge(prev_agg, on=['StrkPric', 'OptnTp'], how='left')
    else:
        agg['prevDayOi'] = None
        agg['prevDayVolume'] = None
        agg['prevDayClose'] = None

    agg['priceChange'] = agg.apply(lambda row: (row['close'] - row['prevDayClose']) if pd.notna(row.get('prevDayClose')) else (row['close'] - row['prevClose']), axis=1)
    agg['absCoi'] = agg['coi'].abs()
    agg['activityScore'] = (
        100 * (
            0.50 * percentile_rank(agg['absCoi']) +
            0.30 * percentile_rank(agg['volume']) +
            0.20 * percentile_rank(agg['oi'])
        )
    )

    rows = []
    for _, item in agg.sort_values(['OptnTp', 'activityScore'], ascending=[True, False]).iterrows():
        side = str(item['OptnTp']).upper()
        build, actor = classify_strike_build(side, item.get('coi'), item.get('priceChange'))
        rows.append({
            'strike': float(item['StrkPric']),
            'side': side,
            'oi': float(item.get('oi') or 0),
            'coi': float(item.get('coi') or 0),
            'volume': float(item.get('volume') or 0),
            'close': float(item.get('close') or 0),
            'priceChange': float(item.get('priceChange') or 0),
            'prevDayOi': None if pd.isna(item.get('prevDayOi')) else float(item.get('prevDayOi') or 0),
            'activityScore': float(item.get('activityScore') or 0),
            'build': build,
            'actor': actor,
            'meaning': strike_side_meaning(side, build),
        })

    ce_rows = [row for row in rows if row['side'] == 'CE']
    pe_rows = [row for row in rows if row['side'] == 'PE']
    top_ce = sorted(ce_rows, key=lambda row: row['activityScore'], reverse=True)[:12]
    top_pe = sorted(pe_rows, key=lambda row: row['activityScore'], reverse=True)[:12]

    ce_candidates = ce_rows
    pe_candidates = pe_rows
    if spot:
        ce_candidates = [row for row in ce_rows if row['strike'] >= spot]
        pe_candidates = [row for row in pe_rows if row['strike'] <= spot]
    resistance = sorted(ce_candidates or ce_rows, key=lambda row: (row['activityScore'], row['oi']), reverse=True)[0] if ce_rows else None
    support = sorted(pe_candidates or pe_rows, key=lambda row: (row['activityScore'], row['oi']), reverse=True)[0] if pe_rows else None

    return {
        'error': '',
        'sourceFile': current_path,
        'previousDate': previous_day,
        'expiry': selected_expiry,
        'availableExpiries': available_expiries,
        'spot': spot,
        'rows': sorted(rows, key=lambda row: (abs((row['strike'] or 0) - (spot or row['strike'] or 0)), row['side'])),
        'topCe': top_ce,
        'topPe': top_pe,
        'walls': {
            'resistance': resistance,
            'support': support,
        },
    }


def build_eod_day_core(symbol, trade_date, expiry=None):
    all_dates = discover_eod_dates()
    prev_candidates = [day for day in all_dates if day < trade_date]
    previous_day = sorted(prev_candidates)[-1] if prev_candidates else None
    oi_df, oi_path = read_participant_report('participant_oi', trade_date)
    vol_df, vol_path = read_participant_report('participant_vol', trade_date)
    prev_oi_df = pd.DataFrame()
    if previous_day:
        prev_oi_df, _ = read_participant_report('participant_oi', previous_day)
    participants = participant_table(oi_df, vol_df, prev_oi_df)
    big_money = big_money_from_participants(participants)
    strikes = build_eod_strike_activity(symbol, trade_date, expiry=expiry)
    futures = build_eod_future_activity(symbol, trade_date)
    cash = build_eod_cash_footprint(trade_date)
    cm_market = build_cm_market_regime(trade_date)
    view360 = build_eod_360_summary(big_money, strikes, futures, cash, cm_market)

    walls = strikes.get('walls') or {}
    resistance = walls.get('resistance')
    support = walls.get('support')
    decision = 'Wait / Neutral'
    trigger = None
    invalidation = None
    if big_money['direction'] == 'Bearish' and resistance:
        trigger = resistance.get('strike')
        invalidation = support.get('strike') if support else None
        decision = f"Bearish / capped near CE wall {trigger:.0f}"
    elif big_money['direction'] == 'Bullish' and support:
        trigger = support.get('strike')
        invalidation = resistance.get('strike') if resistance else None
        decision = f"Bullish / supported near PE wall {trigger:.0f}"
    elif resistance and support:
        decision = f"Range between {support.get('strike'):.0f} and {resistance.get('strike'):.0f}"

    notes = []
    if big_money.get('fiiDirection') or big_money.get('propDirection'):
        notes.append(f"FII {big_money.get('fiiDirection') or 'NA'} ({big_money.get('fiiScore') if big_money.get('fiiScore') is not None else 0:.1f}), Prop {big_money.get('propDirection') or 'NA'} ({big_money.get('propScore') if big_money.get('propScore') is not None else 0:.1f}).")
    if resistance:
        notes.append(f"Nearest active CE wall: {resistance.get('strike'):.0f} / {resistance.get('build')} / score {resistance.get('activityScore'):.1f}.")
    if support:
        notes.append(f"Nearest active PE wall: {support.get('strike'):.0f} / {support.get('build')} / score {support.get('activityScore'):.1f}.")
    if big_money['direction'] == 'Bearish':
        notes.append('Priority inference: look for market respecting CE walls; failure happens if spot sustains above resistance with fresh CE covering.')
    elif big_money['direction'] == 'Bullish':
        notes.append('Priority inference: look for market respecting PE support; failure happens if spot sustains below support with PE unwinding.')
    else:
        notes.append('Priority inference: no strong FII/Prop alignment; treat strike walls as range levels until live data confirms breakout.')

    return {
        'symbol': symbol,
        'date': trade_date,
        'previousDate': previous_day,
        'participantOiFile': oi_path,
        'participantVolFile': vol_path,
        'participants': participants,
        'bigMoney': big_money,
        'strikes': strikes,
        'futures': futures,
        'cash': cash,
        'cmMarket': cm_market,
        'view360': view360,
        'decision': {
            'text': decision,
            'triggerStrike': trigger,
            'invalidationStrike': invalidation,
            'notes': notes,
        },
    }


def eod_spot_for_date(symbol, trade_date):
    df, _ = read_fo_bhavcopy_for_date(trade_date)
    if df.empty:
        return None
    work = df[(df.get('FinInstrmTp').astype(str).str.upper() == 'IDO') & (df.get('TckrSymb').astype(str).str.upper() == symbol.upper())].copy()
    if work.empty or 'UndrlygPric' not in work.columns:
        return None
    values = pd.to_numeric(work['UndrlygPric'], errors='coerce')
    values = values[values > 0]
    if values.empty:
        return None
    return float(values.median())


def build_eod_memory(symbol, dates):
    rows = []
    asc_dates = sorted(dates)
    for index, day in enumerate(asc_dates[:-1]):
        next_day = asc_dates[index + 1]
        try:
            core = build_eod_day_core(symbol, day)
        except Exception:
            continue
        big = core.get('bigMoney') or {}
        walls = ((core.get('strikes') or {}).get('walls') or {})
        resistance = walls.get('resistance') or {}
        support = walls.get('support') or {}
        signal_spot = (core.get('strikes') or {}).get('spot') or eod_spot_for_date(symbol, day)
        next_spot = eod_spot_for_date(symbol, next_day)
        if signal_spot is None or next_spot is None:
            continue
        direction = big.get('direction', 'Neutral')
        validation = 'NEUTRAL'
        reason = ''
        if direction == 'Bearish':
            wall = resistance.get('strike')
            respected = bool(wall and next_spot <= wall)
            validation = 'RESPECTED' if respected else 'FAILED'
            reason = f"Next close {next_spot:.2f} vs CE wall {wall:.0f}" if wall else 'No CE wall available'
        elif direction == 'Bullish':
            wall = support.get('strike')
            respected = bool(wall and next_spot >= wall)
            validation = 'RESPECTED' if respected else 'FAILED'
            reason = f"Next close {next_spot:.2f} vs PE wall {wall:.0f}" if wall else 'No PE wall available'
        else:
            move_pct = ((next_spot - signal_spot) / signal_spot) * 100 if signal_spot else 0
            validation = 'RANGE OK' if abs(move_pct) <= 0.40 else 'TREND MOVED'
            reason = f"Neutral day; next move {move_pct:+.2f}%"
        rows.append({
            'signalDate': day,
            'nextDate': next_day,
            'symbol': symbol,
            'signalSpot': signal_spot,
            'nextSpot': next_spot,
            'movePts': next_spot - signal_spot,
            'movePct': ((next_spot - signal_spot) / signal_spot) * 100 if signal_spot else None,
            'bigMoneyDirection': direction,
            'bigMoneyScore': big.get('score'),
            'ceWall': resistance.get('strike'),
            'peWall': support.get('strike'),
            'decision': (core.get('decision') or {}).get('text'),
            'validation': validation,
            'reason': reason,
        })
    return rows





def read_db_volume_spurts_for_date(trade_date):
    """Read STD-200 volume-spurt rows directly from PostgreSQL result table."""
    if not trade_date:
        return None
    try:
        with EOD_ANALYTICS_ENGINE.connect() as conn:
            df = pd.read_sql(
                sqlalchemy.text(
                    """
                    SELECT scan_date, timeframe, symbol, close, volume, norm_vol, bubble, updated_at
                    FROM nse_volume_spurt_scan
                    WHERE scan_date = CAST(:trade_date AS DATE)
                    ORDER BY timeframe, norm_vol DESC
                    """
                ),
                conn,
                params={"trade_date": trade_date},
            )
        rows = []
        if not df.empty:
            for _, row in df.iterrows():
                rows.append({
                    "scan_date": str(row.get("scan_date") or trade_date),
                    "date": str(row.get("scan_date") or trade_date),
                    "updatedAt": str(row.get("updated_at") or ""),
                    "timeframe": str(row.get("timeframe") or ""),
                    "symbol": str(row.get("symbol") or ""),
                    "close": to_number(row.get("close")),
                    "volume": to_number(row.get("volume")),
                    "norm_vol": to_number(row.get("norm_vol")),
                    "bubble": str(row.get("bubble") or ""),
                })
        return {
            "summary": {
                "lookback": 200,
                "minNormVol": 6.0,
                "count": len(rows),
                "note": "Daily norm_vol = volume / rolling 200-day standard deviation of volume. Loaded directly from nse_volume_spurt_scan.",
            },
            "rows": rows,
        }
    except Exception:
        return None



def _db_json_value(value):
    """Return dict/list from JSONB/text payload safely."""
    if value is None:
        return None
    if isinstance(value, (dict, list)):
        return value
    try:
        if pd.isna(value):
            return None
    except Exception:
        pass
    if isinstance(value, str):
        try:
            return json.loads(value)
        except Exception:
            return None
    return value


def _read_eod_df(sql, params=None):
    """Read from EOD analytics PostgreSQL DB. Returns empty DataFrame on any DB/schema miss."""
    try:
        with EOD_ANALYTICS_ENGINE.connect() as conn:
            return pd.read_sql(sqlalchemy.text(sql), conn, params=params or {})
    except Exception:
        return pd.DataFrame()


def read_db_eod_available_dates(symbol=None):
    """Return EOD dates available in DB tables, not from local files."""
    symbol = normalize_index_symbol(symbol or 'NIFTY')
    frames = []
    queries = [
        ("SELECT DISTINCT trade_date FROM nse_eod_payload_cache WHERE symbol = :symbol", {"symbol": symbol}),
        ("SELECT DISTINCT trade_date FROM nse_360_decision_daily WHERE symbol = :symbol", {"symbol": symbol}),
        ("SELECT DISTINCT trade_date FROM nse_participant_bias_daily", {}),
        ("SELECT DISTINCT trade_date FROM nse_participant_oi_raw", {}),
    ]
    for sql, params in queries:
        df = _read_eod_df(sql, params)
        if not df.empty and 'trade_date' in df.columns:
            frames.append(df[['trade_date']])
    if not frames:
        return []
    all_dates = pd.concat(frames, ignore_index=True).dropna().drop_duplicates()
    out = []
    for value in all_dates['trade_date'].tolist():
        try:
            out.append(pd.to_datetime(value).strftime('%Y-%m-%d'))
        except Exception:
            pass
    return sorted(set(out), reverse=True)


def read_db_eod_available_expiries(symbol, trade_date):
    """Return expiries available in DB result/cache tables."""
    symbol = normalize_index_symbol(symbol or 'NIFTY')
    if not trade_date:
        return []
    frames = []
    queries = [
        ("SELECT DISTINCT expiry_date FROM nse_eod_payload_cache WHERE symbol = :symbol AND trade_date = CAST(:trade_date AS DATE)", {"symbol": symbol, "trade_date": trade_date}),
        ("SELECT DISTINCT expiry_date FROM nse_360_decision_daily WHERE symbol = :symbol AND trade_date = CAST(:trade_date AS DATE)", {"symbol": symbol, "trade_date": trade_date}),
        ("SELECT DISTINCT expiry_date FROM nse_option_wall_daily WHERE symbol = :symbol AND trade_date = CAST(:trade_date AS DATE)", {"symbol": symbol, "trade_date": trade_date}),
    ]
    for sql, params in queries:
        df = _read_eod_df(sql, params)
        if not df.empty and 'expiry_date' in df.columns:
            frames.append(df[['expiry_date']])
    if not frames:
        return []
    values = []
    for value in pd.concat(frames, ignore_index=True)['expiry_date'].dropna().tolist():
        text = str(value or '').strip()
        if text and text not in values:
            values.append(text)
    return sorted(values, key=expiry_sort_key)


