def _db_big_money_from_participants(rows):
    if not rows:
        return {'score': 0, 'direction': 'Neutral', 'confidence': 'Low', 'note': 'No DB participant rows found'}
    by_participant = {str(row.get('participant') or '').upper(): row for row in rows}
    by_raw = {str(row.get('rawParticipant') or '').upper(): row for row in rows}
    fii = by_participant.get('FII') or by_raw.get('FII')
    prop = by_participant.get('PROP') or by_raw.get('PRO') or by_raw.get('PROP')
    if not fii and not prop:
        return {'score': 0, 'direction': 'Neutral', 'confidence': 'Low', 'note': 'FII/Prop DB rows not available'}
    if fii and prop:
        score = (0.60 * (to_number(fii.get('score')) or 0)) + (0.40 * (to_number(prop.get('score')) or 0))
        aligned = str(fii.get('direction')) == str(prop.get('direction')) and str(fii.get('direction')) != 'Neutral'
    elif fii:
        score = to_number(fii.get('score')) or 0
        aligned = False
    else:
        score = to_number(prop.get('score')) or 0
        aligned = False
    direction = eod_direction(score)
    strength = abs(score)
    confidence = 'High' if aligned and strength >= 15 else ('Medium' if strength >= 8 else 'Low')
    return {
        'score': score,
        'direction': direction,
        'confidence': confidence,
        'fiiScore': to_number(fii.get('score')) if fii else None,
        'propScore': to_number(prop.get('score')) if prop else None,
        'fiiDirection': fii.get('direction') if fii else '',
        'propDirection': prop.get('direction') if prop else '',
        'aligned': aligned,
    }


def _db_decision_row(symbol, trade_date, expiry=None):
    symbol = normalize_index_symbol(symbol or 'NIFTY')
    params = {'symbol': symbol, 'trade_date': trade_date}
    sql = """
        SELECT * FROM nse_360_decision_daily
        WHERE symbol = :symbol AND trade_date = CAST(:trade_date AS DATE)
    """
    if expiry:
        sql += " AND expiry_date = :expiry"
        params['expiry'] = str(expiry)
    sql += " ORDER BY expiry_date LIMIT 1"
    df = _read_eod_df(sql, params)
    if df.empty and expiry:
        return _db_decision_row(symbol, trade_date, expiry=None)
    return df.iloc[0].to_dict() if not df.empty else {}


def _db_option_walls_payload(symbol, trade_date, expiry=None, spot=None):
    """
    Build expiry-wise CE/PE wall payload from processed DB rows.

    Important interpretation fix:
    - A tradable CE resistance wall should normally be at/above spot/ATM.
    - A tradable PE support wall should normally be at/below spot/ATM.
    - Strong ITM PE/CE activity on the wrong side is still shown in top rows,
      but it should not be labelled as support/resistance.
    """
    symbol = normalize_index_symbol(symbol or 'NIFTY')
    spot = to_number(spot)
    params = {'symbol': symbol, 'trade_date': trade_date}
    sql = """
        SELECT * FROM nse_option_wall_daily
        WHERE symbol = :symbol AND trade_date = CAST(:trade_date AS DATE)
    """
    if expiry:
        sql += " AND expiry_date = :expiry"
        params['expiry'] = str(expiry)
    sql += " ORDER BY side, activity_score DESC NULLS LAST, strike"
    df = _read_eod_df(sql, params)
    rows = []
    if not df.empty:
        for _, r in df.iterrows():
            payload = _db_json_value(r.get('payload')) or {}
            item = dict(payload) if isinstance(payload, dict) else {}
            item.update({
                'symbol': symbol,
                'date': str(r.get('trade_date') or trade_date or ''),
                'updatedAt': str(r.get('updated_at') or item.get('updatedAt') or ''),
                'expiry': str(r.get('expiry_date') or item.get('expiry') or expiry or ''),
                'side': str(r.get('side') or item.get('side') or ''),
                'strike': to_number(r.get('strike')),
                'wallKind': str(r.get('wall_kind') or item.get('wallKind') or ''),
                'build': str(r.get('build') or item.get('build') or ''),
                'meaning': str(r.get('meaning') or item.get('meaning') or ''),
                'activityScore': to_number(r.get('activity_score')),
                'oi': to_number(r.get('oi')),
                'coi': to_number(r.get('coi')),
                'volume': to_number(r.get('volume')),
                'close': to_number(r.get('close')),
                'priceChange': to_number(r.get('price_change')),
            })
            rows.append(item)

    def score_key(row):
        return to_number(row.get('activityScore')) or 0

    ce_rows = [r for r in rows if str(r.get('side')).upper() == 'CE']
    pe_rows = [r for r in rows if str(r.get('side')).upper() == 'PE']
    top_ce = sorted(ce_rows, key=score_key, reverse=True)[:12]
    top_pe = sorted(pe_rows, key=score_key, reverse=True)[:12]

    if spot is not None:
        ce_resistance_zone = [r for r in ce_rows if (to_number(r.get('strike')) or -10**18) >= spot]
        pe_support_zone = [r for r in pe_rows if (to_number(r.get('strike')) or 10**18) <= spot]
    else:
        ce_resistance_zone = ce_rows
        pe_support_zone = pe_rows

    def is_true_ce_resistance(row):
        txt = (str(row.get('wallKind') or '') + ' ' + str(row.get('meaning') or '') + ' ' + str(row.get('build') or '')).lower()
        return 'resistance' in txt or 'call writing' in txt or 'short build' in txt

    def is_true_pe_support(row):
        txt = (str(row.get('wallKind') or '') + ' ' + str(row.get('meaning') or '') + ' ' + str(row.get('build') or '')).lower()
        return 'support' in txt or 'put writing' in txt or 'short build' in txt

    resistance_candidates = [r for r in ce_resistance_zone if is_true_ce_resistance(r)] or ce_resistance_zone
    support_candidates = [r for r in pe_support_zone if is_true_pe_support(r)] or pe_support_zone
    resistance = max(resistance_candidates, key=score_key) if resistance_candidates else {}
    support = max(support_candidates, key=score_key) if support_candidates else {}

    dominant_ce_activity = top_ce[0] if top_ce else {}
    dominant_pe_activity = top_pe[0] if top_pe else {}
    selected_expiry = str(expiry or (rows[0].get('expiry') if rows else '') or '')
    return {
        'rows': rows,
        'topCe': top_ce,
        'topPe': top_pe,
        'walls': {
            'resistance': resistance or {},
            'support': support or {},
            'dominantCeActivity': dominant_ce_activity or {},
            'dominantPeActivity': dominant_pe_activity or {},
        },
        'expiry': selected_expiry,
        'availableExpiries': read_db_eod_available_expiries(symbol, trade_date),
        'spot': spot,
    }


