def _db_cash_trade_info_map(trade_date):
    """
    Return symbol -> traded qty / no. of trades from raw cash tables.

    Prefer nse_sec_bhavdata_raw because it aligns with delivery footprint.
    Fallback to nse_cm_bhavcopy_raw.
    """
    if not trade_date:
        return {}

    queries = [
        """
        SELECT symbol, traded_volume, no_of_trades
        FROM nse_sec_bhavdata_raw
        WHERE trade_date = CAST(:trade_date AS DATE)
          AND UPPER(COALESCE(series,'')) = 'EQ'
        """,
        """
        SELECT symbol, traded_volume, no_of_trades
        FROM nse_cm_bhavcopy_raw
        WHERE trade_date = CAST(:trade_date AS DATE)
          AND (series IS NULL OR UPPER(COALESCE(series,'')) IN ('EQ', ''))
        """,
    ]

    out = {}
    for sql in queries:
        df = _read_eod_df(sql, {"trade_date": trade_date})
        if df.empty:
            continue
        for _, r in df.iterrows():
            symbol = str(r.get("symbol") or "").upper().strip()
            if not symbol:
                continue
            traded_qty = to_number(r.get("traded_volume"))
            no_of_trades = to_number(r.get("no_of_trades"))
            tqy_per_trade = (traded_qty / no_of_trades) if traded_qty is not None and no_of_trades not in (None, 0) else None
            out[symbol] = {
                "tradedQty": traded_qty,
                "noOfTrades": no_of_trades,
                "tqyPerTrade": tqy_per_trade,
            }
        if out:
            return out
    return {}


def _db_cash_payload(trade_date):
    df = _read_eod_df(
        """
        SELECT * FROM nse_cash_delivery_footprint_daily
        WHERE trade_date = CAST(:trade_date AS DATE)
        ORDER BY activity_score DESC NULLS LAST LIMIT 60
        """,
        {'trade_date': trade_date},
    )
    rows = []
    for _, r in df.iterrows() if not df.empty else []:
        payload = _db_json_value(r.get('payload')) or {}
        item = dict(payload) if isinstance(payload, dict) else {}
        item.update({
            'date': str(r.get('trade_date') or trade_date or ''),
            'updatedAt': str(r.get('updated_at') or item.get('updatedAt') or ''),
            'symbol': str(r.get('symbol') or item.get('symbol') or ''),
            'signal': str(r.get('signal') or item.get('signal') or ''),
            'pricePct': to_number(r.get('price_pct')),
            'close': to_number(r.get('close')),
            'deliveryPct': to_number(r.get('delivery_pct')),
            'deliveryValueLacs': to_number(r.get('delivery_value_lacs')),
            'turnoverLacs': to_number(r.get('turnover_lacs')),
            'deliveryQty': to_number(r.get('delivery_qty')),
            'deliveryQtyChangePct': to_number(r.get('delivery_qty_change_pct')),
            'volumeChangePct': to_number(r.get('volume_change_pct')),
            'activityScore': to_number(r.get('activity_score')),
        })
        rows.append(item)
    # V11.8.12: enrich cash rows with traded quantity / no. of trades so
    # TQY/No. Trades is visible in CashBhavCopy/Cash Delivery section.
    trade_info = _db_cash_trade_info_map(trade_date)
    if trade_info:
        for item in rows:
            info = trade_info.get(str(item.get('symbol') or '').upper().strip())
            if not info:
                continue
            item['tradedQty'] = info.get('tradedQty')
            item['noOfTrades'] = info.get('noOfTrades')
            item['tqyPerTrade'] = info.get('tqyPerTrade')

    accumulation = [r for r in rows if 'accumulation' in str(r.get('signal')).lower() or 'buying' in str(r.get('signal')).lower()]
    distribution = [r for r in rows if 'distribution' in str(r.get('signal')).lower() or 'selling' in str(r.get('signal')).lower() or 'pressure' in str(r.get('signal')).lower()]
    no_acceptance = [r for r in rows if 'no price acceptance' in str(r.get('signal')).lower()]
    up_value = sum((to_number(r.get('deliveryValueLacs')) or 0) for r in rows if (to_number(r.get('pricePct')) or 0) > 0)
    down_value = sum((to_number(r.get('deliveryValueLacs')) or 0) for r in rows if (to_number(r.get('pricePct')) or 0) < 0)
    cash_bias_score = ((up_value - down_value) / (up_value + down_value) * 100) if (up_value + down_value) else 0
    return {
        'error': '' if rows else 'No DB cash delivery footprint rows found.',
        'sourceKind': 'db:nse_cash_delivery_footprint_daily',
        'summary': {
            'cashDirection': eod_direction(cash_bias_score),
            'cashBiasScore': cash_bias_score,
            'upDeliveryValueLacs': up_value,
            'downDeliveryValueLacs': down_value,
            'totalDeliveryValueLacs': up_value + down_value,
        },
        'rows': rows,
        'topRows': rows[:30],
        'accumulation': accumulation[:12],
        'distribution': distribution[:12],
        'noAcceptance': no_acceptance[:12],
    }


