def build_eod_participation_payload_from_db(symbol, trade_date=None, expiry=None):
    """Build the EOD Participation payload directly from PostgreSQL result tables."""
    symbol = normalize_index_symbol(symbol or 'NIFTY')
    available_dates = read_db_eod_available_dates(symbol)
    if not available_dates:
        return None
    if not trade_date or trade_date not in available_dates:
        trade_date = available_dates[0]
    available_expiries = read_db_eod_available_expiries(symbol, trade_date)
    if expiry and str(expiry) in available_expiries:
        selected_expiry = str(expiry)
    elif available_expiries:
        selected_expiry = available_expiries[0]
    else:
        selected_expiry = str(expiry or '')

    decision_row = _db_decision_row(symbol, trade_date, selected_expiry)
    if decision_row and not selected_expiry:
        selected_expiry = str(decision_row.get('expiry_date') or '')
    participants = _db_participants_payload(trade_date)
    big_money = _db_big_money_from_participants(participants)
    spot = to_number(decision_row.get('spot_close')) if decision_row else None
    strikes = _db_option_walls_payload(symbol, trade_date, selected_expiry, spot=spot)
    futures = _db_futures_payload(symbol, trade_date)
    cash = _db_cash_payload(trade_date)
    cm_market = _db_cm_market_payload(trade_date)
    volume_spurts = read_db_volume_spurts_for_date(trade_date) or {}
    memory = _db_memory_payload(symbol, trade_date)

    resistance = (strikes.get('walls') or {}).get('resistance') or {}
    support = (strikes.get('walls') or {}).get('support') or {}
    if spot is None:
        spot = to_number(strikes.get('spot'))

    view360 = {
        'verdict': str(decision_row.get('final_360_bias') or 'DB Result') if decision_row else 'DB Result',
        'score': to_number(decision_row.get('confidence_score')) if decision_row else None,
        'participantDirection': str(decision_row.get('big_money_direction') or big_money.get('direction') or 'Neutral') if decision_row else big_money.get('direction', 'Neutral'),
        'futureDirection': str(decision_row.get('future_direction') or ((futures.get('summary') or {}).get('direction')) or 'Neutral') if decision_row else ((futures.get('summary') or {}).get('direction') or 'Neutral'),
        'cashDirection': str(decision_row.get('cash_direction') or ((cash.get('summary') or {}).get('cashDirection')) or 'Neutral') if decision_row else ((cash.get('summary') or {}).get('cashDirection') or 'Neutral'),
        'cmRegime': str(decision_row.get('cm_regime') or ((cm_market.get('summary') or {}).get('regime')) or '') if decision_row else ((cm_market.get('summary') or {}).get('regime') or ''),
        'notes': [
            'Loaded directly from PostgreSQL EOD result tables.',
            f"Big Money: {big_money.get('direction', 'Neutral')} score {big_money.get('score', 0):.2f}.",
            f"CE wall: {resistance.get('strike') or 'NA'}; PE wall: {support.get('strike') or 'NA'}.",
        ],
    }
    decision = {
        'text': str(decision_row.get('decision_text') or '') if decision_row else '',
        'finalBias': str(decision_row.get('final_360_bias') or '') if decision_row else '',
        'confidenceScore': to_number(decision_row.get('confidence_score')) if decision_row else None,
    }

    return {
        'symbol': symbol,
        'date': trade_date,
        'availableDates': available_dates,
        'availableExpiries': available_expiries,
        'expiry': selected_expiry,
        'generatedAt': datetime.now(IST).strftime('%d-%b-%Y %H:%M:%S'),
        'loadedFromDbTables': True,
        'source': 'PostgreSQL result tables',
        'error': '',
        'participants': participants,
        'bigMoney': big_money,
        'decision': decision,
        'spot': spot,
        'strikeRows': strikes.get('rows') or [],
        'topCe': strikes.get('topCe') or [],
        'topPe': strikes.get('topPe') or [],
        'walls': strikes.get('walls') or {},
        'futures': futures,
        'cash': cash,
        'cmMarket': cm_market,
        'view360': view360,
        'volumeSpurts': volume_spurts,
        'memory': memory,
        'memoryUpdatedAt': (memory[0].get('updatedAt') if memory else ''),
        'updatedAt': datetime.now(IST).strftime('%d-%b-%Y %H:%M:%S'),
        'disclaimer': 'Loaded directly from PostgreSQL EOD result tables. Participant OI/volume remains participant-wise, not strike-wise; strike player labels are probabilistic.',
    }

def read_eod_cached_payload(symbol, trade_date=None, expiry=None):
    """
    Read precomputed EOD payload from PostgreSQL cache.

    V11.2 fix:
    - Do not use stale blank-expiry cache when the user selected an expiry.
    - Prefer non-blank expiry cache rows.
    - Reject incomplete cache rows so dashboard can fall through to normalized DB result tables.
    """
    symbol = normalize_index_symbol(symbol or 'NIFTY')
    try:
        with EOD_ANALYTICS_ENGINE.connect() as conn:
            dates_df = pd.read_sql(
                sqlalchemy.text(
                    "SELECT DISTINCT trade_date FROM nse_eod_payload_cache "
                    "WHERE symbol = :symbol ORDER BY trade_date DESC"
                ),
                conn,
                params={"symbol": symbol},
            )
            if dates_df.empty:
                return None
            available_dates = [pd.to_datetime(x).strftime('%Y-%m-%d') for x in dates_df['trade_date'].tolist()]
            if not trade_date or trade_date not in available_dates:
                trade_date = available_dates[0]

            exp_df = pd.read_sql(
                sqlalchemy.text(
                    "SELECT expiry_date FROM nse_eod_payload_cache "
                    "WHERE symbol = :symbol AND trade_date = CAST(:trade_date AS DATE) "
                    "ORDER BY CASE WHEN COALESCE(expiry_date,'') = '' THEN 1 ELSE 0 END, expiry_date"
                ),
                conn,
                params={"symbol": symbol, "trade_date": trade_date},
            )
            expiries = [str(x or '') for x in exp_df['expiry_date'].tolist()] if not exp_df.empty else []
            selected_expiry = str(expiry or '').strip()

            # Important: if user selected an expiry but only blank cache exists, do not use it.
            # This was causing EOD tab to show blank expiry and empty participant rows.
            if selected_expiry:
                if selected_expiry not in expiries:
                    return None
            else:
                non_blank = [x for x in expiries if x]
                selected_expiry = non_blank[0] if non_blank else (expiries[0] if expiries else '')

            payload_df = pd.read_sql(
                sqlalchemy.text(
                    "SELECT payload, updated_at FROM nse_eod_payload_cache "
                    "WHERE symbol = :symbol AND trade_date = CAST(:trade_date AS DATE) "
                    "AND expiry_date = :expiry_date LIMIT 1"
                ),
                conn,
                params={"symbol": symbol, "trade_date": trade_date, "expiry_date": selected_expiry},
            )
            if payload_df.empty:
                return None
            payload = payload_df.iloc[0]['payload']
            if isinstance(payload, str):
                payload = json.loads(payload)
            if not isinstance(payload, dict):
                return None

            has_participants = bool(payload.get('participants'))
            has_walls = bool((payload.get('walls') or {}).get('resistance') or (payload.get('walls') or {}).get('support'))
            has_rows = bool(payload.get('topCe') or payload.get('topPe') or payload.get('strikeRows'))
            has_decision = bool((payload.get('decision') or {}).get('text') or (payload.get('view360') or {}).get('verdict'))
            if not (has_participants or has_walls or has_rows or has_decision):
                return None

            payload['availableDates'] = available_dates
            payload['availableExpiries'] = [x for x in expiries if x] or expiries or []
            payload['date'] = trade_date
            payload['symbol'] = symbol
            payload['expiry'] = selected_expiry or payload.get('expiry') or ''
            payload['loadedFromDbCache'] = True
            payload['dbCacheUpdatedAt'] = str(payload_df.iloc[0].get('updated_at', ''))
            db_volume_spurts = read_db_volume_spurts_for_date(trade_date)
            if db_volume_spurts is not None:
                payload['volumeSpurts'] = db_volume_spurts

            # V11.8.8: keep memory validation fresh even when the main EOD payload
            # comes from nse_eod_payload_cache. The cache can be valid for the EOD
            # section but stale for memory validation after new sessions are imported.
            fresh_memory = _db_memory_payload(symbol, trade_date)
            if fresh_memory:
                payload['memory'] = fresh_memory
                payload['memoryRefreshedFromDb'] = True
                payload['memoryUpdatedAt'] = fresh_memory[0].get('updatedAt') or ''

            payload['updatedAt'] = payload.get('updatedAt') or payload.get('dbCacheUpdatedAt') or ''
            payload['disclaimer'] = (payload.get('disclaimer') or '') + ' | Loaded from PostgreSQL cache; memory/volume freshness checked from DB.'
            return payload
    except Exception:
        return None

def build_eod_participation_payload(symbol, trade_date=None, expiry=None):
    """DB-first EOD Participation payload.

    Order:
      1) nse_eod_payload_cache
      2) normalized PostgreSQL result tables
      3) optional file fallback only if ALLOW_EOD_FILE_FALLBACK=True

    The default is DB-only, so the dashboard will not keep searching the old
    nse_eod_reports folder once EOD data has been imported to PostgreSQL.
    """
    symbol = normalize_index_symbol(symbol or 'NIFTY')
    if symbol not in EOD_INDEX_SYMBOLS:
        symbol = 'NIFTY'

    cached_payload = read_eod_cached_payload(symbol, trade_date=trade_date, expiry=expiry)
    if cached_payload is not None:
        cached_payload['loadedFromDbCache'] = True
        cached_payload['source'] = cached_payload.get('source') or 'PostgreSQL payload cache'
        return cached_payload

    db_payload = build_eod_participation_payload_from_db(symbol, trade_date=trade_date, expiry=expiry)
    if db_payload is not None:
        return db_payload

    # Emergency old behavior. Kept disabled by default because EOD is now DB-backed.
    if globals().get('ALLOW_EOD_FILE_FALLBACK', False):
        dates = discover_eod_dates()
        if not dates:
            return {
                'symbol': symbol,
                'date': trade_date,
                'availableDates': [],
                'availableExpiries': [],
                'error': f'No DB EOD data found and file fallback found no EOD files inside {EOD_REPORTS_DIR}.',
            }
        if not trade_date or trade_date not in dates:
            trade_date = dates[0]
        core = build_eod_day_core(symbol, trade_date, expiry=expiry)
        available_expiries = (core.get('strikes') or {}).get('availableExpiries') or eod_available_expiries(symbol, trade_date)
        db_volume_spurts = read_db_volume_spurts_for_date(trade_date)
        return {
            'symbol': symbol,
            'date': trade_date,
            'availableDates': dates,
            'availableExpiries': available_expiries,
            'expiry': ((core.get('strikes') or {}).get('expiry') or expiry or ''),
            'generatedAt': datetime.now(IST).strftime('%d-%b-%Y %H:%M:%S'),
            'searchDirs': [str(path) for path in eod_search_dirs()],
            'error': (core.get('strikes') or {}).get('error') or '',
            'participantOiFile': core.get('participantOiFile'),
            'participantVolFile': core.get('participantVolFile'),
            'participants': core.get('participants') or [],
            'bigMoney': core.get('bigMoney') or {},
            'decision': core.get('decision') or {},
            'spot': (core.get('strikes') or {}).get('spot'),
            'previousDate': core.get('previousDate'),
            'strikeRows': (core.get('strikes') or {}).get('rows') or [],
            'topCe': (core.get('strikes') or {}).get('topCe') or [],
            'topPe': (core.get('strikes') or {}).get('topPe') or [],
            'walls': (core.get('strikes') or {}).get('walls') or {},
            'futures': core.get('futures') or {},
            'cash': core.get('cash') or {},
            'cmMarket': core.get('cmMarket') or {},
            'view360': core.get('view360') or {},
            'volumeSpurts': db_volume_spurts or {},
            'memory': build_eod_memory(symbol, dates),
            'loadedFromFileFallback': True,
            'disclaimer': 'Loaded through emergency file fallback. Import EOD data to DB/cache for normal operation.',
        }

    available_dates = read_db_eod_available_dates(symbol)
    return {
        'symbol': symbol,
        'date': trade_date,
        'availableDates': available_dates,
        'availableExpiries': read_db_eod_available_expiries(symbol, trade_date) if trade_date else [],
        'error': 'No EOD payload cache or PostgreSQL EOD result rows found. Run the EOD import/process script for this date first.',
        'loadedFromDbTables': False,
        'fileFallbackDisabled': True,
    }

# ============================== LIVE FII/PROP STRIKE DECODER ==============================

def _decoder_direction_score(direction):
    text = str(direction or "").strip().lower()
    if text == "bullish":
        return 1
    if text == "bearish":
        return -1
    return 0


def _safe_abs_pct(value, scale):
    value = to_number(value) or 0
    scale = to_number(scale) or 0
    if scale <= 0:
        return 0
    return min(100.0, abs(value) / scale * 100.0)


INDEX_LOT_SIZE_FALLBACK = {
    "NIFTY": 65,
    "BANKNIFTY": 30,
    "FINNIFTY": 65,
    "MIDCPNIFTY": 120,
}


def _lot_size_for_symbol(symbol):
    return int(INDEX_LOT_SIZE_FALLBACK.get(normalize_index_symbol(symbol or "NIFTY"), 65))


def _row_lot_size(row, lot_col=None, symbol="NIFTY"):
    if row is not None and lot_col:
        lot_size = to_number(row.get(lot_col))
        if lot_size is not None and lot_size > 0:
            return int(lot_size)
    return _lot_size_for_symbol(symbol)


def _coi_volume_lot_score(coi_value, volume_value, lot_size):
    volume = abs(to_number(volume_value) or 0)
    if volume <= 0:
        return None
    return abs(to_number(coi_value) or 0) / volume


def _signed_coi_volume_lot_ratio(coi_value, volume_value, lot_size):
    volume = abs(to_number(volume_value) or 0)
    if volume <= 0:
        return None
    return (to_number(coi_value) or 0) / volume


def _side_live_signal(side, oi_delta, volume_delta, ltp_delta, iv_delta):
    side = str(side or "").upper()
    oi_delta = to_number(oi_delta) or 0
    volume_delta = to_number(volume_delta) or 0
    ltp_delta = to_number(ltp_delta) or 0
    iv_delta = to_number(iv_delta) or 0

    # Core strike tape logic:
    # OI up + premium/IV up = buyer is accepting higher premium.
    # OI up + premium/IV down = writer is absorbing/controlling premium.
    # OI down + premium/IV up = shorts are being forced to cover.
    # OI down + premium/IV down = longs are exiting/decaying.
    premium_up = ltp_delta > 0
    premium_down = ltp_delta < 0
    iv_up = iv_delta > 0
    iv_down = iv_delta < 0

    if oi_delta > 0 and premium_up and (iv_up or iv_delta == 0):
        return f"{side} Buying", "buying"
    if oi_delta > 0 and premium_up and iv_down:
        return f"{side} Buying / IV Divergence", "buying"
    if oi_delta > 0 and (premium_down or ltp_delta == 0) and (iv_down or iv_delta == 0):
        return f"{side} Writing", "writing"
    if oi_delta > 0 and (premium_down or ltp_delta == 0) and iv_up:
        return f"{side} Writing / IV Alert", "writing"
    if oi_delta < 0 and (premium_up or iv_up):
        return f"{side} Short Covering", "short_covering"
    if oi_delta < 0 and (premium_down or ltp_delta == 0) and not iv_up:
        return f"{side} Long Unwinding", "long_unwinding"
    if volume_delta > 0 and (abs(ltp_delta) > 0 or abs(iv_delta) > 0):
        return f"{side} Volume / IV Watch", "volume_watch"
    return "Neutral", "neutral"


def _signal_market_bias(side, action):
    """Return +1 bullish, -1 bearish, 0 neutral for a live side/action."""
    side = str(side or "").upper()
    action = str(action or "").lower()
    if side == "CE" and action in {"buying", "short_covering"}:
        return 1
    if side == "CE" and action in {"writing", "long_unwinding"}:
        return -1
    if side == "PE" and action in {"writing", "long_unwinding"}:
        return 1
    if side == "PE" and action in {"buying", "short_covering"}:
        return -1
    return 0


def _player_probability(fii_dir, prop_dir, signal_bias, live_burst_score, eod_weight=0.0):
    fii_score = _decoder_direction_score(fii_dir)
    prop_score = _decoder_direction_score(prop_dir)
    fii_match = fii_score != 0 and signal_bias == fii_score
    prop_match = prop_score != 0 and signal_bias == prop_score

    if fii_match and prop_match:
        player = "FII + Prop aligned"
        player_score = 28
    elif fii_match:
        player = "FII aligned"
        player_score = 22
    elif prop_match:
        player = "Prop aligned"
        player_score = 20
    elif live_burst_score >= 55:
        player = "Prop-like intraday burst"
        player_score = 12
    else:
        player = "Market-wide / Unclear"
        player_score = 0

    return player, player_score


def _get_eod_bias_for_decoder(symbol, trade_date=None, expiry=None):
    """Use EOD cache/payload to get participant bias. Falls back to latest prior EOD date."""
    tried = []
    for candidate in [trade_date]:
        if candidate:
            tried.append(candidate)
    try:
        eod_dates = []
        cached = read_eod_cached_payload(symbol, trade_date=trade_date, expiry=expiry)
        if cached and cached.get("availableDates"):
            eod_dates = cached.get("availableDates") or []
        else:
            eod_dates = discover_eod_dates()
        if trade_date:
            prior = [d for d in eod_dates if str(d) <= str(trade_date)]
            prior = sorted(set(prior), reverse=True)
            for d in prior[:3]:
                if d not in tried:
                    tried.append(d)
        elif eod_dates:
            tried.append(sorted(eod_dates, reverse=True)[0])
    except Exception:
        pass

    for d in tried:
        try:
            payload = build_eod_participation_payload(symbol, trade_date=d, expiry=expiry)
            parts = payload.get("participants") or []
            if parts:
                by_raw = {r.get("rawParticipant"): r for r in parts}
                fii = by_raw.get("FII") or {}
                prop = by_raw.get("Pro") or by_raw.get("PROP") or {}
                return {
                    "date": payload.get("date") or d,
                    "expiry": payload.get("expiry") or expiry or "",
                    "fiiDirection": fii.get("direction") or "Neutral",
                    "fiiScore": fii.get("score"),
                    "propDirection": prop.get("direction") or "Neutral",
                    "propScore": prop.get("score"),
                    "bigMoney": payload.get("bigMoney") or {},
                    "note": "EOD participant files are participant-wise, not strike-wise. Strike player label is probabilistic.",
                }
        except Exception:
            continue

    return {
        "date": trade_date or "",
        "expiry": expiry or "",
        "fiiDirection": "Neutral",
        "fiiScore": None,
        "propDirection": "Neutral",
        "propScore": None,
        "bigMoney": {"direction": "Neutral", "score": 0},
        "note": "EOD participant bias not available; decoder uses only live strike behaviour.",
    }


_LIVE_PLAYER_MEMORY_TABLES_READY = False


def ensure_live_player_memory_tables():
    """Create DB tables used by the live player decoder memory engine."""
    global _LIVE_PLAYER_MEMORY_TABLES_READY
    if _LIVE_PLAYER_MEMORY_TABLES_READY:
        return
    ddl_statements = [
        """
        CREATE TABLE IF NOT EXISTS live_player_signal_log (
            id bigserial PRIMARY KEY,
            signal_ts_text text NOT NULL,
            trade_date date,
            symbol text NOT NULL,
            expiry_date text NOT NULL,
            strike numeric NOT NULL,
            side text NOT NULL,
            signal_type text,
            action text,
            market_bias text,
            probable_player text,
            confidence numeric,
            repeat_count integer,
            repeat_status text,
            live_burst_score numeric,
            oi_delta numeric,
            volume_delta numeric,
            ltp numeric,
            ltp_delta numeric,
            iv numeric,
            iv_delta numeric,
            spot numeric,
            future_price numeric,
            future_price_roc numeric,
            future_oi_roc numeric,
            message text,
            payload jsonb,
            created_at timestamp DEFAULT now(),
            UNIQUE(signal_ts_text, symbol, expiry_date, strike, side, action)
        );
        """,
        """
        CREATE INDEX IF NOT EXISTS idx_live_player_signal_log_lookup
        ON live_player_signal_log(symbol, expiry_date, strike, side, signal_ts_text);
        """,
        """
        CREATE TABLE IF NOT EXISTS live_player_strike_memory (
            symbol text NOT NULL,
            expiry_date text NOT NULL,
            strike numeric NOT NULL,
            side text NOT NULL,
            first_trade_date date,
            latest_trade_date date,
            first_seen_text text,
            last_seen_text text,
            dominant_signal text,
            dominant_action text,
            market_bias text,
            probable_player text,
            signal_count integer DEFAULT 0,
            strong_signal_count integer DEFAULT 0,
            latest_confidence numeric,
            avg_confidence numeric,
            max_confidence numeric,
            total_oi_delta numeric DEFAULT 0,
            total_abs_oi_delta numeric DEFAULT 0,
            total_volume_delta numeric DEFAULT 0,
            spot_min numeric,
            spot_max numeric,
            last_spot numeric,
            last_ltp numeric,
            last_iv numeric,
            premium_control_score numeric DEFAULT 0,
            iv_confirmation_score numeric DEFAULT 0,
            futures_confirmation_score numeric DEFAULT 0,
            memory_status text,
            remarks text,
            payload jsonb,
            updated_at timestamp DEFAULT now(),
            PRIMARY KEY(symbol, expiry_date, strike, side)
        );
        """,
        """
        CREATE INDEX IF NOT EXISTS idx_live_player_strike_memory_expiry
        ON live_player_strike_memory(symbol, expiry_date, memory_status, max_confidence DESC);
        """,
        """
        CREATE TABLE IF NOT EXISTS live_player_reversal_log (
            id bigserial PRIMARY KEY,
            signal_ts_text text NOT NULL,
            trade_date date,
            symbol text NOT NULL,
            expiry_date text NOT NULL,
            strike numeric NOT NULL,
            side text NOT NULL,
            old_action text,
            new_action text,
            reversal_type text,
            confidence numeric,
            message text,
            payload jsonb,
            created_at timestamp DEFAULT now(),
            UNIQUE(signal_ts_text, symbol, expiry_date, strike, side, reversal_type)
        );
        """,
    ]
    with ENGINE.begin() as conn:
        for stmt in ddl_statements:
            conn.execute(sqlalchemy.text(stmt))
    _LIVE_PLAYER_MEMORY_TABLES_READY = True


def _memory_status_from_counts(signal_count, strong_count, repeat_status, reversal_type=None):
    if reversal_type:
        if "trap" in str(reversal_type).lower() or "broken" in str(reversal_type).lower():
            return "Trap / Broken"
        return "Weakening / Reversal Watch"
    try:
        signal_count = int(signal_count or 0)
        strong_count = int(strong_count or 0)
    except Exception:
        signal_count, strong_count = 0, 0
    repeat_status = str(repeat_status or "")
    if signal_count >= 8 or strong_count >= 3:
        return "Accumulated"
    if repeat_status == "Strong Confirmed" or signal_count >= 4:
        return "Defending / Strong Building"
    if repeat_status == "Confirmed" or signal_count >= 2:
        return "Building"
    return "Fresh Spike"


def _detect_memory_reversal(old_action, new_action, side, market_bias):
    old_action = str(old_action or "").lower()
    new_action = str(new_action or "").lower()
    side = str(side or "").upper()
    if not old_action or old_action == new_action:
        return ""
    if old_action == "writing" and new_action in {"short_covering", "buying"}:
        return "Writer Trap / Zone Broken"
    if old_action == "buying" and new_action in {"long_unwinding", "writing"}:
        return "Buyer Exhaustion / Unwind"
    if old_action == "short_covering" and new_action == "writing":
        return "Re-writing After Covering"
    if old_action == "long_unwinding" and new_action == "buying":
        return "Fresh Buying After Unwind"
    return "Action Changed"


def _row_to_float(value):
    number = to_number(value)
    return None if number is None else float(number)


def persist_live_player_memory(symbol, trade_date, expiry, latest_ts, spot, futures, rows):
    """
    Persist high-confidence decoder rows into DB and maintain expiry-wide memory.

    This intentionally writes only once per timestamp/strike/side/action, so refreshing
    the dashboard at the same timestamp will not inflate memory counts.
    """
    summary = {"enabled": False, "insertedSignals": 0, "reversals": 0, "error": ""}
    if not rows:
        return summary
    try:
        ensure_live_player_memory_tables()
    except Exception as exc:
        summary["error"] = f"memory table init failed: {type(exc).__name__}: {exc}"
        return summary

    future_price = (futures or {}).get("futurePrice")
    future_price_roc = (futures or {}).get("futurePriceRoc")
    future_oi_roc = (futures or {}).get("futureOiRoc")
    inserted = 0
    reversals = 0

    with ENGINE.begin() as conn:
        for row in rows:
            try:
                strike = _row_to_float(row.get("strike"))
                side = str(row.get("side") or "").upper()
                action = str(row.get("action") or "")
                if strike is None or side not in {"CE", "PE"} or action in {"", "neutral", "volume_watch"}:
                    continue
                payload_json = json.dumps(json_safe(row), default=str)
                log_insert = conn.execute(sqlalchemy.text("""
                    INSERT INTO live_player_signal_log
                    (signal_ts_text, trade_date, symbol, expiry_date, strike, side, signal_type, action,
                     market_bias, probable_player, confidence, repeat_count, repeat_status, live_burst_score,
                     oi_delta, volume_delta, ltp, ltp_delta, iv, iv_delta, spot, future_price,
                     future_price_roc, future_oi_roc, message, payload)
                    VALUES
                    (:signal_ts_text, CAST(:trade_date AS date), :symbol, :expiry_date, :strike, :side, :signal_type, :action,
                     :market_bias, :probable_player, :confidence, :repeat_count, :repeat_status, :live_burst_score,
                     :oi_delta, :volume_delta, :ltp, :ltp_delta, :iv, :iv_delta, :spot, :future_price,
                     :future_price_roc, :future_oi_roc, :message, CAST(:payload AS jsonb))
                    ON CONFLICT(signal_ts_text, symbol, expiry_date, strike, side, action) DO NOTHING
                    RETURNING id
                """), {
                    "signal_ts_text": str(latest_ts or ""),
                    "trade_date": signal_trade_date,
                    "symbol": symbol,
                    "expiry_date": str(expiry or ""),
                    "strike": strike,
                    "side": side,
                    "signal_type": row.get("signal"),
                    "action": action,
                    "market_bias": row.get("marketBias"),
                    "probable_player": row.get("probablePlayer"),
                    "confidence": _row_to_float(row.get("confidence")),
                    "repeat_count": int(row.get("repeatCount") or 0),
                    "repeat_status": row.get("repeatStatus"),
                    "live_burst_score": _row_to_float(row.get("liveBurstScore")),
                    "oi_delta": _row_to_float(row.get("oiDelta")),
                    "volume_delta": _row_to_float(row.get("volumeDelta")),
                    "ltp": _row_to_float(row.get("ltp")),
                    "ltp_delta": _row_to_float(row.get("ltpDelta")),
                    "iv": _row_to_float(row.get("iv")),
                    "iv_delta": _row_to_float(row.get("ivDelta")),
                    "spot": _row_to_float(spot),
                    "future_price": _row_to_float(future_price),
                    "future_price_roc": _row_to_float(future_price_roc),
                    "future_oi_roc": _row_to_float(future_oi_roc),
                    "message": row.get("message"),
                    "payload": payload_json,
                }).scalar()
                if not log_insert:
                    continue
                inserted += 1

                old = conn.execute(sqlalchemy.text("""
                    SELECT dominant_action, memory_status, signal_count
                    FROM live_player_strike_memory
                    WHERE symbol=:symbol AND expiry_date=:expiry_date AND strike=:strike AND side=:side
                """), {"symbol": symbol, "expiry_date": str(expiry or ""), "strike": strike, "side": side}).mappings().first()
                reversal_type = _detect_memory_reversal((old or {}).get("dominant_action"), action, side, row.get("marketBias"))
                next_count = int((old or {}).get("signal_count") or 0) + 1
                strong_inc = 1 if str(row.get("repeatStatus") or "") == "Strong Confirmed" or (_row_to_float(row.get("confidence")) or 0) >= 75 else 0
                # Use current repeat status + existing count for status. If a reversal is detected, mark it immediately.
                mem_status = _memory_status_from_counts(next_count, strong_inc, row.get("repeatStatus"), reversal_type)
                remarks = row.get("message") or ""
                if reversal_type:
                    remarks = f"{reversal_type}: {remarks}"

                conn.execute(sqlalchemy.text("""
                    INSERT INTO live_player_strike_memory
                    (symbol, expiry_date, strike, side, first_trade_date, latest_trade_date, first_seen_text, last_seen_text,
                     dominant_signal, dominant_action, market_bias, probable_player, signal_count, strong_signal_count,
                     latest_confidence, avg_confidence, max_confidence, total_oi_delta, total_abs_oi_delta, total_volume_delta,
                     spot_min, spot_max, last_spot, last_ltp, last_iv, premium_control_score, iv_confirmation_score,
                     futures_confirmation_score, memory_status, remarks, payload)
                    VALUES
                    (:symbol, :expiry_date, :strike, :side, CAST(:trade_date AS date), CAST(:trade_date AS date), :ts, :ts,
                     :dominant_signal, :dominant_action, :market_bias, :probable_player, 1, :strong_signal_count,
                     :confidence, :confidence, :confidence, :oi_delta, ABS(:oi_delta), :volume_delta,
                     :spot, :spot, :spot, :ltp, :iv, :premium_control_score, :iv_confirmation_score,
                     :futures_confirmation_score, :memory_status, :remarks, CAST(:payload AS jsonb))
                    ON CONFLICT(symbol, expiry_date, strike, side) DO UPDATE SET
                     latest_trade_date=EXCLUDED.latest_trade_date,
                     last_seen_text=EXCLUDED.last_seen_text,
                     dominant_signal=EXCLUDED.dominant_signal,
                     dominant_action=EXCLUDED.dominant_action,
                     market_bias=EXCLUDED.market_bias,
                     probable_player=EXCLUDED.probable_player,
                     signal_count=live_player_strike_memory.signal_count + 1,
                     strong_signal_count=live_player_strike_memory.strong_signal_count + EXCLUDED.strong_signal_count,
                     latest_confidence=EXCLUDED.latest_confidence,
                     avg_confidence=((COALESCE(live_player_strike_memory.avg_confidence,0) * GREATEST(live_player_strike_memory.signal_count,1)) + EXCLUDED.latest_confidence) / (live_player_strike_memory.signal_count + 1),
                     max_confidence=GREATEST(COALESCE(live_player_strike_memory.max_confidence,0), COALESCE(EXCLUDED.max_confidence,0)),
                     total_oi_delta=COALESCE(live_player_strike_memory.total_oi_delta,0) + COALESCE(EXCLUDED.total_oi_delta,0),
                     total_abs_oi_delta=COALESCE(live_player_strike_memory.total_abs_oi_delta,0) + COALESCE(EXCLUDED.total_abs_oi_delta,0),
                     total_volume_delta=COALESCE(live_player_strike_memory.total_volume_delta,0) + COALESCE(EXCLUDED.total_volume_delta,0),
                     spot_min=LEAST(COALESCE(live_player_strike_memory.spot_min, EXCLUDED.spot_min), COALESCE(EXCLUDED.spot_min, live_player_strike_memory.spot_min)),
                     spot_max=GREATEST(COALESCE(live_player_strike_memory.spot_max, EXCLUDED.spot_max), COALESCE(EXCLUDED.spot_max, live_player_strike_memory.spot_max)),
                     last_spot=EXCLUDED.last_spot,
                     last_ltp=EXCLUDED.last_ltp,
                     last_iv=EXCLUDED.last_iv,
                     premium_control_score=COALESCE(live_player_strike_memory.premium_control_score,0) + COALESCE(EXCLUDED.premium_control_score,0),
                     iv_confirmation_score=COALESCE(live_player_strike_memory.iv_confirmation_score,0) + COALESCE(EXCLUDED.iv_confirmation_score,0),
                     futures_confirmation_score=COALESCE(live_player_strike_memory.futures_confirmation_score,0) + COALESCE(EXCLUDED.futures_confirmation_score,0),
                     memory_status=EXCLUDED.memory_status,
                     remarks=EXCLUDED.remarks,
                     payload=EXCLUDED.payload,
                     updated_at=now()
                """), {
                    "symbol": symbol,
                    "expiry_date": str(expiry or ""),
                    "strike": strike,
                    "side": side,
                    "trade_date": trade_date,
                    "ts": str(latest_ts or ""),
                    "dominant_signal": row.get("signal"),
                    "dominant_action": action,
                    "market_bias": row.get("marketBias"),
                    "probable_player": row.get("probablePlayer"),
                    "strong_signal_count": strong_inc,
                    "confidence": _row_to_float(row.get("confidence")) or 0,
                    "oi_delta": _row_to_float(row.get("oiDelta")) or 0,
                    "volume_delta": _row_to_float(row.get("volumeDelta")) or 0,
                    "spot": _row_to_float(spot),
                    "ltp": _row_to_float(row.get("ltp")),
                    "iv": _row_to_float(row.get("iv")),
                    "premium_control_score": min(10.0, abs(_row_to_float(row.get("ltpDelta")) or 0)),
                    "iv_confirmation_score": min(10.0, abs(_row_to_float(row.get("ivDelta")) or 0)),
                    "futures_confirmation_score": min(10.0, abs(_row_to_float(future_price_roc) or 0) + abs(_row_to_float(future_oi_roc) or 0)),
                    "memory_status": mem_status,
                    "remarks": remarks,
                    "payload": payload_json,
                })

                if reversal_type:
                    reversals += 1
                    conn.execute(sqlalchemy.text("""
                        INSERT INTO live_player_reversal_log
                        (signal_ts_text, trade_date, symbol, expiry_date, strike, side, old_action, new_action,
                         reversal_type, confidence, message, payload)
                        VALUES
                        (:signal_ts_text, CAST(:trade_date AS date), :symbol, :expiry_date, :strike, :side, :old_action, :new_action,
                         :reversal_type, :confidence, :message, CAST(:payload AS jsonb))
                        ON CONFLICT(signal_ts_text, symbol, expiry_date, strike, side, reversal_type) DO NOTHING
                    """), {
                        "signal_ts_text": str(latest_ts or ""),
                        "trade_date": trade_date,
                        "symbol": symbol,
                        "expiry_date": str(expiry or ""),
                        "strike": strike,
                        "side": side,
                        "old_action": (old or {}).get("dominant_action"),
                        "new_action": action,
                        "reversal_type": reversal_type,
                        "confidence": _row_to_float(row.get("confidence")) or 0,
                        "message": remarks,
                        "payload": payload_json,
                    })
            except Exception as row_exc:
                # Do not break live dashboard because one memory write failed.
                summary["error"] = f"row memory write warning: {type(row_exc).__name__}: {row_exc}"
                continue
    summary.update({"enabled": True, "insertedSignals": inserted, "reversals": reversals})
    return summary


def read_live_player_memory(symbol, expiry, limit=80):
    try:
        ensure_live_player_memory_tables()
    except Exception as exc:
        return {"error": f"memory read failed: {type(exc).__name__}: {exc}", "rows": [], "reversals": []}
    try:
        with ENGINE.connect() as conn:
            mem = pd.read_sql(sqlalchemy.text("""
                SELECT symbol, expiry_date, strike, side, first_trade_date, latest_trade_date,
                       first_seen_text, last_seen_text, dominant_signal, dominant_action, market_bias,
                       probable_player, signal_count, strong_signal_count, latest_confidence,
                       avg_confidence, max_confidence, total_oi_delta, total_abs_oi_delta,
                       total_volume_delta, spot_min, spot_max, last_spot, last_ltp, last_iv,
                       memory_status, remarks, updated_at
                FROM live_player_strike_memory
                WHERE symbol=:symbol AND expiry_date=:expiry_date
                ORDER BY
                  CASE memory_status
                    WHEN 'Trap / Broken' THEN 0
                    WHEN 'Accumulated' THEN 1
                    WHEN 'Defending / Strong Building' THEN 2
                    WHEN 'Building' THEN 3
                    ELSE 4
                  END,
                  COALESCE(max_confidence,0) DESC,
                  COALESCE(signal_count,0) DESC
                LIMIT :limit
            """), conn, params={"symbol": symbol, "expiry_date": str(expiry or ""), "limit": int(limit)})
            rev = pd.read_sql(sqlalchemy.text("""
                SELECT signal_ts_text, trade_date, symbol, expiry_date, strike, side, old_action, new_action,
                       reversal_type, confidence, message, created_at
                FROM live_player_reversal_log
                WHERE symbol=:symbol AND expiry_date=:expiry_date
                ORDER BY id DESC
                LIMIT 20
            """), conn, params={"symbol": symbol, "expiry_date": str(expiry or "")})
        return {
            "rows": [row_json(row) for _, row in mem.iterrows()] if not mem.empty else [],
            "reversals": [row_json(row) for _, row in rev.iterrows()] if not rev.empty else [],
            "error": "",
        }
    except Exception as exc:
        return {"error": f"memory read failed: {type(exc).__name__}: {exc}", "rows": [], "reversals": []}



def build_live_player_strike_decoder_payload(symbol, trade_date=None, expiry=None, band=10, min_confidence=35):
    """
    Probabilistic live strike decoder.

    It does NOT claim NSE gives participant-wise strike holdings. It combines:
      - EOD FII/Prop participant bias
      - live strike OI delta, volume delta, premium delta, IV delta
      - ATM proximity and burst strength
      - futures direction where available
    """
    symbol = normalize_index_symbol(symbol or "NIFTY")
    try:
        band = int(band or 10)
    except Exception:
        band = 10
    band = max(3, min(30, band))

    available_dates = get_available_dates(symbol)
    if not trade_date and available_dates:
        trade_date = available_dates[0]

    available_expiries = get_available_expiries_for_date(symbol, trade_date)
    if not expiry and available_expiries:
        expiry = available_expiries[0]

    df = read_symbol_table_for_date(symbol, trade_date, max_timestamps=None)
    if df.empty:
        return {
            "symbol": symbol,
            "date": trade_date,
            "expiry": expiry,
            "availableDates": available_dates,
            "availableExpiries": available_expiries,
            "error": f"No live option rows found for {symbol} on {trade_date or 'selected date'}.",
            "rows": [],
        }

    df = filter_frame_by_expiry(df, expiry)
    if df.empty:
        return {
            "symbol": symbol,
            "date": trade_date,
            "expiry": expiry,
            "availableDates": available_dates,
            "availableExpiries": available_expiries,
            "error": f"No option rows found for expiry {expiry or 'selected expiry'} on {trade_date}.",
            "rows": [],
        }

    strike_col = find_column(df, ("strikePrice", "strike"))
    opt_col = find_column(df, ("optionType", "type"))
    spot_col = find_column(df, ("spotPrice", "underlyingValue"))
    expiry_col = find_column(df, ("expiryDate", "expiry"))
    oi_col = find_column(df, ("openInterest", "openinterest", "oi"))
    volume_col = find_column(df, METRICS["volume"]["aliases"])
    iv_col = find_column(df, ("impliedVolatility", "iv"))
    ltp_col = find_column(df, ("lastPrice", "ltp", "closePrice"))
    change_oi_col = find_column(df, (
        "changeinOI",
        "changeinOpenInterest",
        "changeInOpenInterest",
        "coi",
        "changeOI",
    ))
    lot_col = find_column(df, ("marketLot", "marketLotSize", "lotSize"))

    if not strike_col or not opt_col or not oi_col or not volume_col or not ltp_col:
        return {
            "symbol": symbol,
            "date": trade_date,
            "expiry": expiry,
            "availableDates": available_dates,
            "availableExpiries": available_expiries,
            "error": "Required option columns missing: strikePrice/optionType/openInterest/NSE volume(noOfTrades)/lastPrice.",
            "rows": [],
        }

    work = df.copy()
    work["timestamp"] = work["timestamp"].map(normalize_timestamp)
    work["_strike"] = work[strike_col].map(to_number)
    work["_side"] = work[opt_col].map(lambda v: str(v).upper().strip())

    timestamps = sorted(work["timestamp"].dropna().unique(), key=parse_timestamp)
    if len(timestamps) < 2:
        return {
            "symbol": symbol,
            "date": trade_date,
            "expiry": expiry,
            "availableDates": available_dates,
            "availableExpiries": available_expiries,
            "error": "Need at least two intraday snapshots to decode live activity.",
            "rows": [],
        }

    latest_ts = timestamps[-1]
    prev_ts = timestamps[-2]
    latest_df = work[work["timestamp"] == latest_ts].copy()
    prev_df = work[work["timestamp"] == prev_ts].copy()

    spot = first_valid_number(latest_df[spot_col].tolist()) if spot_col else None
    strikes = [to_number(v) for v in latest_df[strike_col].tolist()]
    atm = nearest_atm(strikes, spot)
    step = infer_strike_step(strikes)
    wanted = {atm + i * step for i in range(-band, band + 1)} if atm is not None else set()

    # Repeat-confirmation engine: inspect the last few DB snapshots and count
    # whether the same strike+side+action repeats consecutively.
    confirmation_timestamps = timestamps[-5:]

    def _pair_signal_map(previous_ts, current_ts):
        current_frame = work[work["timestamp"] == current_ts].copy()
        previous_frame = work[work["timestamp"] == previous_ts].copy()
        if current_frame.empty or previous_frame.empty:
            return {}
        prev_local = {}
        for _, prow in previous_frame.iterrows():
            prev_local[(to_number(prow.get(strike_col)), str(prow.get(opt_col, "")).upper().strip())] = prow
        pair_out = {}
        for pstrike in sorted(wanted):
            sframe = current_frame[current_frame["_strike"].map(lambda v: v is not None and abs(v - pstrike) < 0.0001)]
            if sframe.empty:
                continue
            for pside in ("CE", "PE"):
                crow_frame = sframe[sframe["_side"] == pside]
                if crow_frame.empty:
                    continue
                crow = crow_frame.iloc[0]
                prow = prev_local.get((pstrike, pside))
                if prow is None:
                    continue
                poi = to_number(crow.get(oi_col))
                pprev_oi = to_number(prow.get(oi_col))
                pvolume = to_number(crow.get(volume_col))
                pprev_volume = to_number(prow.get(volume_col))
                pltp = to_number(crow.get(ltp_col))
                pprev_ltp = to_number(prow.get(ltp_col))
                piv = to_number(crow.get(iv_col)) if iv_col else None
                pprev_iv = to_number(prow.get(iv_col)) if iv_col else None
                poi_delta = (poi or 0) - (pprev_oi or 0)
                pvolume_delta = max(0, (pvolume or 0) - (pprev_volume or 0))
                pltp_delta = (pltp or 0) - (pprev_ltp or 0)
                piv_delta = (piv or 0) - (pprev_iv or 0) if piv is not None and pprev_iv is not None else 0
                psignal, paction = _side_live_signal(pside, poi_delta, pvolume_delta, pltp_delta, piv_delta)
                pbias = _signal_market_bias(pside, paction)
                if paction != "neutral" and (pvolume_delta > 0 or abs(poi_delta) > 0 or abs(pltp_delta) > 0):
                    pair_out[(float(pstrike), pside)] = {
                        "signal": psignal,
                        "action": paction,
                        "bias": pbias,
                    }
        return pair_out

    pair_signal_maps = []
    for i in range(1, len(confirmation_timestamps)):
        pair_signal_maps.append(_pair_signal_map(confirmation_timestamps[i - 1], confirmation_timestamps[i]))

    def _repeat_confirmation(strike_value, side_value, action_value):
        if action_value in {"neutral", "volume_watch"}:
            return 0, "Watch", 0
        repeat_count = 0
        key = (float(strike_value), str(side_value).upper())
        for pair_map in reversed(pair_signal_maps):
            rec = pair_map.get(key)
            if rec and rec.get("action") == action_value:
                repeat_count += 1
            else:
                break
        if repeat_count >= 3:
            return repeat_count, "Strong Confirmed", 14
        if repeat_count == 2:
            return repeat_count, "Confirmed", 8
        if repeat_count == 1:
            return repeat_count, "Fresh Spike", 0
        return 0, "Watch", 0

    prev_lookup = {}
    for _, row in prev_df.iterrows():
        prev_lookup[(to_number(row.get(strike_col)), str(row.get(opt_col, "")).upper().strip())] = row

    # Delta distributions for scaling burst scores.
    raw_deltas = []
    for _, row in latest_df.iterrows():
        strike = to_number(row.get(strike_col))
        side = str(row.get(opt_col, "")).upper().strip()
        prev = prev_lookup.get((strike, side))
        if prev is None:
            continue
        vol_delta = (to_number(row.get(volume_col)) or 0) - (to_number(prev.get(volume_col)) or 0)
        oi_delta = (to_number(row.get(oi_col)) or 0) - (to_number(prev.get(oi_col)) or 0)
        if vol_delta > 0 or abs(oi_delta) > 0:
            raw_deltas.append((max(0, vol_delta), abs(oi_delta)))
    vol_scale = pd.Series([x[0] for x in raw_deltas]).quantile(0.90) if raw_deltas else 1
    oi_scale = pd.Series([x[1] for x in raw_deltas]).quantile(0.90) if raw_deltas else 1
    vol_scale = float(vol_scale or 1)
    oi_scale = float(oi_scale or 1)

    eod_bias = _get_eod_bias_for_decoder(symbol, trade_date=trade_date, expiry=expiry)
    fii_dir = eod_bias.get("fiiDirection") or "Neutral"
    prop_dir = eod_bias.get("propDirection") or "Neutral"
    big_dir = (eod_bias.get("bigMoney") or {}).get("direction") or "Neutral"

    futures_series = build_futures_series(symbol, trade_date)
    latest_future = nearest_future_point(latest_ts, futures_series) or (futures_series[-1] if futures_series else {})
    fut_price_roc = to_number((latest_future or {}).get("futurePriceRoc"))
    fut_oi_roc = to_number((latest_future or {}).get("futureOiRoc"))

    rows = []
    for strike in sorted(wanted):
        frame = latest_df[latest_df["_strike"].map(lambda v: v is not None and abs(v - strike) < 0.0001)]
        if frame.empty:
            continue
        for side in ("CE", "PE"):
            side_frame = frame[frame["_side"] == side]
            if side_frame.empty:
                continue
            row = side_frame.iloc[0]
            prev = prev_lookup.get((strike, side))
            if prev is None:
                continue

            oi = to_number(row.get(oi_col))
            prev_oi = to_number(prev.get(oi_col))
            volume = to_number(row.get(volume_col))
            prev_volume = to_number(prev.get(volume_col))
            ltp = to_number(row.get(ltp_col))
            prev_ltp = to_number(prev.get(ltp_col))
            iv = to_number(row.get(iv_col)) if iv_col else None
            prev_iv = to_number(prev.get(iv_col)) if prev is not None and iv_col else None
            current_coi = to_number(row.get(change_oi_col)) if change_oi_col else None
            prev_coi = to_number(prev.get(change_oi_col)) if prev is not None and change_oi_col else None
            lot_size = _row_lot_size(row, lot_col=lot_col, symbol=symbol)

            oi_delta = (oi or 0) - (prev_oi or 0)
            volume_delta = max(0, (volume or 0) - (prev_volume or 0))
            ltp_delta = (ltp or 0) - (prev_ltp or 0)
            iv_delta = (iv or 0) - (prev_iv or 0) if iv is not None and prev_iv is not None else 0
            coi_delta = (current_coi or 0) - (prev_coi or 0) if current_coi is not None and prev_coi is not None else oi_delta
            premium_roc = pct_change(ltp, prev_ltp)
            volume_roc = pct_change(volume, prev_volume)
            oi_roc = pct_change(oi, prev_oi)
            iv_roc = pct_change(iv, prev_iv) if iv is not None and prev_iv is not None else None
            session_presence = _coi_volume_lot_score(current_coi if current_coi is not None else oi_delta, volume, lot_size)
            delta_presence = _coi_volume_lot_score(coi_delta, volume_delta, lot_size)
            lot_presence = max(
                [value for value in (session_presence, delta_presence) if value is not None],
                default=None,
            )
            signal, action = _side_live_signal(side, oi_delta, volume_delta, ltp_delta, iv_delta)
            signal_bias = _signal_market_bias(side, action)

            vol_burst = _safe_abs_pct(volume_delta, vol_scale)
            oi_burst = _safe_abs_pct(oi_delta, oi_scale)
            live_burst = (0.60 * vol_burst) + (0.40 * oi_burst)
            premium_confirm = 0
            if action in {"writing", "buying", "short_covering", "long_unwinding"}:
                premium_confirm = min(20.0, abs(ltp_delta) / max(abs(prev_ltp or 0), 1.0) * 100.0 * 4.0)
            iv_confirm = 0
            if action == "buying" and iv_delta > 0:
                iv_confirm = min(10, iv_delta * 2)
            elif action == "writing" and iv_delta <= 0:
                iv_confirm = 6

            lot_presence_confirm = 0
            if lot_presence is not None:
                if lot_presence >= 0.60:
                    lot_presence_confirm = 14
                elif lot_presence >= 0.40:
                    lot_presence_confirm = 10
                elif lot_presence >= 0.25:
                    lot_presence_confirm = 6
                elif lot_presence < 0.10:
                    lot_presence_confirm = -4

            # ATM proximity matters because near-ATM activity carries more intraday information.
            distance_sp = abs((strike - atm) / step) if atm and step else 0
            proximity = max(0, 12 - min(12, distance_sp * 2))

            futures_confirm = 0
            if signal_bias != 0 and fut_price_roc is not None:
                if (signal_bias > 0 and fut_price_roc > 0) or (signal_bias < 0 and fut_price_roc < 0):
                    futures_confirm += 6
            if signal_bias != 0 and fut_oi_roc is not None and abs(fut_oi_roc) > 0:
                futures_confirm += min(6, abs(fut_oi_roc) * 2)

            player, player_score = _player_probability(fii_dir, prop_dir, signal_bias, live_burst)
            repeat_count, repeat_status, repeat_boost = _repeat_confirmation(strike, side, action)
            confidence = live_burst * 0.38 + premium_confirm + iv_confirm + lot_presence_confirm + proximity + futures_confirm + player_score + repeat_boost
            confidence = max(0, min(100, confidence))

            if confidence < float(min_confidence or 0):
                continue

            if signal_bias < 0:
                message = f"{int(strike) if float(strike).is_integer() else strike} {side}: bearish pressure / resistance behaviour"
            elif signal_bias > 0:
                message = f"{int(strike) if float(strike).is_integer() else strike} {side}: bullish support / breakout behaviour"
            else:
                message = f"{int(strike) if float(strike).is_integer() else strike} {side}: activity watch"

            rows.append({
                "strike": strike,
                "side": side,
                "signal": signal,
                "action": action,
                "marketBias": "Bullish" if signal_bias > 0 else ("Bearish" if signal_bias < 0 else "Neutral"),
                "probablePlayer": player,
                "confidence": round(confidence, 2),
                "repeatCount": repeat_count,
                "repeatStatus": repeat_status,
                "repeatBoost": repeat_boost,
                "liveBurstScore": round(live_burst, 2),
                "volumeDelta": volume_delta,
                "oiDelta": oi_delta,
                "coi": current_coi,
                "coiDelta": coi_delta,
                "premiumRoc": premium_roc,
                "volumeRoc": volume_roc,
                "oiRoc": oi_roc,
                "ivRoc": iv_roc,
                "lotSize": lot_size,
                "coiVolumeLotScore": lot_presence,
                "sessionCoiVolumeLotScore": session_presence,
                "deltaCoiVolumeLotScore": delta_presence,
                "ltp": ltp,
                "ltpDelta": ltp_delta,
                "iv": iv,
                "ivDelta": iv_delta,
                "oi": oi,
                "volume": volume,
                "distanceFromAtm": distance_sp,
                "message": message,
            })

    rows = sorted(rows, key=lambda r: (r.get("confidence") or 0, r.get("liveBurstScore") or 0), reverse=True)
    top = rows[:30]
    resistance = [r for r in top if r.get("marketBias") == "Bearish"][:8]
    support = [r for r in top if r.get("marketBias") == "Bullish"][:8]

    memory_write = persist_live_player_memory(symbol, trade_date, expiry, latest_ts, spot, latest_future or {}, top)
    memory = read_live_player_memory(symbol, expiry, limit=80)
    memory_map = {}
    for mrow in memory.get("rows") or []:
        try:
            memory_map[(float(mrow.get("strike")), str(mrow.get("side") or "").upper())] = mrow
        except Exception:
            pass
    for row in top:
        try:
            mrow = memory_map.get((float(row.get("strike")), str(row.get("side") or "").upper())) or {}
            row["memoryStatus"] = mrow.get("memory_status") or row.get("repeatStatus")
            row["memorySignalCount"] = mrow.get("signal_count")
            row["memoryStrongCount"] = mrow.get("strong_signal_count")
            row["memoryTotalOiDelta"] = mrow.get("total_oi_delta")
            row["memoryTotalVolumeDelta"] = mrow.get("total_volume_delta")
            row["memoryFirstSeen"] = mrow.get("first_seen_text")
            row["memoryLastSeen"] = mrow.get("last_seen_text")
        except Exception:
            pass

    return {
        "symbol": symbol,
        "date": trade_date,
        "expiry": expiry,
        "availableDates": available_dates,
        "availableExpiries": available_expiries,
        "timestamp": latest_ts,
        "previousTimestamp": prev_ts,
        "spot": spot,
        "atm": atm,
        "strikeStep": step,
        "band": band,
        "confirmationWindow": len(confirmation_timestamps),
        "confirmationPairs": len(pair_signal_maps),
        "generatedAt": datetime.now(IST).strftime("%d-%b-%Y %H:%M:%S"),
        "eodBias": eod_bias,
        "futures": latest_future or {},
        "memoryWrite": memory_write,
        "expiryMemory": memory,
        "rows": top,
        "resistanceRows": resistance,
        "supportRows": support,
        "disclaimer": "Probabilistic inference only. NSE public files do not provide live participant-wise strike positions.",
        "howToUse": "Repeat confirmation is automatic. V10.1 DATE LOCK also stores every high-confidence signal in DB and builds expiry-wide memory. Fresh Spike = latest pair only, Confirmed = 2 consecutive DB snapshots, Strong Confirmed = 3+ snapshots; Memory Status shows whether the strike is Building, Accumulated, Defending, or Broken/Trap.",
    }


_OPTION_BUYING_AI_TABLES_READY = False


def ensure_option_buying_ai_tables():
    """Create DB tables used by the option-buying signal memory engine."""
    global _OPTION_BUYING_AI_TABLES_READY
    if _OPTION_BUYING_AI_TABLES_READY:
        return
    statements = [
        """
        CREATE TABLE IF NOT EXISTS option_buying_ai_signal_log (
            id bigserial PRIMARY KEY,
            signal_ts_text text NOT NULL,
            trade_date date,
            symbol text NOT NULL,
            expiry_date text NOT NULL,
            setup_side text NOT NULL,
            setup_type text NOT NULL,
            strike numeric NOT NULL,
            option_side text,
            source_side text,
            score numeric,
            status text,
            probable_player text,
            player_bias text,
            entry_spot numeric,
            entry_option_ltp numeric,
            entry_iv numeric,
            trigger text,
            invalidation text,
            risk_flags text,
            memory_status text,
            repeat_count integer,
            source_payload jsonb,
            outcome text DEFAULT 'OPEN',
            outcome_ts_text text,
            outcome_points numeric,
            outcome_option_points numeric,
            lesson text,
            created_at timestamp DEFAULT now(),
            updated_at timestamp DEFAULT now(),
            UNIQUE(signal_ts_text, symbol, expiry_date, setup_side, setup_type, strike)
        );
        """,
        """
        CREATE INDEX IF NOT EXISTS idx_option_buying_ai_signal_lookup
        ON option_buying_ai_signal_log(symbol, expiry_date, setup_side, outcome, score DESC);
        """,
        """
        CREATE TABLE IF NOT EXISTS nse_live_option_buying_signals (
            id bigserial PRIMARY KEY,
            signal_ts_text text NOT NULL,
            trade_date date,
            symbol text NOT NULL,
            expiry_date text NOT NULL,
            setup_side text NOT NULL,
            setup_type text NOT NULL,
            setup_kind text,
            status text,
            score numeric,
            strike numeric NOT NULL,
            option_side text,
            source_side text,
            source_action text,
            source_signal text,
            probable_player text,
            player_bias text,
            confidence numeric,
            live_burst_score numeric,
            lot_size numeric,
            coi numeric,
            coi_delta numeric,
            coi_volume_proxy numeric,
            coi_volume_lot_score numeric,
            session_coi_volume_lot_score numeric,
            delta_coi_volume_lot_score numeric,
            premium_roc numeric,
            volume_roc numeric,
            oi_roc numeric,
            iv_roc numeric,
            oi_delta numeric,
            volume_delta numeric,
            ltp numeric,
            ltp_delta numeric,
            iv numeric,
            iv_delta numeric,
            spot numeric,
            atm numeric,
            future_price_roc numeric,
            future_oi_roc numeric,
            repeat_count integer,
            repeat_status text,
            memory_status text,
            trigger text,
            invalidation text,
            confirmations text,
            risk_flags text,
            source_payload jsonb,
            created_at timestamp DEFAULT now(),
            updated_at timestamp DEFAULT now(),
            UNIQUE(signal_ts_text, symbol, expiry_date, setup_side, setup_type, strike)
        );
        """,
        """
        CREATE INDEX IF NOT EXISTS idx_nse_live_option_buying_signals_lookup
        ON nse_live_option_buying_signals(symbol, trade_date, expiry_date, status, score DESC);
        """,
        """
        CREATE TABLE IF NOT EXISTS nse_live_option_buying_payload_cache (
            symbol text NOT NULL,
            trade_date date,
            expiry_date text NOT NULL,
            snapshot_ts_text text,
            payload_json jsonb NOT NULL,
            updated_at timestamp DEFAULT now(),
            PRIMARY KEY(symbol, trade_date, expiry_date)
        );
        """,
    ]
    with ENGINE.begin() as conn:
        for stmt in statements:
            conn.execute(sqlalchemy.text(stmt))
    _OPTION_BUYING_AI_TABLES_READY = True


def _setup_direction_score(setup_side):
    value = str(setup_side or "").upper()
    if "CE" in value:
        return 1
    if "PE" in value:
        return -1
    return 0


def _option_setup_from_decoder_row(row):
    side = str(row.get("side") or "").upper()
    action = str(row.get("action") or "").lower()
    bias = str(row.get("marketBias") or "")
    if bias == "Bullish":
        if side == "CE" and action in {"buying", "short_covering"}:
            return "BUY CE", "Direct CE premium expansion", "CE", "direct_buy"
        if side == "PE" and action in {"writing", "long_unwinding"}:
            return "BUY CE", "PE support / writers defending", "CE", "writer_support"
    if bias == "Bearish":
        if side == "PE" and action in {"buying", "short_covering"}:
            return "BUY PE", "Direct PE premium expansion", "PE", "direct_buy"
        if side == "CE" and action in {"writing", "long_unwinding"}:
            return "BUY PE", "CE resistance / writers defending", "PE", "writer_resistance"
    return "", "", "", ""


def _coi_volume_proxy(row):
    oi_delta = abs(to_number(row.get("oiDelta")) or 0)
    volume_delta = max(0, to_number(row.get("volumeDelta")) or 0)
    if volume_delta <= 0:
        return None
    return oi_delta / volume_delta


def _memory_bonus_and_flags(row):
    status = str(row.get("memoryStatus") or row.get("repeatStatus") or "")
    count = int(to_number(row.get("memorySignalCount")) or 0)
    strong = int(to_number(row.get("memoryStrongCount")) or 0)
    bonus = min(10, count * 1.2) + min(8, strong * 2.5)
    flags = []
    if "Accumulated" in status:
        bonus += 5
    elif "Defending" in status or "Strong" in status:
        bonus += 4
    elif "Building" in status:
        bonus += 2
    if "Trap" in status or "Broken" in status or "Reversal" in status:
        bonus -= 16
        flags.append("memory trap/broken")
    return bonus, flags


def _option_buying_candidate_from_row(row, eod_bias, futures, atm, strike_step):
    setup_side, setup_type, option_side, setup_kind = _option_setup_from_decoder_row(row)
    if not setup_side:
        return None

    strike = to_number(row.get("strike"))
    direction = _setup_direction_score(setup_side)
    confidence = to_number(row.get("confidence")) or 0
    live_burst = to_number(row.get("liveBurstScore")) or 0
    ltp_delta = to_number(row.get("ltpDelta")) or 0
    iv_delta = to_number(row.get("ivDelta")) or 0
    repeat_count = int(to_number(row.get("repeatCount")) or 0)
    distance = abs(to_number(row.get("distanceFromAtm")) or 0)
    coi_proxy = _coi_volume_proxy(row)
    coi_lot_score = to_number(row.get("coiVolumeLotScore"))
    session_coi_lot_score = to_number(row.get("sessionCoiVolumeLotScore"))
    delta_coi_lot_score = to_number(row.get("deltaCoiVolumeLotScore"))
    premium_roc = to_number(row.get("premiumRoc"))
    volume_roc = to_number(row.get("volumeRoc"))
    oi_roc = to_number(row.get("oiRoc"))
    iv_roc = to_number(row.get("ivRoc"))
    fut_price_roc = to_number((futures or {}).get("futurePriceRoc"))
    fut_oi_roc = to_number((futures or {}).get("futureOiRoc"))
    big = (eod_bias or {}).get("bigMoney") or {}
    big_direction = big.get("direction") or "Neutral"
    fii_direction = (eod_bias or {}).get("fiiDirection") or "Neutral"
    prop_direction = (eod_bias or {}).get("propDirection") or "Neutral"

    score = (confidence * 0.55) + min(14, live_burst * 0.12) + min(12, repeat_count * 4)
    risk_flags = []
    confirmations = []

    memory_bonus, memory_flags = _memory_bonus_and_flags(row)
    score += memory_bonus
    risk_flags.extend(memory_flags)

    if setup_kind == "direct_buy":
        if ltp_delta > 0:
            score += 10
            confirmations.append("premium expanding")
        else:
            score -= 18
            risk_flags.append("premium decay against buyer")
        if iv_delta > 0:
            score += 7
            confirmations.append("IV expanding")
        elif iv_delta < 0:
            score -= 7
            risk_flags.append("IV not confirming buyer")
        if premium_roc is not None and premium_roc > 0:
            score += min(8, premium_roc * 0.25)
        if iv_roc is not None and iv_roc > 0:
            score += min(6, iv_roc * 0.20)
    else:
        if ltp_delta <= 0:
            score += 7
            confirmations.append("writer controlling premium")
        else:
            score -= 5
            risk_flags.append("writer premium expanding against view")
        if iv_delta <= 0:
            score += 4
            confirmations.append("IV controlled/squeezed")
        if premium_roc is not None and premium_roc <= 0:
            score += min(5, abs(premium_roc) * 0.15)

    if coi_proxy is not None:
        if coi_proxy < 0.05 and (to_number(row.get("volumeDelta")) or 0) > 0:
            score -= 11
            risk_flags.append("exchange-of-hands risk: low COI/volume proxy")
        elif coi_proxy >= 0.25:
            score += 5
            confirmations.append("fresh OI participation proxy")

    if coi_lot_score is not None:
        if coi_lot_score >= 0.60:
            score += 12
            confirmations.append("big-player COI/VOL ratio >= 0.60")
        elif coi_lot_score >= 0.40:
            score += 9
            confirmations.append("big-player COI/VOL ratio >= 0.40")
        elif coi_lot_score >= 0.25:
            score += 5
            confirmations.append("COI/VOL participation ratio >= 0.25")
        elif coi_lot_score < 0.10:
            score -= 5
            risk_flags.append("weak COI/VOL ratio")

    if direction and fut_price_roc is not None:
        if direction > 0 and fut_price_roc > 0:
            score += 6
            confirmations.append("future price aligned")
        elif direction < 0 and fut_price_roc < 0:
            score += 6
            confirmations.append("future price aligned")
        elif abs(fut_price_roc) > 0.01:
            score -= 7
            risk_flags.append("future price conflict")
    if direction and fut_oi_roc is not None and abs(fut_oi_roc) > 0:
        score += min(5, abs(fut_oi_roc) * 1.5)

    for label, eod_direction, weight in (
        ("big money", big_direction, 9),
        ("FII", fii_direction, 5),
        ("Prop", prop_direction, 4),
    ):
        participant_dir = _decoder_direction_score(eod_direction)
        if participant_dir and participant_dir == direction:
            score += weight
            confirmations.append(f"{label} EOD aligned")
        elif participant_dir and participant_dir == -direction:
            score -= weight
            risk_flags.append(f"{label} EOD conflict")

    if distance > 8:
        score -= 6
        risk_flags.append("far from ATM")
    elif distance <= 3:
        score += 4
        confirmations.append("near ATM activity")

    if setup_kind != "direct_buy":
        score -= 4

    score = round(max(0, min(100, score)), 2)
    severe_risk = any("premium decay" in flag or "memory trap" in flag for flag in risk_flags)
    if setup_kind == "direct_buy" and score >= 75 and not severe_risk:
        status = "READY"
    elif setup_kind != "direct_buy" and score >= 82 and not severe_risk and repeat_count >= 2:
        status = "READY"
    elif score >= 50:
        status = "WATCH"
    else:
        status = "AVOID"

    if setup_side == "BUY CE" and setup_kind == "direct_buy":
        trigger = "Buy CE only if spot sustains above ATM/strike zone and CE premium plus IV continue expanding."
        invalidation = "Avoid/exit if CE premium decays, spot loses ATM/support, or CE buying converts to writing/unwinding."
    elif setup_side == "BUY CE":
        trigger = "Buy CE after spot sustains above PE support/writer strike and CE premium starts expanding."
        invalidation = "Avoid if PE support breaks or CE premium does not expand after breakout."
    elif setup_kind == "direct_buy":
        trigger = "Buy PE only if spot rejects below ATM/strike zone and PE premium plus IV continue expanding."
        invalidation = "Avoid/exit if PE premium decays, spot reclaims ATM/resistance, or PE buying converts to writing/unwinding."
    else:
        trigger = "Buy PE after spot rejects below CE resistance/writer strike and PE premium starts expanding."
        invalidation = "Avoid if CE resistance breaks or PE premium does not expand after rejection."

    return {
        "setupSide": setup_side,
        "setupType": setup_type,
        "setupKind": setup_kind,
        "status": status,
        "score": score,
        "strike": strike,
        "sourceSide": row.get("side"),
        "optionSide": option_side,
        "sourceSignal": row.get("signal"),
        "sourceAction": row.get("action"),
        "probablePlayer": row.get("probablePlayer"),
        "playerBias": row.get("marketBias"),
        "confidence": row.get("confidence"),
        "repeatCount": repeat_count,
        "repeatStatus": row.get("repeatStatus"),
        "memoryStatus": row.get("memoryStatus"),
        "memorySignalCount": row.get("memorySignalCount"),
        "liveBurstScore": row.get("liveBurstScore"),
        "coiVolumeProxy": None if coi_proxy is None else round(coi_proxy, 4),
        "coiVolumeLotScore": None if coi_lot_score is None else round(coi_lot_score, 4),
        "sessionCoiVolumeLotScore": None if session_coi_lot_score is None else round(session_coi_lot_score, 4),
        "deltaCoiVolumeLotScore": None if delta_coi_lot_score is None else round(delta_coi_lot_score, 4),
        "premiumRoc": premium_roc,
        "volumeRoc": volume_roc,
        "oiRoc": oi_roc,
        "ivRoc": iv_roc,
        "lotSize": row.get("lotSize"),
        "coi": row.get("coi"),
        "coiDelta": row.get("coiDelta"),
        "oiDelta": row.get("oiDelta"),
        "volumeDelta": row.get("volumeDelta"),
        "ltp": row.get("ltp"),
        "ltpDelta": row.get("ltpDelta"),
        "iv": row.get("iv"),
        "ivDelta": row.get("ivDelta"),
        "distanceFromAtm": distance,
        "trigger": trigger,
        "invalidation": invalidation,
        "riskFlags": risk_flags,
        "confirmations": confirmations,
        "message": row.get("message"),
        "sourceRow": row,
    }



# ============================== V11.8 OPTION BUYING VALIDATION FIX ==============================
# Fixes:
# - Do not validate a signal using an older snapshot.
# - Do not validate signals from another trade_date just because expiry is same.
# - Option-buying outcome must consider option premium movement, not only spot movement.
# - BUY CE / BUY PE learning should not mark "RESPECTED" if the bought option premium decayed.

def _minutes_between_market_ts(start_ts, end_ts):
    start_dt = parse_timestamp(start_ts)
    end_dt = parse_timestamp(end_ts)
    if start_dt == datetime.min or end_dt == datetime.min:
        return None
    return (end_dt - start_dt).total_seconds() / 60.0


def _lookup_option_ltp_iv(symbol, timestamp_text, expiry, strike, side):
    """Lookup the option-side LTP/IV at a specific DB timestamp."""
    symbol = normalize_index_symbol(symbol or "NIFTY")
    if symbol not in SYMBOLS or not timestamp_text:
        return {"ltp": None, "iv": None}

    try:
        df = read_rows_for_timestamps(symbol, [str(timestamp_text)])
        if df.empty:
            return {"ltp": None, "iv": None}

        df = filter_frame_by_expiry(df, expiry)
        if df.empty:
            return {"ltp": None, "iv": None}

        strike_col = find_column(df, ("strikePrice", "strike"))
        side_col = find_column(df, ("optionType", "type"))
        ltp_col = find_column(df, ("lastPrice", "ltp", "closePrice"))
        iv_col = find_column(df, ("impliedVolatility", "iv"))
        if not strike_col or not side_col:
            return {"ltp": None, "iv": None}

        target_strike = to_number(strike)
        target_side = str(side or "").upper().strip()
        if target_strike is None or target_side not in {"CE", "PE"}:
            return {"ltp": None, "iv": None}

        work = df.copy()
        work["_strike"] = work[strike_col].map(to_number)
        work["_side"] = work[side_col].astype(str).str.upper().str.strip()
        work = work[
            (work["_side"] == target_side)
            & (work["_strike"].map(lambda value: value is not None and abs(float(value) - float(target_strike)) < 0.0001))
        ].copy()
        if work.empty:
            return {"ltp": None, "iv": None}

        row = work.iloc[0]
        return {
            "ltp": to_number(row.get(ltp_col)) if ltp_col else None,
            "iv": to_number(row.get(iv_col)) if iv_col else None,
        }
    except Exception:
        return {"ltp": None, "iv": None}


def _option_points_threshold(entry_ltp):
    entry_ltp = to_number(entry_ltp)
    if entry_ltp is None or entry_ltp <= 0:
        return 2.0
    # Minimum 2 points or 5% of premium. Keeps small-premium noise away.
    return max(2.0, abs(entry_ltp) * 0.05)



# ============================== V11.8.3 LEARNING DATE GUARD ==============================
# Fix:
#   Existing rows created by older versions may show impossible validation:
#   signal time = 02-Jun but outcome time = 01-Jun.
#   This can never be valid. V11.8.3 automatically resets such rows to OPEN
#   and filters learning to the selected trade date.

def _market_date_from_ts_text(ts_text):
    dt = parse_timestamp(str(ts_text or ""))
    if dt == datetime.min:
        return ""
    return dt.strftime("%Y-%m-%d")


def _effective_trade_date_for_signal(selected_trade_date, latest_ts):
    """Use the actual market timestamp date for signal logging, not only the selected dropdown date."""
    ts_date = _market_date_from_ts_text(latest_ts)
    return ts_date or selected_trade_date


def cleanup_invalid_option_buying_outcomes(conn, symbol=None, expiry=None, trade_date=None):
    """
    Reset impossible/old-learning rows:
    - outcome timestamp earlier than signal timestamp
    - old spot-only validation lesson
    - optional selected trade_date filter
    """
    where = ["outcome <> 'OPEN'"]
    params = {}
    if symbol:
        where.append("symbol = :symbol")
        params["symbol"] = symbol
    if expiry:
        where.append("expiry_date = :expiry_date")
        params["expiry_date"] = str(expiry or "")
    if trade_date:
        where.append("trade_date = CAST(:trade_date AS DATE)")
        params["trade_date"] = trade_date

    sql = """
        SELECT id, signal_ts_text, outcome_ts_text, lesson
        FROM option_buying_ai_signal_log
        WHERE """ + " AND ".join(where) + """
        ORDER BY id DESC
        LIMIT 5000
    """
    rows = conn.execute(sqlalchemy.text(sql), params).mappings().all()

    bad_ids = []
    for row in rows:
        signal_dt = parse_timestamp(str(row.get("signal_ts_text") or ""))
        outcome_dt = parse_timestamp(str(row.get("outcome_ts_text") or ""))
        lesson = str(row.get("lesson") or "")

        impossible_time = (
            signal_dt != datetime.min
            and outcome_dt != datetime.min
            and outcome_dt < signal_dt
        )
        old_spot_only_logic = "Signal direction respected by spot movement" in lesson

        if impossible_time or old_spot_only_logic:
            bad_ids.append(row.get("id"))

    if bad_ids:
        conn.execute(sqlalchemy.text("""
            UPDATE option_buying_ai_signal_log
            SET outcome = 'OPEN',
                outcome_ts_text = NULL,
                outcome_points = NULL,
                outcome_option_points = NULL,
                lesson = 'Reset by V11.8.3: invalid old validation. Outcome time was older than signal time or old spot-only validation was used.',
                updated_at = now()
            WHERE id = ANY(:ids)
        """), {"ids": bad_ids})

    return len(bad_ids)


def _update_option_buying_outcomes(conn, symbol, trade_date, expiry, latest_ts, spot, strike_step):
    """
    V11.8 outcome logic.

    Old logic used only latest spot vs entry spot and ignored trade_date/time order.
    That could mark BUY PE as RESPECTED even when PE premium decayed or when an
    older selected-date snapshot was compared with a newer signal.

    New logic:
    - same symbol + same expiry + same trade_date only
    - latest_ts must be after signal_ts_text
    - do not finalize before 5 minutes
    - outcome uses both spot direction and bought-option premium movement
    """
    if spot is None:
        return {"checked": 0, "updated": 0}

    rows = conn.execute(sqlalchemy.text("""
        SELECT id, signal_ts_text, trade_date, setup_side, setup_type, strike, option_side,
               entry_spot, entry_option_ltp, entry_iv, score
        FROM option_buying_ai_signal_log
        WHERE symbol=:symbol
          AND expiry_date=:expiry_date
          AND trade_date = CAST(:trade_date AS DATE)
          AND outcome='OPEN'
          AND COALESCE(signal_ts_text,'') <> COALESCE(:latest_ts,'')
        ORDER BY id DESC
        LIMIT 300
    """), {
        "symbol": symbol,
        "expiry_date": str(expiry or ""),
        "trade_date": trade_date,
        "latest_ts": str(latest_ts or ""),
    }).mappings().all()

    checked = 0
    updated = 0
    step = max(10.0, float(strike_step or 50))
    spot_threshold = max(15.0, step * 0.50)

    for row in rows:
        signal_ts = str(row.get("signal_ts_text") or "")
        minutes = _minutes_between_market_ts(signal_ts, latest_ts)
        if minutes is None:
            continue

        # Important: never validate backwards, and wait for at least 5 minutes.
        if minutes < 5:
            continue

        entry_spot = to_number(row.get("entry_spot"))
        if entry_spot is None:
            continue

        checked += 1
        side = str(row.get("setup_side") or "")
        direction = _setup_direction_score(side)
        if not direction:
            continue

        spot_move = (float(spot) - float(entry_spot)) * direction

        strike = row.get("strike")
        option_side = str(row.get("option_side") or ("CE" if direction > 0 else "PE")).upper()
        entry_ltp = to_number(row.get("entry_option_ltp"))

        # If older records did not store entry option LTP, recover it from the market timestamp.
        if entry_ltp is None:
            entry_lookup = _lookup_option_ltp_iv(symbol, signal_ts, expiry, strike, option_side)
            entry_ltp = to_number(entry_lookup.get("ltp"))

        latest_lookup = _lookup_option_ltp_iv(symbol, latest_ts, expiry, strike, option_side)
        current_ltp = to_number(latest_lookup.get("ltp"))

        option_points = None
        option_ok = None
        option_bad = None
        premium_threshold = _option_points_threshold(entry_ltp)

        if entry_ltp is not None and current_ltp is not None:
            option_points = float(current_ltp) - float(entry_ltp)
            option_ok = option_points >= premium_threshold
            option_bad = option_points <= -premium_threshold

        outcome = None
        lesson = ""

        # For option buying, premium is king. If the bought option decays, it is not respected.
        if option_bad:
            outcome = "FAILED"
            lesson = (
                f"Bought option premium decayed by {option_points:.2f}; "
                f"spot move {spot_move:.2f}. Do not count this as respected."
            )
        elif spot_move <= -spot_threshold:
            outcome = "FAILED"
            lesson = (
                f"Spot moved against {side} by {spot_move:.2f}; "
                f"premium move {option_points if option_points is not None else 'NA'}."
            )
        elif option_ok and spot_move >= 0:
            outcome = "RESPECTED"
            lesson = (
                f"Bought option premium expanded by {option_points:.2f} with non-adverse spot move {spot_move:.2f}."
            )
        elif spot_move >= spot_threshold and option_points is None and minutes >= 15:
            # Fallback only when option premium cannot be read.
            outcome = "RESPECTED"
            lesson = f"Spot direction respected by {spot_move:.2f}; option premium unavailable for validation."
        elif minutes >= 30 and option_points is not None and option_points <= 0:
            outcome = "FAILED"
            lesson = (
                f"30-min validation: bought option did not expand; premium move {option_points:.2f}, "
                f"spot move {spot_move:.2f}."
            )
        else:
            continue

        conn.execute(sqlalchemy.text("""
            UPDATE option_buying_ai_signal_log
            SET outcome=:outcome,
                outcome_ts_text=:outcome_ts_text,
                outcome_points=:outcome_points,
                outcome_option_points=:outcome_option_points,
                lesson=:lesson,
                updated_at=now()
            WHERE id=:id
        """), {
            "id": row.get("id"),
            "outcome": outcome,
            "outcome_ts_text": str(latest_ts or ""),
            "outcome_points": round(spot_move, 2),
            "outcome_option_points": None if option_points is None else round(option_points, 2),
            "lesson": lesson,
        })
        updated += 1

    return {"checked": checked, "updated": updated}


def persist_option_buying_ai_signals(symbol, trade_date, expiry, latest_ts, spot, strike_step, candidates):
    summary = {"enabled": False, "insertedSignals": 0, "outcomesUpdated": 0, "error": ""}
    try:
        ensure_option_buying_ai_tables()
    except Exception as exc:
        summary["error"] = f"option buying memory init failed: {type(exc).__name__}: {exc}"
        return summary

    inserted = 0
    try:
        signal_trade_date = _effective_trade_date_for_signal(trade_date, latest_ts)
        with ENGINE.begin() as conn:
            cleanup_invalid_option_buying_outcomes(conn, symbol=symbol, expiry=expiry, trade_date=signal_trade_date)
            outcome_summary = _update_option_buying_outcomes(conn, symbol, signal_trade_date, expiry, latest_ts, spot, strike_step)
            for candidate in candidates or []:
                if candidate.get("status") not in {"READY", "WATCH"}:
                    continue
                if (to_number(candidate.get("score")) or 0) < 45:
                    continue
                option_quote = _lookup_option_ltp_iv(
                    symbol,
                    latest_ts,
                    expiry,
                    candidate.get("strike"),
                    candidate.get("optionSide"),
                )
                entry_option_ltp = _row_to_float(option_quote.get("ltp"))
                entry_iv_value = _row_to_float(option_quote.get("iv"))
                if entry_option_ltp is None and candidate.get("sourceSide") == candidate.get("optionSide"):
                    entry_option_ltp = _row_to_float(candidate.get("ltp"))
                if entry_iv_value is None and candidate.get("sourceSide") == candidate.get("optionSide"):
                    entry_iv_value = _row_to_float(candidate.get("iv"))

                payload_json = json.dumps(json_safe(candidate), default=str)
                result = conn.execute(sqlalchemy.text("""
                    INSERT INTO option_buying_ai_signal_log
                    (signal_ts_text, trade_date, symbol, expiry_date, setup_side, setup_type, strike,
                     option_side, source_side, score, status, probable_player, player_bias, entry_spot,
                     entry_option_ltp, entry_iv, trigger, invalidation, risk_flags, memory_status,
                     repeat_count, source_payload)
                    VALUES
                    (:signal_ts_text, CAST(:trade_date AS date), :symbol, :expiry_date, :setup_side, :setup_type, :strike,
                     :option_side, :source_side, :score, :status, :probable_player, :player_bias, :entry_spot,
                     :entry_option_ltp, :entry_iv, :trigger, :invalidation, :risk_flags, :memory_status,
                     :repeat_count, CAST(:source_payload AS jsonb))
                    ON CONFLICT(signal_ts_text, symbol, expiry_date, setup_side, setup_type, strike) DO NOTHING
                    RETURNING id
                """), {
                    "signal_ts_text": str(latest_ts or ""),
                    "trade_date": trade_date,
                    "symbol": symbol,
                    "expiry_date": str(expiry or ""),
                    "setup_side": candidate.get("setupSide"),
                    "setup_type": candidate.get("setupType"),
                    "strike": _row_to_float(candidate.get("strike")) or 0,
                    "option_side": candidate.get("optionSide"),
                    "source_side": candidate.get("sourceSide"),
                    "score": _row_to_float(candidate.get("score")) or 0,
                    "status": candidate.get("status"),
                    "probable_player": candidate.get("probablePlayer"),
                    "player_bias": candidate.get("playerBias"),
                    "entry_spot": _row_to_float(spot),
                    "entry_option_ltp": entry_option_ltp,
                    "entry_iv": entry_iv_value,
                    "trigger": candidate.get("trigger"),
                    "invalidation": candidate.get("invalidation"),
                    "risk_flags": "; ".join(candidate.get("riskFlags") or []),
                    "memory_status": candidate.get("memoryStatus"),
                    "repeat_count": int(candidate.get("repeatCount") or 0),
                    "source_payload": payload_json,
                }).scalar()
                if result:
                    inserted += 1
        summary.update({
            "enabled": True,
            "insertedSignals": inserted,
            "outcomesUpdated": int((outcome_summary or {}).get("updated") or 0),
        })
    except Exception as exc:
        summary["error"] = f"option buying memory write failed: {type(exc).__name__}: {exc}"
    return summary


