    summary = {"enabled": False, "storedCandidates": 0, "payloadCached": False, "error": ""}
    try:
        ensure_option_buying_ai_tables()
    except Exception as exc:
        summary["error"] = f"option buying result table init failed: {type(exc).__name__}: {exc}"
