    symbol = normalize_index_symbol((payload or {}).get("symbol") or "NIFTY")
    expiry = str((payload or {}).get("expiry") or "")
    latest_ts = str((payload or {}).get("timestamp") or "")
    trade_date = _effective_trade_date_for_signal((payload or {}).get("date"), latest_ts)
    spot = _row_to_float((payload or {}).get("spot"))
    atm = _row_to_float((payload or {}).get("atm"))
    futures = (payload or {}).get("futures") or {}
    candidates = (payload or {}).get("candidates") or []

