# ============================== V11.8.2 FAST SNAPSHOT OVERRIDE ==============================
# Main loading problem fix:
# The initial /api/snapshot used full-day chart calculation. On a large DB this can
# hang before dates/expiry appear. V11.8.2 adds a lightweight snapshot for
# Numerical/EOD/OptionBuying tabs and keeps full-day chart calculation only for
# Graphical tab when explicitly requested.

def read_latest_futures_point_fast(symbol, trade_date):
    """Read latest futures snapshot for top summary cards without full-day futures chart scan."""
    if symbol not in SYMBOLS or not trade_date:
        return {}
    try:
        prefix = trade_date_to_nse_prefix(trade_date)
        date_attempts = []
        if prefix:
            date_attempts.append(('"timestamp" LIKE :ts_prefix', {"ts_prefix": prefix + "%"}))
        date_attempts.append(('CAST("timestamp" AS DATE) = CAST(:trade_date AS DATE)', {"trade_date": trade_date}))

        for date_sql, params in date_attempts:
            ts_df = pd.read_sql(
                sqlalchemy.text(f'SELECT DISTINCT "timestamp" FROM "{symbol}" WHERE {date_sql}'),
                FUTURES_ENGINE,
                params=params,
            )
            if ts_df.empty or "timestamp" not in ts_df.columns:
                continue
            timestamps = sorted(
                {normalize_timestamp(v) for v in ts_df["timestamp"].dropna().astype(str).tolist()},
                key=parse_timestamp,
                reverse=True,
            )
            if not timestamps:
                continue
            latest_ts = timestamps[0]
            previous_ts = timestamps[1] if len(timestamps) > 1 else None

            df = pd.read_sql(
                sqlalchemy.text(f'SELECT * FROM "{symbol}" WHERE "timestamp" = :ts'),
                FUTURES_ENGINE,
                params={"ts": latest_ts},
            )
            prev_df = pd.DataFrame()
            if previous_ts:
                prev_df = pd.read_sql(
                    sqlalchemy.text(f'SELECT * FROM "{symbol}" WHERE "timestamp" = :ts'),
                    FUTURES_ENGINE,
                    params={"ts": previous_ts},
                )

            if df.empty:
                continue

            price_col = find_column(df, ("lastPrice", "ltp", "closePrice", "vwap"))
            oi_col = find_column(df, ("openInterest", "openinterest", "oi"))
            volume_col = find_column(df, ("tradedContracts", "volume", "totalTradedVolume", "numberOfContractsTraded"))
            change_oi_col = find_column(df, ("changeinOI", "changeinOpenInterest", "changeInOpenInterest", "coi", "changeOI"))
            spot_col = find_column(df, ("spotPrice", "underlyingValue"))
            expiry_col = find_column(df, ("expiryDate", "expiry"))

            price = first_valid_number(df[price_col].tolist()) if price_col else None
            spot = first_valid_number(df[spot_col].tolist()) if spot_col else None
            oi = aggregate_sum_values(df[oi_col].tolist()) if oi_col else None
            volume = aggregate_sum_values(df[volume_col].tolist()) if volume_col else None
            coi = aggregate_sum_values(df[change_oi_col].tolist()) if change_oi_col else None

            prev_price = first_valid_number(prev_df[price_col].tolist()) if not prev_df.empty and price_col and price_col in prev_df.columns else None
            prev_oi = aggregate_sum_values(prev_df[oi_col].tolist()) if not prev_df.empty and oi_col and oi_col in prev_df.columns else None
            prev_volume = aggregate_sum_values(prev_df[volume_col].tolist()) if not prev_df.empty and volume_col and volume_col in prev_df.columns else None
            prev_coi = aggregate_sum_values(prev_df[change_oi_col].tolist()) if not prev_df.empty and change_oi_col and change_oi_col in prev_df.columns else None

            basis = price - spot if price is not None and spot not in (None, 0) else None
            basis_pct = (basis / spot) * 100.0 if basis is not None and spot not in (None, 0) else None
            coi_vol_pct = safe_ratio_pct(coi, volume)
            prev_coi_vol_pct = safe_ratio_pct(prev_coi, prev_volume)

            return {
                "futureTimestamp": latest_ts,
                "futureExpiry": str(df.iloc[0].get(expiry_col, "")) if expiry_col else "",
                "futurePrice": price,
                "futurePriceRoc": pct_change(price, prev_price),
                "futureOpenInterest": oi,
                "futureOiRoc": pct_change(oi, prev_oi),
                "futureVolume": volume,
                "futureVolumeRoc": pct_change(volume, prev_volume),
                "futureCoi": coi,
                "futureCoiRoc": pct_change(coi, prev_coi),
                "futureCoiVolPct": coi_vol_pct,
                "futureCoiVolRoc": pct_change(coi_vol_pct, prev_coi_vol_pct),
                "futureSpot": spot,
                "basis": basis,
                "basisPct": basis_pct,
            }
    except Exception:
        return {}
    return {}


def _v11811_future_oi_context(symbol, trade_date=None):
    """Current/previous/day-high futures OI for top card and reduction popup."""
    try:
        symbol = normalize_index_symbol(symbol or "NIFTY")
        df = read_futures_table_for_date(symbol, trade_date)
        if df is None or df.empty or "timestamp" not in df.columns:
            return {}
        oi_col = find_column(df, ("openInterest", "openinterest", "oi"))
        expiry_col = find_column(df, ("expiryDate", "expiry"))
        if not oi_col:
            return {}
        timestamps = sorted({normalize_timestamp(v) for v in df["timestamp"].dropna().astype(str).tolist()}, key=parse_timestamp)
        if not timestamps:
            return {}

        def oi_at(ts):
            frame = df[df["timestamp"].map(normalize_timestamp) == ts]
            if frame.empty:
                return None, ""
            expiry_value = str(frame.iloc[0].get(expiry_col, "")) if expiry_col else ""
            return aggregate_sum_values(frame[oi_col].tolist()), expiry_value

        current_ts = timestamps[-1]
        previous_ts = timestamps[-2] if len(timestamps) > 1 else ""
        current_oi, current_expiry = oi_at(current_ts)
        previous_oi, _ = oi_at(previous_ts) if previous_ts else (None, "")

        best = None
        for ts in timestamps:
            value, expiry_value = oi_at(ts)
            if value is None:
                continue
            if best is None or value > best["value"]:
                best = {"value": value, "timestamp": ts, "time": timestamp_time_label(ts), "expiry": expiry_value}

        change = current_oi - previous_oi if current_oi is not None and previous_oi is not None else None
        return {
            "futureOiCurrent": current_oi,
            "futureOiPrevious": previous_oi,
            "futureOiChange": change,
            "futureOiChangePct": pct_change(current_oi, previous_oi),
            "futureOiTimestamp": current_ts,
            "futureOiPreviousTimestamp": previous_ts,
            "futureOiTime": timestamp_time_label(current_ts),
            "futureOiPreviousTime": timestamp_time_label(previous_ts) if previous_ts else "",
            "futureOiExpiry": current_expiry,
            "futureOiDayHigh": best or {},
            "futureOiDayPoints": len(timestamps),
        }
    except Exception:
        return {}


def _v11811_enrich_future_oi_context(payload, symbol=None, trade_date=None):
    if not isinstance(payload, dict):
        return payload
    ctx = _v11811_future_oi_context(symbol or payload.get("symbol"), trade_date or payload.get("date"))
    if not ctx:
        return payload
    fut = payload.get("futuresLatest") or {}
    if isinstance(fut, dict):
        fut.update(ctx)
        payload["futuresLatest"] = fut
    drops = payload.get("optionExtremeDrops") or []
    cur = ctx.get("futureOiCurrent")
    prev = ctx.get("futureOiPrevious")
    if cur is not None and prev is not None and cur < prev:
        drops.append({
            "key": "futureOi",
            "label": "Future OI",
            "timestamp": ctx.get("futureOiTimestamp") or payload.get("timestamp") or "",
            "previousTimestamp": ctx.get("futureOiPreviousTimestamp") or payload.get("previousTimestamp") or "",
            "current": {"value": cur, "time": ctx.get("futureOiTime") or ""},
            "previous": {"value": prev, "time": ctx.get("futureOiPreviousTime") or ""},
            "currentValue": cur,
            "previousValue": prev,
            "change": cur - prev,
            "changePct": ctx.get("futureOiChangePct"),
        })
    payload["optionExtremeDrops"] = drops
    return payload

def build_dashboard_payload_lite(symbol, band, trade_date=None, expiry=None):
    """Fast latest-snapshot payload for startup and non-graphical tabs."""
    symbol = normalize_index_symbol(symbol or "NIFTY")
    available_dates = get_available_dates(symbol)
    if not trade_date and available_dates:
        trade_date = available_dates[0]

    available_expiries = get_available_expiries_for_date(symbol, trade_date)
    if not expiry and available_expiries:
        expiry = available_expiries[0]

    df, latest_ts = read_latest_option_snapshot_for_date_expiry(symbol, trade_date, expiry)
    if df.empty:
        return {
            "symbol": symbol,
            "date": trade_date,
            "expiry": expiry,
            "availableDates": available_dates,
            "availableExpiries": available_expiries,
            "error": f"No latest option rows found for {trade_date or 'selected date'} / expiry {expiry or 'selected expiry'}",
            "rows": [],
            "charts": {},
            "fastLite": True,
        }

    strike_col = find_column(df, ("strikePrice", "strike"))
    opt_col = find_column(df, ("optionType", "type"))
    spot_col = find_column(df, ("spotPrice", "underlyingValue"))
    expiry_col = find_column(df, ("expiryDate", "expiry"))

    if not strike_col or not opt_col:
        return {
            "symbol": symbol,
            "date": trade_date,
            "expiry": expiry,
            "availableDates": available_dates,
            "availableExpiries": available_expiries,
            "error": "Required columns strikePrice/optionType not found",
            "rows": [],
            "charts": {},
            "fastLite": True,
        }

    df = df.copy()
    df["_strike"] = df[strike_col].map(to_number)
    df["_optionType"] = df[opt_col].map(lambda value: str(value).upper().strip())

    spot = first_valid_number(df[spot_col].tolist()) if spot_col else None
    strikes = [to_number(v) for v in df[strike_col].tolist()]
    atm = nearest_atm(strikes, spot)
    step = infer_strike_step(strikes)
    wanted = {atm + (i * step) for i in range(-int(band), int(band) + 1)} if atm is not None else set()

    # Find previous timestamp for ROC, but only one snapshot, not full day.
    previous_ts = None
    previous_df = pd.DataFrame()
    try:
        prefix = trade_date_to_nse_prefix(trade_date)
        date_sql = '"timestamp" LIKE :ts_prefix' if prefix else 'CAST("timestamp" AS DATE) = CAST(:trade_date AS DATE)'
        params = {"ts_prefix": prefix + "%"} if prefix else {"trade_date": trade_date}
        ts_df = pd.read_sql(
            sqlalchemy.text(f'SELECT DISTINCT "timestamp" FROM "{symbol}" WHERE {date_sql}'),
            ENGINE,
            params=params,
        )
        timestamps = sorted(
            {normalize_timestamp(v) for v in ts_df["timestamp"].dropna().astype(str).tolist()},
            key=parse_timestamp,
            reverse=True,
        )
        if latest_ts in timestamps:
            idx = timestamps.index(latest_ts)
            if idx + 1 < len(timestamps):
                previous_ts = timestamps[idx + 1]
        elif len(timestamps) > 1:
            previous_ts = timestamps[1]
        if previous_ts:
            previous_df = read_rows_for_timestamps(symbol, [previous_ts])
            previous_df = filter_frame_by_expiry(previous_df, expiry)
    except Exception:
        previous_df = pd.DataFrame()

    metric_cols = {key: find_column(df, config["aliases"]) for key, config in METRICS.items()}
    change_oi_col = find_column(df, ("changeinOI", "changeinOpenInterest", "changeInOpenInterest", "coi", "changeOI"))

    previous_lookup = {}
    if not previous_df.empty:
        p_strike_col = find_column(previous_df, ("strikePrice", "strike"))
        p_opt_col = find_column(previous_df, ("optionType", "type"))
        if p_strike_col and p_opt_col:
            for _, prow in previous_df.iterrows():
                previous_lookup[(to_number(prow.get(p_strike_col)), str(prow.get(p_opt_col, "")).upper())] = prow

    rows = []
    for _, row in df.iterrows():
        strike = to_number(row.get(strike_col))
        if strike not in wanted:
            continue
        option_type = str(row.get(opt_col, "")).upper()
        if option_type not in {"CE", "PE"}:
            continue

        prev_row = previous_lookup.get((strike, option_type))
        item = {
            "symbol": symbol,
            "timestamp": latest_ts,
            "previousTimestamp": previous_ts,
            "expiryDate": str(row.get(expiry_col, "")) if expiry_col else "",
            "strike": strike,
            "optionType": option_type,
            "distance": int(round((strike - atm) / step)) if atm and step else 0,
            "atm": strike == atm,
        }

        for key, col in metric_cols.items():
            current = to_number(row.get(col)) if col else None
            prev_col = find_column(previous_df, METRICS[key]["aliases"]) if not previous_df.empty else col
            previous = to_number(prev_row.get(prev_col)) if prev_row is not None and prev_col else None
            item[key] = current
            item[f"{key}Roc"] = pct_change(current, previous)

        current_coi = to_number(row.get(change_oi_col)) if change_oi_col else None
        prev_coi_col = find_column(previous_df, ("changeinOI", "changeinOpenInterest", "changeInOpenInterest", "coi", "changeOI")) if not previous_df.empty else change_oi_col
        previous_coi = to_number(prev_row.get(prev_coi_col)) if prev_row is not None and prev_coi_col else None
        current_volume = item.get("volume")
        prev_vol_col = find_column(previous_df, METRICS["volume"]["aliases"]) if not previous_df.empty else metric_cols.get("volume")
        previous_volume = to_number(prev_row.get(prev_vol_col)) if prev_row is not None and prev_vol_col else None
        item["coi"] = current_coi
        item["coiVolPct"] = safe_ratio_pct(current_coi, current_volume)
        item["coiVolRoc"] = pct_change(item["coiVolPct"], safe_ratio_pct(previous_coi, previous_volume))
        rows.append(item)

    rows.sort(key=lambda item: (item["strike"], item["optionType"]))

    latest_future = read_latest_futures_point_fast(symbol, trade_date)
    futures_fields = (
        "futureTimestamp", "futureExpiry", "futurePrice", "futurePriceRoc",
        "futureOpenInterest", "futureOiRoc", "futureVolume", "futureVolumeRoc",
        "futureCoi", "futureCoiRoc", "futureCoiVolPct", "futureCoiVolRoc",
        "basis", "basisPct"
    )
    for item in rows:
        for field in futures_fields:
            item[field] = latest_future.get(field)

    return {
        "symbol": symbol,
        "date": trade_date,
        "expiry": expiry,
        "availableDates": available_dates,
        "availableExpiries": available_expiries,
        "generatedAt": datetime.now(IST).strftime("%d-%b-%Y %H:%M:%S"),
        "timestamp": latest_ts,
        "previousTimestamp": previous_ts,
        "firstTimestamp": latest_ts,
        "lastTimestamp": latest_ts,
        "chartPoints": 0,
        "futuresPoints": 1 if latest_future else 0,
        "futuresLatest": latest_future,
        "spot": spot,
        "atm": atm,
        "strikeStep": step,
        "band": int(band),
        "rows": rows,
        "charts": {},
        "fastLite": True,
    }


