def read_eod_cached_payload(symbol, trade_date=None, expiry=None):
    """V11.3: Cache intentionally disabled. EOD tab reads directly from raw DB tables."""
    return None


def build_eod_participation_payload(symbol, trade_date=None, expiry=None):
    """
    V11.3 RAW-DB-ONLY EOD Participation payload.

    It calculates the EOD view directly from raw imported PostgreSQL tables on every
    dashboard request. This removes dependence on nse_eod_payload_cache and avoids
    stale/blank-expiry cache rows.
    """
    symbol = normalize_index_symbol(symbol or "NIFTY")
    if symbol not in EOD_INDEX_SYMBOLS:
        symbol = "NIFTY"

    dates = discover_eod_dates()
    if not dates:
        return {
            "symbol": symbol,
            "date": trade_date,
            "availableDates": [],
            "availableExpiries": [],
            "error": "No raw EOD rows found in PostgreSQL. Run the EOD import script first.",
            "loadedFromRawDbTables": False,
        }

    if not trade_date or trade_date not in dates:
        trade_date = dates[0]

    try:
        core = build_eod_day_core(symbol, trade_date, expiry=expiry)
        available_expiries = (core.get("strikes") or {}).get("availableExpiries") or eod_available_expiries(symbol, trade_date)
        selected_expiry = ((core.get("strikes") or {}).get("expiry") or expiry or "")
        db_volume_spurts = read_db_volume_spurts_for_date(trade_date)

        return {
            "symbol": symbol,
            "date": trade_date,
            "availableDates": dates,
            "availableExpiries": available_expiries,
            "expiry": selected_expiry,
            "generatedAt": datetime.now(IST).strftime("%d-%b-%Y %H:%M:%S"),
            "error": (core.get("strikes") or {}).get("error") or "",
            "participantOiFile": core.get("participantOiFile"),
            "participantVolFile": core.get("participantVolFile"),
            "participants": core.get("participants") or [],
            "bigMoney": core.get("bigMoney") or {},
            "decision": core.get("decision") or {},
            "spot": (core.get("strikes") or {}).get("spot"),
            "previousDate": core.get("previousDate"),
            "strikeRows": (core.get("strikes") or {}).get("rows") or [],
            "topCe": (core.get("strikes") or {}).get("topCe") or [],
            "topPe": (core.get("strikes") or {}).get("topPe") or [],
            "walls": (core.get("strikes") or {}).get("walls") or {},
            "futures": core.get("futures") or {},
            "cash": core.get("cash") or {},
            "cmMarket": core.get("cmMarket") or {},
            "view360": core.get("view360") or {},
            "volumeSpurts": db_volume_spurts or {},
            "memory": build_eod_memory(symbol, dates),
            "loadedFromRawDbTables": True,
            "source": "PostgreSQL raw EOD tables",
            "disclaimer": "Loaded directly from PostgreSQL raw EOD tables; no payload cache and no EOD folder parsing. Participant OI/volume remains participant-wise, not strike-wise; strike player labels are probabilistic.",
        }
    except Exception as exc:
        return {
            "symbol": symbol,
            "date": trade_date,
            "availableDates": dates,
            "availableExpiries": eod_available_expiries(symbol, trade_date),
            "error": f"Raw DB EOD calculation failed: {type(exc).__name__}: {exc}",
            "loadedFromRawDbTables": False,
        }



# ============================== V11.4 FAST RAW-DB MEMORY OVERRIDE ==============================
# V11.3 was raw-DB-only, but it recalculated full memory for every available EOD date.
# That is slow when 200+ cash-history dates are present. V11.4 keeps raw DB reading
# for the selected EOD date, but limits memory validation to recent processed rows
# or the latest few participant+FO dates.

def read_memory_validation_fast(symbol, trade_date=None, max_rows=8):
    """Read precomputed memory validation from DB if available."""
    try:
        sql = """
            SELECT signal_date, validation_date, symbol, expected_bias, big_money_score,
                   signal_spot, next_spot, move_pts, move_pct, ce_wall, pe_wall,
                   decision, validation, reason
            FROM nse_360_memory_validation
            WHERE UPPER(symbol) = UPPER(:symbol)
        """
        params = {"symbol": symbol, "limit": int(max_rows)}
        if trade_date:
            sql += " AND signal_date <= CAST(:trade_date AS DATE)"
            params["trade_date"] = trade_date
        sql += " ORDER BY signal_date DESC LIMIT :limit"

        df = _raw_db_df(sql, params)
        if df.empty:
            return []
        rows = []
        for _, row in df.iterrows():
            rows.append({
                "signalDate": pd.to_datetime(row.get("signal_date")).strftime("%Y-%m-%d") if row.get("signal_date") is not None else "",
                "nextDate": pd.to_datetime(row.get("validation_date")).strftime("%Y-%m-%d") if row.get("validation_date") is not None else "",
                "symbol": str(row.get("symbol") or symbol),
                "bigMoneyDirection": str(row.get("expected_bias") or ""),
                "bigMoneyScore": to_number(row.get("big_money_score")),
                "signalSpot": to_number(row.get("signal_spot")),
                "nextSpot": to_number(row.get("next_spot")),
                "movePts": to_number(row.get("move_pts")),
                "movePct": to_number(row.get("move_pct")),
                "ceWall": to_number(row.get("ce_wall")),
                "peWall": to_number(row.get("pe_wall")),
                "decision": str(row.get("decision") or ""),
                "validation": str(row.get("validation") or ""),
                "reason": str(row.get("reason") or ""),
            })
        return rows
    except Exception:
        return []


def discover_eod_decision_dates_fast(symbol, trade_date=None, max_dates=9):
    """Return only recent dates that have both participant OI and FO bhavcopy rows."""
    try:
        sql = """
            SELECT DISTINCT p.trade_date
            FROM nse_participant_oi_raw p
            WHERE EXISTS (
                SELECT 1
                FROM nse_fo_bhavcopy_raw f
                WHERE f.trade_date = p.trade_date
                  AND UPPER(f.symbol) = UPPER(:symbol)
            )
        """
        params = {"symbol": symbol, "limit": int(max_dates)}
        if trade_date:
            sql += " AND p.trade_date <= CAST(:trade_date AS DATE)"
            params["trade_date"] = trade_date
        sql += " ORDER BY p.trade_date DESC LIMIT :limit"

        df = _raw_db_df(sql, params)
        if df.empty:
            return []
        out = []
        for value in df["trade_date"].tolist():
            try:
                out.append(pd.to_datetime(value).strftime("%Y-%m-%d"))
            except Exception:
                pass
        return sorted(set(out))
    except Exception:
        return []


def build_eod_memory_fast(symbol, all_dates, trade_date=None, max_checks=6):
    """
    Fast memory layer:
    1) Prefer precomputed nse_360_memory_validation rows.
    2) Otherwise calculate only last few participant+FO sessions, not 200+ cash-history dates.
    """
    rows = read_memory_validation_fast(symbol, trade_date=trade_date, max_rows=max_checks)
    if rows:
        return rows

    decision_dates = discover_eod_decision_dates_fast(symbol, trade_date=trade_date, max_dates=max_checks + 1)
    if len(decision_dates) < 2:
        # Fallback to the last few dates from the supplied list only.
        usable = sorted([d for d in (all_dates or []) if (not trade_date or d <= trade_date)])
        decision_dates = usable[-(max_checks + 1):]

    if len(decision_dates) < 2:
        return []

    try:
        return build_eod_memory(symbol, decision_dates)
    except Exception:
        return []


# Replace the V11.3 raw-DB-only payload with a fast-memory version.
def build_eod_participation_payload(symbol, trade_date=None, expiry=None):
    """
    V11.4 RAW-DB-ONLY + FAST MEMORY.

    Current selected date is still calculated directly from raw PostgreSQL tables.
    Historical memory is no longer recalculated for every stored cash-history date,
    so the EOD Participation tab should load much faster.
    """
    symbol = normalize_index_symbol(symbol or "NIFTY")
    if symbol not in EOD_INDEX_SYMBOLS:
        symbol = "NIFTY"

    dates = discover_eod_dates()
    if not dates:
        return {
            "symbol": symbol,
            "date": trade_date,
            "availableDates": [],
            "availableExpiries": [],
            "error": "No raw EOD rows found in PostgreSQL. Run the EOD import script first.",
            "loadedFromRawDbTables": False,
        }

    if not trade_date or trade_date not in dates:
        trade_date = dates[0]

    try:
        core = build_eod_day_core(symbol, trade_date, expiry=expiry)
        available_expiries = (core.get("strikes") or {}).get("availableExpiries") or eod_available_expiries(symbol, trade_date)
        selected_expiry = ((core.get("strikes") or {}).get("expiry") or expiry or "")
        db_volume_spurts = read_db_volume_spurts_for_date(trade_date)

        return {
            "symbol": symbol,
            "date": trade_date,
            "availableDates": dates,
            "availableExpiries": available_expiries,
            "expiry": selected_expiry,
            "generatedAt": datetime.now(IST).strftime("%d-%b-%Y %H:%M:%S"),
            "error": (core.get("strikes") or {}).get("error") or "",
            "participantOiFile": core.get("participantOiFile"),
            "participantVolFile": core.get("participantVolFile"),
            "participants": core.get("participants") or [],
            "bigMoney": core.get("bigMoney") or {},
            "decision": core.get("decision") or {},
            "spot": (core.get("strikes") or {}).get("spot"),
            "previousDate": core.get("previousDate"),
            "strikeRows": (core.get("strikes") or {}).get("rows") or [],
            "topCe": (core.get("strikes") or {}).get("topCe") or [],
            "topPe": (core.get("strikes") or {}).get("topPe") or [],
            "walls": (core.get("strikes") or {}).get("walls") or {},
            "futures": core.get("futures") or {},
            "cash": core.get("cash") or {},
            "cmMarket": core.get("cmMarket") or {},
            "view360": core.get("view360") or {},
            "volumeSpurts": db_volume_spurts or {},
            "memory": build_eod_memory_fast(symbol, dates, trade_date=trade_date, max_checks=6),
            "loadedFromRawDbTables": True,
            "fastMemoryMode": True,
            "source": "PostgreSQL raw EOD tables",
            "disclaimer": "Loaded directly from PostgreSQL raw EOD tables; no payload cache and no EOD folder parsing. Memory validation is limited/precomputed for fast loading.",
        }
    except Exception as exc:
        return {
            "symbol": symbol,
            "date": trade_date,
            "availableDates": dates,
            "availableExpiries": eod_available_expiries(symbol, trade_date),
            "error": f"Raw DB EOD calculation failed: {type(exc).__name__}: {exc}",
            "loadedFromRawDbTables": False,
        }



# ============================== V11.5 PROCESSED-RESULT-ONLY EOD OVERRIDE ==============================
# Fastest stable design:
#   Importer does heavy EOD calculation once after market close.
#   Dashboard reads only compact processed result tables.
#   Dashboard does NOT read raw 35k-row bhavcopy tables and does NOT read stale payload cache.

def _json_payload(value, default=None):
    if default is None:
        default = {}
    if value is None:
        return default
    if isinstance(value, dict):
        return value
    try:
        if pd.isna(value):
            return default
    except Exception:
        pass
    if isinstance(value, str):
        try:
            parsed = json.loads(value)
            return parsed if isinstance(parsed, dict) else default
        except Exception:
            return default
    return default


def _result_df(sql, params=None):
    try:
        with EOD_ANALYTICS_ENGINE.connect() as conn:
            return pd.read_sql(sqlalchemy.text(sql), conn, params=params or {})
    except Exception:
        return pd.DataFrame()


def _fmt_date(value):
    try:
        return pd.to_datetime(value).strftime("%Y-%m-%d")
    except Exception:
        return str(value or "")


def _pick_expiry_row(df, expiry):
    if df is None or df.empty:
        return None
    if expiry:
        target = expiry_key(expiry)
        for _, row in df.iterrows():
            if expiry_key(row.get("expiry_date")) == target:
                return row
    # Prefer non-blank expiry rows.
    for _, row in df.iterrows():
        if str(row.get("expiry_date") or "").strip():
            return row
    return df.iloc[0]


def _available_dates_from_results():
    queries = [
        "SELECT DISTINCT trade_date FROM nse_360_decision_daily",
        "SELECT DISTINCT trade_date FROM nse_participant_bias_daily",
        "SELECT DISTINCT trade_date FROM nse_cm_participation_regime_daily",
    ]
    dates = set()
    for q in queries:
        df = _result_df(q)
        if not df.empty and "trade_date" in df.columns:
            for value in df["trade_date"].dropna().tolist():
                dates.add(_fmt_date(value))
    return sorted(dates, reverse=True)


def _available_expiries_from_results(symbol, trade_date):
    df = _result_df(
        """
        SELECT DISTINCT expiry_date
        FROM nse_360_decision_daily
        WHERE trade_date = CAST(:trade_date AS DATE)
          AND UPPER(symbol) = UPPER(:symbol)
        ORDER BY expiry_date
        """,
        {"trade_date": trade_date, "symbol": symbol},
    )
    if df.empty:
        df = _result_df(
            """
            SELECT DISTINCT expiry_date
            FROM nse_option_wall_daily
            WHERE trade_date = CAST(:trade_date AS DATE)
              AND UPPER(symbol) = UPPER(:symbol)
            ORDER BY expiry_date
            """,
            {"trade_date": trade_date, "symbol": symbol},
        )
    if df.empty:
        return []
    out = []
    for value in df["expiry_date"].dropna().astype(str).tolist():
        if value and value not in out:
            out.append(value)
    return out


def _participants_from_results(trade_date):
    df = _result_df(
        """
        SELECT *
        FROM nse_participant_bias_daily
        WHERE trade_date = CAST(:trade_date AS DATE)
        ORDER BY CASE UPPER(participant)
            WHEN 'FII' THEN 1
            WHEN 'PROP' THEN 2
            WHEN 'DII' THEN 3
            WHEN 'CLIENT' THEN 4
            WHEN 'TOTAL' THEN 5
            ELSE 9
        END
        """,
        {"trade_date": trade_date},
    )
    rows = []
    for _, row in df.iterrows():
        payload = _json_payload(row.get("payload"), {})
        if payload:
            item = dict(payload)
        else:
            item = {}
        item.update({
            "participant": str(row.get("participant") or item.get("participant") or ""),
            "rawParticipant": str(row.get("raw_participant") or item.get("rawParticipant") or row.get("participant") or ""),
            "direction": str(row.get("direction") or item.get("direction") or "Neutral"),
            "score": to_number(row.get("score")),
            "scoreChange": to_number(row.get("score_change")),
            "futureNet": to_number(row.get("future_net")),
            "futureNetChange": to_number(row.get("future_net_change")),
            "futureScore": to_number(row.get("future_score")),
            "optionScore": to_number(row.get("option_score")),
            "buyerScore": to_number(row.get("buyer_score")),
            "writerScore": to_number(row.get("writer_score")),
            "callShortMinusPutShort": to_number(row.get("call_short_minus_put_short")),
            "indexOptionVolume": to_number(row.get("index_option_volume")),
            "indexOptionVolumeScore": to_number(row.get("index_option_volume_score")),
        })
        rows.append(item)
    return rows


def _participant_attribution_from_results(symbol, trade_date, expiry=None, limit=120):
    symbol = normalize_index_symbol(symbol or "NIFTY")
    expiry_rows = []
    strike_rows = []

    exp_df = _result_df(
        """
        SELECT *
        FROM nse_participant_expiry_attribution_daily
        WHERE trade_date = CAST(:trade_date AS DATE)
        ORDER BY
          CASE UPPER(participant) WHEN 'FII' THEN 1 WHEN 'PROP' THEN 2 ELSE 9 END,
          estimated_contracts DESC NULLS LAST
        """,
        {"trade_date": trade_date},
    )
    for _, row in exp_df.iterrows() if not exp_df.empty else []:
        payload = _json_payload(row.get("payload"), {})
        item = dict(payload) if payload else {}
        item.update({
            "participant": str(row.get("participant") or item.get("participant") or ""),
            "action": str(row.get("action") or item.get("action") or ""),
            "symbol": str(row.get("symbol") or item.get("symbol") or ""),
            "expiry": str(row.get("expiry_date") or item.get("expiry") or ""),
            "estimatedContracts": to_number(row.get("estimated_contracts")),
            "candidateChangeOi": to_number(row.get("candidate_change_oi")),
            "candidateVolume": to_number(row.get("candidate_volume")),
            "maxActionScore": to_number(row.get("max_action_score")),
            "topStrikes": str(row.get("top_strikes") or item.get("topStrikes") or ""),
            "topConfidence": str(row.get("top_confidence") or item.get("topConfidence") or ""),
        })
        expiry_rows.append(item)

    params = {"trade_date": trade_date, "symbol": symbol, "limit": int(limit)}
    sql = """
        SELECT *
        FROM nse_participant_strike_attribution_daily
        WHERE trade_date = CAST(:trade_date AS DATE)
          AND UPPER(symbol) = UPPER(:symbol)
    """
    if expiry:
        sql += " AND expiry_date = :expiry"
        params["expiry"] = str(expiry)
    sql += """
        ORDER BY
          shown_in_top_report DESC,
          CASE UPPER(participant) WHEN 'FII' THEN 1 WHEN 'PROP' THEN 2 ELSE 9 END,
          action,
          action_rank NULLS LAST,
          estimated_participant_contracts DESC NULLS LAST
        LIMIT :limit
    """
    strike_df = _result_df(sql, params)
    if strike_df.empty and expiry:
        params = {"trade_date": trade_date, "symbol": symbol, "limit": int(limit)}
        strike_df = _result_df(
            """
            SELECT *
            FROM nse_participant_strike_attribution_daily
            WHERE trade_date = CAST(:trade_date AS DATE)
              AND UPPER(symbol) = UPPER(:symbol)
            ORDER BY
              shown_in_top_report DESC,
              CASE UPPER(participant) WHEN 'FII' THEN 1 WHEN 'PROP' THEN 2 ELSE 9 END,
              action,
              action_rank NULLS LAST,
              estimated_participant_contracts DESC NULLS LAST
            LIMIT :limit
            """,
            params,
        )

    for _, row in strike_df.iterrows() if not strike_df.empty else []:
        payload = _json_payload(row.get("payload"), {})
        item = dict(payload) if payload else {}
        item.update({
            "participant": str(row.get("participant") or item.get("participant") or ""),
            "rawParticipant": str(row.get("raw_participant") or item.get("rawParticipant") or ""),
            "action": str(row.get("action") or item.get("action") or ""),
            "actionMeaning": str(row.get("action_meaning") or item.get("actionMeaning") or ""),
            "sourceChangeColumn": str(row.get("source_change_column") or item.get("sourceChangeColumn") or ""),
            "actionRank": to_number(row.get("action_rank")),
            "shownInTopReport": bool(row.get("shown_in_top_report")) if row.get("shown_in_top_report") is not None else item.get("shownInTopReport"),
            "participantActionContracts": to_number(row.get("participant_action_contracts")),
            "symbol": str(row.get("symbol") or item.get("symbol") or ""),
            "expiry": str(row.get("expiry_date") or item.get("expiry") or ""),
            "strike": to_number(row.get("strike")),
            "side": str(row.get("side") or item.get("side") or ""),
            "estimatedParticipantContracts": to_number(row.get("estimated_participant_contracts")),
            "shareOfParticipantActionPct": to_number(row.get("share_of_participant_action_pct")),
            "candidateChangeOi": to_number(row.get("candidate_change_oi")),
            "candidateOi": to_number(row.get("candidate_oi")),
            "candidateVolume": to_number(row.get("candidate_volume")),
            "close": to_number(row.get("close")),
            "priceChange": to_number(row.get("price_change")),
            "underlying": to_number(row.get("underlying")),
            "build": str(row.get("build") or item.get("build") or ""),
            "actor": str(row.get("actor") or item.get("actor") or ""),
            "actionScore": to_number(row.get("action_score")),
            "confidence": str(row.get("confidence") or item.get("confidence") or ""),
            "exactPriceConfirm": bool(row.get("exact_price_confirm")) if row.get("exact_price_confirm") is not None else item.get("exactPriceConfirm"),
            "modelNote": str(row.get("model_note") or item.get("modelNote") or ""),
        })
        strike_rows.append(item)

    return {
        "modelVersion": "participant_strike_attribution_v1",
        "isInferred": True,
        "source": "db:nse_participant_expiry_attribution_daily + nse_participant_strike_attribution_daily",
        "note": "Participant-wise OI is actual NSE data; strike attribution is inferred from participant OI changes plus FO bhavcopy strike evidence.",
        "expiryRows": expiry_rows,
        "topStrikeRows": strike_rows,
        "fullRowCount": len(strike_rows),
    }


def _walls_from_results(symbol, trade_date, expiry):
    df = _result_df(
        """
        SELECT *
        FROM nse_option_wall_daily
        WHERE trade_date = CAST(:trade_date AS DATE)
          AND UPPER(symbol) = UPPER(:symbol)
          AND expiry_date = :expiry
        ORDER BY wall_kind, side, activity_score DESC NULLS LAST
        """,
        {"trade_date": trade_date, "symbol": symbol, "expiry": str(expiry or "")},
    )
    if df.empty and expiry:
        # Fallback: same date/symbol, any expiry.
        df = _result_df(
            """
            SELECT *
            FROM nse_option_wall_daily
            WHERE trade_date = CAST(:trade_date AS DATE)
              AND UPPER(symbol) = UPPER(:symbol)
            ORDER BY expiry_date, wall_kind, side, activity_score DESC NULLS LAST
            """,
            {"trade_date": trade_date, "symbol": symbol},
        )

    walls = {}
    top_ce, top_pe, strike_rows = [], [], []
    if df.empty:
        return walls, top_ce, top_pe, strike_rows

    for _, row in df.iterrows():
        payload = _json_payload(row.get("payload"), {})
        item = dict(payload) if payload else {}
        item.update({
            "side": str(row.get("side") or item.get("side") or ""),
            "strike": to_number(row.get("strike")),
            "build": str(row.get("build") or item.get("build") or ""),
            "meaning": str(row.get("meaning") or item.get("meaning") or ""),
            "activityScore": to_number(row.get("activity_score")),
            "oi": to_number(row.get("oi")),
            "coi": to_number(row.get("coi")),
            "volume": to_number(row.get("volume")),
            "close": to_number(row.get("close")),
            "priceChange": to_number(row.get("price_change")),
            "wallKind": str(row.get("wall_kind") or item.get("wallKind") or ""),
        })
        strike_rows.append(item)

        wk = str(row.get("wall_kind") or "").lower()
        side = str(row.get("side") or "").upper()
        if wk == "resistance":
            walls["resistance"] = item
        elif wk == "support":
            walls["support"] = item
        elif side == "CE":
            top_ce.append(item)
        elif side == "PE":
            top_pe.append(item)

    return walls, top_ce[:20], top_pe[:20], strike_rows


def _futures_from_results(symbol, trade_date):
    df = _result_df(
        """
        SELECT *
        FROM nse_futures_build_up_daily
        WHERE trade_date = CAST(:trade_date AS DATE)
          AND UPPER(symbol) = UPPER(:symbol)
        ORDER BY expiry_date
        """,
        {"trade_date": trade_date, "symbol": symbol},
    )
    rows = []
    for _, row in df.iterrows():
        payload = _json_payload(row.get("payload"), {})
        item = dict(payload) if payload else {}
        item.update({
            "expiry": str(row.get("expiry_date") or item.get("expiry") or ""),
            "direction": str(row.get("direction") or item.get("direction") or "Neutral"),
            "build": str(row.get("build") or item.get("build") or ""),
            "close": to_number(row.get("close")),
            "priceChange": to_number(row.get("price_change")),
            "pricePct": to_number(row.get("price_pct")),
            "oi": to_number(row.get("oi")),
            "coi": to_number(row.get("coi")),
            "volume": to_number(row.get("volume")),
            "basis": to_number(row.get("basis")),
        })
        rows.append(item)
    current = rows[0] if rows else {}
    return {
        "error": "" if rows else "No processed futures rows found.",
        "sourceFile": "db:nse_futures_build_up_daily",
        "rows": rows,
        "current": current,
        "summary": {
            "direction": current.get("direction", "Neutral"),
            "build": current.get("build", ""),
            "expiry": current.get("expiry", ""),
            "pricePct": current.get("pricePct"),
            "coi": current.get("coi"),
            "volume": current.get("volume"),
            "basis": current.get("basis"),
        },
    }


def _cash_from_results(trade_date):
    df = _result_df(
        """
        SELECT *
        FROM nse_cash_delivery_footprint_daily
        WHERE trade_date = CAST(:trade_date AS DATE)
        ORDER BY activity_score DESC NULLS LAST, delivery_value_lacs DESC NULLS LAST
        LIMIT 80
        """,
        {"trade_date": trade_date},
    )
    rows = []
    for _, row in df.iterrows():
        payload = _json_payload(row.get("payload"), {})
        item = dict(payload) if payload else {}
        item.update({
            "symbol": str(row.get("symbol") or item.get("symbol") or ""),
            "signal": str(row.get("signal") or item.get("signal") or ""),
            "pricePct": to_number(row.get("price_pct")),
            "close": to_number(row.get("close")),
            "deliveryPct": to_number(row.get("delivery_pct")),
            "deliveryValueLacs": to_number(row.get("delivery_value_lacs")),
            "turnoverLacs": to_number(row.get("turnover_lacs")),
            "deliveryQty": to_number(row.get("delivery_qty")),
            "deliveryQtyChangePct": to_number(row.get("delivery_qty_change_pct")),
            "volumeChangePct": to_number(row.get("volume_change_pct")),
            "activityScore": to_number(row.get("activity_score")),
        })
        rows.append(item)

    accumulation = [r for r in rows if "accumulation" in str(r.get("signal", "")).lower() or "buying" in str(r.get("signal", "")).lower()]
    distribution = [r for r in rows if "distribution" in str(r.get("signal", "")).lower() or "selling" in str(r.get("signal", "")).lower() or "pressure" in str(r.get("signal", "")).lower()]
    no_acceptance = [r for r in rows if "no price acceptance" in str(r.get("signal", "")).lower()]

    up_value = sum((r.get("deliveryValueLacs") or 0) for r in rows if (r.get("pricePct") or 0) > 0)
    down_value = sum((r.get("deliveryValueLacs") or 0) for r in rows if (r.get("pricePct") or 0) < 0)
    cash_bias_score = ((up_value - down_value) / (up_value + down_value) * 100) if (up_value + down_value) else 0

    return {
        "error": "" if rows else "No processed cash delivery rows found.",
        "sourceFile": "db:nse_cash_delivery_footprint_daily",
        "sourceKind": "processed_result_table",
        "summary": {
            "cashDirection": eod_direction(cash_bias_score),
            "cashBiasScore": cash_bias_score,
            "upDeliveryValueLacs": up_value,
            "downDeliveryValueLacs": down_value,
            "totalDeliveryValueLacs": up_value + down_value,
            "sourceKind": "processed_result_table",
        },
        "rows": rows,
        "topRows": rows[:30],
        "accumulation": accumulation[:12],
        "distribution": distribution[:12],
        "noAcceptance": no_acceptance[:12],
    }


