def build_eod_participation_payload_from_results_fast(symbol, trade_date=None, expiry=None):
    """
    V11.5: processed-result-only payload for fast EOD tab.

    Requirement:
    Run importer with result-building once for the date:
      python nse_eod_import_process_to_db_direct_range_v5_progress_INTERACTIVE_v11_5_result_fast.py --date DDMMYYYY --force
    """
    symbol = normalize_index_symbol(symbol or "NIFTY")
    if symbol not in EOD_INDEX_SYMBOLS:
        symbol = "NIFTY"

    dates = _available_dates_from_results()
    if not dates:
        return {
            "symbol": symbol,
            "date": trade_date or "",
            "availableDates": [],
            "availableExpiries": [],
            "error": "No processed EOD result rows found. Run the V11.5 importer for this date first.",
            "loadedFromProcessedTables": False,
        }

    if not trade_date or trade_date not in dates:
        trade_date = dates[0]

    available_expiries = _available_expiries_from_results(symbol, trade_date)
    decision_row, stored_payload = _decision_from_results(symbol, trade_date, expiry)

    if decision_row is None:
        return {
            "symbol": symbol,
            "date": trade_date,
            "availableDates": dates,
            "availableExpiries": available_expiries,
            "expiry": expiry or (available_expiries[0] if available_expiries else ""),
            "error": f"No processed 360 decision row found for {symbol} {trade_date}. Run the V11.5 importer with result-building for this date/symbol.",
            "loadedFromProcessedTables": False,
        }

    selected_expiry = str(decision_row.get("expiry_date") or expiry or "")
    participants = _participants_from_results(trade_date)
    big_money = big_money_from_participants(participants)
    if decision_row.get("big_money_direction") is not None:
        big_money["direction"] = str(decision_row.get("big_money_direction") or big_money.get("direction") or "Neutral")
    if decision_row.get("big_money_score") is not None:
        big_money["score"] = to_number(decision_row.get("big_money_score"))

    walls, top_ce, top_pe, strike_rows = _walls_from_results(symbol, trade_date, selected_expiry)
    futures = _futures_from_results(symbol, trade_date)
    cash = _cash_from_results(trade_date)
    cm_market = _cm_from_results(trade_date)
    participant_attribution = (stored_payload.get("participantAttribution") if isinstance(stored_payload, dict) else None) or _participant_attribution_from_results(symbol, trade_date, selected_expiry)
    participant_expiry_attribution = (
        (stored_payload.get("participantExpiryAttribution") if isinstance(stored_payload, dict) else None)
        or (participant_attribution.get("expiryRows") if isinstance(participant_attribution, dict) else [])
        or []
    )
    participant_strike_attribution = (
        (stored_payload.get("participantStrikeAttribution") if isinstance(stored_payload, dict) else None)
        or (participant_attribution.get("topStrikeRows") if isinstance(participant_attribution, dict) else [])
        or []
    )

    # Prefer the stored view360 if available; otherwise build a lightweight view.
    view360 = (stored_payload.get("view360") if isinstance(stored_payload, dict) else None) or {
        "verdict": str(decision_row.get("final_360_bias") or "DB Result"),
        "score": to_number(decision_row.get("confidence_score")),
        "participantDirection": str(decision_row.get("big_money_direction") or ""),
        "futureDirection": str(decision_row.get("future_direction") or ""),
        "cashDirection": str(decision_row.get("cash_direction") or ""),
        "cmRegime": str(decision_row.get("cm_regime") or ""),
        "notes": [str(decision_row.get("decision_text") or "")],
    }

    decision_text = str(decision_row.get("decision_text") or "")
    decision = (stored_payload.get("decision") if isinstance(stored_payload, dict) else None) or {
        "text": decision_text,
        "bias": str(decision_row.get("final_360_bias") or ""),
        "score": to_number(decision_row.get("confidence_score")),
    }

    return {
        "symbol": symbol,
        "date": trade_date,
        "availableDates": dates,
        "availableExpiries": available_expiries,
        "expiry": selected_expiry,
        "generatedAt": datetime.now(IST).strftime("%d-%b-%Y %H:%M:%S"),
        "error": "",
        "participantOiFile": "db:nse_participant_bias_daily",
        "participantVolFile": "db:nse_participant_bias_daily",
        "participants": participants,
        "bigMoney": big_money,
        "decision": decision,
        "spot": to_number(decision_row.get("spot_close")),
        "previousDate": "",
        "strikeRows": strike_rows,
        "topCe": top_ce,
        "topPe": top_pe,
        "walls": walls,
        "futures": futures,
        "cash": cash,
        "cmMarket": cm_market,
        "participantAttribution": participant_attribution,
        "participantExpiryAttribution": participant_expiry_attribution,
        "participantStrikeAttribution": participant_strike_attribution,
        "view360": view360,
        "volumeSpurts": read_db_volume_spurts_for_date(trade_date) or {},
        "memory": _memory_from_results(symbol, trade_date, max_rows=8),
        "loadedFromProcessedTables": True,
        "source": "PostgreSQL processed EOD result tables",
        "disclaimer": "Loaded from compact processed PostgreSQL result tables. No raw bhavcopy scan and no payload-cache read during dashboard view.",
    }



# ============================== V11.6 CACHE-SAFE EOD WRAPPER ==============================
# Fastest dashboard behavior:
# 1) Try nse_eod_payload_cache.
# 2) Validate cache strictly: correct symbol/date/expiry and has real payload content.
# 3) If cache is blank/stale/incomplete, DO NOT show errors; fall back to compact result tables.
# 4) Never scan raw bhavcopy tables while loading the dashboard.

def _normalize_cache_expiry(value):
    return expiry_key(value or "")


def _payload_is_complete(payload):
    if not isinstance(payload, dict):
        return False
    has_participants = bool(payload.get("participants"))
    has_decision = bool((payload.get("decision") or {}).get("text") or (payload.get("view360") or {}).get("verdict"))
    has_walls = bool((payload.get("walls") or {}).get("resistance") or (payload.get("walls") or {}).get("support"))
    has_cash = bool(((payload.get("cash") or {}).get("topRows") or []))
    has_cm = bool(((payload.get("cmMarket") or {}).get("summary") or {}))
    # Participants + some decision/market structure is the minimum useful EOD view.
    return has_participants and (has_decision or has_walls or has_cash or has_cm)


def read_eod_cached_payload_safe(symbol, trade_date=None, expiry=None):
    """Read only a valid cache row. Reject blank/stale/incomplete cache rows."""
    symbol = normalize_index_symbol(symbol or "NIFTY")
    try:
        with EOD_ANALYTICS_ENGINE.connect() as conn:
            dates_df = pd.read_sql(
                sqlalchemy.text(
                    """
                    SELECT DISTINCT trade_date
                    FROM nse_eod_payload_cache
                    WHERE UPPER(symbol) = UPPER(:symbol)
                    ORDER BY trade_date DESC
                    """
                ),
                conn,
                params={"symbol": symbol},
            )
            if dates_df.empty:
                return None

            available_dates = []
            for value in dates_df["trade_date"].dropna().tolist():
                try:
                    available_dates.append(pd.to_datetime(value).strftime("%Y-%m-%d"))
                except Exception:
                    pass

            if not trade_date or trade_date not in available_dates:
                trade_date = available_dates[0] if available_dates else trade_date

            cache_df = pd.read_sql(
                sqlalchemy.text(
                    """
                    SELECT expiry_date, payload, updated_at
                    FROM nse_eod_payload_cache
                    WHERE UPPER(symbol) = UPPER(:symbol)
                      AND trade_date = CAST(:trade_date AS DATE)
                    ORDER BY
                      CASE WHEN COALESCE(expiry_date,'') = '' THEN 1 ELSE 0 END,
                      updated_at DESC
                    """
                ),
                conn,
                params={"symbol": symbol, "trade_date": trade_date},
            )
            if cache_df.empty:
                return None

            requested_key = _normalize_cache_expiry(expiry) if expiry else ""
            candidates = []

            for _, row in cache_df.iterrows():
                row_expiry = str(row.get("expiry_date") or "").strip()
                row_key = _normalize_cache_expiry(row_expiry)
                payload = row.get("payload")
                if isinstance(payload, str):
                    try:
                        payload = json.loads(payload)
                    except Exception:
                        payload = None
                if not isinstance(payload, dict):
                    continue

                payload_expiry = str(payload.get("expiry") or row_expiry or "").strip()
                payload_key = _normalize_cache_expiry(payload_expiry)

                # If user selected expiry, accept only matching cache rows.
                if requested_key and requested_key not in {row_key, payload_key}:
                    continue

                # If user did not select expiry, avoid blank cache if non-blank exists.
                if not requested_key and not (row_key or payload_key):
                    # keep as very low priority only
                    priority = 99
                else:
                    priority = 0

                if not _payload_is_complete(payload):
                    continue

                candidates.append((priority, row_expiry or payload_expiry, payload, row.get("updated_at")))

            if not candidates:
                return None

            candidates.sort(key=lambda x: x[0])
            _, selected_expiry, payload, updated_at = candidates[0]

            # Available expiries from cache, normalized but preserving text.
            expiries = []
            for value in cache_df["expiry_date"].dropna().astype(str).tolist():
                value = value.strip()
                if value and value not in expiries:
                    expiries.append(value)

            payload["availableDates"] = available_dates
            payload["availableExpiries"] = expiries or _available_expiries_from_results(symbol, trade_date)
            payload["date"] = trade_date
            payload["symbol"] = symbol
            payload["expiry"] = selected_expiry or payload.get("expiry") or (expiry or "")
            payload["loadedFromSafeCache"] = True
            payload["loadedFromDbCache"] = True
            payload["dbCacheUpdatedAt"] = str(updated_at or "")

            db_volume_spurts = read_db_volume_spurts_for_date(trade_date)
            if db_volume_spurts is not None:
                payload["volumeSpurts"] = db_volume_spurts

            if not payload.get("participantAttribution"):
                participant_attribution = _participant_attribution_from_results(symbol, trade_date, payload.get("expiry") or selected_expiry)
                if participant_attribution.get("expiryRows") or participant_attribution.get("topStrikeRows"):
                    payload["participantAttribution"] = participant_attribution
                    payload["participantExpiryAttribution"] = participant_attribution.get("expiryRows") or []
                    payload["participantStrikeAttribution"] = participant_attribution.get("topStrikeRows") or []

            payload["disclaimer"] = (
                "Loaded from validated PostgreSQL cache. "
                "If cache is incomplete/stale, dashboard falls back to compact result tables automatically."
            )
            return payload
    except Exception:
        return None


def build_eod_participation_payload(symbol, trade_date=None, expiry=None):
    """
    V11.6 cache-safe EOD payload.

    This restores the fast cached behavior that worked earlier, but prevents the
    blank-expiry/stale-cache error by validating cache rows before use.
    """
    cached = read_eod_cached_payload_safe(symbol, trade_date=trade_date, expiry=expiry)
    if cached:
        return cached

    fallback = build_eod_participation_payload_from_results_fast(symbol, trade_date=trade_date, expiry=expiry)
    if isinstance(fallback, dict):
        fallback["cacheFallbackReason"] = "No valid cache row found; loaded from compact processed result tables."
        fallback["disclaimer"] = (
            (fallback.get("disclaimer") or "")
            + " | Cache-safe fallback used because cache was missing, blank-expiry, stale, or incomplete."
        )
    return fallback



# ============================== V11.8.1 FAST STARTUP OVERRIDES ==============================
# V11.8 fixed option-learning validation, but initial dashboard startup can still
# become slow when get_available_dates_fast() scans the whole option table using
# SELECT DISTINCT CAST(timestamp AS DATE).
#
# This override uses a recent-row sample first and caches dates/expiries in memory.
# That keeps the first /api/snapshot response fast.

_FAST_DATES_CACHE = {}
_FAST_EXPIRIES_CACHE = {}

def get_available_dates_fast(symbol, row_limit=120000):
    """Fast recent-date discovery. Avoid full-table DISTINCT scan on every startup."""
    symbol = normalize_index_symbol(symbol or "NIFTY")
    if symbol not in SYMBOLS:
        raise ValueError("Invalid symbol")

    cache_key = (symbol, int(row_limit))
    now_ts = datetime.now().timestamp()
    cached = _FAST_DATES_CACHE.get(cache_key)
    if cached and now_ts - cached.get("ts", 0) < 120:
        return cached.get("dates", [])

    dates = []
    try:
        query = sqlalchemy.text(f'SELECT "timestamp" FROM "{symbol}" ORDER BY ctid DESC LIMIT :limit')
        df = pd.read_sql(query, ENGINE, params={"limit": int(row_limit)})
        if not df.empty and "timestamp" in df.columns:
            found = []
            for value in df["timestamp"].dropna().astype(str).tolist():
                day = timestamp_date(value)
                if day and day not in found:
                    found.append(day)
            dates = sorted(found, reverse=True)
    except Exception:
        dates = []

    # Fallback only if sample failed.
    if not dates:
        try:
            query = sqlalchemy.text(
                f'SELECT DISTINCT CAST("timestamp" AS DATE) AS trade_date FROM "{symbol}" ORDER BY trade_date DESC'
            )
            df = pd.read_sql(query, ENGINE)
            if not df.empty and "trade_date" in df.columns:
                for value in df["trade_date"].dropna().tolist():
                    try:
                        dates.append(pd.to_datetime(value).strftime("%Y-%m-%d"))
                    except Exception:
                        dates.append(str(value))
        except Exception:
            dates = []

    _FAST_DATES_CACHE[cache_key] = {"ts": now_ts, "dates": dates}
    return dates


def get_available_dates(symbol):
    return get_available_dates_fast(symbol)


def get_available_expiries_for_date(symbol, trade_date):
    """Cached expiry discovery for selected date."""
    symbol = normalize_index_symbol(symbol or "NIFTY")
    if symbol not in SYMBOLS or not trade_date:
        return []

    cache_key = (symbol, str(trade_date))
    now_ts = datetime.now().timestamp()
    cached = _FAST_EXPIRIES_CACHE.get(cache_key)
    if cached and now_ts - cached.get("ts", 0) < 120:
        return cached.get("expiries", [])

    prefix = trade_date_to_nse_prefix(trade_date)
    queries = []
    if prefix:
        queries.append((
            f'SELECT DISTINCT "expiryDate" FROM "{symbol}" WHERE "timestamp" LIKE :ts_prefix',
            {"ts_prefix": prefix + "%"},
        ))
    queries.append((
        f'SELECT DISTINCT "expiryDate" FROM "{symbol}" WHERE CAST("timestamp" AS DATE) = CAST(:trade_date AS DATE)',
        {"trade_date": trade_date},
    ))

    values = []
    for sql, params in queries:
        try:
            df = pd.read_sql(sqlalchemy.text(sql), ENGINE, params=params)
            if not df.empty and "expiryDate" in df.columns:
                for value in df["expiryDate"].dropna().astype(str).tolist():
                    value = value.strip()
                    if value and value not in values:
                        values.append(value)
                if values:
                    break
        except Exception:
            continue

    expiries = sorted(values, key=expiry_sort_key)
    _FAST_EXPIRIES_CACHE[cache_key] = {"ts": now_ts, "expiries": expiries}
    return expiries


def main():
    url = f"http://127.0.0.1:{PORT}/?v=v11840_master_payload_fix_8102"
    server = ThreadingHTTPServer((os.getenv("DASHBOARD_HOST", "127.0.0.1"), PORT), DashboardHandler)
    print("V11.8.40 MASTER PAYLOAD FIX 8102 is running. Date dropdown uses full DISTINCT query.", flush=True)
    print(f"ATM ROC dashboard running at {url}", flush=True)
    if os.getenv("OPEN_BROWSER", "0") == "1":
        try:
            webbrowser.open(url)
        except Exception:
            pass
    server.serve_forever()



# ============================== V11.8.4 DATE DROPDOWN FIX ==============================
# Problem:
# V11.8.1 fast-startup override used only latest ctid rows to discover dates.
# If recent table rows contain only 1-2 sessions, date dropdown shows only those
# 1-2 dates even when the table has many historical dates.
#
# Fix:
# Use full DISTINCT date query for dropdown, cache it for 10 minutes, then use
# ctid sampling only as fallback.

_FULL_DATES_CACHE = {}

def get_available_dates_fast(symbol, row_limit=60000):
    """Return all option table dates for dropdown, not only recent ctid sample."""
    symbol = normalize_index_symbol(symbol or "NIFTY")
    if symbol not in SYMBOLS:
        raise ValueError("Invalid symbol")

    cache_key = symbol
    now_ts = datetime.now().timestamp()
    cached = _FULL_DATES_CACHE.get(cache_key)
    if cached and now_ts - cached.get("ts", 0) < 600:
        return cached.get("dates", [])

    dates = []

    # Correct primary path: all distinct trade dates.
    try:
        query = sqlalchemy.text(
            f'SELECT DISTINCT CAST("timestamp" AS DATE) AS trade_date '
            f'FROM "{symbol}" '
            f'ORDER BY trade_date DESC'
        )
        df = pd.read_sql(query, ENGINE)
        if not df.empty and "trade_date" in df.columns:
            for value in df["trade_date"].dropna().tolist():
                try:
                    dates.append(pd.to_datetime(value).strftime("%Y-%m-%d"))
                except Exception:
                    text_value = str(value).strip()
                    if text_value:
                        dates.append(text_value[:10])
            dates = [d for d in dates if d]
            if dates:
                _FULL_DATES_CACHE[cache_key] = {"ts": now_ts, "dates": dates}
                return dates
    except Exception:
        pass

    # Fallback only if DISTINCT fails.
    try:
        query = sqlalchemy.text(f'SELECT "timestamp" FROM "{symbol}" ORDER BY ctid DESC LIMIT :limit')
        df = pd.read_sql(query, ENGINE, params={"limit": int(max(row_limit, 300000))})
        if not df.empty and "timestamp" in df.columns:
            found = []
            for value in df["timestamp"].dropna().astype(str).tolist():
                day = timestamp_date(value)
                if day and day not in found:
                    found.append(day)
            dates = sorted(found, reverse=True)
    except Exception:
        dates = []

    _FULL_DATES_CACHE[cache_key] = {"ts": now_ts, "dates": dates}
    return dates


def get_available_dates(symbol):
    return get_available_dates_fast(symbol)



# ============================== V11.8.5 FINAL DATE FORCE OVERRIDE ==============================
# This is intentionally placed immediately before __main__, so it is the final
# active get_available_dates() implementation before the server starts.

_FORCE_DATE_CACHE = {}

def get_available_dates_fast(symbol, row_limit=60000):
    symbol = normalize_index_symbol(symbol or "NIFTY")
    if symbol not in SYMBOLS:
        raise ValueError("Invalid symbol")

    now_ts = datetime.now().timestamp()
    cached = _FORCE_DATE_CACHE.get(symbol)
    if cached and now_ts - cached.get("ts", 0) < 300:
        return cached.get("dates", [])

    dates = []
    try:
        sql = sqlalchemy.text(
            f'SELECT DISTINCT CAST("timestamp" AS DATE) AS trade_date '
            f'FROM "{symbol}" '
            f'ORDER BY trade_date DESC'
        )
        df = pd.read_sql(sql, ENGINE)
        if not df.empty:
            for value in df["trade_date"].dropna().tolist():
                try:
                    dates.append(pd.to_datetime(value).strftime("%Y-%m-%d"))
                except Exception:
                    dates.append(str(value)[:10])
    except Exception as exc:
        print(f"V11.8.5 date DISTINCT failed for {symbol}: {type(exc).__name__}: {exc}", flush=True)
        try:
            df = pd.read_sql(
                sqlalchemy.text(f'SELECT "timestamp" FROM "{symbol}"'),
                ENGINE,
            )
            if not df.empty and "timestamp" in df.columns:
                dates = sorted(
                    {timestamp_date(value) for value in df["timestamp"].dropna().astype(str).tolist() if timestamp_date(value)},
                    reverse=True,
                )
        except Exception as exc2:
            print(f"V11.8.5 date fallback failed for {symbol}: {type(exc2).__name__}: {exc2}", flush=True)
            dates = []

    dates = [d for d in dates if d]
    _FORCE_DATE_CACHE[symbol] = {"ts": now_ts, "dates": dates}
    print(f"V11.8.5 date dropdown for {symbol}: {len(dates)} dates -> {dates[:20]}", flush=True)
    return dates


def get_available_dates(symbol):
    return get_available_dates_fast(symbol)



# ============================== V11.8.6 OLD-DATE CHART FAST OVERRIDE ==============================
# Problem fixed:
# For old dates, the date dropdown is correct, but Graphical tab may show no intraday chart data
# because the full /api/snapshot?lite=0 request loads the full day first and only then filters expiry.
# On large old sessions this can exceed the browser timeout; the request gets aborted and the UI keeps
# the previous lite payload with 0 chart points.
#
# Fix:
# Full chart payload now reads only selected date + selected expiry at SQL level.
# Browser timeout for full snapshot is also increased.

def read_symbol_table_for_date_expiry_fast(symbol, trade_date, expiry=None, max_timestamps=None):
    """Read option rows for selected date and selected expiry using SQL-side filters."""
    symbol = normalize_index_symbol(symbol or "NIFTY")
    if symbol not in SYMBOLS:
        raise ValueError("Invalid symbol")
    if not trade_date:
        return read_symbol_table(symbol, max_timestamps=max_timestamps or 8)

    prefix = trade_date_to_nse_prefix(trade_date)
    variants = expiry_variants(expiry) if expiry else []
    variants = [str(v).strip() for v in variants if str(v).strip()]

    attempts = []
    if prefix and variants:
        attempts.append((
            f'SELECT * FROM "{symbol}" '
            f'WHERE "timestamp" LIKE :ts_prefix AND "expiryDate" = ANY(:expiries)',
            {"ts_prefix": prefix + "%", "expiries": variants},
        ))
    if variants:
        attempts.append((
            f'SELECT * FROM "{symbol}" '
            f'WHERE CAST("timestamp" AS DATE) = CAST(:trade_date AS DATE) '
            f'AND "expiryDate" = ANY(:expiries)',
            {"trade_date": trade_date, "expiries": variants},
        ))
    if prefix:
        attempts.append((
            f'SELECT * FROM "{symbol}" WHERE "timestamp" LIKE :ts_prefix',
            {"ts_prefix": prefix + "%"},
        ))
    attempts.append((
        f'SELECT * FROM "{symbol}" WHERE CAST("timestamp" AS DATE) = CAST(:trade_date AS DATE)',
        {"trade_date": trade_date},
    ))

    last_error = None
    for sql, params in attempts:
        try:
            df = pd.read_sql(sqlalchemy.text(sql), ENGINE, params=params)
            if df.empty or "timestamp" not in df.columns:
                continue
            df["timestamp"] = df["timestamp"].map(normalize_timestamp)

            # If SQL fallback read all expiries, do robust expiry filter in pandas.
            if expiry:
                expiry_col = find_column(df, ("expiryDate", "expiry"))
                if expiry_col:
                    df = filter_frame_by_expiry(df, expiry, expiry_col=expiry_col)
                    if df.empty:
                        continue

            if max_timestamps is not None:
                timestamps = sorted(df["timestamp"].dropna().unique(), key=parse_timestamp, reverse=True)
                keep = set(timestamps[:max_timestamps])
                df = df[df["timestamp"].isin(keep)].copy()

            print(
                f"V11.8.6 read {symbol} {trade_date} expiry={expiry or ''}: "
                f"{len(df)} rows, {df['timestamp'].nunique() if 'timestamp' in df.columns else 0} timestamps",
                flush=True,
            )
            return df
        except Exception as exc:
            last_error = exc
            continue

    if last_error:
        print(
            f"V11.8.6 read failed for {symbol} {trade_date} expiry={expiry}: "
            f"{type(last_error).__name__}: {last_error}",
            flush=True,
        )
    return pd.DataFrame()


def build_dashboard_payload(symbol, band, trade_date=None, expiry=None, chart_strike=None):
    """
    V11.8.6 full payload builder.
    Uses SQL-side date+expiry filtering so old-date Graphical tab can load chart points.
    """
    available_dates = get_available_dates(symbol)
    if not trade_date and available_dates:
        trade_date = available_dates[0]

    available_expiries = get_available_expiries_for_date(symbol, trade_date)
    if not expiry and available_expiries:
        expiry = available_expiries[0]

    df = read_symbol_table_for_date_expiry_fast(symbol, trade_date, expiry=expiry, max_timestamps=None)
    if df.empty:
        return {
            "symbol": symbol,
            "date": trade_date,
            "expiry": expiry,
            "availableDates": available_dates,
            "availableExpiries": available_expiries,
            "error": f"No option rows found for {trade_date or 'selected date'} / expiry {expiry or 'selected expiry'}",
            "rows": [],
            "charts": {},
        }

    strike_col = find_column(df, ("strikePrice", "strike"))
    opt_col = find_column(df, ("optionType", "type"))
    spot_col = find_column(df, ("spotPrice", "underlyingValue"))
    expiry_col = find_column(df, ("expiryDate", "expiry"))

    if not available_expiries:
        available_expiries = get_expiries_from_frame(df, expiry_col)

    if expiry and expiry_col:
        df = filter_frame_by_expiry(df, expiry, expiry_col=expiry_col)

    if df.empty:
        return {
            "symbol": symbol,
            "date": trade_date,
            "expiry": expiry,
            "availableDates": available_dates,
            "availableExpiries": available_expiries,
            "error": f"No option rows found for expiry {expiry or 'selected expiry'} on {trade_date or 'selected date'}",
            "rows": [],
            "charts": {},
        }

    if not strike_col or not opt_col:
        return {
            "symbol": symbol,
            "date": trade_date,
            "expiry": expiry,
            "availableDates": available_dates,
            "availableExpiries": available_expiries,
            "error": "Required columns strikePrice/optionType not found",
            "rows": [],
            "charts": {},
        }

    latest_ts, previous_ts, latest_df, previous_df = latest_previous_frames(df)
    latest_df["_strike"] = latest_df[strike_col].map(to_number)
    if not previous_df.empty:
        previous_df["_strike"] = previous_df[strike_col].map(to_number)

    spot = None
    if spot_col:
        spot_candidates = [to_number(v) for v in latest_df[spot_col].tolist()]
        spot_candidates = [v for v in spot_candidates if v is not None and v > 0]
        spot = spot_candidates[0] if spot_candidates else None

    strikes = [to_number(v) for v in latest_df[strike_col].tolist()]
    atm = nearest_atm(strikes, spot)
    step = infer_strike_step(strikes)
    wanted = {atm + (i * step) for i in range(-int(band), int(band) + 1)} if atm is not None else set()

    metric_cols = {key: find_column(df, config["aliases"]) for key, config in METRICS.items()}
    change_oi_col = find_column(df, (
        "changeinOI", "changeinOpenInterest", "changeInOpenInterest", "coi", "changeOI",
    ))

    previous_lookup = {}
    if previous_ts and not previous_df.empty:
        for _, row in previous_df.iterrows():
            strike = to_number(row.get(strike_col))
            option_type = str(row.get(opt_col, "")).upper()
            previous_lookup[(strike, option_type)] = row

    rows = []
    for _, row in latest_df.iterrows():
        strike = to_number(row.get(strike_col))
        if strike not in wanted:
            continue

        option_type = str(row.get(opt_col, "")).upper()
        if option_type not in {"CE", "PE"}:
            continue

        previous_row = previous_lookup.get((strike, option_type))
        item = {
            "symbol": symbol,
            "timestamp": latest_ts,
            "previousTimestamp": previous_ts,
            "expiryDate": str(row.get(expiry_col, "")) if expiry_col else "",
            "strike": strike,
            "optionType": option_type,
            "distance": int(round((strike - atm) / step)) if atm and step else 0,
            "atm": strike == atm,
        }

        for key, col in metric_cols.items():
            current = to_number(row.get(col)) if col else None
            previous = to_number(previous_row.get(col)) if previous_row is not None and col else None
            item[key] = current
            item[f"{key}Roc"] = pct_change(current, previous)

        current_coi = to_number(row.get(change_oi_col)) if change_oi_col else None
        previous_coi = to_number(previous_row.get(change_oi_col)) if previous_row is not None and change_oi_col else None
        current_volume = item.get("volume")
        previous_volume = to_number(previous_row.get(metric_cols.get("volume"))) if previous_row is not None and metric_cols.get("volume") else None
        item["coi"] = current_coi
        item["coiVolPct"] = safe_ratio_pct(current_coi, current_volume)
        item["coiVolRoc"] = pct_change(item["coiVolPct"], safe_ratio_pct(previous_coi, previous_volume))
        rows.append(item)

    rows.sort(key=lambda item: (item["strike"], item["optionType"]))

    charts = build_intraday_line_charts(
        df=df,
        band=int(band),
        strike_col=strike_col,
        opt_col=opt_col,
        spot_col=spot_col,
        metric_cols=metric_cols,
        chart_strike=chart_strike,
    )

    futures_series = build_futures_series(symbol, trade_date)
    charts = enrich_charts_with_futures(charts, futures_series)
    futures_latest = futures_series[-1] if futures_series else {}
    latest_future = nearest_future_point(latest_ts, futures_series) or futures_latest or {}
    futures_row_fields = (
        "futureTimestamp", "futureExpiry", "futurePrice", "futurePriceRoc",
        "futureOpenInterest", "futureOiRoc", "futureVolume", "futureVolumeRoc",
        "futureCoi", "futureCoiRoc", "futureCoiVolPct", "futureCoiVolRoc",
        "basis", "basisPct"
    )
    for item in rows:
        for field in futures_row_fields:
            item[field] = latest_future.get(field)

    timestamps_asc = sorted(df["timestamp"].dropna().unique(), key=parse_timestamp)
    first_ts = timestamps_asc[0] if timestamps_asc else ""
    last_ts = timestamps_asc[-1] if timestamps_asc else ""

    return {
        "symbol": symbol,
        "date": trade_date,
        "expiry": expiry,
        "availableDates": available_dates,
        "availableExpiries": available_expiries,
        "generatedAt": datetime.now(IST).strftime("%d-%b-%Y %H:%M:%S"),
        "timestamp": latest_ts,
        "previousTimestamp": previous_ts,
        "firstTimestamp": first_ts,
        "lastTimestamp": last_ts,
        "chartPoints": len(timestamps_asc),
        "futuresPoints": len(futures_series),
        "futuresLatest": futures_latest,
        "spot": spot,
        "atm": atm,
        "strikeStep": step,
        "band": int(band),
        "chartStrike": to_number(chart_strike),
        "chartScope": "specific" if to_number(chart_strike) is not None else "atm_band",
        "rows": rows,
        "charts": charts,
        "oldDateChartFast": True,
    }



# ============================== V11.8.11 FLOW + OI/COI ENRICHMENT ==============================
# Adds:
# - Live and EOD COI/OI %.
# - Live header cards for highest CE/PE COI and total OI strikes.
# - EOD option extreme cards based on available CE/PE activity rows.
# - Participant "overall bias vs today's flow" helpers.
# - Cash rows TQY / No. Trades, enriched from nse_cm_bhavcopy_raw when available.

def _v11811_float(value):
    try:
        if value is None:
            return None
        number = float(value)
        if math.isnan(number) or math.isinf(number):
            return None
        return number
    except Exception:
        return None


def _v11811_ratio_pct(numerator, denominator):
    numerator = _v11811_float(numerator)
    denominator = _v11811_float(denominator)
    if numerator is None or denominator in (None, 0):
        return None
    return (numerator / denominator) * 100.0


def _v11811_make_extreme_record(row, strike_col, side_col, value_col, oi_col=None, coi_col=None, close_col=None, volume_col=None):
    if row is None or value_col is None:
        return None
    try:
        side = str(row.get(side_col, "") or "").upper() if side_col else ""
        ts_raw = row.get("timestamp")
        ts_text = normalize_timestamp(ts_raw) if ts_raw is not None else ""
        return {
            "strike": _v11811_float(row.get(strike_col)) if strike_col else None,
            "side": side,
            "value": _v11811_float(row.get(value_col)),
            "oi": _v11811_float(row.get(oi_col)) if oi_col else None,
            "coi": _v11811_float(row.get(coi_col)) if coi_col else None,
            "close": _v11811_float(row.get(close_col)) if close_col else None,
            "volume": _v11811_float(row.get(volume_col)) if volume_col else None,
            "timestamp": ts_text,
            "time": timestamp_time_label(ts_text) if ts_text else "",
        }
    except Exception:
        return None


def _v11811_compute_live_option_extremes(symbol, trade_date=None, expiry=None):
    """Highest COI and total OI strike from latest live option snapshot for selected expiry."""
    try:
        df, latest_ts = read_latest_option_snapshot_for_date_expiry(symbol, trade_date, expiry)
        if df is None or df.empty:
            return {}
        strike_col = find_column(df, ("strikePrice", "strike"))
        side_col = find_column(df, ("optionType", "type"))
        oi_col = find_column(df, METRICS["openInterest"]["aliases"])
        coi_col = find_column(df, ("changeinOI", "changeinOpenInterest", "changeInOpenInterest", "coi", "changeOI"))
        close_col = find_column(df, METRICS["premium"]["aliases"])
        volume_col = find_column(df, METRICS["volume"]["aliases"])
        if not strike_col or not side_col:
            return {}
        work = df.copy()
        work["_side"] = work[side_col].astype(str).str.upper().str.strip()
        if oi_col:
            work["_oi"] = pd.to_numeric(work[oi_col], errors="coerce")
        else:
            work["_oi"] = None
        if coi_col:
            work["_coi"] = pd.to_numeric(work[coi_col], errors="coerce")
        else:
            work["_coi"] = None
        result = {"timestamp": latest_ts, "expiry": expiry or ""}
        for side, prefix in (("CE", "ce"), ("PE", "pe")):
            side_df = work[work["_side"].eq(side)].copy()
            if side_df.empty:
                continue
            if coi_col and side_df["_coi"].notna().any():
                idx = side_df["_coi"].idxmax()
                result[f"{prefix}MaxCoi"] = _v11811_make_extreme_record(side_df.loc[idx], strike_col, side_col, coi_col, oi_col, coi_col, close_col, volume_col)
            if oi_col and side_df["_oi"].notna().any():
                idx = side_df["_oi"].idxmax()
                result[f"{prefix}MaxOi"] = _v11811_make_extreme_record(side_df.loc[idx], strike_col, side_col, oi_col, oi_col, coi_col, close_col, volume_col)
        return result
    except Exception as exc:
        return {"error": f"option extremes failed: {type(exc).__name__}: {exc}"}


def _v11811_compute_live_option_extreme_drops(symbol, trade_date=None, expiry=None):
    """Compare top CE/PE COI/OI cards with the previous snapshot and return reductions."""
    try:
        symbol = normalize_index_symbol(symbol or "NIFTY")
        df = read_symbol_table_for_date_expiry_fast(symbol, trade_date, expiry=expiry, max_timestamps=2)
        if df is None or df.empty or "timestamp" not in df.columns:
            return []
        timestamps = sorted(df["timestamp"].dropna().unique(), key=parse_timestamp, reverse=True)
        if len(timestamps) < 2:
            return []

        latest_ts = timestamps[0]
        previous_ts = timestamps[1]
        strike_col = find_column(df, ("strikePrice", "strike"))
        side_col = find_column(df, ("optionType", "type"))
        oi_col = find_column(df, METRICS["openInterest"]["aliases"])
        coi_col = find_column(df, ("changeinOI", "changeinOpenInterest", "changeInOpenInterest", "coi", "changeOI"))
        close_col = find_column(df, METRICS["premium"]["aliases"])
        volume_col = find_column(df, METRICS["volume"]["aliases"])
        if not strike_col or not side_col:
            return []

        def frame_extremes(frame):
            if frame is None or frame.empty:
                return {}
            work = frame.copy()
            work["_side"] = work[side_col].astype(str).str.upper().str.strip()
            work["_oi"] = pd.to_numeric(work[oi_col], errors="coerce") if oi_col else None
            work["_coi"] = pd.to_numeric(work[coi_col], errors="coerce") if coi_col else None
            result = {}
            for side, prefix in (("CE", "ce"), ("PE", "pe")):
                side_df = work[work["_side"].eq(side)].copy()
                if side_df.empty:
                    continue
                if coi_col and side_df["_coi"].notna().any():
                    idx = side_df["_coi"].idxmax()
                    result[f"{prefix}MaxCoi"] = _v11811_make_extreme_record(side_df.loc[idx], strike_col, side_col, "_coi", "_oi", "_coi", close_col, volume_col)
                if oi_col and side_df["_oi"].notna().any():
                    idx = side_df["_oi"].idxmax()
                    result[f"{prefix}MaxOi"] = _v11811_make_extreme_record(side_df.loc[idx], strike_col, side_col, "_oi", "_oi", "_coi", close_col, volume_col)
            return result

        current = frame_extremes(df[df["timestamp"] == latest_ts])
        previous = frame_extremes(df[df["timestamp"] == previous_ts])
        labels = {
            "ceMaxCoi": "CE Max COI",
            "peMaxCoi": "PE Max COI",
            "ceMaxOi": "CE Max OI",
            "peMaxOi": "PE Max OI",
        }
        drops = []
        for key, label in labels.items():
            cur = current.get(key)
            prev = previous.get(key)
            cur_val = _v11811_float((cur or {}).get("value"))
            prev_val = _v11811_float((prev or {}).get("value"))
            if cur_val is None or prev_val is None or cur_val >= prev_val:
                continue
            drops.append({
                "key": key,
                "label": label,
                "timestamp": latest_ts,
                "previousTimestamp": previous_ts,
                "current": cur,
                "previous": prev,
                "currentValue": cur_val,
                "previousValue": prev_val,
                "change": cur_val - prev_val,
                "changePct": pct_change(cur_val, prev_val),
            })
        return drops
    except Exception:
        return []


def _v11811_compute_live_option_day_extremes(symbol, trade_date=None, expiry=None):
    """Highest CE/PE COI and OI seen from day start through the latest DB timestamp."""
    try:
        symbol = normalize_index_symbol(symbol or "NIFTY")
        df = read_symbol_table_for_date_expiry_fast(symbol, trade_date, expiry=expiry, max_timestamps=None)
        if df is None or df.empty or "timestamp" not in df.columns:
            return {}

        strike_col = find_column(df, ("strikePrice", "strike"))
        side_col = find_column(df, ("optionType", "type"))
        oi_col = find_column(df, METRICS["openInterest"]["aliases"])
        coi_col = find_column(df, ("changeinOI", "changeinOpenInterest", "changeInOpenInterest", "coi", "changeOI"))
        close_col = find_column(df, METRICS["premium"]["aliases"])
        volume_col = find_column(df, METRICS["volume"]["aliases"])
        if not strike_col or not side_col:
            return {}

        timestamps = sorted(df["timestamp"].dropna().unique(), key=parse_timestamp)
        work = df.copy()
        work["_side"] = work[side_col].astype(str).str.upper().str.strip()
        work["_oi"] = pd.to_numeric(work[oi_col], errors="coerce") if oi_col else None
        work["_coi"] = pd.to_numeric(work[coi_col], errors="coerce") if coi_col else None

        result = {
            "firstTimestamp": timestamps[0] if timestamps else "",
            "lastTimestamp": timestamps[-1] if timestamps else "",
            "expiry": expiry or "",
            "points": len(timestamps),
        }
        for side, prefix in (("CE", "ce"), ("PE", "pe")):
            side_df = work[work["_side"].eq(side)].copy()
            if side_df.empty:
                continue
            if coi_col and side_df["_coi"].notna().any():
                idx = side_df["_coi"].idxmax()
                result[f"{prefix}DayMaxCoi"] = _v11811_make_extreme_record(side_df.loc[idx], strike_col, side_col, "_coi", "_oi", "_coi", close_col, volume_col)
            if oi_col and side_df["_oi"].notna().any():
                idx = side_df["_oi"].idxmax()
                result[f"{prefix}DayMaxOi"] = _v11811_make_extreme_record(side_df.loc[idx], strike_col, side_col, "_oi", "_oi", "_coi", close_col, volume_col)
        return result
    except Exception as exc:
        return {"error": f"option day extremes failed: {type(exc).__name__}: {exc}"}

def _v11811_add_coi_oi_to_rows(rows):
    for row in rows or []:
        if not isinstance(row, dict):
            continue
        oi = row.get("openInterest")
        if oi is None:
            oi = row.get("oi")
        coi = row.get("coi")
        if coi is None:
            coi = row.get("changeinOI") or row.get("changeInOpenInterest")
        row["coiOiPct"] = _v11811_ratio_pct(coi, oi)
    return rows


def _v11811_extremes_from_eod_rows(payload):
    rows = []
    for key in ("topCe", "topPe", "strikeRows"):
        value = payload.get(key) if isinstance(payload, dict) else None
        if isinstance(value, list):
            rows.extend([r for r in value if isinstance(r, dict)])
    result = {}
    for side, prefix in (("CE", "ce"), ("PE", "pe")):
        side_rows = [r for r in rows if str(r.get("side") or "").upper() == side]
        if not side_rows:
            continue
        coi_rows = [r for r in side_rows if _v11811_float(r.get("coi")) is not None]
        oi_rows = [r for r in side_rows if _v11811_float(r.get("oi")) is not None]
        if coi_rows:
            r = max(coi_rows, key=lambda x: _v11811_float(x.get("coi")) or -10**30)
            result[f"{prefix}MaxCoi"] = {"strike": _v11811_float(r.get("strike")), "side": side, "value": _v11811_float(r.get("coi")), "oi": _v11811_float(r.get("oi")), "coi": _v11811_float(r.get("coi")), "close": _v11811_float(r.get("close")), "volume": _v11811_float(r.get("volume"))}
        if oi_rows:
            r = max(oi_rows, key=lambda x: _v11811_float(x.get("oi")) or -10**30)
            result[f"{prefix}MaxOi"] = {"strike": _v11811_float(r.get("strike")), "side": side, "value": _v11811_float(r.get("oi")), "oi": _v11811_float(r.get("oi")), "coi": _v11811_float(r.get("coi")), "close": _v11811_float(r.get("close")), "volume": _v11811_float(r.get("volume"))}
    return result


def _v11811_participant_flow_label(row):
    if not isinstance(row, dict):
        return row
    direction = str(row.get("direction") or "Neutral")
    score = _v11811_float(row.get("score")) or 0
    score_chg = _v11811_float(row.get("scoreChange"))
    fut_chg = _v11811_float(row.get("futureNetChange"))
    parts = []
    flow_score = 0
    if fut_chg is not None:
        if fut_chg > 0:
            parts.append(f"Fut net +{fut_chg:,.0f}")
            flow_score += 1
        elif fut_chg < 0:
            parts.append(f"Fut net {fut_chg:,.0f}")
            flow_score -= 1
    if score_chg is not None:
        if score_chg > 1:
            parts.append(f"score +{score_chg:.2f}")
            flow_score += 1
        elif score_chg < -1:
            parts.append(f"score {score_chg:.2f}")
            flow_score -= 1
    if flow_score > 0:
        today_flow = "Bullish / improving"
    elif flow_score < 0:
        today_flow = "Bearish / worsening"
    else:
        today_flow = "Neutral / mixed"
    direction_l = direction.lower()
    if "bear" in direction_l and flow_score > 0:
        interpretation = "Overall short, but today added longs / covered shorts"
    elif "bull" in direction_l and flow_score < 0:
        interpretation = "Overall long, but today selling / reducing longs"
    elif "bear" in direction_l and flow_score < 0:
        interpretation = "Overall short and today added more bearish flow"
    elif "bull" in direction_l and flow_score > 0:
        interpretation = "Overall long and today added more bullish flow"
    else:
        interpretation = "Overall and today flow mixed/neutral"
    row["todayFlow"] = today_flow
    row["todayFlowDetail"] = "; ".join(parts) if parts else "No strong one-day change"
    row["overallVsToday"] = interpretation
    row["positionBiasNote"] = f"Overall {direction} ({score:.2f}); Today: {today_flow}"
    return row


def _v11811_enrich_participants(payload):
    for row in (payload.get("participants") or []) if isinstance(payload, dict) else []:
        _v11811_participant_flow_label(row)
    return payload


def _v11811_cash_trade_lookup(trade_date):
    try:
        df = _read_eod_df(
            """
            SELECT * FROM nse_cm_bhavcopy_raw
            WHERE trade_date = CAST(:trade_date AS DATE)
            """,
            {"trade_date": trade_date},
        )
        if df.empty:
            return {}
        sym_col = find_column(df, ("symbol", "SYMBOL"))
        qty_col = find_column(df, ("traded_volume", "traded_qty", "traded_quantity", "ttl_trd_qnty", "ttl_trd_qty", "total_traded_quantity", "volume"))
        trades_col = find_column(df, ("no_of_trades", "number_of_trades", "trades", "no_trades", "no_of_trade"))
        if not sym_col:
            return {}
        lookup = {}
        for _, row in df.iterrows():
            sym = str(row.get(sym_col) or "").strip().upper()
            if not sym:
                continue
            qty = _v11811_float(row.get(qty_col)) if qty_col else None
            trades = _v11811_float(row.get(trades_col)) if trades_col else None
            lookup[sym] = {
                "tradedQty": qty,
                "noOfTrades": trades,
                "tqyPerTrade": (qty / trades) if qty is not None and trades not in (None, 0) else None,
            }
        return lookup
    except Exception:
        return {}


def _v11811_enrich_cash_rows(payload):
    if not isinstance(payload, dict):
        return payload
    cash = payload.get("cash") or {}
    if not isinstance(cash, dict):
        return payload
    lookup = _v11811_cash_trade_lookup(payload.get("date"))
    for section in ("topRows", "accumulation", "distribution", "noAcceptance"):
        rows = cash.get(section) or []
        if not isinstance(rows, list):
            continue
        for row in rows:
            if not isinstance(row, dict):
                continue
            sym = str(row.get("symbol") or "").strip().upper()
            info = lookup.get(sym, {})
            if row.get("tradedQty") is None and info.get("tradedQty") is not None:
                row["tradedQty"] = info.get("tradedQty")
            if row.get("noOfTrades") is None and info.get("noOfTrades") is not None:
                row["noOfTrades"] = info.get("noOfTrades")
            row["tqyPerTrade"] = _v11811_float(row.get("tqyPerTrade"))
            if row["tqyPerTrade"] is None:
                row["tqyPerTrade"] = _v11811_ratio_pct(row.get("tradedQty"), row.get("noOfTrades"))
                if row["tqyPerTrade"] is not None:
                    row["tqyPerTrade"] = row["tqyPerTrade"] / 100.0
    return payload


def _v11811_enrich_eod_payload(payload):
    if not isinstance(payload, dict):
        return payload
    for key in ("topCe", "topPe", "strikeRows"):
        if isinstance(payload.get(key), list):
            _v11811_add_coi_oi_to_rows(payload[key])
    payload["optionExtremes"] = payload.get("optionExtremes") or _v11811_extremes_from_eod_rows(payload)
    _v11811_enrich_participants(payload)
    _v11811_enrich_cash_rows(payload)
    return payload


def _v11811_enrich_live_payload(payload, symbol=None, trade_date=None, expiry=None):
    if not isinstance(payload, dict):
        return payload
    _v11811_add_coi_oi_to_rows(payload.get("rows") or [])
    if not payload.get("optionExtremes"):
        payload["optionExtremes"] = _v11811_compute_live_option_extremes(
            symbol or payload.get("symbol"),
            trade_date or payload.get("date"),
            expiry or payload.get("expiry"),
        )
    payload["optionExtremeDrops"] = _v11811_compute_live_option_extreme_drops(
        symbol or payload.get("symbol"),
        trade_date or payload.get("date"),
        expiry or payload.get("expiry"),
    )
    payload["optionDayExtremes"] = _v11811_compute_live_option_day_extremes(
        symbol or payload.get("symbol"),
        trade_date or payload.get("date"),
        expiry or payload.get("expiry"),
    )
    _v11811_enrich_future_oi_context(
        payload,
        symbol=symbol or payload.get("symbol"),
        trade_date=trade_date or payload.get("date"),
    )
    return payload


_v11811_base_build_dashboard_payload = build_dashboard_payload

def build_dashboard_payload(symbol, band, trade_date=None, expiry=None, chart_strike=None):
    payload = _v11811_base_build_dashboard_payload(symbol, band, trade_date=trade_date, expiry=expiry)
    return _v11811_enrich_live_payload(payload, symbol=symbol, trade_date=trade_date, expiry=expiry)

def _v11811_future_oi_context(symbol, trade_date=None):
    """Current/previous/day-high futures OI for top card and reduction popup."""
    try:
        symbol = normalize_index_symbol(symbol or "NIFTY")
        df = read_futures_table_for_date(symbol, trade_date)
        if df is None or df.empty or "timestamp" not in df.columns:
            return {}
        oi_col = find_column(df, ("openInterest", "openinterest", "oi"))
        expiry_col = find_column(df, ("expiryDate", "expiry"))
        if not oi_col:
            return {}
        timestamps = sorted({normalize_timestamp(v) for v in df["timestamp"].dropna().astype(str).tolist()}, key=parse_timestamp)
        if not timestamps:
            return {}

        normalized_ts = df["timestamp"].map(normalize_timestamp)

        def oi_at(ts):
            frame = df[normalized_ts == ts]
            if frame.empty:
                return None, ""
            expiry_value = str(frame.iloc[0].get(expiry_col, "")) if expiry_col else ""
            return aggregate_sum_values(frame[oi_col].tolist()), expiry_value

        current_ts = timestamps[-1]
        previous_ts = timestamps[-2] if len(timestamps) > 1 else ""
        current_oi, current_expiry = oi_at(current_ts)
        previous_oi, _ = oi_at(previous_ts) if previous_ts else (None, "")

        best = None
        for ts in timestamps:
            value, expiry_value = oi_at(ts)
            if value is None:
                continue
            if best is None or value > best["value"]:
                best = {"value": value, "timestamp": ts, "time": timestamp_time_label(ts), "expiry": expiry_value}

        change = current_oi - previous_oi if current_oi is not None and previous_oi is not None else None
        return {
            "futureOiCurrent": current_oi,
            "futureOiPrevious": previous_oi,
            "futureOiChange": change,
            "futureOiChangePct": pct_change(current_oi, previous_oi),
            "futureOiTimestamp": current_ts,
            "futureOiPreviousTimestamp": previous_ts,
            "futureOiTime": timestamp_time_label(current_ts),
            "futureOiPreviousTime": timestamp_time_label(previous_ts) if previous_ts else "",
            "futureOiExpiry": current_expiry,
            "futureOiDayHigh": best or {},
            "futureOiDayPoints": len(timestamps),
        }
    except Exception:
        return {}


def _v11811_enrich_future_oi_context(payload, symbol=None, trade_date=None):
    if not isinstance(payload, dict):
        return payload
    ctx = _v11811_future_oi_context(symbol or payload.get("symbol"), trade_date or payload.get("date"))
    if not ctx:
        return payload
    fut = payload.get("futuresLatest") or {}
    if isinstance(fut, dict):
        fut.update(ctx)
        payload["futuresLatest"] = fut
    drops = payload.get("optionExtremeDrops") or []
    cur = ctx.get("futureOiCurrent")
    prev = ctx.get("futureOiPrevious")
    if cur is not None and prev is not None and cur < prev:
        drops.append({
            "key": "futureOi",
            "label": "Future OI",
            "timestamp": ctx.get("futureOiTimestamp") or payload.get("timestamp") or "",
            "previousTimestamp": ctx.get("futureOiPreviousTimestamp") or payload.get("previousTimestamp") or "",
            "current": {"value": cur, "time": ctx.get("futureOiTime") or ""},
            "previous": {"value": prev, "time": ctx.get("futureOiPreviousTime") or ""},
            "currentValue": cur,
            "previousValue": prev,
            "change": cur - prev,
            "changePct": ctx.get("futureOiChangePct"),
        })
    payload["optionExtremeDrops"] = drops
    return payload


