def _v11850_float(v):
    try:
        n = float(v)
        return None if (_math.isnan(n) or _math.isinf(n)) else n
    except Exception:
        return None


def _v11850_sign(v):
    n = _v11850_float(v)
    if n is None:
        return 0
    return 1 if n > 0 else (-1 if n < 0 else 0)


def _v11850_clamp(v, lo=-100.0, hi=100.0):
    n = _v11850_float(v)
    if n is None:
        return 0.0
    return max(lo, min(hi, n))


def _v11850_strength(score):
    """Convert an abs score to a human-readable strength label."""
    a = abs(_v11850_clamp(score))
    if a >= 60:
        return "High"
    if a >= 30:
        return "Medium"
    if a >= 12:
        return "Low"
    return "Negligible"


def _v11850_direction_from_score(score, bull=18, bear=-18):
    s = _v11850_clamp(score)
    if s >= bull:
        return "Bullish"
    if s <= bear:
        return "Bearish"
    return "Neutral"


