def _v11850_futures_lane(future_payload):
    """
    Build the Futures lane dict from the already-computed future_payload.
    future_payload comes straight from _v11820_future_range_action() output
    merged into the money-flow payload["future"].
    """
    f = future_payload or {}

    dir_score = _v11850_float(f.get("directionScore")) or 0.0
    confidence = _v11850_float(f.get("confidence")) or 0.0
    lane_score = _v11850_clamp(dir_score * confidence)

    direction = f.get("direction") or _v11850_direction_from_score(lane_score)
    action    = f.get("action") or "Neutral"

