    # basis = futurePrice - spotPrice.  We look at the range start vs end.
    basis_start = _v11850_float(f.get("rangeStartPrice"))  # price proxy; true basis needs spot
    basis_end   = _v11850_float(f.get("rangeEndPrice"))
    basis_raw   = _v11850_float(f.get("basis"))            # latest single-tick basis
    oi_change   = _v11850_float(f.get("rangeOiChange"))

    if basis_start is not None and basis_end is not None:
        basis_delta = basis_end - basis_start
    else:
        basis_delta = None

    # basisTrend: combine direction of basis move with OI change
    if basis_delta is not None and oi_change is not None:
        if basis_delta > 0 and oi_change > 0:
            basis_trend = "Expanding"        # longs paying up = long build-up
        elif basis_delta < 0 and oi_change > 0:
            basis_trend = "Collapsing"       # basis eroding while OI adds = short build-up
        elif abs(basis_delta) < 2:
            basis_trend = "Flat"
        else:
            basis_trend = "Mixed"
    else:
        basis_trend = "Unavailable"

