def _v11850_atm_iv_by_side(rows, atm, step):
    """
    From the money-flow rows list, find ATM CE IV and ATM PE IV.
    ATM = rows where distanceFromAtm == 0.  Fallback: nearest 1 strike.
    Returns (ce_iv, pe_iv) as floats or None.
    """
    ce_iv = pe_iv = None

    def _iv(r):
        return _v11850_float(r.get("iv"))

    # Exact ATM first
    for r in rows:
        dist = _v11850_float(r.get("distanceFromAtm"))
        side = str(r.get("side") or "").upper()
        if dist is not None and abs(dist) < 0.01:
            iv_val = _iv(r)
            if iv_val is not None and iv_val > 0:
                if side == "CE" and ce_iv is None:
                    ce_iv = iv_val
                elif side == "PE" and pe_iv is None:
                    pe_iv = iv_val

    if ce_iv is not None and pe_iv is not None:
        return ce_iv, pe_iv

    # Fallback: nearest within 1 strike
    for r in rows:
        dist = _v11850_float(r.get("distanceFromAtm"))
        side = str(r.get("side") or "").upper()
        if dist is not None and abs(dist) <= 1:
            iv_val = _iv(r)
            if iv_val is not None and iv_val > 0:
                if side == "CE" and ce_iv is None:
                    ce_iv = iv_val
                elif side == "PE" and pe_iv is None:
                    pe_iv = iv_val

    return ce_iv, pe_iv


def _v11850_iv_skew_regime(ce_iv, pe_iv, threshold=1.5):
    """
    ce_iv - pe_iv:
      positive (CE IV > PE IV) ГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓвЂљГ‚В ГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓВўГўв‚¬ЕѕГ‚Вў upside uncertainty / CE writers commanding premium ГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓвЂљГ‚В ГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓВўГўв‚¬ЕѕГ‚Вў Bearish lean
      negative (PE IV > CE IV) ГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓвЂљГ‚В ГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓВўГўв‚¬ЕѕГ‚Вў downside fear / put demand ГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓвЂљГ‚В ГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓВўГўв‚¬ЕѕГ‚Вў Bearish lean too (but different kind)

    We return the regime name AND the skew value so the caller can decide how to use it.
    threshold: minimum absolute skew to call a regime (avoids noise).
    """
    if ce_iv is None or pe_iv is None:
        return "Unavailable", None
    skew = ce_iv - pe_iv
    if skew > threshold:
        return "CeIvExpanding", round(skew, 2)   # CE writers pricing in upside risk ГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓвЂљГ‚В ГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓВўГўв‚¬ЕѕГ‚Вў bearish for spot
    if skew < -threshold:
        return "PeIvExpanding", round(skew, 2)   # PE demand / downside fear ГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓвЂљГ‚В ГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓВўГўв‚¬ЕѕГ‚Вў bearish for spot too
    return "Balanced", round(skew, 2)


def _v11850_writing_confirmed(rows):
    """
    True when dominant side shows: OI adding + premium flat/falling + IV rising.
    We check CE and PE separately and return whichever side (or both) confirm.
    """
    confirmed = []
    for side in ("CE", "PE"):
        side_rows = [r for r in rows if str(r.get("side") or "").upper() == side]
        writing_rows = [r for r in side_rows if "Writing" in str(r.get("action") or "")]
        if not writing_rows:
            continue
        # weighted check: most writing rows should have premium_delta <= 0
        prem_ok = sum(
            1 for r in writing_rows
            if (_v11850_float(r.get("premiumDelta")) or 0) <= 0
        )
        iv_ok = sum(
            1 for r in writing_rows
            if (_v11850_float(r.get("ivDelta")) or 0) >= 0   # IV flat or rising is fine for writing
        )
        if len(writing_rows) > 0 and prem_ok / len(writing_rows) >= 0.6:
            confirmed.append(side)
    return confirmed  # list of sides with confirmed writing


def _v11850_options_lane(summary, rows, atm, step):
    """
    Build the Options lane dict.
    summary  = payload["summary"]
    rows     = payload["rows"]  (list of per-strike money-flow rows)
    """
    s = summary or {}

    bull_cr = _v11850_float(s.get("bullishOptionFlowCr")) or 0.0
    bear_cr = _v11850_float(s.get("bearishOptionFlowCr")) or 0.0
    total_cr = bull_cr + bear_cr
    option_score = ((bull_cr - bear_cr) / total_cr * 100.0) if total_cr > 0 else 0.0
    lane_score = _v11850_clamp(option_score)
