# ============================== V11.8.54 PREMIUM DECAY ROC + MODEL WORDING ==============================
# Additive wrapper: keeps the existing Money Flow payload shape, then adds a
# focused ATM +/- N premium-decay model from day open and previous close.


def _v11854_date_key(value):
    try:
        return pd.to_datetime(value).date()
    except Exception:
        return None


def _v11854_previous_trade_date(symbol, trade_date):
    current = _v11854_date_key(trade_date)
    if not current:
        return None
    prev = []
    try:
        for value in get_available_dates(symbol) or []:
            d = _v11854_date_key(value)
            if d and d < current:
                prev.append(d)
    except Exception:
        return None
    if not prev:
        return None
    return max(prev).strftime("%Y-%m-%d")


def _v11854_frame_at_timestamp(df, timestamp_value, prefer_last_before=True):
    if df is None or df.empty or "timestamp" not in df.columns:
        return "", pd.DataFrame()
    timestamps = sorted(df["timestamp"].dropna().unique(), key=parse_timestamp)
    if not timestamps:
        return "", pd.DataFrame()
    target_dt = parse_timestamp(timestamp_value) if timestamp_value else parse_timestamp(timestamps[-1])
    chosen = timestamps[-1]
    if prefer_last_before and target_dt != datetime.min:
        before = [ts for ts in timestamps if parse_timestamp(ts) <= target_dt]
        chosen = before[-1] if before else timestamps[0]
    else:
        chosen = timestamp_value if timestamp_value in timestamps else timestamps[-1]
    return chosen, df[df["timestamp"] == chosen].copy()


def _v11854_option_frame_map(frame, strike_col, side_col):
    out = {}
    if frame is None or frame.empty:
        return out
    for _, row in frame.iterrows():
        strike = to_number(row.get(strike_col))
        side = str(row.get(side_col) or "").upper().strip()
        if strike is None or side not in {"CE", "PE"}:
            continue
        out[(float(strike), side)] = row
    return out


def _v11854_side_summary(rows, side):
    side_rows = [r for r in rows if r.get("side") == side]
    if not side_rows:
        return {"count": 0, "basketRoc": None, "decayPct": 0.0, "expansionPct": 0.0, "oiDelta": 0.0, "oiRoc": None}
    ref_sum = sum(to_number(r.get("referencePremium")) or 0 for r in side_rows)
    cur_sum = sum(to_number(r.get("currentPremium")) or 0 for r in side_rows)
    ref_oi = sum(to_number(r.get("referenceOI")) or 0 for r in side_rows)
    cur_oi = sum(to_number(r.get("currentOI")) or 0 for r in side_rows)
    rocs = [to_number(r.get("premiumRoc")) for r in side_rows if to_number(r.get("premiumRoc")) is not None]
    weighted_num = 0.0
    weighted_den = 0.0
    for row in side_rows:
        roc = to_number(row.get("premiumRoc"))
        wt = abs(to_number(row.get("currentOI")) or 0) or 1.0
        if roc is not None:
            weighted_num += roc * wt
            weighted_den += wt
    basket_roc = pct_change(cur_sum, ref_sum)
    decay_pct = max(0.0, -(basket_roc or 0.0))
    expansion_pct = max(0.0, basket_roc or 0.0)
    return {
        "count": len(side_rows),
        "referencePremiumSum": round(ref_sum, 4),
        "currentPremiumSum": round(cur_sum, 4),
        "premiumChangeSum": round(cur_sum - ref_sum, 4),
        "basketRoc": round(basket_roc, 2) if basket_roc is not None else None,
        "avgRoc": round(sum(rocs) / len(rocs), 2) if rocs else None,
        "weightedRoc": round(weighted_num / weighted_den, 2) if weighted_den else None,
        "decayPct": round(decay_pct, 2),
        "expansionPct": round(expansion_pct, 2),
        "referenceOI": round(ref_oi, 0),
        "currentOI": round(cur_oi, 0),
        "oiDelta": round(cur_oi - ref_oi, 0),
        "oiRoc": round(pct_change(cur_oi, ref_oi), 2) if ref_oi else None,
    }


def _v11854_decay_bias(ce, pe, spot_roc):
    ce_decay = to_number((ce or {}).get("decayPct")) or 0.0
    pe_decay = to_number((pe or {}).get("decayPct")) or 0.0
    ce_oi_delta = to_number((ce or {}).get("oiDelta")) or 0.0
    pe_oi_delta = to_number((pe or {}).get("oiDelta")) or 0.0
    score = (pe_decay - ce_decay) * 2.0
    if ce_decay > pe_decay and ce_oi_delta > 0:
        score -= min(15.0, abs(ce_oi_delta) / 10000.0)
    if pe_decay > ce_decay and pe_oi_delta > 0:
        score += min(15.0, abs(pe_oi_delta) / 10000.0)
    score = max(-100.0, min(100.0, score))
    if score >= 12:
        bias = "Bullish PE Writing / Support"
        side = "PE"
        text = "PE premium is decaying more than CE around ATM; with PE OI adding it suggests put writing support."
    elif score <= -12:
        bias = "Bearish CE Writing / Resistance"
        side = "CE"
        text = "CE premium is decaying more than PE around ATM; with CE OI adding it suggests call writing resistance."
    else:
        bias = "Neutral / Mixed Decay"
        side = "Mixed"
        text = "CE and PE decay are balanced or not strong enough for a writing bias."
    if spot_roc is not None:
        text += " Compare against NIFTY ROC to avoid mistaking normal directional option decay for writing."
    return {"bias": bias, "score": round(score, 2), "strongerDecaySide": side, "interpretation": text}


def _v11854_compute_decay_for_frames(symbol, trade_date, expiry, payload, ref_label, ref_ts, ref_frame, cur_ts, cur_frame, atm_band=5):
    if ref_frame is None or ref_frame.empty or cur_frame is None or cur_frame.empty:
        return {"available": False, "mode": ref_label, "error": "Reference or current option frame is empty."}
    strike_col = find_column(cur_frame, ("strikePrice", "strike"))
    side_col = find_column(cur_frame, ("optionType", "type"))
    premium_col = find_column(cur_frame, METRICS["premium"]["aliases"])
    oi_col = find_column(cur_frame, METRICS["openInterest"]["aliases"])
    spot_col = find_column(cur_frame, ("spotPrice", "underlyingValue"))
    ref_strike_col = find_column(ref_frame, ("strikePrice", "strike")) or strike_col
    ref_side_col = find_column(ref_frame, ("optionType", "type")) or side_col
    ref_premium_col = find_column(ref_frame, METRICS["premium"]["aliases"]) or premium_col
    ref_oi_col = find_column(ref_frame, METRICS["openInterest"]["aliases"]) or oi_col
    ref_spot_col = find_column(ref_frame, ("spotPrice", "underlyingValue")) or spot_col
    if not strike_col or not side_col or not premium_col or not ref_strike_col or not ref_side_col or not ref_premium_col:
        return {"available": False, "mode": ref_label, "error": "Required strike/side/premium columns are missing."}

    current_spot = first_valid_number(cur_frame[spot_col].tolist()) if spot_col else to_number(payload.get("spot"))
    reference_spot = first_valid_number(ref_frame[ref_spot_col].tolist()) if ref_spot_col else None
    strikes = sorted({to_number(v) for v in cur_frame[strike_col].tolist() if to_number(v) is not None})
    atm = to_number(payload.get("atm")) or (nearest_atm(strikes, current_spot) if strikes and current_spot is not None else None)
    step = to_number(payload.get("strikeStep")) or (infer_strike_step(strikes) if strikes else 50)
    if atm is None:
        return {"available": False, "mode": ref_label, "error": "ATM could not be determined."}
    low = atm - int(atm_band) * step
    high = atm + int(atm_band) * step

    ref_map = _v11854_option_frame_map(ref_frame, ref_strike_col, ref_side_col)
    cur_map = _v11854_option_frame_map(cur_frame, strike_col, side_col)
    rows = []
    for (strike, side), cur_row in cur_map.items():
        if strike < low or strike > high:
            continue
        ref_row = ref_map.get((strike, side))
        if ref_row is None:
            continue
        cur_premium = to_number(cur_row.get(premium_col))
        ref_premium = to_number(ref_row.get(ref_premium_col))
        if cur_premium is None or ref_premium is None or ref_premium <= 0:
            continue
        cur_oi = to_number(cur_row.get(oi_col)) if oi_col else None
        ref_oi = to_number(ref_row.get(ref_oi_col)) if ref_oi_col else None
        premium_roc = pct_change(cur_premium, ref_premium)
        rows.append({
            "side": side,
            "strike": strike,
            "referencePremium": round(ref_premium, 4),
            "currentPremium": round(cur_premium, 4),
            "premiumChange": round(cur_premium - ref_premium, 4),
            "premiumRoc": round(premium_roc, 2) if premium_roc is not None else None,
            "referenceOI": ref_oi,
            "currentOI": cur_oi,
            "oiDelta": (cur_oi - ref_oi) if cur_oi is not None and ref_oi is not None else None,
            "oiRoc": round(pct_change(cur_oi, ref_oi), 2) if cur_oi is not None and ref_oi else None,
            "signal": "Decay" if (premium_roc or 0) < 0 else ("Expansion" if (premium_roc or 0) > 0 else "Flat"),
        })
    if not rows:
        return {"available": False, "mode": ref_label, "error": "No matched ATM +/- %s strikes between reference and current frame." % atm_band}

    ce = _v11854_side_summary(rows, "CE")
    pe = _v11854_side_summary(rows, "PE")
    spot_roc = pct_change(current_spot, reference_spot) if current_spot is not None and reference_spot else None
    bias = _v11854_decay_bias(ce, pe, spot_roc)
    top_decay = sorted(rows, key=lambda r: to_number(r.get("premiumRoc")) or 0)[:20]
    top_expansion = sorted(rows, key=lambda r: to_number(r.get("premiumRoc")) or 0, reverse=True)[:20]
    return {
        "available": True,
        "mode": ref_label,
        "referenceLabel": ref_label,
        "referenceTimestamp": ref_ts,
        "referenceTime": timestamp_time_label(ref_ts),
        "currentTimestamp": cur_ts,
        "currentTime": timestamp_time_label(cur_ts),
        "referenceSpot": round(reference_spot, 2) if reference_spot is not None else None,
        "currentSpot": round(current_spot, 2) if current_spot is not None else None,
        "spotChange": round((current_spot - reference_spot), 2) if current_spot is not None and reference_spot is not None else None,
        "spotRoc": round(spot_roc, 2) if spot_roc is not None else None,
        "atm": atm,
        "strikeStep": step,
        "atmBand": int(atm_band),
        "strikeRange": {"from": low, "to": high},
        "ce": ce,
        "pe": pe,
        "bias": bias.get("bias"),
        "score": bias.get("score"),
        "strongerDecaySide": bias.get("strongerDecaySide"),
        "interpretation": bias.get("interpretation"),
        "rows": rows,
        "topDecay": top_decay,
        "topExpansion": top_expansion,
        "method": "Basket ROC uses sum of option premiums in ATM +/- %s strikes. More negative ROC means more premium decay; OI addition confirms writing." % atm_band,
    }


def _v11854_premium_decay_payload(payload, atm_band=5):
    if not isinstance(payload, dict) or payload.get("error"):
        return {"available": False, "error": "Base money-flow payload unavailable."}
    symbol = payload.get("symbol") or "NIFTY"
    trade_date = payload.get("date")
    expiry = payload.get("expiry")
    current_ts = ((payload.get("range") or {}).get("endTimestamp") or payload.get("timestamp"))
    try:
        df = read_symbol_table_for_date_expiry_fast(symbol, trade_date, expiry=expiry, max_timestamps=None)
        if df.empty or "timestamp" not in df.columns:
            return {"available": False, "error": "No option rows for premium decay."}
        df = df.copy()
        df["timestamp"] = df["timestamp"].map(normalize_timestamp)
        timestamps = sorted(df["timestamp"].dropna().unique(), key=parse_timestamp)
        if not timestamps:
            return {"available": False, "error": "No timestamps for premium decay."}
        ref_open_ts = timestamps[0]
        ref_open_frame = df[df["timestamp"] == ref_open_ts].copy()
        cur_ts, cur_frame = _v11854_frame_at_timestamp(df, current_ts, prefer_last_before=True)
        open_decay = _v11854_compute_decay_for_frames(symbol, trade_date, expiry, payload, "Day Open", ref_open_ts, ref_open_frame, cur_ts, cur_frame, atm_band=atm_band)

        previous_decay = {"available": False, "mode": "Previous Close", "error": "Previous close reference not available."}
        prev_date = _v11854_previous_trade_date(symbol, trade_date)
        if prev_date:
            prev_df = read_symbol_table_for_date_expiry_fast(symbol, prev_date, expiry=expiry, max_timestamps=None)
            if prev_df is not None and not prev_df.empty and "timestamp" in prev_df.columns:
                prev_df = prev_df.copy()
                prev_df["timestamp"] = prev_df["timestamp"].map(normalize_timestamp)
                prev_ts_values = sorted(prev_df["timestamp"].dropna().unique(), key=parse_timestamp)
                if prev_ts_values:
                    prev_ts = prev_ts_values[-1]
                    prev_frame = prev_df[prev_df["timestamp"] == prev_ts].copy()
                    previous_decay = _v11854_compute_decay_for_frames(symbol, trade_date, expiry, payload, "Previous Close", prev_ts, prev_frame, cur_ts, cur_frame, atm_band=atm_band)
                    previous_decay["previousDate"] = prev_date
        return {
            "available": bool(open_decay.get("available") or previous_decay.get("available")),
            "activeMode": "Day Open",
            "active": open_decay,
            "open": open_decay,
            "previousClose": previous_decay,
            "atmBand": atm_band,
            "note": "Premium Decay ROC compares NIFTY spot ROC with total CE/PE premium basket ROC around ATM +/- %s." % atm_band,
        }
    except Exception as exc:
        return {"available": False, "error": "%s: %s" % (type(exc).__name__, exc)}


def _v11854_inject_money_flow_model(payload):
    if not isinstance(payload, dict):
        return payload
    try:
        payload["premiumDecay"] = _v11854_premium_decay_payload(payload, atm_band=5)
    except Exception as exc:
        payload["premiumDecay"] = {"available": False, "error": "%s: %s" % (type(exc).__name__, exc)}
    payload["howToUse"] = (
        "Option flow is a premium-exposure proxy, not exact participant ownership: gross exposure = 1m option NSE Volume (DB noOfTrades delta) * premium * lot; "
        "fresh exposure = positive 1m COI * premium * lot; closed exposure = abs(negative 1m COI) * premium * lot; "
        "churn/exchange-of-hands = volume not converting into OI. Direction comes from COI + premium ROC + IV ROC + COI/NT; OI up always has both buyer and seller. "
        "Futures use price/OI build-up classification plus live volume notional. Premium Decay compares ATM +/-5 CE/PE basket ROC from day open and previous close against NIFTY ROC."
    )
    payload["disclaimer"] = (
        "Use this as a probability/risk-management dashboard. NSE public live data cannot confirm FII/Prop strike ownership; it infers behavior from public OI, volume, premium, IV, futures, and cash proxies."
    )
    return payload


_v11854_base_build_360_money_flow_payload = build_360_money_flow_payload


def build_360_money_flow_payload(symbol, trade_date=None, expiry=None, band=20,
                                  start_index=None, end_index=None):
    payload = _v11854_base_build_360_money_flow_payload(
        symbol,
        trade_date=trade_date,
        expiry=expiry,
        band=band,
        start_index=start_index,
        end_index=end_index,
    )
    return _v11854_inject_money_flow_model(payload)

