# V11.8.56 Pro Edge Layer: compact four-phase decision support.
_V11856_PRO_EDGE_CACHE = {}

def _v11856_f(v, d=None):
    try:
        if v is None: return d
        if isinstance(v, str):
            v = v.replace(',', '').replace('%', '').strip()
            if not v: return d
        return float(v)
    except Exception:
        return d

def _v11856_clip(v, lo=-100.0, hi=100.0):
    return max(lo, min(hi, _v11856_f(v, 0.0) or 0.0))

def _v11856_dir_score(v):
    t = str(v or '').lower()
    if 'bull' in t or 'support' in t or 'long build' in t or 'short covering' in t: return 1
    if 'bear' in t or 'resistance' in t or 'short build' in t or 'long unwind' in t: return -1
    return 0

def _v11856_dir(v, th=12.0):
    v = _v11856_f(v, 0.0) or 0.0
    return 'Bullish' if v >= th else ('Bearish' if v <= -th else 'Neutral')

def _v11856_r(v, n=2):
    v = _v11856_f(v)
    return round(v, n) if v is not None else None

def _v11856_defaults(symbol, trade_date, expiry):
    symbol = normalize_index_symbol(symbol or 'NIFTY')
    dates = get_available_dates(symbol)
    if not trade_date and dates: trade_date = dates[0]
    expiries = get_available_expiries_for_date(symbol, trade_date)
    if not expiry and expiries: expiry = expiries[0]
    return symbol, trade_date, expiry

def _v11856_ts(values):
    vals = []
    for value in values:
        ts = normalize_timestamp(value)
        if ts: vals.append(ts)
    return sorted(set(vals), key=parse_timestamp)

def _v11856_option_frame(symbol, trade_date, expiry, max_timestamps=120):
    df = read_symbol_table_for_date_expiry_fast(symbol, trade_date, expiry=expiry, max_timestamps=max_timestamps)
    if df is None or df.empty or 'timestamp' not in df.columns: return pd.DataFrame(), {}, []
    df = df.copy(); df['timestamp'] = df['timestamp'].map(normalize_timestamp)
    cols = {
        'strike': find_column(df, ('strikePrice','strike','StrikePrice')),
        'side': find_column(df, ('optionType','type','OptionType')),
        'oi': find_column(df, METRICS['openInterest']['aliases']),
        'coi': find_column(df, ('changeinOpenInterest','changeInOpenInterest','change_in_open_interest','changeOI','COI')),
        'premium': find_column(df, METRICS['premium']['aliases']),
        'iv': find_column(df, ('impliedVolatility','iv','IV')),
        'spot': find_column(df, ('underlyingValue','spot','spotPrice','Spot')),
    }
    if not cols['strike'] or not cols['side']: return pd.DataFrame(), cols, []
    df['_strike'] = df[cols['strike']].map(to_number)
    df['_side'] = df[cols['side']].map(lambda x: str(x or '').upper().strip())
    df = df[(df['_strike'].notna()) & (df['_side'].isin(['CE','PE']))].copy()
    return df, cols, _v11856_ts(df['timestamp'].dropna().tolist())

def _v11856_pick_frame(df, timestamps, timestamp=None):
    if df.empty or not timestamps: return None, pd.DataFrame()
    chosen = timestamps[-1]
    if timestamp:
        want = parse_timestamp(normalize_timestamp(timestamp)); prior = [ts for ts in timestamps if parse_timestamp(ts) <= want]
        chosen = prior[-1] if prior else chosen
    return chosen, df[df['timestamp'] == chosen].copy()

def _v11856_institutional(symbol, trade_date, expiry):
    try:
        p = build_eod_participation_payload(symbol, trade_date=trade_date, expiry=expiry)
        big = p.get('bigMoney') or {}; rows = p.get('participants') or []
        by = {str(r.get('participant') or r.get('rawParticipant') or '').upper(): r for r in rows}
        fii = by.get('FII') or {}; prop = by.get('PROP') or by.get('PRO') or {}
        fii_score = _v11856_f(big.get('fiiScore'), _v11856_f(fii.get('score'), 0.0)) or 0.0
        prop_score = _v11856_f(big.get('propScore'), _v11856_f(prop.get('score'), 0.0)) or 0.0
        score = _v11856_f(big.get('score'), None)
        if score is None: score = 0.65 * fii_score + 0.35 * prop_score
        direction = big.get('direction') or _v11856_dir(score, 8)
        return {'available': True, 'date': p.get('date') or trade_date, 'direction': direction, 'score': round(_v11856_clip(score),2), 'fiiDirection': big.get('fiiDirection') or fii.get('direction') or 'Neutral', 'propDirection': big.get('propDirection') or prop.get('direction') or 'Neutral', 'fiiScore': round(fii_score,2), 'propScore': round(prop_score,2), 'source': 'EOD participant OI/volume'}
    except Exception as exc:
        return {'available': False, 'direction': 'Neutral', 'score': 0.0, 'error': '%s: %s' % (type(exc).__name__, exc)}

def _v11856_regime(symbol, trade_date, expiry, timestamp=None, band=5):
    try:
        df, c, timestamps = _v11856_option_frame(symbol, trade_date, expiry, max_timestamps=120)
        ts, cur = _v11856_pick_frame(df, timestamps, timestamp)
        if cur.empty: return {'available': False, 'error': 'No option frame.'}
        if not c.get('oi') or not c.get('premium'): return {'available': False, 'error': 'OI/premium columns missing.'}
        spot = first_valid_number(cur[c['spot']].tolist()) if c.get('spot') and c['spot'] in cur.columns else None
        strikes = sorted({to_number(v) for v in cur[c['strike']].tolist() if to_number(v) is not None})
        step = infer_strike_step(strikes) if strikes else 50
        atm = nearest_atm(strikes, spot) if strikes and spot is not None else (strikes[len(strikes)//2] if strikes else None)
        if atm is None: return {'available': False, 'error': 'ATM unavailable.'}
        low = atm - band * step; high = atm + band * step
        basket = cur[(cur['_strike'] >= low) & (cur['_strike'] <= high)]
        iv_vals = []
        if c.get('iv'):
            for t in timestamps:
                f = df[(df['timestamp'] == t) & (df['_strike'] >= low) & (df['_strike'] <= high)]
                vals = [_v11856_f(v) for v in f[c['iv']].tolist()]; vals = [v for v in vals if v and v > 0]
                if vals: iv_vals.append(sum(vals)/len(vals))
        cur_ivs = [_v11856_f(v) for v in basket[c['iv']].tolist()] if c.get('iv') else []
        cur_ivs = [v for v in cur_ivs if v and v > 0]
        iv_avg = sum(cur_ivs)/len(cur_ivs) if cur_ivs else None
        iv_low = min(iv_vals) if iv_vals else None; iv_high = max(iv_vals) if iv_vals else None
        iv_rank = ((iv_avg-iv_low)*100/(iv_high-iv_low)) if iv_avg is not None and iv_low is not None and iv_high and iv_high > iv_low else None
        iv_pct = (sum(1 for v in iv_vals if v <= iv_avg)*100/len(iv_vals)) if iv_avg is not None and iv_vals else None
        def one(strike, side):
            x = cur[(cur['_strike'] == strike) & (cur['_side'] == side)]
            return x.iloc[0] if not x.empty else None
        ce_atm = one(atm, 'CE'); pe_atm = one(atm, 'PE')
        ce_p = _v11856_f(ce_atm.get(c['premium']),0.0) if ce_atm is not None else 0.0
        pe_p = _v11856_f(pe_atm.get(c['premium']),0.0) if pe_atm is not None else 0.0
        rows=[]; lo=atm-10*step; hi=atm+10*step
        for strike in [s for s in strikes if lo <= s <= hi]:
            ce=one(strike,'CE'); pe=one(strike,'PE')
            ce_oi=_v11856_f(ce.get(c['oi']),0.0) if ce is not None else 0.0; pe_oi=_v11856_f(pe.get(c['oi']),0.0) if pe is not None else 0.0
            bias='Resistance' if ce_oi > pe_oi*1.18 else ('Support' if pe_oi > ce_oi*1.18 else 'Balanced')
            rows.append({'strike': strike, 'ceOi': round(ce_oi,0), 'peOi': round(pe_oi,0), 'pcr': round(pe_oi/ce_oi,2) if ce_oi else None, 'bias': bias})
        top_ce=max(rows,key=lambda r:r.get('ceOi') or 0,default={}); top_pe=max(rows,key=lambda r:r.get('peOi') or 0,default={})
        ce_max=_v11856_f(top_ce.get('ceOi'),0.0) or 0.0; pe_max=_v11856_f(top_pe.get('peOi'),0.0) or 0.0
        heat_score=(pe_max-ce_max)*100/max(ce_max+pe_max,1.0) if (ce_max or pe_max) else 0.0
        heat_bias=_v11856_dir(heat_score,8); heat_bias = 'Range / Wall-Support' if heat_bias == 'Neutral' and rows else heat_bias
        em = (ce_p or 0) + (pe_p or 0)
        return {'available': True, 'timestamp': ts, 'time': timestamp_time_label(ts), 'spot': _v11856_r(spot,2), 'atm': atm, 'strikeStep': step, 'ivAvg': _v11856_r(iv_avg,2), 'ivLow': _v11856_r(iv_low,2), 'ivHigh': _v11856_r(iv_high,2), 'ivRank': _v11856_r(iv_rank,2), 'ivPercentile': _v11856_r(iv_pct,2), 'ivRegime': 'High IV' if (iv_rank or 0) >= 75 else ('Low IV' if iv_rank is not None and iv_rank <= 25 else 'Normal IV'), 'expectedMove': {'points': round(em,2), 'percent': round(em*100/spot,2) if spot else None, 'upper': round(spot+em,2) if spot else None, 'lower': round(spot-em,2) if spot else None, 'atmCePremium': round(ce_p,2), 'atmPePremium': round(pe_p,2)}, 'oiHeatmap': {'bias': heat_bias, 'score': round(_v11856_clip(heat_score),2), 'topCeWall': top_ce, 'topPeSupport': top_pe, 'rows': rows}}
    except Exception as exc:
        return {'available': False, 'error': '%s: %s' % (type(exc).__name__, exc)}

def _v11856_sig(side, oi_delta, prem_delta):
    if abs(oi_delta) < 1: return 0.0
    if side == 'CE': return 1.0 if (oi_delta > 0 and prem_delta > 0) or (oi_delta < 0 and prem_delta > 0) else (-1.0 if oi_delta > 0 else -0.5)
    if side == 'PE': return -1.0 if (oi_delta > 0 and prem_delta > 0) or (oi_delta < 0 and prem_delta > 0) else (1.0 if oi_delta > 0 else 0.5)
    return 0.0

def _v11856_validation(symbol, trade_date, expiry, band=5):
    try:
        df,c,timestamps=_v11856_option_frame(symbol, trade_date, expiry, max_timestamps=90)
        if len(timestamps) < 8 or not c.get('oi') or not c.get('premium'): return {'available': False, 'bias': 'Neutral', 'error': 'Not enough validation data.'}
        lot=_lot_size_for_symbol(symbol); by={ts:df[df['timestamp']==ts] for ts in timestamps}; scored=[]
        for i in range(1,len(timestamps)):
            cur=by[timestamps[i]]; prev=by[timestamps[i-1]]; spot=first_valid_number(cur[c['spot']].tolist()) if c.get('spot') else None
            strikes=sorted({to_number(v) for v in cur[c['strike']].tolist() if to_number(v) is not None}); step=infer_strike_step(strikes) if strikes else 50; atm=nearest_atm(strikes,spot) if strikes and spot is not None else None
            if atm is None: continue
            lo=atm-max(3,int(band))*step; hi=atm+max(3,int(band))*step; pm={(r.get('_strike'),r.get('_side')):r for _,r in prev.iterrows()}; signed=0.0
            for _,r in cur.iterrows():
                strike=r.get('_strike'); side=r.get('_side')
                if strike is None or strike < lo or strike > hi or (strike,side) not in pm: continue
                old=pm[(strike,side)]; oi_delta=(_v11856_f(r.get(c['oi']),0) or 0)-(_v11856_f(old.get(c['oi']),0) or 0); prem=(_v11856_f(r.get(c['premium']),0) or 0); prem_delta=prem-(_v11856_f(old.get(c['premium']),0) or 0)
                signed += _v11856_sig(side, oi_delta, prem_delta) * abs(oi_delta) * max(prem,1) * lot / 10000000.0
            score=_v11856_clip(signed*8); scored.append({'index':i,'timestamp':timestamps[i],'time':timestamp_time_label(timestamps[i]),'spot':spot,'score':round(score,2),'direction':_v11856_dir(score,10)})
        spot_by={x['index']:x.get('spot') for x in scored}; sigs=[x for x in scored if abs(x.get('score') or 0)>=10 and x.get('direction')!='Neutral']; recent=[]; hits={5:0,10:0,15:0}; tots={5:0,10:0,15:0}
        for x in sigs:
            s=1 if x['direction']=='Bullish' else -1; moves={}
            for h in (5,10,15):
                fs=spot_by.get(x['index']+h); mv=(fs-x.get('spot')) if fs is not None and x.get('spot') is not None else None; moves[h]=mv
                if mv is not None: tots[h]+=1; hits[h]+=1 if s*mv>=5 else 0
            res='Open' if moves[5] is None else ('Hit' if s*moves[5]>=5 else ('Miss' if s*moves[5]<=-5 else 'Flat'))
            recent.append({'time':x['time'],'direction':x['direction'],'score':x['score'],'next5Move':_v11856_r(moves[5],2),'next10Move':_v11856_r(moves[10],2),'next15Move':_v11856_r(moves[15],2),'result':res})
        rates={h:(hits[h]*100/tots[h] if tots[h] else None) for h in (5,10,15)}; recent_score=sum([x.get('score') or 0 for x in scored[-10:]])/max(1,len(scored[-10:])); quality=sum([v for v in rates.values() if v is not None])/max(1,len([v for v in rates.values() if v is not None])); bias_score=_v11856_clip(recent_score*.65+(quality-50)*.7)
        return {'available': True, 'bias': _v11856_dir(bias_score,10), 'score': round(bias_score,2), 'recentScore': round(recent_score,2), 'hitRate5': _v11856_r(rates[5],1), 'hitRate10': _v11856_r(rates[10],1), 'hitRate15': _v11856_r(rates[15],1), 'signalsChecked': len(sigs), 'recentSignals': recent[-14:][::-1]}
    except Exception as exc:
        return {'available': False, 'bias': 'Neutral', 'score': 0.0, 'error': '%s: %s' % (type(exc).__name__, exc)}

def _v11856_build_pro_edge(symbol, trade_date=None, expiry=None, band=5, base_payload=None):
    symbol,trade_date,expiry=_v11856_defaults(symbol,trade_date,expiry); base_payload=base_payload or {}; ts=((base_payload.get('range') or {}).get('endTimestamp') or base_payload.get('timestamp') or ((base_payload.get('fastWindow') or {}).get('to')))
    key=(symbol,str(trade_date),str(expiry),str(ts),'v11856'); now=datetime.now().timestamp(); cached=_V11856_PRO_EDGE_CACHE.get(key)
    if cached and now-cached['created']<45: return cached['payload']
    inst=_v11856_institutional(symbol,trade_date,expiry); reg=_v11856_regime(symbol,trade_date,expiry,timestamp=ts,band=5); val=_v11856_validation(symbol,trade_date,expiry,band=band)
    trade=base_payload.get('tradeDecision') or {}; summary=base_payload.get('summary') or {}; master=base_payload.get('master') or {}; master_score=_v11856_f(trade.get('masterScore'), _v11856_f(master.get('masterScore'), _v11856_f(summary.get('finalScore'),0.0))) or 0.0
    heat_score=_v11856_f(((reg.get('oiHeatmap') or {}).get('score') if isinstance(reg,dict) else 0),0) or 0; score=_v11856_clip(.48*master_score+.22*(_v11856_f(inst.get('score'),0) or 0)+.20*(_v11856_f(val.get('score'),0) or 0)+.10*heat_score); direction=_v11856_dir(score,14)
    label='Neutral / Wait' if direction=='Neutral' else (('High Probability %s Edge' % direction) if abs(score)>=45 else ('%s Watch' % direction)); action='No clean edge; observe only.' if direction=='Neutral' else 'Trade only after trigger and risk level confirm.'
    warnings=[]; iv_rank=_v11856_f(reg.get('ivRank') if isinstance(reg,dict) else None)
    if iv_rank is not None and iv_rank>=80: warnings.append('High IV rank: option buying has premium-risk; prefer clean trigger or smaller size.')
    if val.get('available') and (_v11856_f(val.get('hitRate5'),50) or 0)<45: warnings.append('Recent validation is weak; flow has not been leading price well today.')
    if direction!='Neutral' and inst.get('direction')!='Neutral' and _v11856_dir_score(inst.get('direction')) != _v11856_dir_score(direction): warnings.append('EOD FII/Prop context conflicts with live edge.')
    payload={'available':True,'version':'V11.8.56','symbol':symbol,'date':trade_date,'expiry':expiry,'institutional':inst,'optionRegime':reg,'signalValidation':val,'finalEdge':{'direction':direction,'label':label,'score':round(score,2),'action':action},'warnings':warnings}
    _V11856_PRO_EDGE_CACHE[key]={'created':now,'payload':payload}
    return payload

def _v11856_inject_pro_edge(payload, symbol=None, trade_date=None, expiry=None, band=5):
    if not isinstance(payload,dict): return payload
    try:
        pro=_v11856_build_pro_edge(symbol or payload.get('symbol') or 'NIFTY', trade_date or payload.get('date'), expiry or payload.get('expiry'), band, payload); payload['proEdge']=pro
        trade=payload.get('tradeDecision')
        if isinstance(trade,dict):
            risks=list(trade.get('riskFlags') or []); conf=list(trade.get('confirmations') or []); edge=pro.get('finalEdge') or {}; ed=edge.get('direction') or 'Neutral'; td=trade.get('direction') or 'Neutral'
            for w in pro.get('warnings') or []:
                if w not in risks: risks.append(w)
            if ed!='Neutral' and td!='Neutral' and _v11856_dir_score(ed)!=_v11856_dir_score(td):
                msg='Pro Edge conflicts with Trade Decision; downgrade to WATCH until alignment returns.'; risks.append(msg) if msg not in risks else None
                if trade.get('decision')=='READY': trade['decision']='WATCH'; trade['action']=msg
            elif ed!='Neutral' and td!='Neutral':
                msg='Pro Edge confirms %s with score %+.2f.'%(ed,_v11856_f(edge.get('score'),0) or 0); conf.append(msg) if msg not in conf else None
            trade['riskFlags']=risks; trade['confirmations']=conf
    except Exception as exc:
        payload['proEdge']={'available':False,'error':'%s: %s'%(type(exc).__name__,exc)}
    return payload


def _v11856_cached_pro_edge(symbol, trade_date, expiry, timestamp):
    key_prefix=(normalize_index_symbol(symbol or 'NIFTY'),str(trade_date),str(expiry),str(timestamp))
    for key,item in list(_V11856_PRO_EDGE_CACHE.items()):
        if len(key)>=4 and key[:4]==key_prefix and datetime.now().timestamp()-item.get('created',0)<45:
            return item.get('payload')
    return None

def _v11856_money_flow_light_pro_edge(payload, symbol=None, trade_date=None, expiry=None):
    summary=payload.get('summary') or {}; lanes=payload.get('moneyFlowLanes') or {}; con=lanes.get('confluence') or {}; cash=payload.get('liveCash') or payload.get('cash') or {}; fut=payload.get('future') or {}
    score=_v11856_f(summary.get('finalScore'),0.0) or 0.0; direction=summary.get('finalDirection') or _v11856_dir(score,14)
    heat_bias=con.get('agreedDirection') or summary.get('optionDirection') or 'Neutral'
    warnings=[]
    if summary.get('futureOptionDivergenceFlag'): warnings.append(summary.get('futureOptionDivergenceType') or 'Future/Option divergence warning.')
    if con.get('divergenceAlert'): warnings.append(con.get('divergenceType') or 'Lane divergence warning.')
    return {'available':True,'version':'V11.8.56-light','symbol':symbol or payload.get('symbol'),'date':trade_date or payload.get('date'),'expiry':expiry or payload.get('expiry'),'institutional':{'available':False,'direction':cash.get('direction') or 'Neutral','score':_v11856_r(cash.get('score'),2),'fiiDirection':'EOD tab','propDirection':'EOD tab','source':'Light money-flow summary'},'optionRegime':{'available':False,'ivRank':None,'ivPercentile':None,'ivRegime':'Open 360 Decision for full IV/EM','expectedMove':{},'oiHeatmap':{'bias':heat_bias,'score':_v11856_r(con.get('score'),2),'topCeWall':{},'topPeSupport':{},'rows':[]}},'signalValidation':{'available':False,'bias':'Decision Cache','hitRate5':None,'hitRate10':None,'hitRate15':None,'signalsChecked':0,'recentSignals':[]},'finalEdge':{'direction':direction,'label':('Neutral / Wait' if direction=='Neutral' else ('%s Watch' % direction)),'score':round(_v11856_clip(score),2),'action':'Money Flow range summary; open 360 Decision for full Pro Edge validation.'},'warnings':warnings}
_v11856_base_fast_trade_decision_payload=_v11842_fast_trade_decision_payload
def _v11842_fast_trade_decision_payload(symbol, trade_date=None, expiry=None, band=5):
    return _v11856_inject_pro_edge(_v11856_base_fast_trade_decision_payload(symbol, trade_date=trade_date, expiry=expiry, band=band), symbol, trade_date, expiry, band)

_v11856_base_build_360_money_flow_payload=build_360_money_flow_payload
def build_360_money_flow_payload(symbol, trade_date=None, expiry=None, band=20, start_index=None, end_index=None):
    payload=_v11856_base_build_360_money_flow_payload(symbol, trade_date=trade_date, expiry=expiry, band=band, start_index=start_index, end_index=end_index)
    ts=((payload.get('range') or {}).get('endTimestamp') or payload.get('timestamp')) if isinstance(payload,dict) else None
    cached=_v11856_cached_pro_edge(symbol or (payload.get('symbol') if isinstance(payload,dict) else 'NIFTY'), trade_date or (payload.get('date') if isinstance(payload,dict) else None), expiry or (payload.get('expiry') if isinstance(payload,dict) else None), ts) if isinstance(payload,dict) else None
    if isinstance(payload,dict): payload['proEdge']=cached or _v11856_money_flow_light_pro_edge(payload, symbol, trade_date, expiry)
    return payload

# ============================== V11.8.57 BIG PLAYER RULE ENGINE ==============================
# COI/VOL is a concentration clue, not a standalone big-player proof. This layer
# adds size, premium exposure, COI/NT concentration, z-score, and repeat checks.
_V11857_BIG_PLAYER_STREAKS = {}


def _v11857_num(value, default=0.0):
    number = to_number(value)
    return default if number is None else float(number)


def _v11857_safe_div(num, den):
    num = to_number(num)
    den = to_number(den)
    if num is None or den in (None, 0):
        return None
    return float(num) / float(den)


def _v11857_percentile(values, pct):
    vals = sorted(float(v) for v in values if to_number(v) is not None)
    if not vals:
        return 0.0
    if len(vals) == 1:
        return vals[0]
    pos = (len(vals) - 1) * max(0.0, min(100.0, float(pct))) / 100.0
    low = int(math.floor(pos))
    high = int(math.ceil(pos))
    if low == high:
        return vals[low]
    return vals[low] + (vals[high] - vals[low]) * (pos - low)


def _v11857_mean_std(values):
    vals = [float(v) for v in values if to_number(v) is not None]
    if not vals:
        return 0.0, 0.0
    mean = sum(vals) / len(vals)
    if len(vals) < 2:
        return mean, 0.0
    var = sum((v - mean) ** 2 for v in vals) / max(1, len(vals) - 1)
    return mean, math.sqrt(max(0.0, var))


def _v11857_thresholds(payload, rows):
    rng = payload.get("range") or {}
    points = int(_v11857_num(rng.get("points"), 1) or 1)
    scale = math.sqrt(max(1, points))
    vol_values = [abs(_v11857_num(r.get("volumeDelta"), 0.0)) for r in rows]
    coi_values = [abs(_v11857_num(r.get("oiDelta"), 0.0)) for r in rows]
    gross_values = [abs(_v11857_num(r.get("grossFlowCr", r.get("premiumFlowCr")), 0.0)) for r in rows]
    min_volume = max(250.0, 500.0 * scale)
    min_abs_coi = max(100.0, 100.0 * scale)
    min_gross_cr = max(0.03, 0.03 * scale)
    if vol_values:
        min_volume = max(min_volume, _v11857_percentile(vol_values, 35) * 0.20)
    if coi_values:
        min_abs_coi = max(min_abs_coi, _v11857_percentile(coi_values, 35) * 0.20)
    if gross_values:
        min_gross_cr = max(min_gross_cr, _v11857_percentile(gross_values, 35) * 0.20)
    return {
        "points": points,
        "minVolume": round(min_volume, 2),
        "minAbsCoi": round(min_abs_coi, 2),
        "minPremiumCr": round(min_gross_cr, 4),
        "watchRatio": 0.25,
        "activeRatio": 0.40,
        "strongRatio": 0.60,
    }


def _v11857_action_state(row):
    action = str(row.get("action") or "").lower()
    side = str(row.get("side") or "").upper()
    if row.get("exchangeHandsRisk") or "exchange" in action:
        return "Exchange of Hands / Trap Risk"
    if "fresh buying" in action:
        return "CE Buying Breakout" if side == "CE" else "PE Buying Breakdown"
    if "buying watch" in action:
        return "Buying Watch"
    if "short covering" in action:
        return "CE Wall Unwind" if side == "CE" else "PE Writer Exit"
    if "writing" in action:
        return "CE Writing Resistance" if side == "CE" else "PE Writing Support"
    if "long unwinding" in action:
        return "CE Long Exit" if side == "CE" else "PE Long Exit"
    if "volume" in action:
        return "Volume Watch"
    return "Neutral"


def _v11857_presence_tier(row):
    ratio = _v11857_num(row.get("coiVolScore"), 0.0)
    if row.get("dataGlitch"):
        return "Data Watch"
    if ratio < 0.10:
        return "Normal"
    if ratio < 0.25:
        return "Active Participation"
    if not row.get("sizeOk"):
        return "Ratio Watch - Small Size"
    if row.get("strongBigPlayer"):
        return "Strong Big Player"
    if row.get("bigPlayerActive"):
        return "Big Player Active"
    return "Big Player Watch"


def _v11857_streak_group(row):
    action = str(row.get("action") or "").lower()
    if "writing" in action:
        return "writing"
    if "covering" in action:
        return "covering"
    if "buying" in action:
        return "buying"
    if "unwinding" in action:
        return "unwinding"
    if "exchange" in action:
        return "exchange"
    return "watch"


def _v11857_update_streak(payload, row):
    rng = payload.get("range") or {}
    points = int(_v11857_num(rng.get("points"), 1) or 1)
    if points > 3 or not row.get("bigPlayerActive"):
        return int(_v11857_num(row.get("repeatCount"), 0))
    timestamp = str((rng.get("endTimestamp") or payload.get("timestamp") or row.get("timestamp") or ""))
    if not timestamp:
        return 0
    key = "{}|{}|{}|{}|{}".format(payload.get("symbol") or row.get("symbol") or "", payload.get("date") or "", payload.get("expiry") or row.get("expiry") or "", row.get("strike"), row.get("side"))
    group = _v11857_streak_group(row)
    direction = str(row.get("direction") or "Neutral")
    prev = _V11857_BIG_PLAYER_STREAKS.get(key)
    if prev and prev.get("timestamp") == timestamp:
        return int(prev.get("count") or 1)
    if prev and prev.get("direction") == direction and prev.get("group") == group:
        count = int(prev.get("count") or 0) + 1
    else:
        count = 1
    _V11857_BIG_PLAYER_STREAKS[key] = {"timestamp": timestamp, "direction": direction, "group": group, "count": count}
    return count


def _v11857_player_confidence(row, thresholds):
    ratio = _v11857_num(row.get("coiVolScore"), 0.0)
    abs_nt = abs(_v11857_num(row.get("coiPerNT"), 0.0))
    z = _v11857_num(row.get("coiNtZScore"), 0.0)
    repeat = int(_v11857_num(row.get("repeatCount"), 0))
    conf = 20.0
    if ratio >= 0.60:
        conf += 30
    elif ratio >= 0.40:
        conf += 24
    elif ratio >= 0.25:
        conf += 16
    elif ratio >= 0.10:
        conf += 6
    if row.get("sizeOk"):
        conf += 22
    elif row.get("bigPlayerWatch"):
        conf -= 16
    if abs_nt >= 5:
        conf += 15
    elif abs_nt >= 4:
        conf += 12
    elif abs_nt >= 2:
        conf += 6
    if z >= 2:
        conf += 12
    elif z >= 1.25:
        conf += 6
    if repeat >= 3:
        conf += 15
    elif repeat >= 2:
        conf += 9
    gross = abs(_v11857_num(row.get("grossFlowCr", row.get("premiumFlowCr")), 0.0))
    if gross >= (thresholds.get("minPremiumCr") or 0.03) * 3:
        conf += 8
    if row.get("exchangeHandsRisk"):
        conf -= 18
    return round(max(0.0, min(100.0, conf)), 2)


def _v11857_guard_reason(row, thresholds):
    reasons = []
    if row.get("coiVolScore", 0) >= 0.25:
        reasons.append("COI/VOL ok")
    if not row.get("sizeOk"):
        reasons.append("size too small")
    if abs(_v11857_num(row.get("coiPerNT"), 0.0)) >= 4:
        reasons.append("COI/NT ok")
    elif _v11857_num(row.get("coiNtZScore"), 0.0) >= 2:
        reasons.append("COI/NT unusual")
    if int(_v11857_num(row.get("repeatCount"), 0)) >= 2:
        reasons.append("repeat confirmed")
    if row.get("exchangeHandsRisk"):
        reasons.append("churn risk")
    return "; ".join(reasons) if reasons else "normal"


def _v11857_apply_big_player_rules(payload):
    if not isinstance(payload, dict):
        return payload
    rows = payload.get("rows") or []
    if not rows:
        return payload
    lot = int(_v11857_num(payload.get("lotSize"), _v11819_lot_size(payload.get("symbol") or "NIFTY")) or 65)
    thresholds = _v11857_thresholds(payload, rows)
    abs_nt_values = [abs(_v11857_num(r.get("coiPerNT"), 0.0)) for r in rows if to_number(r.get("coiPerNT")) is not None]
    nt_mean, nt_std = _v11857_mean_std(abs_nt_values)
    for row in rows:
        vol = abs(_v11857_num(row.get("volumeDelta"), 0.0))
        abs_coi = abs(_v11857_num(row.get("oiDelta"), 0.0))
        gross = abs(_v11857_num(row.get("grossFlowCr", row.get("premiumFlowCr")), 0.0))
        ratio = (abs_coi / vol) if vol > 0 else 0.0
        abs_nt = abs(_v11857_num(row.get("coiPerNT"), 0.0))
        nt_z = ((abs_nt - nt_mean) / nt_std) if nt_std > 0 else 0.0
        size_ok = vol >= thresholds["minVolume"] and abs_coi >= thresholds["minAbsCoi"] and gross >= thresholds["minPremiumCr"]
        watch = ratio >= thresholds["watchRatio"]
        active = watch and size_ok
        row["coiVolScore"] = round(ratio, 4)
        row["coiVolPct"] = round(_v11857_safe_div(abs_coi * 100.0, vol) or 0.0, 4)
        row["coiNtZScore"] = round(nt_z, 2)
        row["sizeOk"] = bool(size_ok)
        row["bigPlayerWatch"] = bool(watch)
        row["bigPlayerActive"] = bool(active)
        row["bigPlayerNTOnly"] = bool(row.get("bigPlayerNT"))
        row["dataGlitch"] = bool(vol <= 0 and abs_coi > 0)
    for row in rows:
        repeat = _v11857_update_streak(payload, row)
        row["repeatCount"] = repeat
        ratio = _v11857_num(row.get("coiVolScore"), 0.0)
        abs_nt = abs(_v11857_num(row.get("coiPerNT"), 0.0))
        nt_z = _v11857_num(row.get("coiNtZScore"), 0.0)
        strong = bool(row.get("bigPlayerActive") and ratio >= thresholds["strongRatio"] and (abs_nt >= 4 or nt_z >= 2 or repeat >= 2))
        row["strongBigPlayer"] = strong
        row["playerState"] = _v11857_action_state(row)
        row["presenceTier"] = _v11857_presence_tier(row)
        row["playerConfidence"] = _v11857_player_confidence(row, thresholds)
        row["guardReason"] = _v11857_guard_reason(row, thresholds)
    summary = payload.setdefault("summary", {})
    gross_total = _v11857_num(summary.get("grossFlowCr"), 0.0) or sum(abs(_v11857_num(r.get("grossFlowCr", r.get("premiumFlowCr")), 0.0)) for r in rows)
    active_rows = [r for r in rows if r.get("bigPlayerActive")]
    strong_rows = [r for r in rows if r.get("strongBigPlayer")]
    watch_rows = [r for r in rows if r.get("bigPlayerWatch")]
    small_rows = [r for r in rows if r.get("bigPlayerWatch") and not r.get("sizeOk")]
    active_flow = sum(abs(_v11857_num(r.get("grossFlowCr", r.get("premiumFlowCr")), 0.0)) for r in active_rows)
    strong_flow = sum(abs(_v11857_num(r.get("grossFlowCr", r.get("premiumFlowCr")), 0.0)) for r in strong_rows)
    signed_active = sum(_v11857_num(r.get("signedFlowCr"), 0.0) for r in active_rows)
    quality_direction = "Bullish" if signed_active > 0.05 else ("Bearish" if signed_active < -0.05 else "Neutral")
    top_row = max(active_rows, key=lambda r: (_v11857_num(r.get("playerConfidence"), 0.0), abs(_v11857_num(r.get("grossFlowCr", r.get("premiumFlowCr")), 0.0))), default={})
    summary.update({
        "bigPlayerRuleVersion": "V11.8.57",
        "bigPlayerThresholds": thresholds,
        "bigPlayerWatchRows": len(watch_rows),
        "bigPlayerActiveRows": len(active_rows),
        "strongBigPlayerRows": len(strong_rows),
        "bigPlayerSmallSizeRows": len(small_rows),
        "bigPlayerActiveFlowCr": round(active_flow, 4),
        "strongBigPlayerFlowCr": round(strong_flow, 4),
        "bigPlayerActiveConcentrationPct": round((active_flow / gross_total * 100.0) if gross_total else 0.0, 2),
        "strongBigPlayerConcentrationPct": round((strong_flow / gross_total * 100.0) if gross_total else 0.0, 2),
        "bigPlayerQualityDirection": quality_direction,
        "bigPlayerQualityScore": round(max(-100.0, min(100.0, signed_active / max(active_flow, 0.0001) * 100.0)) if active_flow else 0.0, 2),
        "topBigPlayerState": top_row.get("playerState") or "None",
        "topBigPlayerStrike": top_row.get("strike"),
        "topBigPlayerSide": top_row.get("side"),
        "topBigPlayerConfidence": top_row.get("playerConfidence"),
        "bigPlayerRuleText": "COI/VOL >= 0.25 is watch only. Active requires size and premium exposure. Strong requires ratio >= 0.60 plus COI/NT, z-score, or repeat.",
    })
    payload["rows"] = sorted(rows, key=lambda r: (bool(r.get("strongBigPlayer")), bool(r.get("bigPlayerActive")), _v11857_num(r.get("playerConfidence"), 0.0), abs(_v11857_num(r.get("grossFlowCr", r.get("premiumFlowCr")), 0.0))), reverse=True)
    note = " Big Player rule: COI/VOL alone is watch only; Active/Strong needs size, premium exposure, COI/NT or repeat confirmation."
    payload["howToUse"] = (payload.get("howToUse") or "") + note
    return payload


def _v11857_apply_presence_guard(payload):
    if not isinstance(payload, dict):
        return payload
    rows = payload.get("rows") or []
    if not rows:
        return payload
    lot = int(_v11857_num(payload.get("lotSize"), 65) or 65)
    fake_payload = {"symbol": payload.get("symbol"), "lotSize": lot, "range": {"points": 1}}
    fake_rows = []
    for row in rows:
        premium = _v11857_num(row.get("premium"), 0.0)
        volume = abs(_v11857_num(row.get("volume"), 0.0))
        gross_cr = premium * volume * lot / 10000000.0
        fake_rows.append({"volumeDelta": volume, "oiDelta": row.get("coi"), "grossFlowCr": gross_cr})
    thresholds = _v11857_thresholds(fake_payload, fake_rows)
    for row in rows:
        volume = abs(_v11857_num(row.get("volume"), 0.0))
        abs_coi = abs(_v11857_num(row.get("coi"), 0.0))
        premium = _v11857_num(row.get("premium"), 0.0)
        gross_cr = premium * volume * lot / 10000000.0
        ratio = _v11857_num(row.get("presence"), 0.0)
        size_ok = volume >= thresholds["minVolume"] and abs_coi >= thresholds["minAbsCoi"] and gross_cr >= thresholds["minPremiumCr"]
        active = ratio >= 4 and size_ok
        strong = active and ratio >= 6
        row["grossFlowCr"] = round(gross_cr, 4)
        row["sizeOk"] = bool(size_ok)
        row["bigPlayerWatch"] = ratio >= thresholds["watchRatio"]
        row["bigPlayerActive"] = bool(active)
        row["strongBigPlayer"] = bool(strong)
        row["coiVolScore"] = round(ratio, 4)
        row["presenceTier"] = _v11857_presence_tier(row)
        row["guardReason"] = _v11857_guard_reason(row, thresholds)
    active_rows = [r for r in rows if r.get("bigPlayerActive")]
    payload["summary"] = {
        "ruleVersion": "V11.8.57",
        "thresholds": thresholds,
        "watchRows": sum(1 for r in rows if r.get("bigPlayerWatch")),
        "activeRows": len(active_rows),
        "strongRows": sum(1 for r in rows if r.get("strongBigPlayer")),
        "smallSizeRows": sum(1 for r in rows if r.get("bigPlayerWatch") and not r.get("sizeOk")),
    }
    payload["rows"] = sorted(rows, key=lambda r: (bool(r.get("strongBigPlayer")), bool(r.get("bigPlayerActive")), _v11857_num(r.get("presence"), 0.0)), reverse=True)
    payload["formula"] = "COI/VOL >= 0.25 is watch. Active/Strong also requires meaningful 1m volume, COI, and premium exposure."
    return payload


_v11857_base_build_360_money_flow_payload = build_360_money_flow_payload

def build_360_money_flow_payload(symbol, trade_date=None, expiry=None, band=20, start_index=None, end_index=None):
    return _v11857_apply_big_player_rules(_v11857_base_build_360_money_flow_payload(symbol, trade_date=trade_date, expiry=expiry, band=band, start_index=start_index, end_index=end_index))


_v11857_base_build_big_player_presence_payload = build_big_player_presence_payload

def build_big_player_presence_payload(symbol, trade_date=None, expiry=None, threshold=0.25, lot_size=65):
    return _v11857_apply_presence_guard(_v11857_base_build_big_player_presence_payload(symbol, trade_date=trade_date, expiry=expiry, threshold=threshold, lot_size=lot_size))

# ============================== V11.8.59 FUTURE FLOW V2 ==============================
# Futures money flow is upgraded from price/OI only to price + OI + basis trend
# + volume expansion + COI/NT concentration. Basis = future price - spot.

def _v11859_f(value, default=0.0):
    number = to_number(value)
    return default if number is None else float(number)


def _v11859_clip(value, low=-100.0, high=100.0):
    return max(low, min(high, _v11859_f(value, 0.0)))


def _v11859_sign(value, threshold=0.0):
    value = _v11859_f(value, 0.0)
    if value > threshold:
        return 1
    if value < -threshold:
        return -1
    return 0


def _v11859_avg(values):
    vals = [_v11859_f(v, None) for v in values]
    vals = [v for v in vals if v is not None]
    return (sum(vals) / len(vals)) if vals else None


def _v11859_halves(points, field):
    points = points or []
    if not points:
        return None, None
    split = max(1, len(points) // 2)
    first = _v11859_avg([p.get(field) for p in points[:split]])
    second = _v11859_avg([p.get(field) for p in points[split:]]) if len(points) > split else _v11859_avg([points[-1].get(field)])
    return first, second


def _v11859_pct_change(new, old):
    old = _v11859_f(old, None)
    new = _v11859_f(new, None)
    if old in (None, 0) or new is None:
        return None
    return ((new - old) / abs(old)) * 100.0


def _v11859_future_point_nt(point, cpt):
    trades = to_number((point or {}).get("futureNoOfTrades"))
    if trades is not None and trades > 0:
        return trades, "Live noOfTrades"
    volume = to_number((point or {}).get("futureVolume"))
    nt = _v11819_safe_div(volume, cpt)
    return nt, "EOD CPT Approx"


def _v11859_future_point_coi_nt(point, cpt):
    nt, _source = _v11859_future_point_nt(point, cpt)
    return _v11819_safe_div((point or {}).get("futureCoi"), nt)


def _v11859_future_flow_v2(payload):
    if not isinstance(payload, dict) or payload.get("error"):
        return payload
    future = payload.get("future") or {}
    summary = payload.get("summary") or {}
    symbol = payload.get("symbol") or "NIFTY"
    trade_date = payload.get("date")
    rng = payload.get("range") or {}
    start_ts = rng.get("startTimestamp") or future.get("rangeStartTimestamp") or payload.get("previousTimestamp") or payload.get("timestamp")
    end_ts = rng.get("endTimestamp") or future.get("rangeEndTimestamp") or payload.get("timestamp")
    try:
        futures_series = build_futures_series(symbol, trade_date)
        selected = _v11820_future_points_in_range(futures_series, start_ts, end_ts)
    except Exception:
        selected = []
    if not selected:
        latest = future or {}
        selected = [latest] if latest else []
    if not selected:
        return payload

    first = selected[0]
    last = selected[-1]
    cpt = _v11859_f(future.get("contractsPerTrade"), _v11819_contracts_per_trade(payload.get("calibration") or {}, segment="FUTURE")) or 1.0
    first_price = to_number(first.get("futurePrice"))
    last_price = to_number(last.get("futurePrice"))
    first_oi = to_number(first.get("futureOpenInterest"))
    last_oi = to_number(last.get("futureOpenInterest"))
    first_basis = to_number(first.get("basis"))
    last_basis = to_number(last.get("basis"))
    price_change = (last_price - first_price) if first_price is not None and last_price is not None else to_number(future.get("rangePriceChange"))
    oi_change = (last_oi - first_oi) if first_oi is not None and last_oi is not None else to_number(future.get("rangeOiChange"))
    basis_delta = (last_basis - first_basis) if first_basis is not None and last_basis is not None else None

    vol_first, vol_second = _v11859_halves(selected, "futureVolume")
    volume_trend = (vol_second - vol_first) if vol_first is not None and vol_second is not None else None
    volume_trend_pct = _v11859_pct_change(vol_second, vol_first)
    coi_nt_values = [_v11859_future_point_coi_nt(p, cpt) for p in selected]
    split = max(1, len(coi_nt_values) // 2)
    coi_nt_first = _v11859_avg([abs(v) for v in coi_nt_values[:split] if v is not None])
    coi_nt_second = _v11859_avg([abs(v) for v in coi_nt_values[split:] if v is not None]) if len(coi_nt_values) > split else _v11859_avg([abs(coi_nt_values[-1])] if coi_nt_values[-1] is not None else [])
    coi_nt_trend = (coi_nt_second - coi_nt_first) if coi_nt_first is not None and coi_nt_second is not None else None
    range_nt = _v11859_f(future.get("approxNT"), 0.0)
    range_coi_nt = to_number(future.get("futureCoiPerNT"))

    price_sign = _v11859_sign(price_change, 0.05)
    oi_sign = _v11859_sign(oi_change, 0.0)
    basis_sign = _v11859_sign(basis_delta, 0.10) if basis_delta is not None else 0
    volume_expanding = bool(volume_trend is not None and volume_trend > 0)
    coi_nt_increasing = bool(coi_nt_trend is not None and coi_nt_trend > 0)

    score = 0.0
    reasons = []
    if price_sign:
        price_score = min(34.0, abs(_v11859_f(price_change)) * 1.15)
        score += price_sign * price_score
        reasons.append("future price {} {:+.2f} pts".format("up" if price_sign > 0 else "down", _v11859_f(price_change)))
    if price_sign and oi_change is not None:
        if oi_sign > 0:
            oi_score = min(22.0, abs(_v11859_f(oi_change)) / 55.0)
            score += price_sign * oi_score
            reasons.append("OI adding confirms build-up")
        elif oi_sign < 0:
            oi_score = min(12.0, abs(_v11859_f(oi_change)) / 90.0)
            score += price_sign * oi_score
            reasons.append("OI reducing: covering/unwinding, lower conviction")
    if basis_sign:
        basis_score = min(22.0, abs(_v11859_f(basis_delta)) * 4.0)
        score += basis_sign * basis_score
        reasons.append("basis {} {:+.2f}".format("widening" if basis_sign > 0 else "collapsing", _v11859_f(basis_delta)))
        if price_sign and basis_sign != price_sign:
            reasons.append("basis diverges from futures price move")
    if price_sign and volume_trend is not None:
        vol_score = min(12.0, abs(_v11859_f(volume_trend_pct, 0.0)) / 4.0 if volume_trend_pct is not None else abs(_v11859_f(volume_trend)) / 5000.0)
        if volume_expanding:
            score += price_sign * vol_score
            reasons.append("future volume expanding")
        else:
            score -= price_sign * min(6.0, vol_score)
            reasons.append("future volume not expanding")
    if price_sign and coi_nt_trend is not None:
        nt_score = min(12.0, abs(_v11859_f(coi_nt_trend)) * 3.0)
        if coi_nt_increasing:
            score += price_sign * nt_score
            reasons.append("COI/NT concentration rising")
        else:
            score -= price_sign * min(6.0, nt_score)
            reasons.append("COI/NT concentration not rising")
    score = round(_v11859_clip(score), 2)
    direction = "Bullish" if score >= 15 else ("Bearish" if score <= -15 else "Neutral")
    direction_score = 1 if direction == "Bullish" else (-1 if direction == "Bearish" else 0)
    if direction == "Bullish" and oi_sign > 0 and basis_sign >= 0:
        action = "V2 Long Build-up"
    elif direction == "Bullish" and oi_sign < 0:
        action = "V2 Short Covering"
    elif direction == "Bearish" and oi_sign > 0 and basis_sign <= 0:
        action = "V2 Short Build-up"
    elif direction == "Bearish" and oi_sign < 0:
        action = "V2 Long Unwinding"
    elif direction == "Neutral":
        action = "V2 Neutral / Mixed"
    else:
        action = "V2 Future Flow Watch"
    confirmations = sum(bool(x) for x in [price_sign, oi_sign, basis_sign, volume_expanding, coi_nt_increasing])
    confidence = round(max(0.0, min(100.0, 28.0 + abs(score) * 0.65 + confirmations * 5.0)), 2)
    flow_cr = _v11859_f(future.get("futureFlowCr"), 0.0)

    legacy = {
        "action": future.get("action"),
        "direction": future.get("direction"),
        "directionScore": future.get("directionScore"),
        "confidence": future.get("confidence"),
        "summaryScore": summary.get("futureScore"),
    }
    v2 = {
        "version": "V11.8.59",
        "action": action,
        "direction": direction,
        "directionScore": direction_score,
        "score": score,
        "confidence": confidence,
        "priceChange": round(_v11859_f(price_change), 4) if price_change is not None else None,
        "oiChange": round(_v11859_f(oi_change), 4) if oi_change is not None else None,
        "basisStart": round(_v11859_f(first_basis), 4) if first_basis is not None else None,
        "basisEnd": round(_v11859_f(last_basis), 4) if last_basis is not None else None,
        "basisDelta": round(_v11859_f(basis_delta), 4) if basis_delta is not None else None,
        "basisTrend": "Widening" if basis_sign > 0 else ("Collapsing" if basis_sign < 0 else "Flat/NA"),
        "volumeFirstAvg": round(_v11859_f(vol_first), 2) if vol_first is not None else None,
        "volumeSecondAvg": round(_v11859_f(vol_second), 2) if vol_second is not None else None,
        "volumeTrend": round(_v11859_f(volume_trend), 2) if volume_trend is not None else None,
        "volumeTrendPct": round(_v11859_f(volume_trend_pct), 2) if volume_trend_pct is not None else None,
        "volumeExpanding": volume_expanding,
        "coiNtFirstAvg": round(_v11859_f(coi_nt_first), 4) if coi_nt_first is not None else None,
        "coiNtSecondAvg": round(_v11859_f(coi_nt_second), 4) if coi_nt_second is not None else None,
        "coiNtTrend": round(_v11859_f(coi_nt_trend), 4) if coi_nt_trend is not None else None,
        "coiNtIncreasing": coi_nt_increasing,
        "rangeCoiPerNT": round(_v11859_f(range_coi_nt), 4) if range_coi_nt is not None else None,
        "rangeNT": round(range_nt, 2),
        "points": len(selected),
        "reasons": reasons,
        "legacy": legacy,
    }
    future.update({
        "futureFlowV2": v2,
        "legacyAction": legacy.get("action"),
        "legacyDirection": legacy.get("direction"),
        "legacyConfidence": legacy.get("confidence"),
        "action": action,
        "direction": direction,
        "directionScore": direction_score,
        "confidence": confidence,
        "signedFlowCr": direction_score * flow_cr,
        "futureV2Score": score,
        "basisDelta": v2.get("basisDelta"),
        "basisTrend": v2.get("basisTrend"),
        "volumeTrendPct": v2.get("volumeTrendPct"),
        "coiNtTrend": v2.get("coiNtTrend"),
    })
    payload["future"] = future

    option_score = _v11859_f(summary.get("optionScore"), 0.0)
    live_cash = payload.get("liveCash") or {}
    live_cash_score = _v11859_clip(live_cash.get("score"), -100, 100)
    cash = payload.get("cash") or {}
    cash_dir = 1 if cash.get("direction") == "Bullish" else (-1 if cash.get("direction") == "Bearish" else 0)
    cash_score = cash_dir * min(100.0, abs(_v11859_f(cash.get("score"), 0.0)))
    summary["futureLegacyScore"] = legacy.get("summaryScore")
    summary["futureScore"] = score
    summary["futureV2Action"] = action
    summary["futureV2Direction"] = direction
    summary["futureV2Confidence"] = confidence
    weights = summary.get("weights") or {}
    if live_cash.get("available"):
        final_score = round((0.40 * score) + (0.35 * live_cash_score) + (0.20 * option_score) + (0.05 * cash_score), 2)
        weights = {"future": 40, "liveCash": 35, "option": 20, "cashEod": 5}
    else:
        final_score = round((0.60 * score) + (0.30 * option_score) + (0.10 * cash_score), 2)
        weights = {"future": 60, "liveCash": 0, "option": 30, "cashEod": 10}
    summary["weights"] = weights
    summary["finalScore"] = final_score
    summary["finalDirection"] = "Bullish" if final_score > 15 else ("Bearish" if final_score < -15 else "Neutral / Range")
    divergence = abs(score - option_score)
    summary["futureOptionDivergence"] = round(divergence, 2)
    summary["futureOptionDivergenceFlag"] = divergence > 35
    summary["futureOptionDivergenceType"] = ("Futures bullish / Options bearish" if score > option_score else "Options bullish / Futures bearish") if divergence > 35 else ""
    payload["summary"] = summary
    lanes = payload.get("moneyFlowLanes")
    if isinstance(lanes, dict):
        fut_lane = dict(lanes.get("futures") or {})
        try:
            strength_fn = globals().get("_v11850_strength")
            strength = strength_fn(score) if strength_fn else ("Strong" if abs(score) >= 60 else ("Medium" if abs(score) >= 25 else "Low"))
            fut_lane.update({
                "direction": direction,
                "strength": strength,
                "score": score,
                "action": action,
                "confidence": confidence,
                "source": "future_flow_v2",
                "basisDelta": v2.get("basisDelta"),
                "basisTrend": v2.get("basisTrend"),
                "volumeTrendPct": v2.get("volumeTrendPct"),
                "coiNtTrend": v2.get("coiNtTrend"),
            })
            lanes["futures"] = fut_lane
            confluence_fn = globals().get("_v11850_confluence")
            if confluence_fn:
                lanes["confluence"] = confluence_fn(fut_lane, lanes.get("options") or {}, lanes.get("cash") or {})
            lanes["futureFlowV2"] = v2
            lanes["version"] = "%s+V11.8.59" % (lanes.get("version") or "V11.8.50")
        except Exception as exc:
            lanes["futureFlowV2Error"] = "%s: %s" % (type(exc).__name__, exc)
        payload["moneyFlowLanes"] = lanes
    payload["howToUse"] = (payload.get("howToUse") or "") + " Future Flow V2 uses basis widening/collapsing, future volume expansion, and COI/NT concentration with price/OI action."
    return payload


_v11859_base_build_360_money_flow_payload = build_360_money_flow_payload

def build_360_money_flow_payload(symbol, trade_date=None, expiry=None, band=20, start_index=None, end_index=None):
    return _v11859_future_flow_v2(_v11859_base_build_360_money_flow_payload(symbol, trade_date=trade_date, expiry=expiry, band=band, start_index=start_index, end_index=end_index))

# ============================== V11.8.61 NSE OC TOTAL COI/OI ==============================
# In the NSE OC snapshot, CE/PE COI/OI % should show total day change in OI
# divided by current OI, while the separate 1m COI columns remain unchanged.

def _v11861_first_oi_map(symbol, trade_date=None, expiry=None):
    try:
        df = read_symbol_table_for_date_expiry_fast(symbol, trade_date, expiry=expiry, max_timestamps=None)
    except Exception:
        try:
            df = read_symbol_table_for_date(symbol, trade_date, max_timestamps=None)
            df = filter_frame_by_expiry(df, expiry)
        except Exception:
            df = pd.DataFrame()
    if df.empty or "timestamp" not in df.columns:
        return {}, None
    strike_col = find_column(df, ("strikePrice", "strike"))
    side_col = find_column(df, ("optionType", "type"))
    oi_col = find_column(df, METRICS["openInterest"]["aliases"])
    if not strike_col or not side_col or not oi_col:
        return {}, None
    timestamps = sorted(df["timestamp"].dropna().unique(), key=parse_timestamp)
    first_ts = timestamps[0] if timestamps else None
    first_df = df[df["timestamp"] == first_ts].copy() if first_ts else pd.DataFrame()
    out = {}
    for _, row in first_df.iterrows():
        strike = to_number(row.get(strike_col))
        side = str(row.get(side_col, "")).upper().strip()
        if strike is None or side not in {"CE", "PE"}:
            continue
        out[(float(strike), side)] = to_number(row.get(oi_col))
    return out, first_ts


def _v11861_apply_nse_oc_total_coi_oi(payload, symbol=None, trade_date=None, expiry=None):
    if not isinstance(payload, dict) or not payload.get("rows"):
        return payload
    symbol = normalize_index_symbol(symbol or payload.get("symbol") or "NIFTY")
    trade_date = trade_date or payload.get("date")
    expiry = expiry or payload.get("expiry")
    first_oi_map, first_ts = _v11861_first_oi_map(symbol, trade_date, expiry)
    if not first_oi_map:
        return payload
    for item in payload.get("rows") or []:
        strike = to_number(item.get("strike"))
        if strike is None:
            continue
        for side, prefix in (("CE", "ce"), ("PE", "pe")):
            cur_oi = to_number(item.get(f"{prefix}Oi"))
            first_oi = first_oi_map.get((float(strike), side))
            if cur_oi is None or first_oi is None:
                continue
            total_coi = cur_oi - first_oi
            total_pct = safe_ratio_pct(total_coi, cur_oi)
            item[f"{prefix}DayStartOi"] = first_oi
            item[f"{prefix}TotalCoi"] = total_coi
            item[f"{prefix}RangePct"] = total_pct
            item[f"{prefix}CoiOiPct"] = total_pct
    payload["coiOiLogic"] = "Total COI/OI % = (current OI - day-start OI) / current OI * 100. 1m COI columns stay unchanged."
    payload["coiOiReferenceTimestamp"] = first_ts
    return payload


_v11861_base_build_nse_oc_payload = build_nse_oc_payload

def build_nse_oc_payload(symbol, trade_date=None, expiry=None, band=5):
    payload = _v11861_base_build_nse_oc_payload(symbol, trade_date=trade_date, expiry=expiry, band=band)
    return _v11861_apply_nse_oc_total_coi_oi(payload, symbol=symbol, trade_date=trade_date, expiry=expiry)

# ============================== V11.8.62 NSE OC SIMPLE COI/OI ==============================
# NSE OC COI/OI % should be the raw latest row formula: changeinOI / openInterest * 100.
# This intentionally differs from 1m COI and day-start total COI calculations.

def _v11862_latest_raw_coi_oi_map(symbol, trade_date=None, expiry=None):
    try:
        df, latest_ts = read_latest_option_snapshot_for_date_expiry(symbol, trade_date, expiry)
    except Exception:
        return {}, None
    if df.empty:
        return {}, latest_ts
    strike_col = find_column(df, ("strikePrice", "strike"))
    side_col = find_column(df, ("optionType", "type"))
    oi_col = find_column(df, METRICS["openInterest"]["aliases"])
    coi_col = find_column(df, ("changeinOI", "changeinOpenInterest", "changeInOpenInterest", "coi", "changeOI"))
    if not strike_col or not side_col or not oi_col or not coi_col:
        return {}, latest_ts
    out = {}
    for _, row in df.iterrows():
        strike = to_number(row.get(strike_col))
        side = str(row.get(side_col, "")).upper().strip()
        if strike is None or side not in {"CE", "PE"}:
            continue
        oi = to_number(row.get(oi_col))
        coi = to_number(row.get(coi_col))
        out[(float(strike), side)] = {
            "openInterest": oi,
            "changeinOI": coi,
            "coiOiPct": safe_ratio_pct(coi, oi),
        }
    return out, latest_ts


def _v11862_apply_nse_oc_simple_coi_oi(payload, symbol=None, trade_date=None, expiry=None):
    if not isinstance(payload, dict) or not payload.get("rows"):
        return payload
    symbol = normalize_index_symbol(symbol or payload.get("symbol") or "NIFTY")
    trade_date = trade_date or payload.get("date")
    expiry = expiry or payload.get("expiry")
    raw_map, latest_ts = _v11862_latest_raw_coi_oi_map(symbol, trade_date, expiry)
    if not raw_map:
        return payload
    for item in payload.get("rows") or []:
        strike = to_number(item.get("strike"))
        if strike is None:
            continue
        for side, prefix in (("CE", "ce"), ("PE", "pe")):
            raw = raw_map.get((float(strike), side))
            if not raw:
                continue
            item[f"{prefix}RawChangeInOI"] = raw.get("changeinOI")
            item[f"{prefix}RawOpenInterest"] = raw.get("openInterest")
            item[f"{prefix}CoiOiPct"] = raw.get("coiOiPct")
            item[f"{prefix}RangePct"] = raw.get("coiOiPct")
    payload["coiOiLogic"] = "Simple COI/OI % = raw changeinOI / raw openInterest * 100 from the latest NSE OC row."
    payload["coiOiReferenceTimestamp"] = latest_ts or payload.get("timestamp")
    return payload


_v11862_base_build_nse_oc_payload = build_nse_oc_payload

def build_nse_oc_payload(symbol, trade_date=None, expiry=None, band=5):
    payload = _v11862_base_build_nse_oc_payload(symbol, trade_date=trade_date, expiry=expiry, band=band)
    return _v11862_apply_nse_oc_simple_coi_oi(payload, symbol=symbol, trade_date=trade_date, expiry=expiry)

# ============================== V11.8.66 STRIKE DATE/TIME COMPARE ==============================
# Compare one CE/PE strike between two date/time snapshots.


def _v11866_number(value):
    return to_number(value)


def _v11866_ratio(num, den):
    num = _v11866_number(num)
    den = _v11866_number(den)
    if num is None or den in (None, 0):
        return None
    try:
        return float(num) / float(den)
    except Exception:
        return None


def _v11866_target_dt(trade_date, time_value):
    text = str(time_value or "").strip()
    if not text:
        return None
    for fmt in ("%d-%b-%Y %H:%M:%S", "%d-%b-%Y %H:%M", "%Y-%m-%d %H:%M:%S", "%Y-%m-%d %H:%M"):
        try:
            return datetime.strptime(text, fmt)
        except Exception:
            pass
    if trade_date:
        short = text[:8]
        for fmt in ("%Y-%m-%d %H:%M:%S", "%Y-%m-%d %H:%M"):
            try:
                candidate = f"{trade_date} {short}"
                return datetime.strptime(candidate, fmt)
            except Exception:
                pass
    return parse_timestamp(text)


def _v11866_time_options(df):
    if df is None or df.empty or "timestamp" not in df.columns:
        return []
    values = sorted({normalize_timestamp(v) for v in df["timestamp"].dropna().tolist()}, key=parse_timestamp)
    return [{"timestamp": ts, "time": timestamp_time_label(ts)} for ts in values]


def _v11866_pick_snapshot_row(df, trade_date=None, time_value=None):
    if df is None or df.empty:
        return None, "No rows found."
    if "timestamp" not in df.columns:
        return df.iloc[-1], "Timestamp column missing; used last row."
    work = df.copy()
    work["_dt"] = work["timestamp"].map(parse_timestamp)
    work = work.sort_values("_dt")
    target = _v11866_target_dt(trade_date, time_value)
    if target is None or target == datetime.min:
        return work.iloc[-1], "Latest snapshot used."
    before = work[work["_dt"] <= target]
    if not before.empty:
        return before.iloc[-1], "At-or-before selected time."
    return work.iloc[0], "No row before selected time; used first available row."


def _v11866_snapshot(symbol, trade_date, expiry, strike, side, time_value):
    available_expiries = get_available_expiries_for_date(symbol, trade_date) if trade_date else []
    chosen_expiry = expiry or (available_expiries[0] if available_expiries else None)
    df = read_option_strike_side_for_date_expiry(symbol, trade_date, chosen_expiry, strike, side)
    times = _v11866_time_options(df)
    row, note = _v11866_pick_snapshot_row(df, trade_date=trade_date, time_value=time_value)
    base = {
        "symbol": symbol,
        "date": trade_date,
        "expiry": chosen_expiry,
        "strike": strike,
        "side": side,
        "requestedTime": time_value or "",
        "timeOptions": times,
        "available": row is not None,
        "note": note,
    }
    if row is None:
        base["error"] = f"No {side} rows found for {strike} on {trade_date} / expiry {chosen_expiry or ''}."
        return base

    frame_cols = df.columns if df is not None else []
    premium_col = find_column(df, METRICS["premium"]["aliases"]) if len(frame_cols) else None
    iv_col = find_column(df, METRICS["iv"]["aliases"]) if len(frame_cols) else None
    volume_col = find_column(df, METRICS["volume"]["aliases"]) if len(frame_cols) else None
    oi_col = find_column(df, METRICS["openInterest"]["aliases"]) if len(frame_cols) else None
    coi_col = find_column(df, ("changeinOI", "changeinOpenInterest", "changeInOpenInterest", "coi", "changeOI")) if len(frame_cols) else None
    spot_col = find_column(df, ("spotPrice", "underlyingValue")) if len(frame_cols) else None

    ltp = _v11866_number(row.get(premium_col)) if premium_col else None
    iv = _v11866_number(row.get(iv_col)) if iv_col else None
    volume = _v11866_number(row.get(volume_col)) if volume_col else None
    oi = _v11866_number(row.get(oi_col)) if oi_col else None
    coi = _v11866_number(row.get(coi_col)) if coi_col else None
    spot = _v11866_number(row.get(spot_col)) if spot_col else None

    base.update({
        "timestamp": normalize_timestamp(row.get("timestamp")) if "timestamp" in row.index else "",
        "time": timestamp_time_label(row.get("timestamp")) if "timestamp" in row.index else "",
        "spot": spot,
        "ltp": ltp,
        "iv": iv,
        "coiVol": _v11866_ratio(coi, volume),
        "coiOiPct": safe_ratio_pct(coi, oi),
        "volume": volume,
        "oi": oi,
        "coi": coi,
        "columns": {
            "ltp": premium_col,
            "iv": iv_col,
            "volume": volume_col,
            "oi": oi_col,
            "coi": coi_col,
            "spot": spot_col,
        },
    })
    return base


def _v11866_diff(a, b):
    labels = [
        ("ltp", "LTP"),
        ("iv", "IV"),
        ("coiVol", "COI/VOL"),
        ("coiOiPct", "COI/OI %"),
        ("volume", "VOL"),
        ("oi", "OI"),
        ("coi", "COI"),
    ]
    out = []
    for key, label in labels:
        av = _v11866_number((a or {}).get(key))
        bv = _v11866_number((b or {}).get(key))
        diff = None if av is None or bv is None else bv - av
        diff_pct = safe_ratio_pct(diff, av) if av not in (None, 0) and diff is not None else None
        out.append({"key": key, "label": label, "a": av, "b": bv, "diff": diff, "diffPct": diff_pct})
    return out


def _v11867_parse_strikes(strike_value):
    if strike_value is None:
        return []
    if isinstance(strike_value, (list, tuple, set)):
        raw_parts = []
        for item in strike_value:
            raw_parts.extend(_v11867_parse_strikes(item))
        out = []
        seen = set()
        for item in raw_parts:
            key = round(float(item), 6)
            if key not in seen:
                seen.add(key)
                out.append(item)
        return out
    text = str(strike_value).strip()
    if not text:
        return []
    for sep in [";", "|", "\n", "\r", "\t", " "]:
        text = text.replace(sep, ",")
    out = []
    seen = set()
    for token in text.split(","):
        token = token.strip()
        if not token:
            continue
        value = to_number(token)
        if value is None:
            continue
        value = int(value) if float(value).is_integer() else value
        key = round(float(value), 6)
        if key in seen:
            continue
        seen.add(key)
        out.append(value)
    return out


def build_strike_compare_payload(symbol, trade_date_a=None, time_a=None, trade_date_b=None, time_b=None, expiry=None, strike_value=None, side="CE"):
    symbol = normalize_index_symbol(symbol or "NIFTY")
    available_dates = get_available_dates(symbol)
    if not trade_date_a and available_dates:
        trade_date_a = available_dates[0]
    if not trade_date_b:
        trade_date_b = trade_date_a
    available_expiries = get_available_expiries_for_date(symbol, trade_date_a) if trade_date_a else []
    if not expiry and available_expiries:
        expiry = available_expiries[0]

    side = str(side or "CE").upper().strip()
    if side not in {"CE", "PE"}:
        side = "CE"

    strikes = _v11867_parse_strikes(strike_value)
    if len(strikes) > 1:
        limited_strikes = strikes[:40]
        items = [
            build_strike_compare_payload(
                symbol,
                trade_date_a=trade_date_a,
                time_a=time_a,
                trade_date_b=trade_date_b,
                time_b=time_b,
                expiry=expiry,
                strike_value=strike,
                side=side,
            )
            for strike in limited_strikes
        ]
        first_item = next((item for item in items if not item.get("error")), items[0] if items else {})
        return {
            "multi": True,
            "symbol": symbol,
            "dateA": trade_date_a,
            "dateB": trade_date_b,
            "expiry": expiry,
            "side": side,
            "strike": ", ".join(str(item) for item in limited_strikes),
            "strikeList": limited_strikes,
            "availableDates": available_dates,
            "availableExpiries": available_expiries,
            "left": first_item.get("left", {}),
            "right": first_item.get("right", {}),
            "items": items,
            "diffRows": [],
            "formula": "COI/VOL = raw changeinOI / raw NSE option-chain Volume (DB noOfTrades). COI/OI % = raw changeinOI / raw openInterest * 100 at the selected timestamp.",
            "generatedAt": datetime.now(IST).strftime("%d-%b-%Y %H:%M:%S"),
            "note": f"Multi-strike compare: {len(limited_strikes)} strike(s).",
        }

    strike = strikes[0] if strikes else None
    if strike is None:
        return {
            "symbol": symbol,
            "dateA": trade_date_a,
            "dateB": trade_date_b,
            "expiry": expiry,
            "side": side,
            "strike": strike_value,
            "availableDates": available_dates,
            "availableExpiries": available_expiries,
            "error": "Please enter a valid strike price. For multiple strikes use comma-separated values like 24350,24400,24450.",
            "left": {},
            "right": {},
            "diffRows": [],
        }

    left = _v11866_snapshot(symbol, trade_date_a, expiry, strike, side, time_a)
    right = _v11866_snapshot(symbol, trade_date_b, expiry, strike, side, time_b)
    return {
        "symbol": symbol,
        "dateA": trade_date_a,
        "dateB": trade_date_b,
        "expiry": expiry,
        "side": side,
        "strike": strike,
        "availableDates": available_dates,
        "availableExpiries": available_expiries,
        "left": left,
        "right": right,
        "diffRows": _v11866_diff(left, right),
        "formula": "COI/VOL = raw changeinOI / raw NSE option-chain Volume (DB noOfTrades). COI/OI % = raw changeinOI / raw openInterest * 100 at the selected timestamp.",
        "generatedAt": datetime.now(IST).strftime("%d-%b-%Y %H:%M:%S"),
    }
# ============================== V11.8.67 HERMES BRIEF ==============================
# Compact Telegram-style smart-money brief built from transparent 360 dashboard layers.

def _v11867_num(value, default=0.0):
    number = to_number(value)
    return default if number is None else float(number)


def _v11867_fmt(value, digits=0):
    number = to_number(value)
    if number is None:
        return "-"
    if digits <= 0:
        return f"{number:,.0f}"
    return f"{number:,.{digits}f}"


def _v11867_signed(value, digits=0):
    number = to_number(value)
    if number is None:
        return "-"
    sign = "+" if number >= 0 else ""
    return sign + _v11867_fmt(number, digits)


def _v11867_direction(value, positive_label="Bullish", negative_label="Bearish", flat_label="Neutral"):
    number = _v11867_num(value, 0.0)
    if number > 0:
        return positive_label
    if number < 0:
        return negative_label
    return flat_label


def _v11867_side_action(side, last20_build, premium_change_pct, iv_change, status):
    side = str(side or "").upper()
    build = _v11867_num(last20_build, 0.0)
    prem = _v11867_num(premium_change_pct, 0.0)
    iv = _v11867_num(iv_change, 0.0)
    status_text = str(status or "")
    if build > 0:
        if side == "CE":
            if prem <= 0 and iv <= 0:
                return "CE writing / resistance build"
            if prem > 0:
                return "CE buying / short-cover watch"
            return "CE OI adding"
        if side == "PE":
            if prem <= 0 and iv <= 0:
                return "PE writing / support build"
            if prem > 0:
                return "PE buying / protection watch"
            return "PE OI adding"
    if build < 0:
        if side == "CE":
            return "CE unwinding / resistance easing"
        if side == "PE":
            return "PE unwinding / support easing"
    if status_text:
        return status_text
    return "Watch"


def _v11867_side_rows(memory_payload, side, limit=5):
    rows = []
    for item in (memory_payload or {}).get("rows") or []:
        side_data = item.get(side) or {}
        if not side_data or str(side_data.get("status") or "") == "No Data":
            continue
        row = {
            "side": side,
            "strike": item.get("strike"),
            "currentOi": side_data.get("currentOi"),
            "last20Build": side_data.get("last20Build"),
            "todayBuild": side_data.get("todayBuild"),
            "currentPremium": side_data.get("currentPremium"),
            "premiumChangePct": side_data.get("premiumChangePct"),
            "ivChange": side_data.get("ivChange"),
            "status": side_data.get("status"),
            "bias": side_data.get("bias"),
            "holdingPct": side_data.get("holdingPct"),
            "action": _v11867_side_action(side, side_data.get("last20Build"), side_data.get("premiumChangePct"), side_data.get("ivChange"), side_data.get("status")),
        }
        rows.append(row)
    rows.sort(key=lambda r: (abs(_v11867_num(r.get("last20Build"), 0.0)), _v11867_num(r.get("currentOi"), 0.0)), reverse=True)
    return rows[:limit]


def _v11867_find_side_row(memory_payload, strike, side):
    target = to_number(strike)
    if target is None:
        return {}
    for item in (memory_payload or {}).get("rows") or []:
        if to_number(item.get("strike")) == target:
            return item.get(side) or {}
    return {}


def build_360_hermes_brief_payload(symbol, trade_date=None, expiry=None, band=5, minutes=20):
    symbol = normalize_index_symbol(symbol or "NIFTY")
    try:
        minutes = max(5, min(60, int(float(minutes or 20))))
    except Exception:
        minutes = 20
    try:
        band = max(1, min(20, int(float(band or 5))))
    except Exception:
        band = 5

    memory = build_360_expiry_memory_payload(symbol, trade_date=trade_date, expiry=expiry, mode="top", span=5, strikes_text="")
    date_value = trade_date or memory.get("date")
    expiry_value = expiry or memory.get("expiry")
    money = build_360_money_flow_payload(symbol, trade_date=date_value, expiry=expiry_value, band=max(20, band), start_index=None, end_index=None)
    master = _v11842_fast_trade_decision_payload(symbol, trade_date=date_value, expiry=expiry_value, band=band)

    mem_summary = memory.get("summary") or {}
    flow_summary = money.get("summary") or {}
    sfm = money.get("signedFlowMomentum") or {}
    lanes = sfm.get("lanes") or {}
    lane_summary = lanes.get("summary") or {}
    opt_lane = lane_summary.get("options") or {}
    fut_lane = lane_summary.get("futures") or {}
    cash_lane = lane_summary.get("cash") or {}
    spot_lane = lane_summary.get("spot") or {}
    trade_decision = master.get("tradeDecision") or {}
    master_summary = master.get("master") or {}

    ce_rows = _v11867_side_rows(memory, "CE", 5)
    pe_rows = _v11867_side_rows(memory, "PE", 5)
    top_ce = mem_summary.get("topCeWall") or {}
    top_pe = mem_summary.get("topPeSupport") or {}
    ce_side = _v11867_find_side_row(memory, top_ce.get("strike"), "CE")
    pe_side = _v11867_find_side_row(memory, top_pe.get("strike"), "PE")
    ce_wall_strike = to_number(top_ce.get("strike"))
    pe_support_strike = to_number(top_pe.get("strike"))
    ce_premium = to_number(ce_side.get("currentPremium"))
    pe_premium = to_number(pe_side.get("currentPremium"))
    ce_ceiling = ce_wall_strike + ce_premium if ce_wall_strike is not None and ce_premium is not None else ce_wall_strike
    pe_floor = pe_support_strike - pe_premium if pe_support_strike is not None and pe_premium is not None else pe_support_strike

    current_ts = memory.get("currentTimestamp") or money.get("currentTimestamp") or money.get("timestamp") or ""
    first_ts = money.get("range", {}).get("fromTimestamp") or memory.get("firstTimestamp") or ""
    last_ts = money.get("range", {}).get("toTimestamp") or current_ts
    spot = to_number(memory.get("spot")) or to_number(spot_lane.get("current")) or to_number(money.get("spot"))
    spot_move = to_number(spot_lane.get("change"))
    if spot_move is None:
        spot_move = to_number((money.get("future") or {}).get("rangePriceChange")) or 0.0
    market_direction = _v11867_direction(spot_move)

    decision_label = trade_decision.get("decision") or master_summary.get("conclusion") or flow_summary.get("finalDirection") or "WAIT"
    recommended = trade_decision.get("recommendedStrike") or trade_decision.get("strike") or master_summary.get("action") or "No trade"
    trigger = trade_decision.get("trigger") or master_summary.get("action") or "Wait for confirmation"
    invalidation = trade_decision.get("invalidation") or trade_decision.get("stop") or "Exit if key wall/support breaks."

    ce_last20 = sum(_v11867_num(row.get("last20Build"), 0.0) for row in ce_rows)
    pe_last20 = sum(_v11867_num(row.get("last20Build"), 0.0) for row in pe_rows)
    ce_today = sum(_v11867_num(row.get("todayBuild"), 0.0) for row in ce_rows)
    pe_today = sum(_v11867_num(row.get("todayBuild"), 0.0) for row in pe_rows)

    key_ce_line = "No clear CE wall."
    if ce_wall_strike is not None:
        key_ce_line = "CE wall %s | OI %s | holding %s%% | ceiling approx %s." % (
            _v11867_fmt(ce_wall_strike, 0),
            _v11867_fmt(top_ce.get("currentOi"), 0),
            _v11867_fmt(top_ce.get("holdingPct"), 2),
            _v11867_fmt(ce_ceiling, 2),
        )
    key_pe_line = "No clear PE support."
    if pe_support_strike is not None:
        key_pe_line = "PE support %s | OI %s | holding %s%% | floor approx %s." % (
            _v11867_fmt(pe_support_strike, 0),
            _v11867_fmt(top_pe.get("currentOi"), 0),
            _v11867_fmt(top_pe.get("holdingPct"), 2),
            _v11867_fmt(pe_floor, 2),
        )

    brief_lines = [
        "%s 360 HERMES BRIEF" % symbol,
        "Time: %s | Expiry: %s | Window: %sm" % (current_ts, expiry_value or "", minutes),
        "Market: %s pts from selected lead-line range. %s tape." % (_v11867_signed(spot_move, 2), market_direction),
        "Spot: %s" % _v11867_fmt(spot, 2),
        "",
        "WHO DID WHAT",
        "Options: %s | current %s Cr | slope %s Cr/min." % (opt_lane.get("direction") or "Neutral", _v11867_signed(opt_lane.get("current"), 4), _v11867_signed(opt_lane.get("slope5"), 4)),
        "Futures V2: %s | current %s Cr | slope %s Cr/min." % (fut_lane.get("direction") or "Neutral", _v11867_signed(fut_lane.get("current"), 4), _v11867_signed(fut_lane.get("slope5"), 4)),
        "Cash: %s | current %s Cr | slope %s Cr/min." % (cash_lane.get("direction") or "Neutral", _v11867_signed(cash_lane.get("current"), 4), _v11867_signed(cash_lane.get("slope5"), 4)),
        "",
        "POSITION MEMORY",
        "CE top rows last20 %s, today %s. PE top rows last20 %s, today %s." % (_v11867_signed(ce_last20, 0), _v11867_signed(ce_today, 0), _v11867_signed(pe_last20, 0), _v11867_signed(pe_today, 0)),
        key_ce_line,
        key_pe_line,
        "Expiry memory: %s | ROC memory: %s." % (mem_summary.get("finalBias") or "Neutral", mem_summary.get("rocFinalBias") or "Neutral"),
        "",
        "PLAN",
        "Decision: %s | Strike: %s." % (decision_label, recommended),
        "Trigger: %s" % trigger,
        "Invalidation: %s" % invalidation,
        "Note: Public data cannot prove FII/Prop ownership intraday; this is probability inference from OI, COI, volume, premium, IV, futures, and cash flow.",
    ]

    return {
        "symbol": symbol,
        "date": date_value,
        "expiry": expiry_value,
        "minutes": minutes,
        "firstTimestamp": first_ts,
        "currentTimestamp": current_ts,
        "generatedAt": datetime.now(IST).strftime("%d-%b-%Y %H:%M:%S"),
        "briefText": "\n".join(brief_lines),
        "cards": {
            "spot": spot,
            "spotMove": spot_move,
            "marketDirection": market_direction,
            "timeBand": "%s to %s" % (timestamp_time_label(first_ts), timestamp_time_label(last_ts)),
            "optionsDirection": opt_lane.get("direction") or "Neutral",
            "optionsCurrentCr": opt_lane.get("current"),
            "optionsSlope5": opt_lane.get("slope5"),
            "futuresDirection": fut_lane.get("direction") or "Neutral",
            "futuresCurrentCr": fut_lane.get("current"),
            "futuresSlope5": fut_lane.get("slope5"),
            "cashDirection": cash_lane.get("direction") or "Neutral",
            "cashCurrentCr": cash_lane.get("current"),
            "cashSlope5": cash_lane.get("slope5"),
            "memoryBias": mem_summary.get("finalBias"),
            "rocMemoryBias": mem_summary.get("rocFinalBias"),
            "rocConfidence": mem_summary.get("rocMemoryConfidence"),
        },
        "levels": {
            "ceWallStrike": ce_wall_strike,
            "ceWallOi": top_ce.get("currentOi"),
            "ceCeiling": ce_ceiling,
            "peSupportStrike": pe_support_strike,
            "peSupportOi": top_pe.get("currentOi"),
            "peFloor": pe_floor,
        },
        "masterDecision": {
            "decision": decision_label,
            "recommendedStrike": recommended,
            "trigger": trigger,
            "invalidation": invalidation,
            "conclusion": master_summary.get("conclusion"),
            "action": master_summary.get("action"),
        },
        "ceRows": ce_rows,
        "peRows": pe_rows,
        "sourceNote": "Hermes Brief reuses 360 Money Flow lead lines, Future Flow V2, live Cash Flow, 360 Expiry Memory, and 360 Trade Decision. It is an inference layer, not direct FII/Prop proof.",
        "raw": {
            "moneySummary": flow_summary,
            "memorySummary": mem_summary,
        },
    }

if __name__ == "__main__":
    main()









